class ResearchManager {
  constructor(game) {
    this.game = game;
    this.researchTopics = [];
    this.branchLabels = {
      propulsion: 'Propulsion',
      energy: 'Energy Systems',
      industry: 'Industrial Engineering',
      materials: 'Advanced Materials',
      colony: 'Colony Development',
      weapons: 'Weapons',
      shields: 'Shielding',
      sensors: 'Sensors & Exploration',
      biology: 'Biology & Medicine',
      computation: 'Computation & AI'
    };
    this.researchTiers = {
      1: { requiredHabitats: 0, minTurns: 0 },
      2: { requiredHabitats: 1, minTurns: 2 },
      3: { requiredHabitats: 2, minTurns: 6 },
      4: { requiredHabitats: 3, minTurns: 12 }
    };
    this.loadResearchTopics();
  }

  loadResearchTopics() {
    $.getJSON('/data/researchTopics.json')
      .done((data) => {
        this.researchTopics = data.map(topic => this.normalizeResearchTopic(topic));
        this.researchTopics = this.researchTopics.map(topic => ({
          ...topic,
          tier: topic.tier || this.calculateResearchTier(topic)
        }));
        console.log('Research topics loaded:', this.researchTopics);
      })
      .fail((jqxhr, textStatus, error) => {
        console.error('Error loading researchTopics.json:', textStatus, error);
      });
  }

  calculateResearchTier(topic) {
    const prereqDepth = this.getPrerequisiteDepth(topic.id, 0);
    const cost = topic.cost || 0;

    if (prereqDepth >= 3 || cost >= 4000) return 4;
    if (prereqDepth >= 2 || cost >= 2500) return 3;
    if (prereqDepth >= 1 || cost >= 1400) return 2;
    return 1;
  }

  getPrerequisiteDepth(topicId, currentDepth, visited = new Set()) {
    if (visited.has(topicId)) return currentDepth;
    visited.add(topicId);

    const topic = this.researchTopics.find(t => t.id === topicId);
    if (!topic || !topic.prerequisites || topic.prerequisites.length === 0) {
      return currentDepth;
    }

    return Math.max(
      ...topic.prerequisites.map(prereqId =>
        this.getPrerequisiteDepth(prereqId, currentDepth + 1, new Set(visited))
      )
    );
  }

  normalize(name) {
    return String(name || '').trim().toLowerCase();
  }

  normalizeResearchTopic(topic) {
    return {
      ...topic,
      branch: topic.branch || this.deriveResearchBranch(topic),
      strategicEffects: topic.strategicEffects || this.deriveStrategicEffects(topic),
      prototypeRequirements: topic.prototypeRequirements || this.buildDefaultPrototypeRequirements(topic)
    };
  }

  deriveResearchBranch(topic) {
    const name = this.normalize(topic.name || '');
    const tags = Array.isArray(topic.tags) ? topic.tags.map(t => this.normalize(t)) : [];
    const desc = this.normalize(topic.description || '');

    if (tags.includes('propulsion') || name.includes('engine') || name.includes('thruster') || name.includes('drive')) return 'propulsion';
    if (tags.includes('weapon') || tags.includes('weapons') || name.includes('laser') || name.includes('missile') || name.includes('rail')) return 'weapons';
    if (tags.includes('shield') || tags.includes('shielding') || name.includes('shield')) return 'shields';
    if (tags.includes('energy') || name.includes('reactor') || name.includes('solar') || name.includes('battery') || name.includes('power')) return 'energy';
    if (tags.includes('industry') || tags.includes('industrial') || name.includes('factory') || name.includes('manufacturing') || name.includes('refinery')) return 'industry';
    if (tags.includes('material') || tags.includes('materials') || name.includes('alloy') || name.includes('composite')) return 'materials';
    if (tags.includes('sensor') || tags.includes('exploration') || tags.includes('scan') || name.includes('sensor') || name.includes('probe')) return 'sensors';
    if (tags.includes('colony') || tags.includes('habitat') || tags.includes('terraforming') || name.includes('habitat') || name.includes('terraf')) return 'colony';
    if (tags.includes('biology') || tags.includes('medical') || tags.includes('medicine') || name.includes('medic') || name.includes('bio')) return 'biology';
    if (tags.includes('computation') || tags.includes('ai') || tags.includes('computing') || name.includes('computer') || name.includes('quantum') || name.includes('neural')) return 'computation';

    if (desc.includes('propulsion') || desc.includes('engine') || desc.includes('drive')) return 'propulsion';
    if (desc.includes('weapon') || desc.includes('combat')) return 'weapons';
    if (desc.includes('shield') || desc.includes('defense')) return 'shields';
    if (desc.includes('energy') || desc.includes('power')) return 'energy';
    if (desc.includes('industrial') || desc.includes('manufacturing')) return 'industry';
    if (desc.includes('material')) return 'materials';
    if (desc.includes('sensor') || desc.includes('exploration') || desc.includes('scan')) return 'sensors';
    if (desc.includes('habitat') || desc.includes('colony') || desc.includes('terraforming')) return 'colony';
    if (desc.includes('biology') || desc.includes('medical')) return 'biology';
    if (desc.includes('computation') || desc.includes('computing') || desc.includes('ai')) return 'computation';

    return 'general';
  }

  deriveStrategicEffects(topic) {
    const effects = [];

    const branch = topic.branch || this.deriveResearchBranch(topic);
    const tier = topic.tier || this.calculateResearchTier(topic);
    const magnitude = tier * 0.25;

    if (branch === 'propulsion') effects.push({ stat: 'shipSpeed', modifier: 1 + magnitude });
    if (branch === 'energy') effects.push({ stat: 'powerOutput', modifier: 1 + magnitude });
    if (branch === 'industry') effects.push({ stat: 'buildSpeed', modifier: 1 + magnitude });
    if (branch === 'materials') effects.push({ stat: 'hullIntegrity', modifier: 1 + magnitude });
    if (branch === 'colony') effects.push({ stat: 'colonyGrowth', modifier: 1 + magnitude });
    if (branch === 'weapons') effects.push({ stat: 'attackPower', modifier: 1 + magnitude });
    if (branch === 'shields') effects.push({ stat: 'shieldStrength', modifier: 1 + magnitude });
    if (branch === 'sensors') effects.push({ stat: 'sensorRange', modifier: 1 + magnitude });
    if (branch === 'biology') effects.push({ stat: 'crewHealth', modifier: 1 + magnitude });
    if (branch === 'computation') effects.push({ stat: 'researchSpeed', modifier: 1 + magnitude });

    if (effects.length === 0) {
      effects.push({ stat: 'researchSpeed', modifier: 1 + magnitude * 0.5 });
    }

    return effects;
  }

  buildDefaultPrototypeRequirements(topic) {
    const tier = topic.tier || this.calculateResearchTier(topic);
    const branch = topic.branch || this.deriveResearchBranch(topic);
    const base = { credits: 500, turns: 3 };

    const tierMul = [1, 1, 1.5, 2.5, 4];
    const branchMul = branch === 'propulsion' || branch === 'energy' ? 1.2 : 1;
    const mul = (tierMul[tier] || 1) * branchMul;

    return {
      credits: Math.round(base.credits * mul),
      turns: Math.round(base.turns * mul),
      facilities: []
    };
  }

  getCommittedBranch(player) {
    return player?.committedResearchBranch || null;
  }

  getPrototypeFacility(player) {
    return player?.colonies?.find(c =>
      (c.buildings || []).some(b => {
        const bn = this.normalize(b.blueprintName || b.name || b.type);
        return bn.includes('prototype') || bn.includes('r&d') || bn.includes('research') || bn.includes('lab');
      })
    ) || null;
  }

  resolvePrototypeResourceAmount(amount, player) {
    const facility = this.getPrototypeFacility(player);
    if (!facility) return amount;
    const eff = (facility.prototypeEfficiency ?? 1);
    return Math.max(1, Math.round(amount / eff));
  }

  getPrototypeReadiness(player, topic) {
    if (!topic || !player) return 0;
    const reqs = topic.prototypeRequirements || this.buildDefaultPrototypeRequirements(topic);
    const creditsOk = (player.credits || 0) >= this.resolvePrototypeResourceAmount(reqs.credits, player);
    const facilityOk = !reqs.facilities || reqs.facilities.length === 0 || !!this.getPrototypeFacility(player);
    if (creditsOk && facilityOk) return 1;
    if ((player.credits || 0) >= Math.round((reqs.credits || 500) * 0.5)) return 0.5;
    return 0;
  }

  consumePrototypeRequirements(player, topic) {
    const reqs = topic.prototypeRequirements || this.buildDefaultPrototypeRequirements(topic);
    const cost = this.resolvePrototypeResourceAmount(reqs.credits, player);
    if ((player.credits || 0) < cost) return false;
    player.credits -= cost;
    if (reqs.turns && typeof player.startPrototypeTimer === 'function') {
      player.startPrototypeTimer(reqs.turns);
    }
    return true;
  }

  getResearchAvailability(player) {
    if (!player || !this.researchTopics.length) return { available: [], locked: [], completed: [] };

    const completed = this.researchTopics.filter(t => player.completedResearch?.includes(t.id));
    const locked = this.researchTopics.filter(t =>
      !player.completedResearch?.includes(t.id) && !this.canStartResearch(player, t.id)
    );
    const available = this.researchTopics.filter(t =>
      !player.completedResearch?.includes(t.id) && this.canStartResearch(player, t.id)
    );

    return { available, locked, completed };
  }

  canStartResearch(player, topicId) {
    const topic = this.researchTopics.find(t => t.id === topicId);
    if (!topic) return false;

    if (player.credits < topic.cost) return false;
    if (player.currentResearch) return false;
    if (player.completedResearch.includes(topicId)) return false;

    const hasPrerequisites = topic.prerequisites.every(prereqId =>
      player.completedResearch.includes(prereqId)
    );
    if (!hasPrerequisites) return false;

    const habitatCount = player.colonies.length;
    const tierReqs = this.researchTiers[topic.tier];
    if (!tierReqs) return false;

    if (habitatCount < tierReqs.requiredHabitats) return false;
    if (this.game.getElapsedLegacyTurnsEquivalent() < tierReqs.minTurns) return false;

    return true;
  }

  getAvailableResearch(player) {
    return this.researchTopics.filter(topic =>
      !player.completedResearch.includes(topic.id) &&
      this.canStartResearch(player, topic.id)
    );
  }

  getTierRequirements(tier) {
    return this.researchTiers[tier];
  }

  getResearchCostMultiplier(player) {
    if (player.isAI) {
      return 1 + (player.personality.researchFocus * 0.5);
    }
    return 1;
  }

  getResearchCatalogue() {
    return this.researchTopics.map(topic => ({
      id: topic.id,
      name: topic.name,
      description: topic.description,
      branch: topic.branch || this.deriveResearchBranch(topic),
      branchLabel: this.branchLabels[topic.branch] || 'General',
      tier: topic.tier || this.calculateResearchTier(topic),
      cost: topic.cost || 0,
      prerequisites: topic.prerequisites || [],
      strategicEffects: topic.strategicEffects || this.deriveStrategicEffects(topic),
      prototypeRequirements: topic.prototypeRequirements || this.buildDefaultPrototypeRequirements(topic)
    }));
  }

  commitPlayerToBranch(player, branch) {
    if (!player || !branch) return false;
    player.committedResearchBranch = branch;
    return true;
  }
}
ResearchManager;


