/**
 * Calculates the 3D position of a celestial body based on its orbital elements and the current date.
 *
 * @param {Object} orbitalElements - The orbital elements of the celestial body.
 * @param {Date} date - The current date.
 * @returns {BABYLON.Vector3} - The 3D position vector of the celestial body.
 */function calculateOrbitalPosition(orbitalElements, date) {
    try {
        const {
            semiMajorAxis: a,
            eccentricity: e,
            inclination: i,
            longitudeOfAscendingNode: Ω,
            argumentOfPeriapsis: ω,
            meanAnomalyAtEpoch: M0,
            epoch,
        } = orbitalElements;

        const degToRad = Math.PI / 180;
        const mu = 1.32712440018e20;

        const i_rad = i * degToRad;
        const Ω_rad = Ω * degToRad;
        const ω_rad = ω * degToRad;

        const julianDate = date.getTime() / 86400000 + 2440587.5;
        const timeSinceEpoch = (julianDate - epoch) * 86400;

        const n = Math.sqrt(mu / Math.pow(a, 3));

        let M = (M0 * degToRad) + n * timeSinceEpoch;
        M = M % (2 * Math.PI);
        if (M < 0) M += 2 * Math.PI;

        let E = M;
        const epsilon = 1e-6;
        let delta = 1;
        let iterations = 0;
        const maxIterations = 100;

        while (delta > epsilon && iterations < maxIterations) {
            const f = E - e * Math.sin(E) - M;
            const fPrime = 1 - e * Math.cos(E);
            const ENext = E - f / fPrime;
            delta = Math.abs(ENext - E);
            E = ENext;
            iterations++;
        }

        if (iterations === maxIterations) {
            console.warn(`Kepler's equation did not converge for ${orbitalElements.name || 'Unnamed Body'}.`);
        }

        const sin_v = (Math.sqrt(1 - e * e) * Math.sin(E)) / (1 - e * Math.cos(E));
        const cos_v = (Math.cos(E) - e) / (1 - e * Math.cos(E));
        const v = Math.atan2(sin_v, cos_v);

        const r = a * (1 - e * Math.cos(E));

        const x_orb = r * Math.cos(v);
        const y_orb = r * Math.sin(v);

        const cos_wv = Math.cos(ω_rad + v);
        const sin_wv = Math.sin(ω_rad + v);

        const cos_Omega = Math.cos(Ω_rad);
        const sin_Omega = Math.sin(Ω_rad);
        const cos_i = Math.cos(i_rad);
        const sin_i = Math.sin(i_rad);

        const x = r * (cos_Omega * cos_wv - sin_Omega * sin_wv * cos_i);
        const y = r * (sin_Omega * cos_wv + cos_Omega * sin_wv * cos_i);
        const z = r * (sin_wv * sin_i);

        return new BABYLON.Vector3(x, y, z);
    } catch (error) {
        console.error(`Error in calculateOrbitalPosition: ${error.message}`);
        return new BABYLON.Vector3(0, 0, 0);
    }
}

