// ===== public/utils.js =====
// public/utils.js

function sanitizeForId(name) {
  if (typeof name !== 'string') return '';
  return name.replace(/[^a-zA-Z0-9-]/g, '-').toLowerCase();
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function updateLabelMetrics($label) {
  if (!$label || $label.length === 0) {
    return null;
  }

  const label = $label.get(0);
  const previousDisplay = label.style.display;
  const previousVisibility = label.style.visibility;

  if (previousDisplay === 'none') {
    label.style.display = 'flex';
  }

  label.style.visibility = 'hidden';

  const rect = label.getBoundingClientRect();
  const width = Math.max(48, Math.ceil(rect.width || label.offsetWidth || 120));
  const height = Math.max(22, Math.ceil(rect.height || label.offsetHeight || 28));

  label.dataset.labelWidth = String(width);
  label.dataset.labelHeight = String(height);

  label.style.display = previousDisplay === 'none' ? 'none' : previousDisplay;
  label.style.visibility = previousVisibility || 'visible';

  return { width, height };
}

const GAME_LOG_MAX_ENTRIES = 120;

const gameLogIconByLevel = {
  info: 'mdi-information-outline',
  success: 'mdi-check-circle-outline',
  warning: 'mdi-alert-outline',
  error: 'mdi-close-circle-outline'
};
function appendGameLogEntry(message, level = 'info', persist = false) {
  const entriesEl = document.getElementById('game-log-entries');
  if (!entriesEl || !message) return;

  const normalizedLevel = ['info', 'success', 'warning', 'error'].includes(level)
    ? level
    : 'info';

  const timestamp = new Date().toLocaleTimeString([], {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  });

  const entry = document.createElement('div');
  entry.className = `game-log-entry game-log-${normalizedLevel}${persist ? ' is-persistent' : ''}`;
  entry.innerHTML = `
    <div class="game-log-icon">
      <i class="mdi ${gameLogIconByLevel[normalizedLevel]}"></i>
    </div>
    <div class="game-log-copy">
      <div class="game-log-meta">${escapeHtml(timestamp)} · ${escapeHtml(normalizedLevel)}</div>
      <div class="game-log-message">${escapeHtml(message)}</div>
    </div>
  `;

  entriesEl.prepend(entry);

  while (entriesEl.children.length > GAME_LOG_MAX_ENTRIES) {
    entriesEl.removeChild(entriesEl.lastChild);
  }

  entriesEl.scrollTop = 0;
}

if (typeof globalThis !== 'undefined') {
  globalThis.showToast = (message, level = 'info', persist = false) => {
    appendGameLogEntry(message, level, persist);
  };
}
function refreshSpaceLabelMetrics(label) {
  if (!label) {
    return null;
  }

  return updateLabelMetrics($(label));
}
function createAggregateLabel(game, clusterIndex = 0) {
  const labelsContainer = $('#labels-container');
  if (labelsContainer.length === 0) return null;

  const labelId = `label-overlap-cluster-${clusterIndex}`;
  let $label = $(`#${labelId}`);

  if ($label.length === 0) {
    $label = $('<div>', {
      id: labelId,
      class: 'space-label space-label--grouped space-label--aggregate',
      title: '',
      html: `
        <div class="label-chip">
          <span class="label-chip-icon"><i class="mdi mdi-label-multiple-outline"></i></span>
          <span class="label-chip-text" style="max-width:220px;">Grouped objects</span>
          <span class="label-chip-count" style="min-width:20px;height:20px;padding:0 6px;border-radius:999px;display:inline-flex;align-items:center;justify-content:center;background:rgba(86,215,255,0.14);border:1px solid rgba(86,215,255,0.18);color:#f3fbff;font-size:10px;font-weight:800;line-height:1;">0</span>
        </div>
      `
    });

    $label.css({
      left: '0px',
      top: '0px',
      display: 'none',
      visibility: 'hidden',
      transform: 'translate3d(-9999px, -9999px, 0) translate(-50%, -50%)',
      willChange: 'transform'
    });

    $label.on('click', (e) => {
      e.stopPropagation();

      const label = e.currentTarget;
      const primaryName = label.dataset.primaryName;
      const primaryType = label.dataset.primaryType || 'planet';

      if (!primaryName) {
        return;
      }

      game.focusOnObject(primaryName, primaryType);
    });

    labelsContainer.append($label);
    updateLabelMetrics($label);
  }

  return $label.get(0);
}
function createLabel(game, object, type) {
  const labelsContainer = $('#labels-container');
  if (labelsContainer.length === 0) return;

  const sanitizedName = sanitizeForId(object.name);
  const labelId = `label-${sanitizedName}`;

  if ($(`#${labelId}`).length > 0) {
    return;
  }

  if (object.mesh) {
    game.labeledObjects.push(object);
  } else if (type === 'colony' && object.planet && object.planet.mesh) {
    game.labeledObjects.push({ ...object, mesh: object.planet.mesh });
  }

  let iconClass = 'mdi-help-circle-outline';
  if (type === 'planet') iconClass = 'mdi-earth';
  if (type === 'moon') iconClass = 'mdi-moon-waning-crescent';
  if (type === 'spaceship') iconClass = 'mdi-rocket-launch-outline';
  if (type === 'colony') iconClass = 'mdi-home-city-outline';

  const labelClass = `${type}-label`;

  const $label = $('<div>', {
    id: labelId,
    class: `space-label ${labelClass}`,
    title: object.name,
    html: `
      <div class="label-chip">
        <span class="label-chip-icon"><i class="mdi ${iconClass}"></i></span>
        <span class="label-chip-text">${escapeHtml(object.name)}</span>
      </div>
    `
  });

  const objectType = type === 'moon' ? 'moon' : type;

  $label.attr({
    'data-object-name': object.name,
    'data-object-type': objectType,
    'data-label-text': object.name
  });

  $label.css({
    left: '0px',
    top: '0px',
    display: 'flex',
    visibility: 'hidden',
    transform: 'translate3d(-9999px, -9999px, 0) translate(-50%, -50%)',
    willChange: 'transform'
  });

  $label.on('click', (e) => {
    e.stopPropagation();
    game.focusOnObject(object.name, objectType);
  });

  labelsContainer.append($label);
  updateLabelMetrics($label);

  $label.css({
    display: 'none',
    visibility: 'visible'
  });
}

class HistoryManager {
  constructor() {
    const savedHistory = localStorage.getItem('gameHistoryLog');
    try {
      this.history = savedHistory ? JSON.parse(savedHistory) : [];
    } catch (e) {
      console.error('Could not parse history from localStorage', e);
      this.history = [];
    }
  }

  addEntry(message, type = 'info', inGameDay = 0) {
    this.history.unshift({
      inGameDay: Number(inGameDay || 0).toFixed(1),
      message,
      type
    });
    this.saveHistory();
  }

  saveHistory() {
    try {
      localStorage.setItem('gameHistoryLog', JSON.stringify(this.history));
    } catch (e) {
      console.error('Failed to save history to localStorage', e);
    }
  }

  getHistory() {
    return this.history;
  }

  clearHistory() {
    this.history = [];
    this.saveHistory();
  }
}
const historyManager = new HistoryManager();

class SeededRandom {
  constructor(seed = 'space2100-default') {
    this.seed = String(seed);
    this.state = SeededRandom.hashSeed(this.seed) || 0x6d2b79f5;
    this.drawCount = 0;
  }

  static hashSeed(seed) {
    let hash = 2166136261 >>> 0;
    for (let i = 0; i < seed.length; i += 1) {
      hash ^= seed.charCodeAt(i);
      hash = Math.imul(hash, 16777619);
    }
    return hash >>> 0;
  }

  next() {
    this.state = (this.state + 0x6d2b79f5) >>> 0;
    let value = this.state;
    value = Math.imul(value ^ (value >>> 15), value | 1);
    value ^= value + Math.imul(value ^ (value >>> 7), value | 61);
    this.drawCount += 1;
    return ((value ^ (value >>> 14)) >>> 0) / 4294967296;
  }

  float(min = 0, max = 1) {
    return min + ((max - min) * this.next());
  }

  int(min, maxInclusive) {
    const low = Math.ceil(Math.min(min, maxInclusive));
    const high = Math.floor(Math.max(min, maxInclusive));
    return low + Math.floor(this.next() * ((high - low) + 1));
  }

  chance(probability) {
    return this.next() < Math.max(0, Math.min(1, Number(probability) || 0));
  }

  pick(items) {
    if (!Array.isArray(items) || items.length === 0) return null;
    return items[this.int(0, items.length - 1)];
  }

  weightedPick(items, getWeight = item => item?.weight ?? 1) {
    if (!Array.isArray(items) || items.length === 0) return null;
    const weights = items.map(item => Math.max(0, Number(getWeight(item)) || 0));
    const total = weights.reduce((sum, weight) => sum + weight, 0);
    if (total <= 0) return items[items.length - 1];

    let roll = this.next() * total;
    for (let i = 0; i < items.length; i += 1) {
      roll -= weights[i];
      if (roll <= 0) return items[i];
    }
    return items[items.length - 1];
  }

  exportState() {
    return {
      seed: this.seed,
      state: this.state >>> 0,
      drawCount: this.drawCount
    };
  }

  importState(snapshot = {}) {
    if (snapshot.seed != null) this.seed = String(snapshot.seed);
    if (Number.isFinite(snapshot.state)) this.state = Number(snapshot.state) >>> 0;
    if (Number.isFinite(snapshot.drawCount)) this.drawCount = Number(snapshot.drawCount);
  }
}
{ SeededRandom };

class GamePerformanceMonitor {
  constructor(game) {
    this.game = game;
    this.visible = false;
    this.overlay = null;
    this.samples = [];
    this.maxSamples = 90;
    this.timers = new Map();
    this.metrics = {
      turnMs: 0,
      aiMs: 0,
      colonyMs: 0,
      marketMs: 0,
      simulationMs: 0,
      simulationSteps: 0,
      labelMs: 0
    };
    this.lastFrameAt = 0;
    this.lastPaintAt = 0;
    this.frameObserver = null;
  }

  initialize() {
    if (!this.game?.scene) return;
    this.createOverlay();
    this.frameObserver = this.game.scene.onAfterRenderObservable.add(() => this.onFrame());
    window.addEventListener('keydown', event => {
      if (event.key === 'F3') {
        event.preventDefault();
        this.toggle();
      }
    });
  }

  createOverlay() {
    if (this.overlay || typeof document === 'undefined') return;
    const overlay = document.createElement('pre');
    overlay.id = 'performance-monitor';
    overlay.setAttribute('aria-live', 'off');
    Object.assign(overlay.style, {
      position: 'fixed',
      right: '12px',
      bottom: '12px',
      zIndex: '100000',
      display: 'none',
      margin: '0',
      padding: '10px 12px',
      minWidth: '250px',
      border: '1px solid rgba(120, 190, 255, 0.35)',
      borderRadius: '8px',
      background: 'rgba(3, 9, 18, 0.92)',
      color: '#d8efff',
      font: '12px/1.45 ui-monospace, SFMono-Regular, Menlo, monospace',
      pointerEvents: 'none'
    });
    document.body.appendChild(overlay);
    this.overlay = overlay;
  }

  toggle(force = null) {
    this.visible = force == null ? !this.visible : !!force;
    if (this.overlay) this.overlay.style.display = this.visible ? 'block' : 'none';
  }

  start(name) {
    this.timers.set(name, performance.now());
  }

  stop(name, metricName = `${name}Ms`) {
    const startedAt = this.timers.get(name);
    if (!Number.isFinite(startedAt)) return 0;
    const elapsed = performance.now() - startedAt;
    this.timers.delete(name);
    this.metrics[metricName] = elapsed;
    return elapsed;
  }

  setMetric(name, value) {
    this.metrics[name] = Number(value) || 0;
  }

  onFrame() {
    const now = performance.now();
    if (this.lastFrameAt > 0) {
      const frameMs = now - this.lastFrameAt;
      this.samples.push(frameMs);
      if (this.samples.length > this.maxSamples) this.samples.shift();
    }
    this.lastFrameAt = now;

    if (!this.visible || (now - this.lastPaintAt) < 250) return;
    this.lastPaintAt = now;
    this.paint();
  }

  paint() {
    if (!this.overlay) return;
    const scene = this.game.scene;
    const engine = this.game.engine;
    const avgFrameMs = this.samples.length
      ? this.samples.reduce((sum, value) => sum + value, 0) / this.samples.length
      : 0;
    const heap = performance.memory?.usedJSHeapSize
      ? `${(performance.memory.usedJSHeapSize / 1048576).toFixed(1)} MB`
      : 'n/a';

    this.overlay.textContent = [
      'SPACE2100 PERFORMANCE  [F3]',
      `FPS                 ${(engine?.getFps?.() || 0).toFixed(1)}`,
      `Frame               ${avgFrameMs.toFixed(2)} ms`,
      `Active meshes       ${scene?.getActiveMeshes?.().length || 0}`,
      `Total vertices      ${(scene?.getTotalVertices?.() || 0).toLocaleString()}`,
      `Draw calls          ${engine?._drawCalls?.current ?? 'n/a'}`,
      `JS heap             ${heap}`,
      `Quality             ${this.game.userSettings?.graphicsQuality || 'high'}${this.game.userSettings?.graphicsQuality === 'auto' ? ` → ${this.game.userSettings?.autoResolvedQuality || 'high'}` : ''}`,
      `Visual tier         ${this.game.visualHierarchyManager?.currentTier || 'system'}`,
      `Entities            ${this.game.entityRegistry?.byId?.size || 0}`,
      `Pending courses     ${this.game.pendingCalculations || 0}`,
      `Turn                ${this.metrics.turnMs.toFixed(1)} ms`,
      `  AI                ${this.metrics.aiMs.toFixed(1)} ms`,
      `  Colonies          ${this.metrics.colonyMs.toFixed(1)} ms`,
      `  Markets           ${this.metrics.marketMs.toFixed(1)} ms`,
      `  Simulation        ${this.metrics.simulationMs.toFixed(1)} ms`,
      `  Steps             ${Math.round(this.metrics.simulationSteps)}`,
      `Labels              ${this.metrics.labelMs.toFixed(2)} ms`
    ].join('\n');
  }
}
{ GamePerformanceMonitor };


// ===== public/classes/managers/CelestialBodyManager.js =====
// public/classes/managers/CelestialBodyManager.js




class CelestialBodyManager {
  constructor(game) {
    this.game = game;
  }

  isLagrangeBody(bodyData) {
    return bodyData?.type === 'lagrange_point' || bodyData?.dynamicOrbit?.type === 'lagrange';
  }

  createCelestialBodies() {
    const sun = new CelestialBody(
      'Sun',
      'star',
      1.989e30,
      new BABYLON.Vector3(0, 0, 0),
      new BABYLON.Vector3(0, 0, 0),
      696340,
      'img/textures/sun.jpg',
      this.game.scene,
      SUN_SIZE_SCALE,
      null,
      this.game
    );

    this.game.bodies.push(sun);

    const remainingBodies = [...this.game.planetData];
    let createdSomething = true;

    while (remainingBodies.length > 0 && createdSomething) {
      createdSomething = false;

      for (let i = remainingBodies.length - 1; i >= 0; i--) {
        const bodyData = remainingBodies[i];
        const centralBodyName = bodyData.centralBody || bodyData.orbitalElements?.centralBody || bodyData.dynamicOrbit?.primaryBody;
        const centralBody = centralBodyName
          ? this.game.bodies.find(body => body.name === centralBodyName)
          : null;

        const secondaryBodyName = bodyData.secondaryBody || bodyData.dynamicOrbit?.secondaryBody;
        const secondaryBody = secondaryBodyName
          ? this.game.bodies.find(body => body.name === secondaryBodyName)
          : null;

        const lagrangeReady = !this.isLagrangeBody(bodyData) || !secondaryBodyName || secondaryBody;

        if ((!centralBodyName || centralBody) && lagrangeReady) {
          const body = this.createPlanet(bodyData, !centralBodyName || centralBodyName === 'Sun');
          this.game.bodies.push(body);
          const labelType = body.type === 'lagrange_point'
            ? 'lagrange_point'
            : (body.type === 'moon' ? 'moon' : 'planet');
          createLabel(this.game, body, labelType);

          if (bodyData.hasAtmosphere && this.game.vfxHandler) {
            this.game.vfxHandler.createPlanetAtmosphere(body);
          }

          remainingBodies.splice(i, 1);
          createdSomething = true;
        }
      }
    }

    if (remainingBodies.length > 0) {
      console.warn('Some celestial bodies could not be created because their parent body was not found:', remainingBodies);
    }
  }

  createPlanet(planetData, drawOrbit = true) {
    const orbitalElements = { ...(planetData.orbitalElements || {}) };
    if (planetData.centralBody) {
      orbitalElements.centralBody = planetData.centralBody;
    }

    const currentDate = this.game.getCurrentGameDate();

    let position = new BABYLON.Vector3(0, 0, 0);
    let velocity = new BABYLON.Vector3(0, 0, 0);

    if (!this.isLagrangeBody(planetData) && Object.keys(orbitalElements).length > 0) {
      let centralBodyPosition = new BABYLON.Vector3(0, 0, 0);
      let centralBodyVelocity = new BABYLON.Vector3(0, 0, 0);
      let centralBodyMass = 1.989e30;

      if (planetData.centralBody) {
        const centralBody = this.game.bodies.find(body => body.name === planetData.centralBody);
        if (centralBody) {
          centralBodyPosition = centralBody.position.clone();
          centralBodyVelocity = centralBody.velocity.clone();
          centralBodyMass = centralBody.mass;
        }
      }

      const state = calculateOrbitalStateVectors(
        orbitalElements,
        currentDate,
        centralBodyPosition,
        centralBodyVelocity,
        centralBodyMass
      );

      position = state.position;
      velocity = state.velocity;
    }

    const planet = new CelestialBody(
      planetData.name,
      planetData.type,
      planetData.mass,
      position,
      velocity,
      planetData.radius,
      planetData.textureUrl,
      this.game.scene,
      SIZE_SCALE,
      Object.keys(orbitalElements).length > 0 ? orbitalElements : null,
      this.game,
      planetData.mineralReserves || {},
      planetData.hasAtmosphere || false,
      {
        isColonizable: planetData.isColonizable,
        centralBody: planetData.centralBody || planetData.dynamicOrbit?.primaryBody || null,
        gravity: planetData.gravity,
        temperatureClass: planetData.temperatureClass,
        strategicValue: planetData.strategicValue,
        description: planetData.description,
        resourceTags: planetData.resourceTags || [],
        secondaryBody: planetData.secondaryBody || planetData.dynamicOrbit?.secondaryBody || null,
        lagrangePoint: planetData.lagrangePoint || planetData.dynamicOrbit?.point || null,
        dynamicOrbit: planetData.dynamicOrbit || null
      }
    );

    if (planet.dynamicOrbit?.type === 'lagrange') {
      const dynamicState = planet.getStateAtDate(currentDate, new Map(), planet._orbitalStateScratch);
      planet.position.copyFrom(dynamicState.position);
      planet.velocity.copyFrom(dynamicState.velocity);
      planet.syncRenderedPosition();
    }

    if (drawOrbit && !this.isLagrangeBody(planetData)) {
      this.createOrbitPath(planet, orbitalElements, new BABYLON.Vector3(0, 0, 0));
    }

    return planet;
  }

  createOrbitPath(planet, orbitalElements, centralBodyPosition = new BABYLON.Vector3(0, 0, 0)) {
    const points = [];
    const quality = this.game?.userSettings?.graphicsQuality || 'high';
    const resolvedQuality = quality === 'auto' ? (this.game?.userSettings?.autoResolvedQuality || 'high') : quality;
    const numPoints = resolvedQuality === 'low' ? 96 : resolvedQuality === 'medium' ? 180 : 360;
    const angleIncrement = (2 * Math.PI) / numPoints;
    const a = orbitalElements.semiMajorAxis;
    const e = orbitalElements.eccentricity;
    const iRad = orbitalElements.inclination * (Math.PI / 180);
    const omegaRad = orbitalElements.longitudeOfAscendingNode * (Math.PI / 180);
    const periapsisRad = orbitalElements.argumentOfPeriapsis * (Math.PI / 180);

    const cosOmega = Math.cos(omegaRad);
    const sinOmega = Math.sin(omegaRad);
    const cosI = Math.cos(iRad);
    const sinI = Math.sin(iRad);
    const cosPeriapsis = Math.cos(periapsisRad);
    const sinPeriapsis = Math.sin(periapsisRad);

    const R11 = cosOmega * cosPeriapsis - sinOmega * sinPeriapsis * cosI;
    const R12 = -cosOmega * sinPeriapsis - sinOmega * cosPeriapsis * cosI;
    const R13 = sinOmega * sinI;
    const R21 = sinOmega * cosPeriapsis + cosOmega * sinPeriapsis * cosI;
    const R22 = -sinOmega * sinPeriapsis + cosOmega * cosPeriapsis * cosI;
    const R23 = -cosOmega * sinI;
    const R31 = sinPeriapsis * sinI;
    const R32 = cosPeriapsis * sinI;
    const R33 = cosI;

    for (let nu = 0; nu <= 2 * Math.PI + angleIncrement; nu += angleIncrement) {
      const r = (a * (1 - e * e)) / (1 + e * Math.cos(nu));
      const xPQW = r * Math.cos(nu);
      const yPQW = r * Math.sin(nu);
      const zPQW = 0;

      const x = R11 * xPQW + R12 * yPQW + R13 * zPQW;
      const y = R21 * xPQW + R22 * yPQW + R23 * zPQW;
      const z = R31 * xPQW + R32 * yPQW + R33 * zPQW;

      const point = new BABYLON.Vector3(x, y, z).add(centralBodyPosition).scale(DISTANCE_SCALE);
      points.push(point);
    }

    points.push(points[0]);

    const orbit = BABYLON.MeshBuilder.CreateLines(`orbit_${planet.name}`, { points }, this.game.scene);
    orbit.isPickable = false;
    orbit.alwaysSelectAsActiveMesh = false;
    orbit.metadata = { ...(orbit.metadata || {}), visualRole: 'orbit', bodyId: planet.id || planet.name, bodyType: planet.type };
    const orbitMaterial = new BABYLON.StandardMaterial(`orbitMat_${planet.name}`, this.game.scene);
    const orbitColor = planet.type === 'moon'
      ? new BABYLON.Color3(0.34, 0.47, 0.58)
      : new BABYLON.Color3(0.36, 0.57, 0.7);
    orbitMaterial.emissiveColor = orbitColor;
    orbitMaterial.alpha = 0.38;
    orbit.material = orbitMaterial;
    planet.orbitMesh = orbit;
  }

  getPlanetVisualRadius(planet) {
    return planet?.mesh?.getBoundingInfo?.()?.boundingSphere?.radiusWorld || 0.05;
  }

  clamp(value, min, max) {
    return Math.min(max, Math.max(min, value));
  }

  getSurfaceMarkerScale(planet, ratio, minSize, maxSize) {
    const visualRadius = this.getPlanetVisualRadius(planet);
    return this.clamp(visualRadius * ratio, minSize, maxSize);
  }

  getSurfaceNormalFromSeed(seed) {
    const str = String(seed ?? 'surface-object');
    let hash1 = 0;
    let hash2 = 5381;

    for (let i = 0; i < str.length; i++) {
      const code = str.charCodeAt(i);
      hash1 = ((hash1 << 5) - hash1) + code;
      hash1 |= 0;
      hash2 = ((hash2 << 5) + hash2) ^ code;
      hash2 |= 0;
    }

    const u = ((Math.abs(hash1) % 10000) + 0.5) / 10000;
    const v = ((Math.abs(hash2) % 10000) + 0.5) / 10000;

    const theta = 2 * Math.PI * u;
    const z = (2 * v) - 1;
    const radial = Math.sqrt(Math.max(0, 1 - z * z));

    return new BABYLON.Vector3(
      radial * Math.cos(theta),
      z,
      radial * Math.sin(theta)
    ).normalize();
  }

  alignMeshToSurface(mesh, normal) {
    const up = BABYLON.Axis.Y;
    const safeNormal = normal.clone().normalize();
    const dot = BABYLON.Vector3.Dot(up, safeNormal);

    if (dot > 0.9999) {
      mesh.rotationQuaternion = BABYLON.Quaternion.Identity();
      return;
    }

    if (dot < -0.9999) {
      mesh.rotationQuaternion = BABYLON.Quaternion.RotationAxis(BABYLON.Axis.Z, Math.PI);
      return;
    }

    const axis = BABYLON.Vector3.Cross(up, safeNormal).normalize();
    const angle = Math.acos(this.clamp(dot, -1, 1));
    mesh.rotationQuaternion = BABYLON.Quaternion.RotationAxis(axis, angle);
  }

  placeSurfaceMesh(planet, mesh, seed, surfaceOffset = 0) {
    if (!planet?.mesh || !mesh) return;

    const visualRadius = this.getPlanetVisualRadius(planet);
    const normal = this.getSurfaceNormalFromSeed(seed);

    mesh.parent = planet.mesh;
    mesh.position = normal.scale(visualRadius + surfaceOffset);
    this.alignMeshToSurface(mesh, normal);
  }

  addColonyToPlanet(planet, colony) {
    if (!planet.mesh) return;

    const colonySize = this.getSurfaceMarkerScale(planet, 0.12, 0.004, 0.012);

    const colonyMesh = window.BABYLON.MeshBuilder.CreateBox(
      `${colony.name}_Mesh`,
      { size: colonySize },
      this.game.scene
    );

    this.placeSurfaceMesh(planet, colonyMesh, colony.name, colonySize * 0.55);

    const colonyMaterial = new window.BABYLON.StandardMaterial(`${colony.name}_Material`, this.game.scene);
    colonyMaterial.diffuseColor = new BABYLON.Color3(0, 1, 0);
    colonyMaterial.emissiveColor = new BABYLON.Color3(0, 0.5, 0);
    colonyMesh.material = colonyMaterial;
    colony.mesh = colonyMesh;
  }

  addBuildingToPlanet(planet, building) {
    if (!planet.mesh || building.type === 'habitat') return;

    const buildingSize = this.getSurfaceMarkerScale(planet, 0.09, 0.003, 0.010);

    const buildingMesh = window.BABYLON.MeshBuilder.CreateBox(
      `${building.name}_Mesh`,
      { size: buildingSize },
      this.game.scene
    );

    this.placeSurfaceMesh(planet, buildingMesh, `${planet.name}_${building.name}`, buildingSize * 0.55);

    const buildingMaterial = new window.BABYLON.StandardMaterial(`${building.name}_Material`, this.game.scene);

    switch (building.type) {
      case 'farm':
        buildingMaterial.emissiveColor = new BABYLON.Color3(0, 0.8, 0.2);
        break;
      case 'factory':
        buildingMaterial.emissiveColor = new BABYLON.Color3(0.5, 0.5, 0.5);
        break;
      case 'mine':
        buildingMaterial.emissiveColor = new BABYLON.Color3(0.8, 0.5, 0.2);
        break;
      case 'powerplant':
        buildingMaterial.emissiveColor = new BABYLON.Color3(1, 1, 0);
        break;
      case 'shipyard':
        buildingMaterial.emissiveColor = new BABYLON.Color3(0.2, 0.5, 0.8);
        break;
      case 'research':
        buildingMaterial.emissiveColor = new BABYLON.Color3(0.7, 0.2, 1);
        break;
      case 'commerce':
        buildingMaterial.emissiveColor = new BABYLON.Color3(0.2, 1, 1);
        break;
      default:
        buildingMaterial.emissiveColor = new BABYLON.Color3(1, 1, 1);
    }

    buildingMesh.material = buildingMaterial;
    building.mesh = buildingMesh;
  }

  addConstructionSiteToPlanet(planet, project) {
    if (!planet.mesh) return;

    const siteDiameter = this.getSurfaceMarkerScale(planet, 0.10, 0.004, 0.012);
    const siteHeight = this.getSurfaceMarkerScale(planet, 0.03, 0.0015, 0.004);

    const siteMesh = window.BABYLON.MeshBuilder.CreateCylinder(
      `Construction_${project.blueprintName}`,
      { height: siteHeight, diameter: siteDiameter, tessellation: 24 },
      this.game.scene
    );

    const siteSeed = `${planet.name}_${project.id || project.blueprintName}_${project.startDay || project.progress || 0}`;
    this.placeSurfaceMesh(planet, siteMesh, siteSeed, siteHeight * 0.55);

    const siteMaterial = new window.BABYLON.StandardMaterial(
      `Construction_Mat_${planet.name}_${project.blueprintName}`,
      this.game.scene
    );
    siteMaterial.diffuseColor = new BABYLON.Color3(1, 0.65, 0);
    siteMaterial.alpha = 0.85;
    siteMaterial.emissiveColor = new BABYLON.Color3(0.8, 0.4, 0.05);

    siteMesh.material = siteMaterial;
    project.siteMesh = siteMesh;
  }
}
CelestialBodyManager;


// ===== public/classes/spaceship/SpaceshipVisuals.js =====
const TWO_PI = Math.PI * 2;
const SHIP_VISUAL_SCALE = 0.08;
const SHIP_RADIUS_PADDING = 1.2;

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function lerp(a, b, t) {
  return a + (b - a) * t;
}

function hashString(input) {
  const text = String(input || 'ship');
  let hash = 2166136261;
  for (let i = 0; i < text.length; i += 1) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

function createSeededRng(seed) {
  let state = (seed >>> 0) || 1;
  return () => {
    state = (Math.imul(1664525, state) + 1013904223) >>> 0;
    return state / 4294967296;
  };
}

function ensureSceneCache(scene) {
  if (!scene.metadata) {
    scene.metadata = {};
  }
  if (!scene.metadata.shipVisualCache) {
    scene.metadata.shipVisualCache = {};
  }
  return scene.metadata.shipVisualCache;
}

function makePanelTexture(scene, key, baseHex, lineHex, accentHex) {
  const cache = ensureSceneCache(scene);
  const cacheKey = `texture:${key}`;
  if (cache[cacheKey]) {
    return cache[cacheKey];
  }

  const texture = new BABYLON.DynamicTexture(`shipPanel-${key}`, { width: 512, height: 512 }, scene, false);
  const ctx = texture.getContext();

  ctx.fillStyle = baseHex;
  ctx.fillRect(0, 0, 512, 512);

  ctx.strokeStyle = lineHex;
  ctx.lineWidth = 3;
  for (let x = 24; x < 512; x += 64) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, 512);
    ctx.stroke();
  }
  for (let y = 24; y < 512; y += 64) {
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(512, y);
    ctx.stroke();
  }

  ctx.strokeStyle = accentHex;
  ctx.lineWidth = 6;
  ctx.strokeRect(20, 20, 472, 472);

  ctx.fillStyle = accentHex;
  for (let i = 0; i < 6; i += 1) {
    const y = 46 + i * 72;
    ctx.fillRect(42, y, 72, 12);
  }

  ctx.save();
  ctx.translate(384, 128);
  ctx.rotate(-Math.PI / 8);
  ctx.fillRect(-92, -18, 184, 36);
  ctx.restore();

  ctx.fillStyle = 'rgba(0, 0, 0, 0.18)';
  for (let i = 0; i < 90; i += 1) {
    const x = (i * 47) % 512;
    const y = (i * 91) % 512;
    ctx.fillRect(x, y, 3, 3);
  }

  texture.update(false);
  cache[cacheKey] = texture;
  return texture;
}

function makeHazardTexture(scene, key) {
  const cache = ensureSceneCache(scene);
  const cacheKey = `texture:${key}`;
  if (cache[cacheKey]) {
    return cache[cacheKey];
  }

  const texture = new BABYLON.DynamicTexture(`shipHazard-${key}`, { width: 256, height: 256 }, scene, false);
  const ctx = texture.getContext();

  ctx.fillStyle = '#2b2d31';
  ctx.fillRect(0, 0, 256, 256);

  ctx.save();
  ctx.translate(-32, 0);
  ctx.rotate(-Math.PI / 4);
  for (let i = 0; i < 18; i += 1) {
    ctx.fillStyle = i % 2 === 0 ? '#c49f2d' : '#3a3d42';
    ctx.fillRect(i * 28, -90, 18, 420);
  }
  ctx.restore();

  texture.update(false);
  cache[cacheKey] = texture;
  return texture;
}

function createMaterial(scene, name, config = {}) {
  const cache = ensureSceneCache(scene);
  const cacheKey = `material:${name}`;
  if (cache[cacheKey]) {
    return cache[cacheKey];
  }

  const material = new BABYLON.StandardMaterial(name, scene);
  if (config.diffuseColor) material.diffuseColor = config.diffuseColor;
  if (config.specularColor) material.specularColor = config.specularColor;
  if (config.emissiveColor) material.emissiveColor = config.emissiveColor;
  if (typeof config.alpha === 'number') material.alpha = config.alpha;
  if (typeof config.roughness === 'number') material.roughness = config.roughness;
  if (config.diffuseTexture) {
    material.diffuseTexture = config.diffuseTexture;
    material.diffuseTexture.wrapU = BABYLON.Texture.WRAP_ADDRESSMODE;
    material.diffuseTexture.wrapV = BABYLON.Texture.WRAP_ADDRESSMODE;
  }
  if (config.backFaceCulling === false) {
    material.backFaceCulling = false;
  }
  cache[cacheKey] = material;
  return material;
}

function getMaterialAccentByType(type) {
  switch (String(type || '').toLowerCase()) {
    case 'warship':
      return {
        accent: new BABYLON.Color3(0.36, 0.5, 0.66),
        glow: new BABYLON.Color3(0.28, 0.76, 0.94)
      };
    case 'construction':
    case 'colony':
      return {
        accent: new BABYLON.Color3(0.66, 0.52, 0.18),
        glow: new BABYLON.Color3(0.28, 0.78, 0.9)
      };
    case 'transport':
      return {
        accent: new BABYLON.Color3(0.42, 0.56, 0.62),
        glow: new BABYLON.Color3(0.3, 0.82, 0.94)
      };
    default:
      return {
        accent: new BABYLON.Color3(0.25, 0.48, 0.62),
        glow: new BABYLON.Color3(0.24, 0.8, 0.96)
      };
  }
}

function getMaterialSet(scene, type) {
  const hullTexture = makePanelTexture(scene, `${type}-hull`, '#666d74', '#454b52', '#8b9299');
  const armorTexture = makePanelTexture(scene, `${type}-armor`, '#545a60', '#34383d', '#7e858d');
  const radiatorTexture = makePanelTexture(scene, `${type}-radiator`, '#4a5054', '#272b2f', '#636b72');
  const hazardTexture = makeHazardTexture(scene, `${type}-hazard`);
  const accentColors = getMaterialAccentByType(type);

  return {
    hull: createMaterial(scene, `${type}-hull-material`, {
      diffuseColor: new BABYLON.Color3(0.64, 0.66, 0.68),
      specularColor: new BABYLON.Color3(0.12, 0.12, 0.14),
      emissiveColor: new BABYLON.Color3(0.015, 0.016, 0.018),
      diffuseTexture: hullTexture
    }),
    truss: createMaterial(scene, `${type}-truss-material`, {
      diffuseColor: new BABYLON.Color3(0.28, 0.3, 0.33),
      specularColor: new BABYLON.Color3(0.08, 0.08, 0.1)
    }),
    tank: createMaterial(scene, `${type}-tank-material`, {
      diffuseColor: new BABYLON.Color3(0.7, 0.71, 0.72),
      specularColor: new BABYLON.Color3(0.1, 0.1, 0.12),
      diffuseTexture: hullTexture
    }),
    dark: createMaterial(scene, `${type}-dark-material`, {
      diffuseColor: new BABYLON.Color3(0.1, 0.11, 0.12),
      specularColor: new BABYLON.Color3(0.03, 0.03, 0.04)
    }),
    accent: createMaterial(scene, `${type}-accent-material`, {
      diffuseColor: accentColors.accent,
      emissiveColor: accentColors.accent.scale(0.08),
      specularColor: new BABYLON.Color3(0.08, 0.08, 0.1)
    }),
    radiator: createMaterial(scene, `${type}-radiator-material`, {
      diffuseColor: new BABYLON.Color3(0.24, 0.25, 0.28),
      specularColor: new BABYLON.Color3(0.05, 0.05, 0.06),
      diffuseTexture: radiatorTexture
    }),
    glow: createMaterial(scene, `${type}-glow-material`, {
      diffuseColor: accentColors.glow,
      emissiveColor: accentColors.glow.scale(0.62),
      specularColor: new BABYLON.Color3(0.01, 0.01, 0.01)
    }),
    warning: createMaterial(scene, `${type}-warning-material`, {
      diffuseColor: new BABYLON.Color3(0.82, 0.68, 0.24),
      specularColor: new BABYLON.Color3(0.06, 0.06, 0.06),
      diffuseTexture: hazardTexture
    }),
    armor: createMaterial(scene, `${type}-armor-material`, {
      diffuseColor: new BABYLON.Color3(0.5, 0.52, 0.55),
      specularColor: new BABYLON.Color3(0.06, 0.06, 0.07),
      diffuseTexture: armorTexture
    })
  };
}

function tagShipPart(ship, node, partType, details = {}) {
  node.metadata = {
    ...(node.metadata || {}),
    ship,
    shipName: ship.name,
    shipType: ship.type,
    partType,
    details
  };
  node.isPickable = partType === 'selection-hull';
  return node;
}

function createBox(scene, name, options, material, parent, position, rotation = null) {
  const mesh = BABYLON.MeshBuilder.CreateBox(name, options, scene);
  mesh.material = material;
  mesh.parent = parent;
  if (position) {
    mesh.position.copyFrom(position);
  }
  if (rotation) {
    mesh.rotation.copyFrom(rotation);
  }
  return mesh;
}

function createCylinder(scene, name, options, material, parent, position, rotation = null) {
  const mesh = BABYLON.MeshBuilder.CreateCylinder(name, options, scene);
  mesh.material = material;
  mesh.parent = parent;
  if (position) {
    mesh.position.copyFrom(position);
  }
  if (rotation) {
    mesh.rotation.copyFrom(rotation);
  }
  return mesh;
}

function createSphere(scene, name, options, material, parent, position) {
  const mesh = BABYLON.MeshBuilder.CreateSphere(name, options, scene);
  mesh.material = material;
  mesh.parent = parent;
  if (position) {
    mesh.position.copyFrom(position);
  }
  return mesh;
}

function addCrossBrace(scene, parent, name, from, to, thickness, material) {
  const delta = to.subtract(from);
  const length = delta.length();
  const mesh = BABYLON.MeshBuilder.CreateBox(name, {
    width: thickness,
    height: thickness,
    depth: length
  }, scene);
  mesh.material = material;
  mesh.parent = parent;
  mesh.position = BABYLON.Vector3.Center(from, to);
  mesh.lookAt(to);
  return mesh;
}

function addPipe(scene, parent, name, from, to, radius, material) {
  const delta = to.subtract(from);
  const length = delta.length();
  const mesh = BABYLON.MeshBuilder.CreateCylinder(name, {
    height: length,
    diameterTop: radius * 2,
    diameterBottom: radius * 2,
    tessellation: 8
  }, scene);
  mesh.material = material;
  mesh.parent = parent;
  mesh.position = BABYLON.Vector3.Center(from, to);
  mesh.lookAt(to);
  mesh.rotation.x += Math.PI / 2;
  return mesh;
}

function addPanelStrip(ship, scene, parent, namePrefix, count, width, height, depth, zStart, spacing, material, partType, details = {}) {
  for (let i = 0; i < count; i += 1) {
    const strip = createBox(
      scene,
      `${ship.name}-${namePrefix}-${i}`,
      { width, height, depth },
      material,
      parent,
      new BABYLON.Vector3(0, 0, zStart - i * spacing)
    );
    tagShipPart(ship, strip, partType, details);
  }
}

function addExposedTruss(ship, scene, parent, profile, materials, rng = () => 0.5) {
  const trussRoot = new BABYLON.TransformNode(`${ship.name}-truss`, scene);
  trussRoot.parent = parent;

  const halfW = profile.width * 0.34;
  const halfH = profile.height * 0.28;
  const length = profile.length * 0.84;
  const zStart = -length * 0.5;
  const zEnd = length * 0.5;
  const beamThickness = clamp(profile.width * 0.05, 0.012, 0.04);
  const latticeThickness = beamThickness * 0.72;

  const corners = [
    new BABYLON.Vector3(-halfW, -halfH, 0),
    new BABYLON.Vector3(halfW, -halfH, 0),
    new BABYLON.Vector3(-halfW, halfH, 0),
    new BABYLON.Vector3(halfW, halfH, 0)
  ];

  corners.forEach((corner, index) => {
    const beam = createBox(
      scene,
      `${ship.name}-truss-beam-${index}`,
      { width: beamThickness, height: beamThickness, depth: length },
      materials.truss,
      trussRoot,
      new BABYLON.Vector3(corner.x, corner.y, 0)
    );
    tagShipPart(ship, beam, 'truss', { role: 'longeron' });
  });

  const centerSpine = createBox(
    scene,
    `${ship.name}-center-spine`,
    { width: beamThickness * 1.4, height: beamThickness * 1.1, depth: length * 0.96 },
    materials.dark,
    trussRoot,
    new BABYLON.Vector3(0, 0, 0)
  );
  tagShipPart(ship, centerSpine, 'truss', { role: 'spine' });

  const innerRunners = [-1, 1].flatMap((sideX) => [-1, 1].map((sideY) => ({ sideX, sideY })));
  innerRunners.forEach(({ sideX, sideY }, index) => {
    const runner = createBox(
      scene,
      `${ship.name}-inner-runner-${index}`,
      { width: latticeThickness, height: latticeThickness, depth: length * 0.92 },
      materials.truss,
      trussRoot,
      new BABYLON.Vector3(sideX * halfW * 0.56, sideY * halfH * 0.56, 0)
    );
    tagShipPart(ship, runner, 'truss', { role: 'inner-runner' });
  });

  const frameCount = clamp(Math.round(profile.length * 6.4), 5, 12);
  for (let i = 0; i < frameCount; i += 1) {
    const t = frameCount === 1 ? 0.5 : i / (frameCount - 1);
    const z = lerp(zStart, zEnd, t);

    const ringTop = createBox(
      scene,
      `${ship.name}-truss-ring-top-${i}`,
      { width: profile.width * 0.76, height: beamThickness * 0.75, depth: beamThickness * 0.8 },
      materials.truss,
      trussRoot,
      new BABYLON.Vector3(0, halfH, z)
    );
    tagShipPart(ship, ringTop, 'truss', { role: 'ring' });

    const ringBottom = ringTop.clone(`${ship.name}-truss-ring-bottom-${i}`);
    ringBottom.parent = trussRoot;
    ringBottom.position.y = -halfH;
    tagShipPart(ship, ringBottom, 'truss', { role: 'ring' });

    const ringRight = createBox(
      scene,
      `${ship.name}-truss-ring-right-${i}`,
      { width: beamThickness * 0.75, height: profile.height * 0.58, depth: beamThickness * 0.8 },
      materials.truss,
      trussRoot,
      new BABYLON.Vector3(halfW, 0, z)
    );
    tagShipPart(ship, ringRight, 'truss', { role: 'ring' });

    const ringLeft = ringRight.clone(`${ship.name}-truss-ring-left-${i}`);
    ringLeft.parent = trussRoot;
    ringLeft.position.x = -halfW;
    tagShipPart(ship, ringLeft, 'truss', { role: 'ring' });

    if (i < frameCount - 1) {
      const nextZ = lerp(zStart, zEnd, (i + 1) / (frameCount - 1));

      addCrossBrace(scene, trussRoot, `${ship.name}-brace-a-${i}`, new BABYLON.Vector3(-halfW, -halfH, z), new BABYLON.Vector3(halfW, halfH, nextZ), latticeThickness, materials.truss);
      addCrossBrace(scene, trussRoot, `${ship.name}-brace-b-${i}`, new BABYLON.Vector3(halfW, -halfH, z), new BABYLON.Vector3(-halfW, halfH, nextZ), latticeThickness, materials.truss);
      addCrossBrace(scene, trussRoot, `${ship.name}-brace-c-${i}`, new BABYLON.Vector3(-halfW, halfH, z), new BABYLON.Vector3(halfW, halfH, nextZ), latticeThickness * 0.8, materials.dark);
      addCrossBrace(scene, trussRoot, `${ship.name}-brace-d-${i}`, new BABYLON.Vector3(-halfW, -halfH, z), new BABYLON.Vector3(halfW, -halfH, nextZ), latticeThickness * 0.8, materials.dark);
    }

    if (i > 0 && i < frameCount - 1) {
      const gusset = createBox(
        scene,
        `${ship.name}-truss-gusset-${i}`,
        { width: beamThickness * 2.1, height: beamThickness * 0.65, depth: beamThickness * 2.2 },
        i % 2 === 0 ? materials.dark : materials.hull,
        trussRoot,
        new BABYLON.Vector3((i % 2 === 0 ? -1 : 1) * halfW * 0.25, (i % 3 === 0 ? 1 : -1) * halfH * 0.35, z)
      );
      tagShipPart(ship, gusset, 'truss', { role: 'gusset' });
    }
  }

  const conduitCount = clamp(Math.round(profile.length * 1.8), 2, 5);
  for (let i = 0; i < conduitCount; i += 1) {
    const x = (i % 2 === 0 ? -1 : 1) * halfW * (0.48 + rng() * 0.18);
    const y = (i % 3 === 0 ? -1 : 1) * halfH * (0.46 + rng() * 0.22);
    const conduit = createCylinder(
      scene,
      `${ship.name}-truss-conduit-${i}`,
      {
        height: length * (0.58 + rng() * 0.22),
        diameterTop: beamThickness * 0.6,
        diameterBottom: beamThickness * 0.6,
        tessellation: 8
      },
      materials.dark,
      trussRoot,
      new BABYLON.Vector3(x, y, -length * 0.08 + (rng() - 0.5) * profile.length * 0.08),
      new BABYLON.Vector3(Math.PI / 2, 0, 0)
    );
    tagShipPart(ship, conduit, 'truss', { role: 'conduit' });
  }

  const dockingCollar = createCylinder(
    scene,
    `${ship.name}-truss-forward-collar`,
    {
      height: beamThickness * 4,
      diameterTop: profile.width * 0.3,
      diameterBottom: profile.width * 0.34,
      tessellation: 12
    },
    materials.hull,
    trussRoot,
    new BABYLON.Vector3(0, 0, zEnd + beamThickness * 1.2),
    new BABYLON.Vector3(Math.PI / 2, 0, 0)
  );
  tagShipPart(ship, dockingCollar, 'truss', { role: 'forward-collar' });

  trussRoot.getChildMeshes(false).forEach((mesh) => tagShipPart(ship, mesh, 'truss', mesh.metadata?.details || {}));
  return trussRoot;
}

function addCommandSection(ship, scene, parent, profile, materials, rng = () => 0.5) {
  const commandRoot = new BABYLON.TransformNode(`${ship.name}-command-root`, scene);
  commandRoot.parent = parent;

  const moduleLength = clamp(profile.length * 0.16, 0.08, 0.2);
  const moduleWidth = clamp(profile.width * 0.34, 0.06, 0.16);
  const moduleHeight = clamp(profile.height * 0.28, 0.05, 0.14);
  const z = profile.length * 0.34;

  const pressureHull = createCylinder(
    scene,
    `${ship.name}-command-pressure-hull`,
    {
      height: moduleLength,
      diameterTop: moduleWidth * 1.05,
      diameterBottom: moduleWidth * 1.18,
      tessellation: 12
    },
    materials.hull,
    commandRoot,
    new BABYLON.Vector3(0, 0, z),
    new BABYLON.Vector3(Math.PI / 2, 0, 0)
  );
  tagShipPart(ship, pressureHull, 'quarters', { role: 'command-pressure-vessel' });

  const forwardWedge = createCylinder(
    scene,
    `${ship.name}-command-wedge`,
    {
      height: moduleLength * 0.62,
      diameterTop: 0.012,
      diameterBottom: moduleWidth * 0.84,
      tessellation: 10
    },
    materials.dark,
    commandRoot,
    new BABYLON.Vector3(0, 0, z + moduleLength * 0.56),
    new BABYLON.Vector3(Math.PI / 2, 0, 0)
  );
  tagShipPart(ship, forwardWedge, 'quarters', { role: 'meteoroid-bumper' });

  const bridgeBlister = createBox(
    scene,
    `${ship.name}-bridge-blister`,
    {
      width: moduleWidth * 0.42,
      height: moduleHeight * 0.22,
      depth: moduleLength * 0.86
    },
    materials.hull,
    commandRoot,
    new BABYLON.Vector3(0, moduleHeight * 0.42, z - moduleLength * 0.04)
  );
  tagShipPart(ship, bridgeBlister, 'quarters', { role: 'bridge-blister' });

  const windowBand = createBox(
    scene,
    `${ship.name}-bridge-window-band`,
    {
      width: moduleWidth * 0.48,
      height: moduleHeight * 0.06,
      depth: moduleLength * 0.62
    },
    materials.accent,
    commandRoot,
    new BABYLON.Vector3(0, moduleHeight * 0.42, z + moduleLength * 0.12)
  );
  tagShipPart(ship, windowBand, 'quarters', { role: 'window-band' });

  const chinSensor = createBox(
    scene,
    `${ship.name}-command-chin`,
    {
      width: moduleWidth * 0.32,
      height: moduleHeight * 0.12,
      depth: moduleLength * 0.26
    },
    materials.dark,
    commandRoot,
    new BABYLON.Vector3(0, -moduleHeight * 0.24, z + moduleLength * 0.2)
  );
  tagShipPart(ship, chinSensor, 'quarters', { role: 'sensor-chin' });

  const dorsalSpine = createBox(
    scene,
    `${ship.name}-command-dorsal-spine`,
    {
      width: moduleWidth * 0.18,
      height: moduleHeight * 0.24,
      depth: moduleLength * 0.78
    },
    materials.dark,
    commandRoot,
    new BABYLON.Vector3(0, moduleHeight * 0.54, z - moduleLength * 0.02)
  );
  tagShipPart(ship, dorsalSpine, 'quarters', { role: 'avionics-spine' });

  [-1, 1].forEach((side, index) => {
    const cheek = createBox(
      scene,
      `${ship.name}-command-cheek-${index}`,
      {
        width: moduleWidth * 0.12,
        height: moduleHeight * 0.16,
        depth: moduleLength * 0.34
      },
      materials.dark,
      commandRoot,
      new BABYLON.Vector3(side * moduleWidth * 0.44, moduleHeight * 0.04, z + moduleLength * 0.08)
    );
    tagShipPart(ship, cheek, 'quarters', { role: 'side-avionics' });

    const rcs = createCylinder(
      scene,
      `${ship.name}-command-rcs-${index}`,
      {
        height: moduleWidth * 0.12,
        diameterTop: moduleWidth * 0.08,
        diameterBottom: moduleWidth * 0.08,
        tessellation: 8
      },
      materials.warning,
      commandRoot,
      new BABYLON.Vector3(side * moduleWidth * 0.52, moduleHeight * 0.2, z - moduleLength * 0.18),
      new BABYLON.Vector3(0, 0, Math.PI / 2)
    );
    tagShipPart(ship, rcs, 'quarters', { role: 'rcs-thruster' });
  });

  const mastHeight = clamp(moduleHeight * 0.9, 0.045, 0.1);
  const mast = createBox(
    scene,
    `${ship.name}-command-mast`,
    { width: moduleWidth * 0.04, height: mastHeight, depth: moduleWidth * 0.04 },
    materials.truss,
    commandRoot,
    new BABYLON.Vector3(0, moduleHeight * 0.72, z - moduleLength * 0.18)
  );
  tagShipPart(ship, mast, 'quarters', { role: 'comm-mast' });

  const antenna = createBox(
    scene,
    `${ship.name}-command-antenna`,
    { width: moduleWidth * 0.22, height: moduleWidth * 0.03, depth: moduleWidth * 0.03 },
    rng() > 0.5 ? materials.accent : materials.dark,
    commandRoot,
    new BABYLON.Vector3(0, moduleHeight * 0.72 + mastHeight * 0.45, z - moduleLength * 0.18)
  );
  tagShipPart(ship, antenna, 'quarters', { role: 'patch-antenna' });

  return commandRoot;
}

function addHabitatSection(ship, scene, parent, profile, materials, quarters) {
  if (!quarters) {
    return;
  }

  const capacity = Number(quarters.capacity || 4);
  const comfort = Number(quarters.comfort || 0.4);
  const moduleRoot = new BABYLON.TransformNode(`${ship.name}-quarters-root`, scene);
  moduleRoot.parent = parent;

  if (capacity >= 10 && comfort >= 0.75) {
    const ringRadius = clamp(profile.width * 0.42 + capacity * 0.004, 0.08, 0.2);
    const ringTube = clamp(profile.width * 0.06, 0.014, 0.04);
    const torus = BABYLON.MeshBuilder.CreateTorus(`${ship.name}-hab-ring`, {
      diameter: ringRadius * 2,
      thickness: ringTube,
      tessellation: 24
    }, scene);
    torus.material = materials.hull;
    torus.parent = moduleRoot;
    torus.rotation.x = Math.PI / 2;
    torus.position.z = 0.05;
    tagShipPart(ship, torus, 'quarters', { role: 'habitat-ring' });

    const hub = createCylinder(
      scene,
      `${ship.name}-hab-hub`,
      {
        height: profile.length * 0.1,
        diameterTop: ringTube * 1.6,
        diameterBottom: ringTube * 1.8,
        tessellation: 10
      },
      materials.dark,
      moduleRoot,
      new BABYLON.Vector3(0, 0, 0.05),
      new BABYLON.Vector3(Math.PI / 2, 0, 0)
    );
    tagShipPart(ship, hub, 'quarters', { role: 'hub' });
  } else {
    const moduleLength = clamp(profile.length * 0.12 + capacity * 0.003, 0.08, 0.22);
    const moduleRadius = clamp(profile.width * 0.16 + capacity * 0.0015, 0.04, 0.1);
    const hab = createCylinder(
      scene,
      `${ship.name}-hab-module`,
      {
        height: moduleLength,
        diameterTop: moduleRadius * 1.7,
        diameterBottom: moduleRadius * 1.9,
        tessellation: 12
      },
      materials.hull,
      moduleRoot,
      new BABYLON.Vector3(0, 0, 0.02),
      new BABYLON.Vector3(Math.PI / 2, 0, 0)
    );
    tagShipPart(ship, hab, 'quarters', { role: 'crew-module' });

    const spineAdapter = createBox(
      scene,
      `${ship.name}-hab-adapter`,
      { width: moduleRadius * 0.85, height: moduleRadius * 0.85, depth: moduleLength * 0.9 },
      materials.truss,
      moduleRoot,
      new BABYLON.Vector3(0, 0, -moduleLength * 0.08)
    );
    tagShipPart(ship, spineAdapter, 'quarters', { role: 'adapter' });
  }

  moduleRoot.position.z = profile.length * 0.12;
}

function addFuelTanks(ship, scene, parent, profile, materials, components) {
  const fuelCapacity = Number(components.fuel?.capacity || 2500);
  const engineType = String(components.engine?.type || 'Chemical').toLowerCase();
  const tankRoot = new BABYLON.TransformNode(`${ship.name}-fuel-root`, scene);
  tankRoot.parent = parent;

  const count = clamp(Math.ceil(fuelCapacity / 2800), engineType === 'chemical' ? 2 : 1, 6);
  const tankLength = clamp(profile.length * 0.22 + fuelCapacity / 45000, 0.1, 0.28);
  const tankRadius = clamp(profile.width * 0.12 + fuelCapacity / 160000, 0.024, 0.08);
  const orbitRadius = count <= 1 ? 0 : clamp(profile.width * 0.24 + tankRadius * 1.2, 0.06, 0.18);
  const z = -profile.length * 0.08;

  for (let i = 0; i < count; i += 1) {
    const angle = count === 1 ? 0 : (i / count) * TWO_PI;
    const x = count === 1 ? 0 : Math.cos(angle) * orbitRadius;
    const y = count === 1 ? 0 : Math.sin(angle) * orbitRadius * 0.72;

    const tank = createCylinder(
      scene,
      `${ship.name}-fuel-tank-${i}`,
      {
        height: tankLength,
        diameterTop: tankRadius * 2,
        diameterBottom: tankRadius * 2,
        tessellation: 14
      },
      materials.tank,
      tankRoot,
      new BABYLON.Vector3(x, y, z),
      new BABYLON.Vector3(Math.PI / 2, 0, 0)
    );
    tagShipPart(ship, tank, 'fuel', { capacity: fuelCapacity / count, role: 'tank-body' });

    const frontCap = createSphere(
      scene,
      `${ship.name}-fuel-cap-front-${i}`,
      { diameter: tankRadius * 1.95, segments: 10 },
      materials.tank,
      tankRoot,
      new BABYLON.Vector3(x, y, z + tankLength * 0.5)
    );
    frontCap.scaling.z = 0.62;
    tagShipPart(ship, frontCap, 'fuel', { role: 'tank-cap' });

    const rearCap = frontCap.clone(`${ship.name}-fuel-cap-rear-${i}`);
    rearCap.parent = tankRoot;
    rearCap.position.z = z - tankLength * 0.5;
    tagShipPart(ship, rearCap, 'fuel', { role: 'tank-cap' });

    const bandCount = 3;
    for (let bandIndex = 0; bandIndex < bandCount; bandIndex += 1) {
      const bandZ = z + tankLength * 0.35 - bandIndex * tankLength * 0.35;
      const strap = createCylinder(
        scene,
        `${ship.name}-fuel-band-${i}-${bandIndex}`,
        {
          height: tankRadius * 0.22,
          diameterTop: tankRadius * 2.18,
          diameterBottom: tankRadius * 2.18,
          tessellation: 18
        },
        materials.dark,
        tankRoot,
        new BABYLON.Vector3(x, y, bandZ),
        new BABYLON.Vector3(Math.PI / 2, 0, 0)
      );
      tagShipPart(ship, strap, 'fuel', { role: 'strap-band' });
    }

    const saddle = createBox(
      scene,
      `${ship.name}-fuel-saddle-${i}`,
      {
        width: tankRadius * 1.55,
        height: tankRadius * 0.34,
        depth: tankLength * 0.76
      },
      materials.truss,
      tankRoot,
      new BABYLON.Vector3(x, y - tankRadius * 0.88, z)
    );
    tagShipPart(ship, saddle, 'fuel', { role: 'saddle' });

    const lineStart = new BABYLON.Vector3(x, y - tankRadius * 0.18, z - tankLength * 0.18);
    const lineEnd = new BABYLON.Vector3(x * 0.36, y * 0.36, z - tankLength * 0.4);
    const feedLine = addPipe(scene, tankRoot, `${ship.name}-fuel-feed-${i}`, lineStart, lineEnd, tankRadius * 0.14, materials.dark);
    tagShipPart(ship, feedLine, 'fuel', { role: 'feed-line' });

    if (count > 1) {
      const brace = createBox(
        scene,
        `${ship.name}-fuel-brace-${i}`,
        { width: tankRadius * 0.42, height: tankRadius * 0.42, depth: orbitRadius * 0.96 },
        materials.truss,
        tankRoot,
        new BABYLON.Vector3(x * 0.45, y * 0.45, z)
      );
      brace.lookAt(new BABYLON.Vector3(x, y, z));
      tagShipPart(ship, brace, 'fuel', { role: 'support-strut' });
    }

    const serviceBox = createBox(
      scene,
      `${ship.name}-fuel-service-${i}`,
      {
        width: tankRadius * 0.6,
        height: tankRadius * 0.4,
        depth: tankRadius * 0.7
      },
      i % 2 === 0 ? materials.warning : materials.dark,
      tankRoot,
      new BABYLON.Vector3(x, y + tankRadius * 0.95, z - tankLength * 0.08)
    );
    tagShipPart(ship, serviceBox, 'fuel', { role: 'service-box' });
  }
}

function addCargoModules(ship, scene, parent, profile, materials, components) {
  const storageCapacity = Number(components.storage?.capacity || 100);
  const cargoCount = clamp(Math.ceil(storageCapacity / 700), 1, 5);
  const cargoRoot = new BABYLON.TransformNode(`${ship.name}-cargo-root`, scene);
  cargoRoot.parent = parent;

  const moduleLength = clamp(profile.length * 0.12 + storageCapacity / 30000, 0.08, 0.2);
  const moduleWidth = clamp(profile.width * 0.26 + storageCapacity / 60000, 0.08, 0.18);
  const moduleHeight = clamp(profile.height * 0.2 + storageCapacity / 90000, 0.05, 0.12);
  const baseZ = profile.length * -0.04;

  for (let i = 0; i < cargoCount; i += 1) {
    const z = baseZ - i * (moduleLength * 1.08);

    const container = createBox(
      scene,
      `${ship.name}-cargo-module-${i}`,
      { width: moduleWidth, height: moduleHeight, depth: moduleLength },
      i % 2 === 0 ? materials.hull : materials.warning,
      cargoRoot,
      new BABYLON.Vector3(0, 0, z)
    );
    tagShipPart(ship, container, 'cargo', { capacity: storageCapacity / cargoCount, role: 'container' });

    const capA = createBox(
      scene,
      `${ship.name}-cargo-cap-a-${i}`,
      { width: moduleWidth * 0.9, height: moduleHeight * 0.2, depth: moduleLength * 0.18 },
      materials.dark,
      cargoRoot,
      new BABYLON.Vector3(0, moduleHeight * 0.4, z + moduleLength * 0.34)
    );
    tagShipPart(ship, capA, 'cargo', { role: 'end-cap' });

    const capB = capA.clone(`${ship.name}-cargo-cap-b-${i}`);
    capB.parent = cargoRoot;
    capB.position.z = z - moduleLength * 0.34;
    tagShipPart(ship, capB, 'cargo', { role: 'end-cap' });

    const frameTop = createBox(
      scene,
      `${ship.name}-cargo-frame-top-${i}`,
      { width: moduleWidth * 1.08, height: moduleHeight * 0.12, depth: moduleLength * 1.08 },
      materials.truss,
      cargoRoot,
      new BABYLON.Vector3(0, moduleHeight * 0.6, z)
    );
    tagShipPart(ship, frameTop, 'cargo', { role: 'retention-frame' });

    const frameBottom = frameTop.clone(`${ship.name}-cargo-frame-bottom-${i}`);
    frameBottom.parent = cargoRoot;
    frameBottom.position.y = -moduleHeight * 0.6;
    tagShipPart(ship, frameBottom, 'cargo', { role: 'retention-frame' });

    [-1, 1].forEach((side, sideIndex) => {
      const latchRail = createBox(
        scene,
        `${ship.name}-cargo-latch-${i}-${sideIndex}`,
        { width: moduleWidth * 0.08, height: moduleHeight * 0.96, depth: moduleLength * 1.06 },
        materials.dark,
        cargoRoot,
        new BABYLON.Vector3(side * moduleWidth * 0.54, 0, z)
      );
      tagShipPart(ship, latchRail, 'cargo', { role: 'latch-rail' });

      const pad = createBox(
        scene,
        `${ship.name}-cargo-pad-${i}-${sideIndex}`,
        { width: moduleWidth * 0.16, height: moduleHeight * 0.18, depth: moduleLength * 0.18 },
        materials.accent,
        cargoRoot,
        new BABYLON.Vector3(side * moduleWidth * 0.46, -moduleHeight * 0.46, z + moduleLength * 0.24)
      );
      tagShipPart(ship, pad, 'cargo', { role: 'grapple-pad' });
    });

    addPanelStrip(ship, scene, cargoRoot, `cargo-rib-${i}`, 3, moduleWidth * 0.92, moduleHeight * 0.08, moduleLength * 0.06, z + moduleLength * 0.22, moduleLength * 0.22, materials.dark, 'cargo', { role: 'stiffener-rib' });

    const conduit = createBox(
      scene,
      `${ship.name}-cargo-conduit-${i}`,
      { width: moduleWidth * 0.14, height: moduleHeight * 0.14, depth: moduleLength * 0.82 },
      materials.truss,
      cargoRoot,
      new BABYLON.Vector3(0, moduleHeight * 0.7, z)
    );
    tagShipPart(ship, conduit, 'cargo', { role: 'service-conduit' });
  }
}

function addArmor(ship, scene, parent, profile, materials, armor) {
  if (!armor) {
    return;
  }

  const defense = Number(armor.defense || 0);
  const thickness = clamp(0.008 + defense / 8000, 0.008, 0.03);
  const plateLength = clamp(profile.length * 0.46, 0.1, 0.3);
  const plateHeight = clamp(profile.height * 0.32 + defense / 14000, 0.05, 0.14);
  const plateOffsetX = profile.width * 0.42;
  const plateZ = 0;

  ['port', 'starboard'].forEach((side, index) => {
    const direction = index === 0 ? -1 : 1;
    const plate = createBox(
      scene,
      `${ship.name}-armor-${side}`,
      { width: thickness, height: plateHeight, depth: plateLength },
      materials.armor,
      parent,
      new BABYLON.Vector3(direction * plateOffsetX, 0, plateZ)
    );
    tagShipPart(ship, plate, 'armor', { side, defense });

    const skirt = createBox(
      scene,
      `${ship.name}-armor-skirt-${side}`,
      { width: thickness * 1.25, height: plateHeight * 0.42, depth: plateLength * 1.05 },
      materials.dark,
      parent,
      new BABYLON.Vector3(direction * (plateOffsetX + thickness * 0.7), -plateHeight * 0.2, plateZ)
    );
    tagShipPart(ship, skirt, 'armor', { side, defense });

    const wedge = createBox(
      scene,
      `${ship.name}-armor-wedge-${side}`,
      { width: thickness * 1.4, height: plateHeight * 0.22, depth: plateLength * 0.28 },
      materials.armor,
      parent,
      new BABYLON.Vector3(direction * plateOffsetX, plateHeight * 0.28, plateZ + plateLength * 0.28),
      new BABYLON.Vector3(direction * 0.18, 0, 0)
    );
    tagShipPart(ship, wedge, 'armor', { side, defense, role: 'spaced-plate' });
  });

  const keel = createBox(
    scene,
    `${ship.name}-armor-keel`,
    { width: profile.width * 0.44, height: thickness * 1.9, depth: plateLength * 0.88 },
    materials.dark,
    parent,
    new BABYLON.Vector3(0, -profile.height * 0.32, -profile.length * 0.05)
  );
  tagShipPart(ship, keel, 'armor', { role: 'keel' });

  if (defense >= 200) {
    const prow = createBox(
      scene,
      `${ship.name}-armor-prow`,
      { width: profile.width * 0.28, height: profile.height * 0.22, depth: profile.length * 0.14 },
      materials.dark,
      parent,
      new BABYLON.Vector3(0, 0, profile.length * 0.28)
    );
    prow.rotation.x = Math.PI / 8;
    tagShipPart(ship, prow, 'armor', { role: 'citadel' });
  }
}

function addRadiators(ship, scene, parent, profile, materials, components) {
  const engineType = String(components.engine?.type || 'Chemical').toLowerCase();
  const fuelEfficiency = Number(components.engine?.fuelEfficiency || 1);
  const shouldAdd = engineType !== 'chemical' || fuelEfficiency >= 4;
  if (!shouldAdd) {
    return;
  }

  const radiatorRoot = new BABYLON.TransformNode(`${ship.name}-radiators`, scene);
  radiatorRoot.parent = parent;
  const panelCount = engineType === 'fusion' ? 3 : 2;
  const panelWidth = clamp(profile.width * 0.16 + fuelEfficiency * 0.008, 0.06, 0.14);
  const panelHeight = clamp(profile.length * 0.16 + fuelEfficiency * 0.01, 0.12, 0.28);
  const xOffset = clamp(profile.width * 0.52, 0.08, 0.18);
  const zStart = -profile.length * 0.08;

  [-1, 1].forEach((side) => {
    for (let i = 0; i < panelCount; i += 1) {
      const z = zStart - i * panelWidth * 0.96;
      const panel = createBox(
        scene,
        `${ship.name}-radiator-${side}-${i}`,
        { width: panelWidth, height: panelHeight, depth: 0.006 },
        materials.radiator,
        radiatorRoot,
        new BABYLON.Vector3(side * xOffset, 0, z),
        new BABYLON.Vector3(0, side * Math.PI / 5, 0)
      );
      tagShipPart(ship, panel, 'radiator', { side });

      const arm = createBox(
        scene,
        `${ship.name}-radiator-arm-${side}-${i}`,
        { width: 0.01, height: 0.01, depth: xOffset * 0.98 },
        materials.truss,
        radiatorRoot,
        new BABYLON.Vector3(side * xOffset * 0.5, 0, z)
      );
      arm.rotation.y = side > 0 ? Math.PI / 2 : -Math.PI / 2;
      tagShipPart(ship, arm, 'radiator', { side });
    }
  });
}

function addSensorArray(ship, scene, parent, profile, materials, sensor) {
  if (!sensor) {
    return;
  }

  const type = String(sensor.type || 'Standard').toLowerCase();
  const range = Number(sensor.range || sensor.detectionRange || 800);
  const tracking = Number(sensor.trackingResolution || 0.4);
  const mastHeight = clamp(profile.height * 0.4 + tracking * 0.08, 0.05, 0.12);

  const mast = createBox(
    scene,
    `${ship.name}-sensor-mast`,
    { width: 0.01, height: mastHeight, depth: 0.01 },
    materials.truss,
    parent,
    new BABYLON.Vector3(0, profile.height * 0.28 + mastHeight * 0.45, profile.length * 0.2)
  );
  tagShipPart(ship, mast, 'sensor', { type });

  if (type.includes('grav') || type.includes('deep')) {
    const dish = BABYLON.MeshBuilder.CreateDisc(`${ship.name}-sensor-dish`, {
      radius: clamp(0.04 + range / 60000000, 0.04, 0.09),
      tessellation: 24,
      sideOrientation: BABYLON.Mesh.DOUBLESIDE
    }, scene);
    dish.material = materials.accent;
    dish.parent = parent;
    dish.position.set(0, profile.height * 0.45 + mastHeight, profile.length * 0.22);
    dish.rotation.x = Math.PI / 2.6;
    tagShipPart(ship, dish, 'sensor', { type: 'dish' });

    const boom = createBox(
      scene,
      `${ship.name}-sensor-boom`,
      { width: 0.008, height: 0.008, depth: profile.length * 0.16 },
      materials.truss,
      parent,
      new BABYLON.Vector3(0, profile.height * 0.22, profile.length * 0.13)
    );
    tagShipPart(ship, boom, 'sensor', { type: 'boom' });
  } else {
    const sensorHead = createBox(
      scene,
      `${ship.name}-sensor-head`,
      { width: 0.045, height: 0.03, depth: 0.03 },
      tracking >= 0.75 ? materials.glow : materials.accent,
      parent,
      new BABYLON.Vector3(0, profile.height * 0.45 + mastHeight * 0.7, profile.length * 0.2)
    );
    tagShipPart(ship, sensorHead, 'sensor', { type: 'head' });

    if (range >= 1400) {
      ['port', 'starboard'].forEach((side, index) => {
        const direction = index === 0 ? -1 : 1;
        const pod = createSphere(
          scene,
          `${ship.name}-sensor-pod-${side}`,
          { diameter: 0.03, segments: 8 },
          materials.accent,
          parent,
          new BABYLON.Vector3(direction * profile.width * 0.42, profile.height * 0.08, profile.length * 0.16)
        );
        tagShipPart(ship, pod, 'sensor', { type: 'aux-pod' });
      });
    }
  }
}

function addMiningRig(ship, scene, parent, profile, materials, mining) {
  if (!mining) {
    return;
  }

  const miningRoot = new BABYLON.TransformNode(`${ship.name}-mining-root`, scene);
  miningRoot.parent = parent;
  const extractionRate = Number(mining.extractionRate || 10);
  const armLength = clamp(profile.width * 0.42 + extractionRate / 600, 0.08, 0.2);
  const emitterSize = clamp(0.022 + extractionRate / 2000, 0.022, 0.05);
  const z = -profile.length * 0.12;

  [-1, 1].forEach((side) => {
    const arm = createBox(
      scene,
      `${ship.name}-mining-arm-${side}`,
      { width: 0.012, height: 0.012, depth: armLength },
      materials.truss,
      miningRoot,
      new BABYLON.Vector3(side * profile.width * 0.42, 0, z),
      new BABYLON.Vector3(0, side > 0 ? Math.PI / 2 : -Math.PI / 2, 0)
    );
    tagShipPart(ship, arm, 'mining', { extractionRate });

    const emitter = createBox(
      scene,
      `${ship.name}-mining-emitter-${side}`,
      { width: emitterSize, height: emitterSize * 0.55, depth: emitterSize * 0.75 },
      materials.warning,
      miningRoot,
      new BABYLON.Vector3(side * (profile.width * 0.42 + armLength * 0.52), 0, z)
    );
    tagShipPart(ship, emitter, 'mining', { extractionRate });
  });
}

function addPointDefense(ship, scene, parent, profile, materials, pds) {
  if (!pds) {
    return;
  }

  const trackingPower = Number(pds.trackingPower || 0.3);
  const mountCount = trackingPower >= 0.55 ? 4 : 2;
  for (let i = 0; i < mountCount; i += 1) {
    const side = i % 2 === 0 ? -1 : 1;
    const z = i < 2 ? 0.12 : -0.12;
    const base = createCylinder(
      scene,
      `${ship.name}-pds-base-${i}`,
      { height: 0.02, diameterTop: 0.035, diameterBottom: 0.045, tessellation: 10 },
      materials.dark,
      parent,
      new BABYLON.Vector3(side * profile.width * 0.34, profile.height * 0.2, z),
      null
    );
    tagShipPart(ship, base, 'pds', { trackingPower });

    const turret = createBox(
      scene,
      `${ship.name}-pds-turret-${i}`,
      { width: 0.024, height: 0.02, depth: 0.04 },
      materials.hull,
      parent,
      new BABYLON.Vector3(side * profile.width * 0.34, profile.height * 0.235, z)
    );
    tagShipPart(ship, turret, 'pds', { trackingPower });

    const barrelA = createBox(
      scene,
      `${ship.name}-pds-barrel-a-${i}`,
      { width: 0.006, height: 0.006, depth: 0.05 },
      materials.accent,
      parent,
      new BABYLON.Vector3(side * profile.width * 0.34 - 0.008, profile.height * 0.24, z + 0.025)
    );
    tagShipPart(ship, barrelA, 'pds', { trackingPower });

    const barrelB = barrelA.clone(`${ship.name}-pds-barrel-b-${i}`);
    barrelB.parent = parent;
    barrelB.position.x += 0.016;
    tagShipPart(ship, barrelB, 'pds', { trackingPower });
  }
}

function addWeapons(ship, scene, parent, profile, materials, weapons) {
  if (!Array.isArray(weapons) || weapons.length === 0) {
    return;
  }

  const weaponRoot = new BABYLON.TransformNode(`${ship.name}-weapon-root`, scene);
  weaponRoot.parent = parent;

  weapons.forEach((weapon, index) => {
    const weaponType = String(weapon.weaponType || weapon.type || 'laser').toLowerCase();
    const z = profile.length * 0.16 - index * 0.08;

    if (weaponType === 'railgun') {
      const base = createBox(scene, `${ship.name}-railgun-base-${index}`, { width: 0.06, height: 0.026, depth: 0.06 }, materials.dark, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.24, z));
      tagShipPart(ship, base, 'weapon', { weaponType, role: 'traverse-base' });

      const yoke = createBox(scene, `${ship.name}-railgun-yoke-${index}`, { width: 0.08, height: 0.014, depth: 0.03 }, materials.truss, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.27, z));
      tagShipPart(ship, yoke, 'weapon', { weaponType, role: 'yoke' });

      const barrelSpine = createBox(scene, `${ship.name}-railgun-spine-${index}`, { width: 0.024, height: 0.018, depth: clamp(profile.length * 0.28, 0.12, 0.26) }, materials.hull, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.29, z + profile.length * 0.12));
      tagShipPart(ship, barrelSpine, 'weapon', { weaponType, role: 'spine' });

      const guideA = createBox(scene, `${ship.name}-railgun-guide-a-${index}`, { width: 0.007, height: 0.007, depth: clamp(profile.length * 0.32, 0.14, 0.28) }, materials.accent, weaponRoot, new BABYLON.Vector3(-0.012, profile.height * 0.297, z + profile.length * 0.13));
      tagShipPart(ship, guideA, 'weapon', { weaponType, role: 'rail' });

      const guideB = guideA.clone(`${ship.name}-railgun-guide-b-${index}`);
      guideB.parent = weaponRoot;
      guideB.position.x = 0.012;
      tagShipPart(ship, guideB, 'weapon', { weaponType, role: 'rail' });

      ['port', 'starboard'].forEach((side, sideIndex) => {
        const direction = sideIndex === 0 ? -1 : 1;
        const capacitor = createBox(scene, `${ship.name}-railgun-capacitor-${side}-${index}`, { width: 0.03, height: 0.03, depth: 0.08 }, sideIndex === 0 ? materials.accent : materials.dark, weaponRoot, new BABYLON.Vector3(direction * 0.04, profile.height * 0.27, z + 0.005));
        tagShipPart(ship, capacitor, 'weapon', { weaponType, role: 'capacitor' });

        const feed = addPipe(scene, weaponRoot, `${ship.name}-railgun-feed-${side}-${index}`, new BABYLON.Vector3(direction * 0.028, profile.height * 0.272, z + 0.02), new BABYLON.Vector3(direction * 0.01, profile.height * 0.292, z + 0.09), 0.003, materials.dark);
        tagShipPart(ship, feed, 'weapon', { weaponType, role: 'power-feed' });
      });

      const muzzle = createBox(scene, `${ship.name}-railgun-muzzle-${index}`, { width: 0.032, height: 0.024, depth: 0.018 }, materials.warning, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.292, z + clamp(profile.length * 0.28, 0.12, 0.26) * 0.5 + profile.length * 0.12));
      tagShipPart(ship, muzzle, 'weapon', { weaponType, role: 'muzzle-brake' });
      return;
    }

    if (weaponType === 'missile') {
      const rackWidth = clamp(profile.width * 0.14, 0.05, 0.1);

      ['port', 'starboard'].forEach((side, sideIndex) => {
        const direction = sideIndex === 0 ? -1 : 1;
        const rack = createBox(scene, `${ship.name}-missile-rack-${side}-${index}`, { width: rackWidth, height: 0.06, depth: 0.1 }, materials.warning, weaponRoot, new BABYLON.Vector3(direction * profile.width * 0.34, 0, z));
        tagShipPart(ship, rack, 'weapon', { weaponType, role: 'missile-rack' });

        const rackFrame = createBox(scene, `${ship.name}-missile-frame-${side}-${index}`, { width: rackWidth * 1.08, height: 0.072, depth: 0.112 }, materials.truss, weaponRoot, new BABYLON.Vector3(direction * profile.width * 0.34, 0, z));
        tagShipPart(ship, rackFrame, 'weapon', { weaponType, role: 'rack-frame' });

        const tubeOffsets = [[-0.22, 0.16], [0.22, 0.16], [-0.22, -0.16], [0.22, -0.16]];

        tubeOffsets.forEach(([xFactor, yFactor], tubeIndex) => {
          const tube = createCylinder(scene, `${ship.name}-missile-tube-${side}-${index}-${tubeIndex}`, { height: 0.09, diameterTop: 0.016, diameterBottom: 0.018, tessellation: 8 }, materials.dark, weaponRoot, new BABYLON.Vector3(direction * profile.width * 0.34 + xFactor * rackWidth, yFactor * 0.06, z), new BABYLON.Vector3(Math.PI / 2, 0, 0));
          tagShipPart(ship, tube, 'weapon', { weaponType, role: 'tube' });
        });
      });
      return;
    }

    const turretBase = createCylinder(scene, `${ship.name}-laser-base-${index}`, { height: 0.022, diameterTop: 0.04, diameterBottom: 0.05, tessellation: 10 }, materials.dark, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.22, z), null);
    tagShipPart(ship, turretBase, 'weapon', { weaponType, role: 'turret-base' });

    const turretHousing = createBox(scene, `${ship.name}-laser-housing-${index}`, { width: 0.05, height: 0.024, depth: 0.05 }, materials.hull, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.245, z));
    tagShipPart(ship, turretHousing, 'weapon', { weaponType, role: 'turret-housing' });

    const barrelCore = createBox(scene, `${ship.name}-laser-barrel-${index}`, { width: 0.012, height: 0.012, depth: 0.09 }, materials.glow, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.246, z + 0.048));
    tagShipPart(ship, barrelCore, 'weapon', { weaponType, role: 'emitter' });

    const shroud = createBox(scene, `${ship.name}-laser-shroud-${index}`, { width: 0.024, height: 0.018, depth: 0.06 }, materials.dark, weaponRoot, new BABYLON.Vector3(0, profile.height * 0.246, z + 0.02));
    tagShipPart(ship, shroud, 'weapon', { weaponType, role: 'barrel-shroud' });
  });
}

function addEngineBlock(ship, scene, parent, profile, materials, components) {
  const engine = components.engine || {};
  const engineType = String(engine.type || 'Chemical').toLowerCase();
  const thrust = Number(engine.thrust || 100);
  const nozzleCount = clamp(Math.round(thrust / 110), 1, engineType === 'chemical' ? 4 : 3);
  const engineRoot = new BABYLON.TransformNode(`${ship.name}-engine-root`, scene);
  engineRoot.parent = parent;

  const reactorWidth = clamp(profile.width * 0.2 + thrust / 20000, 0.05, 0.13);
  const reactorHeight = clamp(profile.height * 0.22 + thrust / 22000, 0.045, 0.12);
  const reactorDepth = clamp(profile.length * 0.15 + thrust / 18000, 0.07, 0.18);

  const reactor = createBox(scene, `${ship.name}-reactor-block`, { width: reactorWidth, height: reactorHeight, depth: reactorDepth }, engineType === 'chemical' ? materials.hull : materials.dark, engineRoot, new BABYLON.Vector3(0, 0, -profile.length * 0.26));
  tagShipPart(ship, reactor, 'engine', { engineType, thrust, role: 'reactor-block' });

  const aftSkirt = createCylinder(scene, `${ship.name}-engine-skirt`, { height: reactorDepth * 0.42, diameterTop: reactorWidth * 1.18, diameterBottom: reactorWidth * 1.44, tessellation: 14 }, materials.dark, engineRoot, new BABYLON.Vector3(0, 0, -profile.length * 0.34), new BABYLON.Vector3(Math.PI / 2, 0, 0));
  tagShipPart(ship, aftSkirt, 'engine', { engineType, role: 'engine-skirt' });

  const manifold = createBox(scene, `${ship.name}-engine-manifold`, { width: reactorWidth * 1.08, height: reactorHeight * 0.42, depth: reactorDepth * 0.5 }, materials.hull, engineRoot, new BABYLON.Vector3(0, 0, -profile.length * 0.2));
  tagShipPart(ship, manifold, 'engine', { engineType, role: 'prop-manifold' });

  ['port', 'starboard'].forEach((side, sideIndex) => {
    const direction = sideIndex === 0 ? -1 : 1;
    const turbopump = createCylinder(scene, `${ship.name}-turbopump-${side}`, { height: reactorWidth * 0.36, diameterTop: reactorHeight * 0.4, diameterBottom: reactorHeight * 0.48, tessellation: 10 }, materials.hull, engineRoot, new BABYLON.Vector3(direction * reactorWidth * 0.58, 0, -profile.length * 0.24), new BABYLON.Vector3(0, 0, Math.PI / 2));
    tagShipPart(ship, turbopump, 'engine', { engineType, role: 'turbopump' });

    const line = addPipe(scene, engineRoot, `${ship.name}-engine-line-${side}`, new BABYLON.Vector3(direction * reactorWidth * 0.42, 0, -profile.length * 0.22), new BABYLON.Vector3(direction * reactorWidth * 0.2, 0, -profile.length * 0.34), reactorHeight * 0.08, materials.dark);
    tagShipPart(ship, line, 'engine', { engineType, role: 'feed-line' });
  });

  if (engineType === 'nuclear' || engineType === 'fusion') {
    const shield = createCylinder(scene, `${ship.name}-reactor-shield`, { height: 0.03, diameterTop: profile.width * 0.42, diameterBottom: profile.width * 0.46, tessellation: 16 }, materials.warning, engineRoot, new BABYLON.Vector3(0, 0, -profile.length * 0.16), new BABYLON.Vector3(Math.PI / 2, 0, 0));
    tagShipPart(ship, shield, 'engine', { engineType, role: 'shadow-shield' });
  }

  const ringRadius = nozzleCount > 1 ? clamp(profile.width * 0.16, 0.03, 0.08) : 0;
  for (let i = 0; i < nozzleCount; i += 1) {
    const angle = nozzleCount === 1 ? 0 : (i / nozzleCount) * TWO_PI;
    const x = nozzleCount === 1 ? 0 : Math.cos(angle) * ringRadius;
    const y = nozzleCount === 1 ? 0 : Math.sin(angle) * ringRadius * 0.8;
    const nozzleLength = clamp(0.05 + thrust / 12000, 0.05, 0.14);
    const nozzleRadius = clamp(0.018 + thrust / 28000, 0.016, 0.05);

    const nozzleMount = createBox(scene, `${ship.name}-engine-mount-${i}`, { width: nozzleRadius * 1.1, height: nozzleRadius * 1.1, depth: nozzleLength * 0.3 }, materials.truss, engineRoot, new BABYLON.Vector3(x, y, -profile.length * 0.39 + nozzleLength * 0.1));
    tagShipPart(ship, nozzleMount, 'engine', { engineType, role: 'gimbal-mount' });

    const nozzle = createCylinder(scene, `${ship.name}-engine-nozzle-${i}`, { height: nozzleLength, diameterTop: nozzleRadius * 0.7, diameterBottom: nozzleRadius * 1.65, tessellation: 14 }, materials.dark, engineRoot, new BABYLON.Vector3(x, y, -profile.length * 0.43), new BABYLON.Vector3(Math.PI / 2, 0, 0));
    tagShipPart(ship, nozzle, 'engine', { engineType, thrust, role: 'nozzle' });

    const throatRing = createCylinder(scene, `${ship.name}-engine-throat-${i}`, { height: nozzleLength * 0.08, diameterTop: nozzleRadius * 0.86, diameterBottom: nozzleRadius * 0.96, tessellation: 14 }, materials.warning, engineRoot, new BABYLON.Vector3(x, y, -profile.length * 0.38), new BABYLON.Vector3(Math.PI / 2, 0, 0));
    tagShipPart(ship, throatRing, 'engine', { engineType, role: 'throat-ring' });

    // ENGINE_GLOW: commented out - can be restored later
    // if (engineType !== 'chemical') {
    //   const plume = createCylinder(scene, `${ship.name}-engine-glow-${i}`, { height: nozzleLength * 0.5, diameterTop: nozzleRadius * 0.22, diameterBottom: nozzleRadius * 0.92, tessellation: 12 }, materials.glow, engineRoot, new BABYLON.Vector3(x, y, -profile.length * 0.51), new BABYLON.Vector3(Math.PI / 2, 0, 0));
    //   plume.visibility = 0.82;
    //   tagShipPart(ship, plume, 'engine', { engineType, role: 'drive-glow' });
    // }
  }

  if (engineType === 'ion') {
    const ionRing = BABYLON.MeshBuilder.CreateTorus(`${ship.name}-ion-ring`, {
      diameter: clamp(profile.width * 0.44, 0.08, 0.2),
      thickness: 0.012,
      tessellation: 18
    }, scene);
    ionRing.material = materials.accent;
    ionRing.parent = engineRoot;
    ionRing.rotation.x = Math.PI / 2;
    ionRing.position.z = -profile.length * 0.31;
    tagShipPart(ship, ionRing, 'engine', { engineType, role: 'field-ring' });
  }

  return engineRoot;
}

function createProfile(ship) {
  const components = ship.components || {};
  const type = String(ship.type || 'default').toLowerCase();
  const mass = Number(ship.mass || 1200);
  const cargoCapacity = Number(components.storage?.capacity || 0);
  const fuelCapacity = Number(components.fuel?.capacity || 0);
  const quartersCapacity = Number(components.quarters?.capacity || 0);
  const armorDefense = Number(components.armor?.defense || 0);
  const weaponCount = Array.isArray(components.weapons) ? components.weapons.length : 0;

  const baseByType = {
    explorer: { length: 0.34, width: 0.1, height: 0.1, interceptRadiusMeters: 18000 },
    construction: { length: 0.56, width: 0.17, height: 0.17, interceptRadiusMeters: 40000 },
    transport: { length: 0.48, width: 0.15, height: 0.13, interceptRadiusMeters: 36000 },
    warship: { length: 0.44, width: 0.14, height: 0.12, interceptRadiusMeters: 28000 },
    colony: { length: 0.62, width: 0.18, height: 0.19, interceptRadiusMeters: 42000 },
    default: { length: 0.38, width: 0.11, height: 0.11, interceptRadiusMeters: 25000 }
  };

  const base = baseByType[type] || baseByType.default;
  const massScale = clamp(Math.pow(mass / 1800, 0.24), 0.88, 1.45);
  const cargoScale = clamp(1 + cargoCapacity / 9000, 1, 1.32);
  const fuelScale = clamp(1 + fuelCapacity / 36000, 1, 1.3);
  const crewScale = clamp(1 + quartersCapacity / 220, 1, 1.24);
  const armorScale = clamp(1 + armorDefense / 1400, 1, 1.28);
  const weaponScale = clamp(1 + weaponCount * 0.05, 1, 1.18);

  const length = base.length * massScale * Math.max(cargoScale, fuelScale * 0.95);
  const width = base.width * massScale * Math.max(armorScale, cargoScale * 0.92, weaponScale);
  const height = base.height * massScale * Math.max(armorScale * 0.94, crewScale);

  return {
    length: clamp(length, 0.28, 1.1),
    width: clamp(width, 0.09, 0.42),
    height: clamp(height, 0.09, 0.4),
    interceptRadiusMeters: base.interceptRadiusMeters * Math.max(massScale, cargoScale, armorScale)
  };
}

function estimateProfileHalfExtents(ship, hull) {
  const components = ship.components || {};
  const xHalfBase = (hull.width || 0.1) * 0.5;
  const yHalfBase = (hull.height || 0.1) * 0.5;
  const zHalfBase = (hull.length || 0.3) * 0.5;

  let xHalf = xHalfBase;
  let yHalf = yHalfBase;
  let zHalf = zHalfBase;

  if (components.fuel) {
    xHalf = Math.max(xHalf, xHalfBase * 1.55);
    yHalf = Math.max(yHalf, yHalfBase * 1.25);
    zHalf = Math.max(zHalf, zHalfBase * 1.02);
  }

  if (components.radiator || (components.engine && String(components.engine.type || '').toLowerCase() !== 'chemical')) {
    xHalf = Math.max(xHalf, xHalfBase * 1.8);
    yHalf = Math.max(yHalf, yHalfBase * 1.45);
  }

  if (components.mining) {
    xHalf = Math.max(xHalf, xHalfBase * 2.0);
  }

  if (components.sensor) {
    yHalf = Math.max(yHalf, yHalfBase * 1.6);
    zHalf = Math.max(zHalf, zHalfBase * 1.18);
  }

  if (components.weapons?.length) {
    yHalf = Math.max(yHalf, yHalfBase * 1.45);
    zHalf = Math.max(zHalf, zHalfBase * 1.28);
    xHalf = Math.max(xHalf, xHalfBase * 1.35);
  }

  if (components.armor) {
    xHalf = Math.max(xHalf, xHalfBase * 1.18);
    yHalf = Math.max(yHalf, yHalfBase * 1.18);
  }

  if (components.quarters?.capacity >= 10) {
    xHalf = Math.max(xHalf, xHalfBase * 1.6);
    yHalf = Math.max(yHalf, yHalfBase * 1.5);
  }

  return { xHalf, yHalf, zHalf };
}
const spaceshipVisualMethods = {
  resolveHullComponent() {
    const profile = createProfile(this);
    return {
      name: `${this.class || this.name} Hull`,
      type: this.type || 'default',
      style: this.type || 'default',
      length: profile.length,
      width: profile.width,
      height: profile.height,
      interceptRadiusMeters: profile.interceptRadiusMeters
    };
  },

  estimateRadius() {
    if (this.mesh && typeof this.mesh.getHierarchyBoundingVectors === 'function') {
      try {
        this.mesh.computeWorldMatrix?.(true);
        const bounds = this.mesh.getHierarchyBoundingVectors(true);
        if (bounds?.min && bounds?.max) {
          const extent = bounds.max.subtract(bounds.min);
          const measuredRadius = extent.length() * 0.5;
          if (Number.isFinite(measuredRadius) && measuredRadius > 0) {
            return Math.max(measuredRadius * 1.05, 0.03);
          }
        }
      } catch (error) {
        console.warn(`Unable to measure procedural bounds for ${this.name}. Falling back to profile estimate.`, error);
      }
    }

    const hull = this.hull || this.resolveHullComponent();
    const { xHalf, yHalf, zHalf } = estimateProfileHalfExtents(this, hull);
    const profileRadius = Math.sqrt((xHalf * xHalf) + (yHalf * yHalf) + (zHalf * zHalf));

    return Math.max(profileRadius * SHIP_VISUAL_SCALE * SHIP_RADIUS_PADDING, 0.03);
  },

  applyShipMetadataToMeshTree(root = this.mesh) {
    if (!root) {
      return;
    }

    const metadata = {
      ship: this,
      velocity: this.velocity,
      shipName: this.name,
      shipType: this.type
    };

    root.metadata = {
      ...(root.metadata || {}),
      ...metadata
    };

    if (typeof root.getChildMeshes === 'function') {
      root.getChildMeshes(false).forEach((mesh) => {
        mesh.metadata = {
          ...(mesh.metadata || {}),
          ...metadata
        };
      });
    }
  },

  disposeProceduralShipMesh() {
    if (!this.mesh) {
      return;
    }
    this.mesh.dispose(false, true);
    this.mesh = null;
  },

  rebuildProceduralShipMesh(scene) {
    const currentPosition = this.position?.clone ? this.position.clone() : this.position;
    this.disposeProceduralShipMesh();
    this.hull = this.resolveHullComponent();
    this.mesh = this.createProceduralShipMesh(scene);
    this.radius = this.estimateRadius();
    this.applyShipMetadataToMeshTree(this.mesh);
    if (currentPosition) {
      this.syncRenderedPosition(currentPosition);
    }
    return this.mesh;
  },

  createProceduralShipMesh(scene) {
    const profile = this.hull || this.resolveHullComponent();
    const materials = getMaterialSet(scene, String(this.type || 'default').toLowerCase());
    const seed = hashString(`${this.name}|${this.class}|${JSON.stringify(this.components || {})}`);
    const rng = createSeededRng(seed);

    const root = BABYLON.MeshBuilder.CreateBox(`${this.name}-ship-root`, { size: 0.01 }, scene);
    root.visibility = 0;
    root.isPickable = false;
    root.alwaysSelectAsActiveMesh = true;
    root.cullingStrategy = BABYLON.AbstractMesh.CULLINGSTRATEGY_BOUNDINGSPHERE_ONLY;
    root.metadata = { ...(root.metadata || {}), visualRole: 'ship-root', lodTier: 0 };
    root.scaling.setAll(SHIP_VISUAL_SCALE);

    const interactionHull = BABYLON.MeshBuilder.CreateBox(`${this.name}-selection-hull`, {
      width: profile.width * 1.2,
      height: profile.height * 1.15,
      depth: profile.length * 1.02
    }, scene);
    interactionHull.parent = root;
    interactionHull.visibility = 0;
    interactionHull.isPickable = true;
    tagShipPart(this, interactionHull, 'selection-hull');

    const bodyRoot = new BABYLON.TransformNode(`${this.name}-body-root`, scene);
    bodyRoot.parent = root;
    bodyRoot.rotation.z = (rng() - 0.5) * 0.03;

    addExposedTruss(this, scene, bodyRoot, profile, materials, rng);
    addCommandSection(this, scene, bodyRoot, profile, materials, rng);
    addHabitatSection(this, scene, bodyRoot, profile, materials, this.components.quarters);
    addFuelTanks(this, scene, bodyRoot, profile, materials, this.components);
    addCargoModules(this, scene, bodyRoot, profile, materials, this.components);
    addArmor(this, scene, bodyRoot, profile, materials, this.components.armor);
    addRadiators(this, scene, bodyRoot, profile, materials, this.components);
    addSensorArray(this, scene, bodyRoot, profile, materials, this.components.sensor);
    addMiningRig(this, scene, bodyRoot, profile, materials, this.components.mining);
    addPointDefense(this, scene, bodyRoot, profile, materials, this.components.pds);
    addWeapons(this, scene, bodyRoot, profile, materials, this.components.weapons);
    addEngineBlock(this, scene, bodyRoot, profile, materials, this.components);

    root.computeWorldMatrix?.(true);
    bodyRoot.computeWorldMatrix?.(true);
    root.getChildMeshes(false).forEach((mesh) => {
      mesh.computeWorldMatrix?.(true);
      if (mesh.metadata?.partType !== 'selection-hull') mesh.isPickable = false;
      mesh.cullingStrategy = BABYLON.AbstractMesh.CULLINGSTRATEGY_BOUNDINGSPHERE_ONLY;
    });

    this.applyShipMetadataToMeshTree(root);
    return root;
  }
};


// ===== public/classes/spaceship/SpaceshipSystems.js =====

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}
const spaceshipSystemMethods = {
  isDestroyed() {
    return this.hullHP <= 0;
  },

  isArmed() {
    return Array.isArray(this.weapons) && this.weapons.some((weapon) => (weapon?.damage || 0) > 0);
  },

  getStrategicRole() {
    const type = String(this.type || '').toLowerCase();
    const className = String(this.class || '').toLowerCase();
    const hasWeapons = this.isArmed();
    const hasStorage = Number(this.cargoCapacity || 0) >= 150;
    const hasSensors = this.hasAdvancedSensors?.() || Number(this.sensor?.detectionRange || 0) >= 120000000;

    if (type === 'warship' || hasWeapons) return 'warship';
    if (type === 'colony' || className.includes('colony')) return 'colony';
    if (type === 'construction' || className.includes('construct')) return 'construction';
    if (type === 'tanker' || className.includes('tanker') || className.includes('fuel')) return 'tanker';
    if (type === 'transport' || hasStorage) return 'transport';
    if (hasSensors || type === 'explorer') return 'explorer';
    return type || 'utility';
  },

  getMissionTemplates() {
    const role = this.getStrategicRole();
    const common = [
      { id: 'patrol', label: 'Patrol Route', requiresTarget: true },
      { id: 'refuel', label: 'Return to Refuel', requiresTarget: true },
      { id: 'return_repair', label: 'Return for Repair', requiresTarget: true }
    ];
    const byRole = {
      explorer: [
        { id: 'survey', label: 'Survey Body', requiresTarget: true },
        { id: 'explore', label: 'Explore Body', requiresTarget: true }
      ],
      transport: [
        { id: 'deliver', label: 'Deliver Cargo', requiresSource: true, requiresTarget: true },
        { id: 'trade_route', label: 'Maintain Trade Route', requiresSource: true, requiresTarget: true }
      ],
      construction: [
        { id: 'build', label: 'Build Installation', requiresTarget: true },
        { id: 'colonize', label: 'Establish Colony', requiresTarget: true }
      ],
      colony: [
        { id: 'colonize', label: 'Establish Colony', requiresTarget: true }
      ],
      tanker: [
        { id: 'deliver', label: 'Deliver Fuel', requiresSource: true, requiresTarget: true },
        { id: 'refuel_fleet', label: 'Refuel Fleet', requiresTarget: true }
      ],
      warship: [
        { id: 'escort', label: 'Escort Ship', requiresTarget: true },
        { id: 'intercept', label: 'Intercept Target', requiresTarget: true },
        { id: 'defend', label: 'Defend Body', requiresTarget: true }
      ]
    };

    return [...(byRole[role] || []), ...common];
  },

  createDefaultCombatDoctrine() {
    const role = this.getStrategicRole();
    const defaults = {
      formation: role === 'warship' ? 'line_abreast' : 'screened_column',
      preferredRange: role === 'warship' ? 'weapon_optimal' : 'long',
      focusFirePolicy: role === 'warship' ? 'highest_threat' : 'nearest',
      missilePolicy: role === 'warship' ? 'standard' : 'conserve',
      retreatHullPercent: role === 'warship' ? 22 : 40,
      protectTransports: role === 'warship',
      engagementPolicy: role === 'warship' ? 'defensive' : 'avoid',
      objectivePriority: role === 'warship' ? 'mission' : 'survival'
    };
    return defaults;
  },

  setCombatDoctrine(patch = {}) {
    this.combatDoctrine = {
      ...(this.combatDoctrine || this.createDefaultCombatDoctrine()),
      ...(patch || {})
    };
    this.emitStateChanged('ship_combat_doctrine_changed', {
      combatDoctrine: { ...this.combatDoctrine }
    });
    return this.combatDoctrine;
  },

  initializeSubsystemState() {
    const definitions = {
      engines: { label: 'Engines', present: true },
      reactor: { label: 'Reactor', present: true },
      sensors: { label: 'Sensors', present: !!this.sensor },
      weapons: { label: 'Weapons', present: this.isArmed() },
      pointDefense: { label: 'Point Defense', present: !!this.pds },
      cargo: { label: 'Cargo Handling', present: Number(this.cargoCapacity || 0) > 0 },
      lifeSupport: { label: 'Life Support', present: !!this.quarters }
    };

    this.subsystemState = this.subsystemState || {};
    Object.entries(definitions).forEach(([key, definition]) => {
      if (!definition.present) return;
      this.subsystemState[key] = {
        label: definition.label,
        maxHP: 100,
        hp: Number(this.subsystemState[key]?.hp ?? 100),
        disabled: !!this.subsystemState[key]?.disabled,
        lastDamagedTurn: this.subsystemState[key]?.lastDamagedTurn ?? null
      };
    });
    return this.subsystemState;
  },

  getSubsystemEffectiveness(subsystemName) {
    const subsystem = this.subsystemState?.[subsystemName];
    if (!subsystem) return 1;
    if (subsystem.disabled || subsystem.hp <= 0) return 0;
    const ratio = clamp(subsystem.hp / Math.max(1, subsystem.maxHP || 100), 0, 1);
    return Number((0.35 + (ratio * 0.65)).toFixed(3));
  },

  getSubsystemSummary() {
    return Object.entries(this.subsystemState || {}).map(([id, subsystem]) => ({
      id,
      label: subsystem.label || id,
      hp: Number(subsystem.hp || 0),
      maxHP: Number(subsystem.maxHP || 100),
      effectiveness: this.getSubsystemEffectiveness(id),
      disabled: !!subsystem.disabled
    }));
  },

  applySubsystemDamage(rawDamage, damageType = 'kinetic') {
    const candidates = Object.entries(this.subsystemState || {})
      .filter(([, subsystem]) => subsystem && !subsystem.disabled && subsystem.hp > 0);
    if (candidates.length === 0 || Number(rawDamage || 0) <= 0) return null;

    const damageChance = clamp(Number(rawDamage || 0) / Math.max(40, this.maxHullHP), 0.08, 0.7);
    if (!this.game?.randomChance?.(damageChance)) return null;

    const weighted = [];
    candidates.forEach(([id, subsystem]) => {
      let weight = 1;
      if (damageType === 'energy' && ['reactor', 'sensors'].includes(id)) weight = 1.8;
      if (damageType === 'explosive' && ['weapons', 'cargo'].includes(id)) weight = 1.6;
      if (damageType === 'kinetic' && ['engines', 'lifeSupport'].includes(id)) weight = 1.5;
      for (let index = 0; index < Math.ceil(weight * 2); index += 1) weighted.push([id, subsystem]);
    });

    const [id, subsystem] = this.game?.pickRandom?.(weighted) || candidates[0];
    const subsystemDamage = Math.max(4, Math.min(45, Number(rawDamage || 0) * this.game.randomFloat(0.35, 0.8)));
    subsystem.hp = Math.max(0, subsystem.hp - subsystemDamage);
    subsystem.disabled = subsystem.hp <= 0;
    subsystem.lastDamagedTurn = this.game?.turnNumber || 0;

    const result = {
      subsystem: id,
      label: subsystem.label || id,
      damage: subsystemDamage,
      hp: subsystem.hp,
      disabled: subsystem.disabled,
      damageType
    };

    this.emitStateChanged('ship_subsystem_damaged', result);
    if (!this.owner?.isAI) {
      this.notify(
        `${this.name}: ${result.label} ${result.disabled ? 'disabled' : `damaged to ${result.hp.toFixed(0)}%`}.`,
        result.disabled ? 'error' : 'warning'
      );
    }
    return result;
  },

  repairSubsystems(amount = Infinity) {
    let remaining = Number.isFinite(amount) ? Math.max(0, Number(amount)) : Infinity;
    let restored = 0;
    Object.values(this.subsystemState || {}).forEach(subsystem => {
      if (remaining <= 0) return;
      const needed = Math.max(0, Number(subsystem.maxHP || 100) - Number(subsystem.hp || 0));
      const repair = Math.min(needed, remaining);
      subsystem.hp += repair;
      subsystem.disabled = subsystem.hp <= 0;
      restored += repair;
      if (Number.isFinite(remaining)) remaining -= repair;
    });
    if (restored > 0) this.emitStateChanged('ship_subsystems_repaired', { restored });
    return restored;
  },

  resolveMissionReference(reference) {
    if (!reference) return null;
    if (typeof reference === 'object') return reference;
    const name = String(reference);
    return this.game?.bodies?.find(body => body.name === name)
      || this.game?.spaceshipManager?.spaceships?.find(ship => ship.name === name)
      || this.game?.players?.flatMap(player => player.colonies || []).find(colony => colony.name === name || colony.planet?.name === name)
      || null;
  },

  normalizeMissionOrder(order = {}) {
    const type = String(order.type || order.missionType || '').toLowerCase();
    return {
      id: order.id || `mission-${this.name}-${this.game?.turnNumber || 0}-${Math.floor((this.game?.random?.() ?? 0.5) * 1e7)}`,
      type,
      status: order.status || 'queued',
      targetName: order.targetName || order.target?.name || order.destination?.name || null,
      sourceName: order.sourceName || order.source?.name || null,
      target: order.target || null,
      source: order.source || null,
      buildingName: order.buildingName || order.building || null,
      resourceName: order.resourceName || order.resource || null,
      amount: Number(order.amount || 0),
      routeBodyNames: [...(order.routeBodyNames || order.patrolBodyNames || [])],
      coursePreference: order.coursePreference || 'balanced',
      repeat: !!order.repeat,
      contractId: order.contractId || null,
      createdTurn: Number(order.createdTurn ?? this.game?.turnNumber ?? 0),
      startedTurn: order.startedTurn ?? null,
      completedTurn: order.completedTurn ?? null,
      metadata: { ...(order.metadata || {}) }
    };
  },

  queueMissionOrder(order, { startImmediately = true, replace = false } = {}) {
    const normalized = this.normalizeMissionOrder(order);
    if (!normalized.type) return false;
    if (replace) {
      this.missionQueue = [];
      this.activeMissionOrder = null;
    }
    this.missionQueue = this.missionQueue || [];
    const queueCapacity = 5 + Math.max(0, Number(this.owner?.getResearchEffect?.('automationMissionSlots', 0) || 0));
    if (this.missionQueue.length >= queueCapacity) {
      this.notify(`Mission queue is full (${queueCapacity} orders). Research autonomous logistics to expand it.`, 'warning');
      return false;
    }
    this.missionQueue.push(normalized);
    this.emitStateChanged('ship_mission_queued', { missionOrder: normalized });

    if (startImmediately && !this.activeMissionOrder && !this.combat?.isInCombat) {
      this.dispatchNextMissionOrder();
    }
    return normalized;
  },

  setAutomationPolicy(patch = {}) {
    this.automationPolicy = {
      ...(this.automationPolicy || {}),
      ...(patch || {})
    };
    this.emitStateChanged('ship_automation_policy_changed', {
      automationPolicy: { ...this.automationPolicy }
    });
    return this.automationPolicy;
  },

  chooseMissionCourse(options = [], preference = 'balanced') {
    const viable = options.filter(option => option && this.canStartCourseOption(option));
    if (viable.length === 0) return null;
    if (preference === 'fastest') {
      return viable.reduce((best, option) => ((option.totalMissionTime || option.timeOfFlight) < (best.totalMissionTime || best.timeOfFlight) ? option : best));
    }
    if (preference === 'efficient') {
      return viable.reduce((best, option) => (option.totalDeltaV < best.totalDeltaV ? option : best));
    }

    const minDv = Math.min(...viable.map(option => option.totalDeltaV));
    const maxDv = Math.max(...viable.map(option => option.totalDeltaV));
    const minTime = Math.min(...viable.map(option => option.totalMissionTime || option.timeOfFlight));
    const maxTime = Math.max(...viable.map(option => option.totalMissionTime || option.timeOfFlight));
    return viable.reduce((best, option) => {
      const dvScore = (option.totalDeltaV - minDv) / Math.max(1, maxDv - minDv);
      const timeValue = option.totalMissionTime || option.timeOfFlight;
      const timeScore = (timeValue - minTime) / Math.max(1, maxTime - minTime);
      const score = (dvScore * 0.55) + (timeScore * 0.45);
      return !best || score < best.score ? { option, score } : best;
    }, null).option;
  },

  async dispatchNextMissionOrder() {
    if (this.isDestroyed() || this.combat?.isInCombat || this.activeMissionOrder) return false;
    const next = (this.missionQueue || []).shift();
    if (!next) return false;
    this.activeMissionOrder = next;
    next.status = 'active';
    next.startedTurn = this.game?.turnNumber || 0;
    return this.dispatchActiveMissionOrder();
  },

  async dispatchActiveMissionOrder() {
    const order = this.activeMissionOrder;
    if (!order) return false;

    const target = this.resolveMissionReference(order.target || order.targetName);
    const source = this.resolveMissionReference(order.source || order.sourceName);
    const coursePreference = order.coursePreference || 'balanced';

    if (order.type === 'deliver' || order.type === 'trade_route') {
      if (!source || !target || !order.resourceName || order.amount <= 0) {
        this.finishMissionOrder(false, 'Transport order is missing a source, destination, resource, or amount.');
        return false;
      }
      this.assignTransportTask({
        type: order.type === 'trade_route' ? 'internal' : (order.metadata?.transportType || 'internal'),
        source,
        destination: target,
        resourceName: order.resourceName,
        amount: order.amount,
        missionOrderId: order.id,
        coursePreference
      });
      return true;
    }

    const targetBody = target?.planet || target;
    if (!targetBody) {
      this.finishMissionOrder(false, 'Mission target could not be resolved.');
      return false;
    }

    if (this.currentOrbitingBody === targetBody && ['refuel', 'return_repair', 'patrol', 'defend'].includes(order.type)) {
      return this.handleMissionOrderArrival(targetBody);
    }

    let missionType = order.type;
    let maneuverType = 'rendezvous';
    if (order.type === 'survey') missionType = 'prospect';
    if (order.type === 'colonize') {
      missionType = 'build';
      this.assignedBuildingName = order.buildingName || 'Habitat';
    }
    if (order.type === 'build') this.assignedBuildingName = order.buildingName;
    if (['escort', 'intercept'].includes(order.type) && !this.isCelestialTarget(targetBody)) maneuverType = 'intercept';
    this.currentMission = missionType;

    try {
      const options = await this.plotInterceptByDeltaV(targetBody, maneuverType, {
        strategy: coursePreference === 'efficient' ? 'deltaV' : 'time',
        minDays: Number(order.metadata?.minDays || 8),
        maxDays: Number(order.metadata?.maxDays || 300),
        missionType,
        allowGravityAssist: order.metadata?.allowGravityAssist !== false
      });
      const selected = this.chooseMissionCourse(options || [], coursePreference);
      if (!selected) {
        this.finishMissionOrder(false, 'No affordable course could be found.');
        this.clearNavigation({ refundEscrow: order.type === 'build' || order.type === 'colonize' });
        return false;
      }
      this.executeCourseOption(selected, order.contractId);
      this.emitStateChanged('ship_mission_started', { missionOrder: order, courseOption: selected });
      return true;
    } catch (error) {
      this.finishMissionOrder(false, error.message || 'Course calculation failed.');
      return false;
    }
  },

  finishMissionOrder(success = true, detail = '', options = {}) {
    const order = this.activeMissionOrder;
    if (!order) return null;
    order.status = success ? 'completed' : 'failed';
    order.completedTurn = this.game?.turnNumber || 0;
    order.detail = detail;
    this.missionHistory = this.missionHistory || [];
    this.missionHistory.push({ ...order, target: undefined, source: undefined });
    if (this.missionHistory.length > 50) this.missionHistory.shift();
    this.activeMissionOrder = null;

    this.emitStateChanged(success ? 'ship_mission_completed' : 'ship_mission_failed', {
      missionOrder: order,
      detail
    });

    if (order.repeat && success) {
      this.missionQueue.push(this.normalizeMissionOrder({ ...order, id: null, status: 'queued', completedTurn: null, startedTurn: null }));
    }

    if (options.dispatchNext !== false) {
      setTimeout(() => this.dispatchNextMissionOrder(), 0);
    }
    return order;
  },

  handleMissionOrderArrival(destination) {
    const order = this.activeMissionOrder;
    if (!order) return false;

    const colony = this.owner?.colonies?.find(entry => entry.planet === destination) || null;

    if (order.type === 'refuel') {
      const success = colony ? this.refuel(colony) : false;
      this.finishMissionOrder(success, success ? `Refueled at ${destination.name}.` : `No friendly fuel source at ${destination.name}.`, { dispatchNext: false });
      this.clearNavigation({ refundEscrow: false });
      this.dispatchNextMissionOrder();
      return true;
    }

    if (order.type === 'return_repair') {
      const success = colony ? this.repair(colony) : false;
      this.finishMissionOrder(success, success ? `Repaired at ${destination.name}.` : `No repair-capable friendly colony at ${destination.name}.`, { dispatchNext: false });
      this.clearNavigation({ refundEscrow: false });
      this.dispatchNextMissionOrder();
      return true;
    }

    if (['patrol', 'defend'].includes(order.type)) {
      const route = order.routeBodyNames.length > 0 ? order.routeBodyNames : [order.targetName || destination.name];
      order.metadata.visited = [...(order.metadata.visited || []), destination.name];
      const currentIndex = Math.max(0, route.indexOf(destination.name));
      const nextIndex = currentIndex + 1;

      if (nextIndex < route.length || order.repeat || this.automationPolicy?.loopPatrol) {
        const nextName = route[nextIndex < route.length ? nextIndex : 0];
        order.targetName = nextName;
        order.target = null;
        this.clearNavigation({ refundEscrow: false, preserveMissionOrder: true });
        setTimeout(() => this.dispatchActiveMissionOrder(), 0);
      } else {
        this.finishMissionOrder(true, `Patrol completed at ${destination.name}.`, { dispatchNext: false });
        this.clearNavigation({ refundEscrow: false });
        this.dispatchNextMissionOrder();
      }
      return true;
    }

    if (['escort', 'intercept', 'refuel_fleet'].includes(order.type)) {
      this.finishMissionOrder(true, `${order.type} rendezvous completed with ${destination.name}.`, { dispatchNext: false });
      this.clearNavigation({ refundEscrow: false });
      this.dispatchNextMissionOrder();
      return true;
    }

    return false;
  },

  initializePowerSystems() {
    const defaultMode = String(this.type || '').toLowerCase() === 'explorer'
      ? 'sensor_focus'
      : String(this.type || '').toLowerCase() === 'warship'
        ? 'combat'
        : 'balanced';

    this.powerState = {
      mode: defaultMode,
      lastComputedTurn: -1
    };
  },

  getPowerModeDefinitions() {
    return {
      transit: {
        label: 'Transit',
        description: 'Maximum reactor share to the main drive. Point defense is cold and advanced sensors are throttled back.',
        priorityOrder: ['mainDrive', 'advancedSensors', 'pointDefense', 'weapons', 'mining'],
        allocations: {
          mainDrive: 1,
          advancedSensors: 0.42,
          pointDefense: 0,
          weapons: 0,
          mining: 0
        }
      },
      balanced: {
        label: 'Balanced',
        description: 'A safe cruise state with moderate drive output and enough reserve for basic combat housekeeping.',
        priorityOrder: ['mainDrive', 'pointDefense', 'advancedSensors', 'weapons', 'mining'],
        allocations: {
          mainDrive: 0.72,
          advancedSensors: 0.46,
          pointDefense: 0.42,
          weapons: 0.18,
          mining: 0.28
        }
      },
      combat: {
        label: 'Combat',
        description: 'Point defense and weapons are prioritized. The main drive is heavily throttled and survey sensors fall back to passive mode.',
        priorityOrder: ['pointDefense', 'weapons', 'mainDrive', 'advancedSensors', 'mining'],
        allocations: {
          mainDrive: 0.38,
          advancedSensors: 0.2,
          pointDefense: 1,
          weapons: 1,
          mining: 0
        }
      },
      sensor_focus: {
        label: 'Sensor Focus',
        description: 'Boost long-range survey arrays and intercept computation at the expense of drive thrust and close-in defenses.',
        priorityOrder: ['advancedSensors', 'mainDrive', 'pointDefense', 'weapons', 'mining'],
        allocations: {
          mainDrive: 0.36,
          advancedSensors: 1,
          pointDefense: 0.1,
          weapons: 0.1,
          mining: 0.32
        }
      }
    };
  },

  getAvailablePowerModes() {
    const definitions = this.getPowerModeDefinitions();
    return Object.keys(definitions).map((key) => ({
      id: key,
      ...(definitions[key] || {})
    }));
  },

  getPowerMode() {
    const requestedMode = this.powerState?.mode;
    return this.getPowerModeDefinitions()[requestedMode] ? requestedMode : 'balanced';
  },

  setPowerMode(nextMode) {
    const normalizedMode = String(nextMode || '').trim().toLowerCase();
    const definitions = this.getPowerModeDefinitions();

    if (!definitions[normalizedMode]) {
      return false;
    }

    if (!this.powerState) {
      this.initializePowerSystems();
    }

    this.powerState.mode = normalizedMode;
    this.updatePowerMetadata?.();

    const snapshot = this.getPowerBudgetSnapshot();
    const modeLabel = definitions[normalizedMode]?.label || normalizedMode;

    this.notify(
      `${this.name} switched to ${modeLabel} power stance. Reactor ${snapshot.reactorOutput.toFixed(1)} / demand ${snapshot.totalDemand.toFixed(1)}.`,
      'info',
      false,
      { powerSnapshot: snapshot }
    );

    this.emitStateChanged('ship_power_mode_changed', {
      powerMode: normalizedMode,
      powerSnapshot: snapshot
    });

    return true;
  },

  getReactorOutput() {
    const engine = this.components?.engine || this.engine || {};
    const explicitOutput = Number(engine.reactorOutput || engine.powerOutput || this.components?.reactor?.output || 0);

    if (explicitOutput > 0) {
      return Number(explicitOutput.toFixed(1));
    }

    const thrust = Math.max(0, Number(engine.thrust || 0));
    const engineType = String(engine.type || 'chemical').toLowerCase();

    let baseOutput = 8.8;
    if (engineType.includes('fusion')) {
      baseOutput = 12.4;
    } else if (engineType.includes('nuclear')) {
      baseOutput = 11.2;
    } else if (engineType.includes('ion')) {
      baseOutput = 10.1;
    }

    const thrustBonus = Math.min(4.5, thrust / 140);
    const reactorFactor = this.getSubsystemEffectiveness?.('reactor') ?? 1;
    return Number(((baseOutput + thrustBonus) * reactorFactor).toFixed(1));
  },

  getSystemPowerProfile() {
    const thrust = Math.max(0, Number(this.engine?.thrust || this.components?.engine?.thrust || 0));
    const hasAdvancedSensors = this.hasAdvancedSensors();
    const hasPds = !!(this.components?.pds || this.pds);
    const hasWeapons = this.isArmed();
    const hasMining = this.hasMiningCapability();

    return {
      baseline: 0.9,
      lifeSupport: this.quarters ? 0.9 : 0.45,
      mainDrive: Number((4.8 + Math.min(3.3, thrust / 95)).toFixed(1)),
      advancedSensors: hasAdvancedSensors ? 4.2 : 1.5,
      pointDefense: hasPds ? Number((2.7 + Math.min(1.4, Number(this.components?.pds?.trackingPower || this.pds?.trackingPower || 0) * 1.8)).toFixed(1)) : 0,
      weapons: hasWeapons ? Number((1.6 + (this.weapons.length * 0.45)).toFixed(1)) : 0,
      mining: hasMining ? Number((1.8 + Math.min(1.2, Number(this.components?.mining?.extractionRatePerDay || this.components?.mining?.extractionRate || 0) / 18)).toFixed(1)) : 0
    };
  },

  getPowerBudgetSnapshot() {
    const definitions = this.getPowerModeDefinitions();
    const mode = this.getPowerMode();
    const modeDef = definitions[mode];
    const profile = this.getSystemPowerProfile();
    const reactorOutput = this.getReactorOutput();

    const allocations = modeDef?.allocations || {};
    const priorityOrder = Array.isArray(modeDef?.priorityOrder) ? modeDef.priorityOrder : [];

    const subsystemDemand = {};
    const subsystemDelivered = {};
    let totalDemand = Number((profile.baseline + profile.lifeSupport).toFixed(1));
    let powerUsed = profile.baseline + profile.lifeSupport;

    priorityOrder.forEach((subsystem) => {
      const baseLoad = Number(profile[subsystem] || 0);
      const allocation = Number(allocations[subsystem] || 0);
      const desiredLoad = Number((baseLoad * allocation).toFixed(2));
      subsystemDemand[subsystem] = desiredLoad;
      totalDemand += desiredLoad;
    });

    priorityOrder.forEach((subsystem) => {
      const desiredLoad = Number(subsystemDemand[subsystem] || 0);
      if (desiredLoad <= 0) {
        subsystemDelivered[subsystem] = 0;
        return;
      }

      const availablePower = Math.max(0, reactorOutput - powerUsed);
      const delivered = Math.min(desiredLoad, availablePower);
      subsystemDelivered[subsystem] = Number(delivered.toFixed(2));
      powerUsed += delivered;
    });

    const mainDriveNominal = Number(profile.mainDrive || 0);
    const sensorNominal = Number(profile.advancedSensors || 0);
    const pdsNominal = Number(profile.pointDefense || 0);
    const weaponsNominal = Number(profile.weapons || 0);
    const miningNominal = Number(profile.mining || 0);

    const drivePowerFactor = mainDriveNominal > 0
      ? clamp(Number(subsystemDelivered.mainDrive || 0) / mainDriveNominal, 0, 1)
      : 0;

    const sensorPowerFactor = sensorNominal > 0
      ? clamp(Number(subsystemDelivered.advancedSensors || 0) / sensorNominal, 0, 1)
      : 0;

    const pdsPowerFactor = pdsNominal > 0
      ? clamp(Number(subsystemDelivered.pointDefense || 0) / pdsNominal, 0, 1)
      : 0;

    const weaponsPowerFactor = weaponsNominal > 0
      ? clamp(Number(subsystemDelivered.weapons || 0) / weaponsNominal, 0, 1)
      : 0;

    const miningPowerFactor = miningNominal > 0
      ? clamp(Number(subsystemDelivered.mining || 0) / miningNominal, 0, 1)
      : 0;

    return {
      mode,
      modeLabel: modeDef?.label || mode,
      reactorOutput,
      totalDemand: Number(totalDemand.toFixed(1)),
      usedPower: Number(powerUsed.toFixed(1)),
      margin: Number((reactorOutput - powerUsed).toFixed(1)),
      baselineLoad: Number((profile.baseline + profile.lifeSupport).toFixed(1)),
      subsystemDemand,
      subsystemDelivered,
      drivePowerFactor,
      sensorPowerFactor,
      pdsPowerFactor,
      weaponsPowerFactor,
      miningPowerFactor,
      isMainDrivePowered: drivePowerFactor >= 0.55,
      isAdvancedSensorsPowered: this.hasAdvancedSensors() && sensorPowerFactor >= 0.8,
      isPointDefensePowered: !!(this.components?.pds || this.pds) && pdsPowerFactor >= 0.72,
      isWeaponsPowered: this.isArmed() && weaponsPowerFactor >= 0.58,
      isMiningPowered: this.hasMiningCapability() && miningPowerFactor >= 0.68
    };
  },

  getDrivePowerFactor() {
    const snapshot = this.getPowerBudgetSnapshot();
    if (!snapshot.isMainDrivePowered) {
      return 0.3;
    }
    return clamp(snapshot.drivePowerFactor, 0.3, 1);
  },

  isAdvancedSensorsPowered() {
    return !!this.getPowerBudgetSnapshot().isAdvancedSensorsPowered;
  },

  isPointDefenseActive() {
    return !!this.getPowerBudgetSnapshot().isPointDefensePowered;
  },

  isMiningRigPowered() {
    return !!this.getPowerBudgetSnapshot().isMiningPowered;
  },

  getPointDefenseMitigation(damageType = '') {
    if (!this.combat?.isInCombat || !this.isPointDefenseActive()) {
      return 0;
    }

    const trackingPower = Number(this.components?.pds?.trackingPower || this.pds?.trackingPower || 0.2);
    const normalizedType = String(damageType || '').toLowerCase();
    const isInterceptable = !normalizedType || /missile|projectile|kinetic|rail|shell|drone/i.test(normalizedType);

    if (!isInterceptable) {
      return Math.min(0.12, 0.04 + (trackingPower * 0.08));
    }

    return Math.min(0.26, 0.08 + (trackingPower * 0.18));
  },

  updatePowerMetadata() {
    if (!this.mesh?.metadata) {
      return;
    }

    const snapshot = this.getPowerBudgetSnapshot();
    this.mesh.metadata.powerSummary = {
      mode: snapshot.mode,
      reactorOutput: snapshot.reactorOutput,
      totalDemand: snapshot.totalDemand,
      usedPower: snapshot.usedPower,
      margin: snapshot.margin,
      drivePowerFactor: snapshot.drivePowerFactor,
      sensorPowerFactor: snapshot.sensorPowerFactor,
      pdsPowerFactor: snapshot.pdsPowerFactor
    };
  },

  getMiningComponent() {
    return this.components?.mining || null;
  },

  hasMiningCapability() {
    return !!this.getMiningComponent();
  },

  hasAdvancedSensors() {
    const sensor = this.components?.sensor || this.sensor || {};
    const requiredResearch = Array.isArray(sensor.requiredResearch)
      ? sensor.requiredResearch
      : sensor.requiredResearch ? [sensor.requiredResearch] : [];
    const sensorText = [sensor.name, sensor.type, ...requiredResearch]
      .filter(Boolean)
      .join(' ')
      .toLowerCase();

    return (
      sensorText.includes('advanced') ||
      sensorText.includes('gravimetric') ||
      sensorText.includes('survey') ||
      sensorText.includes('prospecting') ||
      requiredResearch.includes('advanced_sensors') ||
      Number(sensor.detectionRange || 0) >= 150000000 ||
      Number(sensor.trackingResolution || 0) >= 0.62
    );
  },

  hasProspectingCapability() {
    return (
      this.hasAdvancedSensors() ||
      String(this.type || '').toLowerCase() === 'explorer' ||
      /pathfinder|scout|survey/i.test(`${this.name || ''} ${this.class || ''}`)
    );
  },

  getProspectingStrength() {
    const sensor = this.components?.sensor || this.sensor || {};
    const powerFactor = this.isAdvancedSensorsPowered() ? 1 : Math.max(0.2, this.getPowerBudgetSnapshot().sensorPowerFactor);
    const detectionScore = Math.min(1.3, Number(sensor.detectionRange || 0) / 180000000) * powerFactor;
    const trackingScore = Math.min(1.2, Number(sensor.trackingResolution || 0) / 0.8) * powerFactor;
    const explorerBonus = String(this.type || '').toLowerCase() === 'explorer' ? 0.18 : 0;
    const classBonus = /pathfinder|scout|survey/i.test(`${this.name || ''} ${this.class || ''}`) ? 0.14 : 0;
    const advancedBonus = this.isAdvancedSensorsPowered() ? 0.28 : 0;
    return Number((1 + detectionScore * 0.18 + trackingScore * 0.14 + explorerBonus + classBonus + advancedBonus).toFixed(3));
  },

  performProspectingScan(targetBody = this.currentOrbitingBody, options = {}) {
    if (!this.game?.performProspectingScan || !targetBody || !this.hasProspectingCapability()) {
      return null;
    }

    if (!this.isAdvancedSensorsPowered()) {
      this.notify(
        `${this.name} cannot characterize ${targetBody.name} in ${this.getPowerBudgetSnapshot().modeLabel}. Switch to Sensor Focus to energize the advanced sensor suite.`,
        'warning'
      );
      return {
        success: false,
        reason: 'power_mode_blocks_sensors',
        targetBody
      };
    }

    return this.game.performProspectingScan({
      ship: this,
      targetBody,
      ...options
    });
  },

  isMineableBody(targetBody = this.currentOrbitingBody) {
    if (!targetBody) return false;
    const bodyType = String(targetBody.type || '').toLowerCase();
    return bodyType === 'asteroid' || bodyType === 'moon';
  },

  getMiningOutputProfile(targetBody = this.currentOrbitingBody) {
    if (!this.isMineableBody(targetBody)) {
      return null;
    }

    const tags = Array.isArray(targetBody?.resourceTags)
      ? targetBody.resourceTags.map((tag) => String(tag).toLowerCase())
      : [];
    const bodyName = String(targetBody?.name || '').toLowerCase();

    const hasWater =
      tags.includes('water') ||
      /ice|europa|enceladus|ceres|x-19/.test(bodyName);

    const hasMinerals =
      tags.includes('industry') ||
      tags.includes('construction') ||
      tags.includes('shipbuilding') ||
      tags.includes('minerals') ||
      String(targetBody?.type || '').toLowerCase() === 'asteroid';

    if (hasWater && hasMinerals) {
      return [
        { resourceName: 'Water', share: 0.55 },
        { resourceName: 'Minerals', share: 0.45 }
      ];
    }

    if (hasWater) {
      return [{ resourceName: 'Water', share: 1 }];
    }

    if (hasMinerals) {
      return [{ resourceName: 'Minerals', share: 1 }];
    }

    return [{
      resourceName: String(targetBody?.type || '').toLowerCase() === 'moon' ? 'Water' : 'Minerals',
      share: 1
    }];
  },

  getMiningRatePerDay(targetBody = this.currentOrbitingBody) {
    const miningComponent = this.getMiningComponent();
    if (!miningComponent || !this.isMineableBody(targetBody)) return 0;

    const baseRate = Number(
      miningComponent.extractionRatePerDay ??
      miningComponent.yieldPerDay ??
      miningComponent.ratePerDay ??
      miningComponent.miningRate ??
      miningComponent.extractionRate ??
      8
    );

    const efficiency = Math.max(0.25, Number(miningComponent.efficiency ?? 1));
    const strategicValue = Math.max(0.5, Number(targetBody?.strategicValue || 1));
    const tags = Array.isArray(targetBody?.resourceTags)
      ? targetBody.resourceTags.map((tag) => String(tag).toLowerCase())
      : [];

    let richnessModifier = 1 + Math.min(0.65, Math.max(0, strategicValue - 1) * 0.12);

    if (tags.includes('water') || tags.includes('industry') || tags.includes('construction')) {
      richnessModifier += 0.15;
    }

    return baseRate * efficiency * richnessModifier;
  },

  extractResource(targetBody = this.currentOrbitingBody, days = this.game?.daysPerTurn || 1) {
    if (!this.hasMiningCapability()) return null;
    if (!targetBody || this.currentOrbitingBody !== targetBody) return null;
    if (!this.isMineableBody(targetBody)) return null;

    const player = this.owner;
    const intel = this.game?.getProspectingIntel?.(targetBody, player);

    if (!intel) {
      if (this.hasProspectingCapability()) {
        this.performProspectingScan(targetBody);
      }

      if (this.lastProspectingWarningTurn !== this.game?.turnNumber) {
        this.lastProspectingWarningTurn = this.game?.turnNumber;
        this.notify(`${this.name} cannot mine ${targetBody.name} yet. Characterize the site first to reveal yield, hazards, and route safety.`, 'warning');
      }

      return {
        success: false,
        targetBody,
        extracted: {},
        reason: 'uncharacterized_site'
      };
    }

    if (!this.isMiningRigPowered()) {
      this.notify(`${this.name} is not allocating enough reactor output to the mining rig. Switch out of Combat or Transit stance to resume extraction.`, 'warning');
      return {
        success: false,
        targetBody,
        extracted: {},
        reason: 'insufficient_mining_power'
      };
    }

    const miningProfile = this.getMiningOutputProfile(targetBody);
    const baseRatePerDay = this.getMiningRatePerDay(targetBody);
    const freshMultiplier = this.game?.getFreshCharacterizationMultiplier?.(intel) || 1;
    const disruptionModifier = this.game?.getMiningDisruptionModifierForBody?.(targetBody) || 1;
    const hazardPenalty = Math.max(0.62, 1 - (Number(intel.hazardRating || 0) * 0.28));
    const powerFactor = clamp(this.getPowerBudgetSnapshot().miningPowerFactor, 0.55, 1);

    const totalExtraction = baseRatePerDay
      * Number(intel.estimatedYieldModifier || 1)
      * freshMultiplier
      * disruptionModifier
      * hazardPenalty
      * powerFactor
      * Math.max(0, Number(days || 0));

    if (!miningProfile || totalExtraction <= 0) {
      return null;
    }

    const extracted = {};
    let extractedTotal = 0;
    let overflowTotal = 0;

    miningProfile.forEach((entry) => {
      const amount = totalExtraction * Number(entry.share || 0);
      if (amount <= 0) return;

      const overflow = this.addResource(entry.resourceName, amount);
      const loadedAmount = amount - overflow;

      if (loadedAmount > 0) {
        extracted[entry.resourceName] = (extracted[entry.resourceName] || 0) + loadedAmount;
        extractedTotal += loadedAmount;
      }

      overflowTotal += overflow;
    });

    if (this.game.randomChance(Math.min(0.22, Number(intel.hazardRating || 0) * 0.25))) {
      const damage = Math.max(0, Math.round(Number(intel.hazardRating || 0) * 6));
      if (damage > 0 && !this.isDestroyed()) {
        this.hullHP = Math.max(1, this.hullHP - damage);
        this.notify(`${this.name} took ${damage} incidental hull damage while working the hazardous ${targetBody.name} site.`, 'warning');
      }
    }

    if (extractedTotal <= 0) {
      if (!this.owner?.isAI) {
        this.notify(`${this.name} could not extract more from ${targetBody.name}; cargo holds are full.`, 'warning');
      }
      return {
        success: false,
        targetBody,
        extracted,
        overflowTotal,
        reason: 'cargo_full'
      };
    }

    const resourceSummary = Object.entries(extracted)
      .map(([resourceName, amount]) => `${amount.toFixed(1)} ${resourceName}`)
      .join(', ');

    if (!this.owner?.isAI) {
      const bonusText = freshMultiplier > 1
        ? ` Fresh site bonus +${Math.round((freshMultiplier - 1) * 100)}%.`
        : '';
      this.notify(`${this.name} extracted ${resourceSummary} from ${targetBody.name}.${bonusText}`, 'success');
    }

    this.emitStateChanged('ship_resources_extracted', {
      targetBody,
      extracted,
      totalExtracted: extractedTotal,
      overflowTotal,
      prospectingIntel: intel,
      freshMultiplier,
      disruptionModifier,
      hazardPenalty,
      powerFactor
    });

    this.game?.eventEmitter?.emit?.('shipResourceExtracted', {
      ship: this,
      targetBody,
      extracted,
      totalExtracted: extractedTotal,
      overflowTotal,
      prospectingIntel: intel,
      freshMultiplier,
      disruptionModifier,
      hazardPenalty,
      powerFactor
    });

    return {
      success: true,
      targetBody,
      extracted,
      totalExtracted: extractedTotal,
      overflowTotal,
      prospectingIntel: intel,
      freshMultiplier,
      disruptionModifier,
      hazardPenalty,
      powerFactor
    };
  },

  getExplorationRewardProfile(targetBody) {
    if (!targetBody || targetBody._explorationRewardResolved) {
      return null;
    }

    const tags = Array.isArray(targetBody?.resourceTags)
      ? targetBody.resourceTags.map((tag) => String(tag).toLowerCase())
      : [];
    const bodyType = String(targetBody?.type || '').toLowerCase();
    const bodyName = String(targetBody?.name || '').toLowerCase();
    const strategicValue = Math.max(1, Number(targetBody?.strategicValue || 1));

    const waterBias =
      tags.includes('water') ||
      /ice|europa|enceladus|ceres|x-19/.test(bodyName);

    const mineralBias =
      bodyType === 'asteroid' ||
      tags.includes('industry') ||
      tags.includes('construction') ||
      tags.includes('shipbuilding');

    const guaranteedDiscovery = bodyName.includes('x-19');
    const discoveryChance =
      guaranteedDiscovery ? 1
        : bodyType === 'asteroid' || bodyType === 'moon' ? 0.7
          : 0.42;

    if (!this.game.randomChance(discoveryChance)) {
      return null;
    }

    if (waterBias && (!mineralBias || this.game.randomChance(0.62))) {
      const amount = Math.round(30 + (strategicValue * 22) + (this.game.random() * 35));
      return {
        type: 'resource',
        rewardKind: 'anomaly',
        resourceName: 'Water',
        amount,
        message: bodyName.includes('x-19')
          ? `Your sensors detected an easily accessible subterranean ice lake on ${targetBody.name}!`
          : `Your survey team found an unusually accessible water deposit on ${targetBody.name}!`
      };
    }

    if (mineralBias) {
      const amount = Math.round(24 + (strategicValue * 18) + (this.game.random() * 32));
      return {
        type: 'resource',
        rewardKind: 'rich_deposit',
        resourceName: 'Minerals',
        amount,
        message: `Your survey team mapped a rich surface deposit on ${targetBody.name}!`
      };
    }

    const strategicBoost = Number((0.35 + (strategicValue * 0.12) + (this.game.random() * 0.28)).toFixed(2));
    return {
      type: 'strategic',
      rewardKind: 'anomaly',
      strategicBoost,
      message: `Long-range scans reveal a valuable anomaly on ${targetBody.name}, improving its long-term strategic outlook.`
    };
  },

  applyExplorationReward(targetBody) {
    const reward = this.getExplorationRewardProfile(targetBody);
    if (!reward) return null;

    targetBody._explorationRewardResolved = true;
    targetBody._explorationRewardType = reward.rewardKind;

    if (reward.type === 'resource') {
      const overflow = this.addResource(reward.resourceName, reward.amount);
      const loadedAmount = reward.amount - overflow;

      const finalReward = {
        ...reward,
        amount: loadedAmount,
        overflow
      };

      if (loadedAmount > 0) {
        this.notify(
          `${reward.message} ${loadedAmount.toFixed(0)} ${reward.resourceName} loaded aboard ${this.name}.`,
          'success',
          true
        );
      } else {
        this.notify(
          `${reward.message} Cargo space on ${this.name} was full, so nothing could be recovered.`,
          'warning',
          true
        );
      }

      this.emitStateChanged('body_anomaly_discovered', {
        body: targetBody,
        reward: finalReward,
        explorer: this
      });

      this.game?.eventEmitter?.emit?.('bodyAnomalyDiscovered', {
        body: targetBody,
        reward: finalReward,
        ship: this
      });

      return finalReward;
    }

    targetBody.strategicValue = Number((Number(targetBody.strategicValue || 1) + reward.strategicBoost).toFixed(2));

    this.notify(
      `${reward.message} Strategic value is now ${targetBody.strategicValue.toFixed(2)}.`,
      'success',
      true
    );

    this.emitStateChanged('body_anomaly_discovered', {
      body: targetBody,
      reward,
      explorer: this
    });

    this.game?.eventEmitter?.emit?.('bodyAnomalyDiscovered', {
      body: targetBody,
      reward,
      ship: this
    });

    return reward;
  },

  notify(message, level = 'info', persist = false, meta = {}) {
    this.game?.notify?.(message, level, persist, {
      ship: this,
      shipName: this.name,
      owner: this.owner,
      ...meta
    });
  },

  emitStateChanged(type, payload = {}) {
    this.game?.emitStateChanged?.(type, {
      ship: this,
      shipName: this.name,
      owner: this.owner,
      status: this.status,
      currentFuel: this.currentFuel,
      hullHP: this.hullHP,
      armorHP: this.armorHP,
      target: this.target,
      currentMission: this.currentMission,
      escrowCredits: this.getEscrowCredits(),
      escrowPurpose: this.escrowPurpose,
      powerMode: this.getPowerMode?.(),
      powerSnapshot: this.getPowerBudgetSnapshot?.(),
      ...payload
    });
  },

  getEscrowCredits() {
    return Math.max(0, Number(this.escrowCredits || 0));
  },

  allocateEscrowCredits(amount, purpose = null) {
    const escrowAmount = Math.max(0, Number(amount || 0));

    if (escrowAmount <= 0) {
      this.escrowCredits = 0;
      this.escrowPurpose = null;
      this.emitStateChanged('ship_escrow_funded', {
        amount: 0,
        escrowCredits: 0,
        escrowPurpose: null
      });
      return { success: true, amount: 0 };
    }

    if (!this.owner || this.owner.credits < escrowAmount) {
      return {
        success: false,
        amount: escrowAmount
      };
    }

    if (this.getEscrowCredits() > 0) {
      this.refundEscrowCredits('escrow_reallocated');
    }

    this.owner.credits -= escrowAmount;
    this.escrowCredits = escrowAmount;
    this.escrowPurpose = purpose ? { ...purpose } : null;

    this.emitStateChanged('ship_escrow_funded', {
      amount: escrowAmount,
      escrowCredits: this.escrowCredits,
      escrowPurpose: this.escrowPurpose
    });

    return {
      success: true,
      amount: escrowAmount
    };
  },

  spendEscrowCredits(amount) {
    const spendTarget = Math.max(0, Number(amount || 0));
    if (spendTarget <= 0) return 0;

    const available = this.getEscrowCredits();
    const spent = Math.min(available, spendTarget);

    if (spent <= 0) return 0;

    this.escrowCredits = Math.max(0, available - spent);
    if (this.escrowCredits <= 0.0001) {
      this.escrowCredits = 0;
      this.escrowPurpose = null;
    }

    this.emitStateChanged('ship_escrow_spent', {
      amount: spent,
      escrowCredits: this.escrowCredits,
      escrowPurpose: this.escrowPurpose
    });

    return spent;
  },

  refundEscrowCredits(reason = 'mission_aborted') {
    const refundable = this.getEscrowCredits();

    if (refundable <= 0) {
      this.escrowCredits = 0;
      this.escrowPurpose = null;
      return 0;
    }

    if (this.owner) {
      this.owner.credits += refundable;
    }

    const previousPurpose = this.escrowPurpose ? { ...this.escrowPurpose } : null;

    this.escrowCredits = 0;
    this.escrowPurpose = null;

    this.emitStateChanged('ship_escrow_refunded', {
      amount: refundable,
      reason,
      escrowCredits: 0,
      escrowPurpose: previousPurpose
    });

    return refundable;
  },

  enterCombat() {
    if (!this.combat.isInCombat) {
      this.preCombatStatus = this.status;
    }

    this.combat.isInCombat = true;
    this.combat.isRetreating = false;
    this.status = 'in combat';

    this.emitStateChanged('ship_combat_state_changed', {
      isInCombat: true,
      isRetreating: false,
      previousStatus: this.preCombatStatus
    });
  },

  exitCombat() {
    this.combat.isInCombat = false;
    this.combat.isEvading = false;
    this.combat.isRetreating = false;

    if (this.isDestroyed()) return;

    if (this.target && this.currentTrajectoryPositions && this.timeSinceDeparture < this.timeToArrival) {
      this.status = 'transiting';
    } else {
      this.status = (this.preCombatStatus && this.preCombatStatus !== 'in combat')
        ? this.preCombatStatus
        : 'idle';
    }

    this.preCombatStatus = null;

    this.emitStateChanged('ship_combat_state_changed', {
      isInCombat: false,
      isEvading: false,
      isRetreating: false
    });
  },

  takeDamage(damage, type) {
    if (this.isDestroyed()) return 0;

    const mitigation = this.getPointDefenseMitigation(type);
    const researchResistance = Math.max(0, Math.min(0.35, Number(this.owner?.getResearchEffect?.('damageResistance', 0) || 0)));
    const adjustedDamage = Math.max(0, damage * (1 - mitigation) * (1 - researchResistance));

    let damageToArmor = adjustedDamage;
    let damageToHull = 0;

    if (this.armorHP > 0) {
      const absorbedDamage = Math.min(this.armorHP, damageToArmor);
      this.armorHP -= absorbedDamage;
      damageToArmor -= absorbedDamage;
    }

    damageToHull = damageToArmor;
    this.hullHP -= damageToHull;
    const subsystemDamage = damageToHull > 0 ? this.applySubsystemDamage?.(damageToHull, type) : null;

    this.game?.vfxHandler?.createExplosion?.(this.mesh.position.scale(1 / DISTANCE_SCALE));

    if (this.isDestroyed()) {
      this.hullHP = 0;
      this.status = 'destroyed';
      this.refundEscrowCredits('ship_destroyed');
      this.notify(`${this.name} has been destroyed!`, 'error', true);
      this.game?.historyManager?.addEntry?.(`${this.name} was destroyed in combat.`, 'error', this.game?.inGameDay || 0);
      this.emitStateChanged('ship_destroyed', {
        damage: adjustedDamage,
        damageType: type,
        damageToHull,
        pointDefenseMitigation: mitigation,
        subsystemDamage
      });
      this.game?.spaceshipManager?.removeSpaceship?.(this);
      return damageToHull;
    }

    this.emitStateChanged('ship_damaged', {
      damage: adjustedDamage,
      damageType: type,
      damageToHull,
      pointDefenseMitigation: mitigation,
      subsystemDamage
    });

    return damageToHull;
  },

  refuel(sourceColony) {
    if (!sourceColony || !this.currentOrbitingBody || this.currentOrbitingBody.name !== sourceColony.planet.name) {
      this.notify('Must be orbiting a friendly colony to refuel.', 'error');
      return false;
    }

    if (this.owner !== sourceColony.owner) {
      this.notify('Cannot refuel at a non-allied colony.', 'error');
      return false;
    }

    const fuelNeeded = this.fuelCapacity - this.currentFuel;
    if (fuelNeeded <= 0) {
      this.notify('Fuel tank is already full.', 'info');
      return true;
    }

    const fuelAvailable = sourceColony.getResourceAmount('Fuel');
    const amountToRefuel = Math.min(fuelNeeded, fuelAvailable);

    if (amountToRefuel <= 0) {
      this.notify(`Colony on ${sourceColony.planet.name} has no Fuel.`, 'warning');
      return false;
    }

    if (sourceColony.removeResource('Fuel', amountToRefuel)) {
      this.currentFuel += amountToRefuel;

      this.notify(`Refueled ${amountToRefuel.toFixed(1)} units of Fuel.`, 'success');
      this.emitStateChanged('ship_refueled', {
        sourceColony,
        amount: amountToRefuel
      });

      return true;
    }

    return false;
  },

  repair(sourceColony) {
    if (!sourceColony || !this.currentOrbitingBody || this.currentOrbitingBody.name !== sourceColony.planet.name) {
      this.notify('Must be orbiting a friendly colony to repair.', 'error');
      return false;
    }

    if (this.owner !== sourceColony.owner) {
      this.notify('Cannot repair at a non-allied colony.', 'error');
      return false;
    }

    const hasShipyard = sourceColony.buildings.some((building) => building.type === 'shipyard');
    if (!hasShipyard) {
      this.notify(`The colony on ${sourceColony.planet.name} must have a Shipyard to perform repairs.`, 'error');
      return false;
    }

    const hullDamage = this.maxHullHP - this.hullHP;
    const armorDamage = this.maxArmorHP - this.armorHP;
    const totalDamage = hullDamage + armorDamage;

    if (totalDamage <= 0) {
      this.notify('Ship is already at full health.', 'info');
      return true;
    }

    const mineralsCostPerHP = 0.5;
    const goodsCostPerHP = 0.2;
    const creditsCostPerHP = 10;

    const totalMineralsNeeded = totalDamage * mineralsCostPerHP;
    const totalGoodsNeeded = totalDamage * goodsCostPerHP;
    const totalCreditsNeeded = totalDamage * creditsCostPerHP;

    if (
      sourceColony.getResourceAmount('Minerals') < totalMineralsNeeded ||
      sourceColony.getResourceAmount('Goods') < totalGoodsNeeded ||
      this.owner.credits < totalCreditsNeeded
    ) {
      this.notify('Insufficient resources or credits for full repair.', 'error');
      return false;
    }

    if (
      sourceColony.removeResource('Minerals', totalMineralsNeeded) &&
      sourceColony.removeResource('Goods', totalGoodsNeeded)
    ) {
      this.owner.credits -= totalCreditsNeeded;
      this.hullHP = this.maxHullHP;
      this.armorHP = this.maxArmorHP;
      this.repairSubsystems?.();

      this.notify(`Ship fully repaired for ${totalCreditsNeeded.toFixed(0)} credits.`, 'success');
      this.emitStateChanged('ship_repaired', {
        sourceColony,
        totalCreditsNeeded
      });

      return true;
    }

    return false;
  },

  getImmediateCourseDeltaV(courseOption) {
    if (!courseOption) return Infinity;

    if (Number.isFinite(courseOption.departureDeltaV)) {
      return courseOption.departureDeltaV;
    }

    if (Number.isFinite(courseOption.totalDeltaV)) {
      return courseOption.totalDeltaV;
    }

    return Infinity;
  },

  canStartCourseOption(courseOption) {
    return this.getEffectiveDeltaV() >= this.getImmediateCourseDeltaV(courseOption);
  },

  getEffectiveDeltaV() {
    const engineFactor = this.getSubsystemEffectiveness?.('engines') ?? 1;
    const researchMultiplier = this.owner?.getResearchEffect?.('fuelEfficiencyMultiplier', 1) || 1;
    return this.currentFuel * (this.engine.fuelEfficiency || 1.0) * engineFactor * researchMultiplier;
  },

  getRemainingTimeToArrivalSeconds() {
    if (!this.target || this.timeToArrival == null) return 0;
    return Math.max(0, this.timeToArrival - this.timeSinceDeparture);
  },

  getRemainingTimeToArrivalDays() {
    return this.getRemainingTimeToArrivalSeconds() / 86400;
  },

  consumeFuel(deltaVAmount) {
    const engineFactor = this.getSubsystemEffectiveness?.('engines') ?? 1;
    const researchMultiplier = this.owner?.getResearchEffect?.('fuelEfficiencyMultiplier', 1) || 1;
    const fuelConsumed = deltaVAmount / ((this.engine.fuelEfficiency || 1.0) * engineFactor * researchMultiplier);

    if (this.currentFuel < fuelConsumed) {
      return false;
    }

    this.currentFuel -= fuelConsumed;
    if (this.currentFuel < 0) this.currentFuel = 0;

    console.log(`${this.name} executed a ${(deltaVAmount / 1000).toFixed(2)} km/s burn, consuming ${fuelConsumed.toFixed(1)} fuel units. Fuel remaining: ${this.currentFuel.toFixed(1)}.`);

    this.emitStateChanged('ship_fuel_changed', {
      deltaVAmount,
      fuelConsumed
    });

    return true;
  },

  assignTransportTask(task) {
    this.transportTask = { ...task, phase: 'moving_to_source' };
    this.currentMission = 'transport';

    this.emitStateChanged('ship_transport_task_assigned', {
      transportTask: this.transportTask
    });

    const sourcePlanet = task.source.planet ? task.source.planet : task.source;

    const coursePreference = task.coursePreference || 'balanced';
    this.plotInterceptByDeltaV(sourcePlanet, 'rendezvous', {
      strategy: coursePreference === 'efficient' ? 'deltaV' : 'time',
      minDays: 8,
      maxDays: 90,
      missionType: 'transport'
    }).then((courseOptions) => {
      if (courseOptions && courseOptions.length > 0) {
        const bestOption = this.chooseMissionCourse(courseOptions, coursePreference);

        if (bestOption && this.canStartCourseOption(bestOption)) {
          this.executeCourseOption(bestOption);
          this.notify(`${this.name} is now en route to ${sourcePlanet.name} for pickup.`, 'info', true);
        } else {
          this.finishMissionOrder(false, 'Cannot afford transport task fuel.');
          this.transportTask = null;
          this.clearNavigation();
        }
      } else {
        this.finishMissionOrder(false, 'No viable course found for transport task.');
        this.transportTask = null;
        this.clearNavigation();
      }
    });
  },

  onArriveAtTarget() {
    const destination = this.target;
    if (!destination) {
      this.clearNavigation();
      return;
    }

    this.emitStateChanged('ship_arrived_at_target', {
      destination
    });

    if (this.activeMissionOrder) {
      const handled = this.handleMissionOrderArrival(destination);
      if (handled) return;
    }

    if (!this.isCelestialTarget(destination)) {
      const success = this.completeObjectRendezvous(destination);

      if (success) {
        this.updateStatus('idle', `Intercepted ${destination.name}`);
        this.finishMissionOrder(true, `Intercepted ${destination.name}.`);
        this.game?.eventEmitter?.emit?.('objectIntercepted', {
          interceptor: this,
          target: destination,
          maneuverType: this.currentManeuverType
        });
      } else {
        this.finishMissionOrder(false, `Failed to intercept ${destination.name}.`);
      }

      this.clearNavigation();
      this.dispatchNextMissionOrder();
      return;
    }

    this.updateStatus('arriving', `Arrived in the vicinity of ${destination.name}`);
    this.currentOrbitingBody = destination;
    this.enterOrbit();

    if (!this.currentOrbitingBody) {
      return;
    }

    if (this.transportTask) {
      this.handleTransportLogic();
      return;
    }

    if (this.currentMission === 'prospect') {
      this.performProspectingScan(destination, { force: true });
      this.finishMissionOrder(true, `Survey completed at ${destination.name}.`);
      this.clearNavigation();
      this.dispatchNextMissionOrder();
      return;
    }

    if (this.currentMission === 'explore') {
      this.explore();
      this.finishMissionOrder(true, `Exploration completed at ${destination.name}.`);
      this.clearNavigation();
      this.dispatchNextMissionOrder();
      return;
    }

    if (this.currentMission === 'build') {
      const success = this.game.buildBuildingOnPlanet(
        destination,
        this.assignedBuildingName,
        this.owner,
        { constructionShip: this }
      );

      if (success) {
        this.finishMissionOrder(true, `Built ${this.assignedBuildingName} at ${destination.name}.`);
      } else {
        this.clearNavigation({ refundEscrow: true });
        this.finishMissionOrder(false, `Failed to build at ${destination.name}.`);
        this.updateStatus('idle', `Holding orbit around ${destination.name}`);
      }

      this.dispatchNextMissionOrder();
      return;
    }

    if (this.hasProspectingCapability() && this.isMineableBody(destination) && !this.game?.getProspectingIntel?.(destination, this.owner)) {
      this.performProspectingScan(destination);
    }

    if (this.hasMiningCapability() && this.isMineableBody(destination) && !this.owner?.isAI) {
      this.notify(`${this.name} is in orbit around ${destination.name} and ready to harvest resources.`, 'info');
    }

    this.finishMissionOrder(true, `Arrived at ${destination.name}.`);
    this.clearNavigation();
    this.dispatchNextMissionOrder();
  },

  clearNavigation(options = {}) {
    const defaultRefundEscrow =
      this.currentMission === 'build' ||
      !!this.assignedBuildingName ||
      this.getEscrowCredits() > 0;

    const { refundEscrow = defaultRefundEscrow, preserveMissionOrder = false } = options;

    if (refundEscrow) {
      this.refundEscrowCredits('mission_aborted');
    }

    if (!preserveMissionOrder && this.activeMissionOrder) {
      this.finishMissionOrder(false, 'Navigation cleared while mission was active.', { dispatchNext: false });
    }

    this.status = 'idle';
    this.currentMission = null;
    this.midCourseUpdateDone = false;
    this.target = null;
    this.currentTrajectoryPositions = null;
    this.currentTrajectoryDt = null;
    this.timeToArrival = null;
    this.timeSinceDeparture = 0;
    this.currentManeuverType = null;
    this.selectedCoursePreviewIndex = null;
    this.assignedContractId = null;
    this.reservedForContractId = null;
    this.assignedBuildingName = null;

    if (typeof this._clearTrajectoryVisuals === 'function') {
      this._clearTrajectoryVisuals();
    } else if (this.spaceshipTrajectory) {
      this.spaceshipTrajectory.dispose();
    }
    this.spaceshipTrajectory = null;

    this.emitStateChanged('ship_navigation_cleared');
  },

  handleTransportLogic() {
    if (!this.transportTask) return;
    const task = this.transportTask;

    switch (task.phase) {
      case 'moving_to_source': {
        this.updateStatus('loading');
        const sourceColony = task.source;
        const amountToLoad = Math.min(task.amount, sourceColony.getResourceAmount(task.resourceName));

        if (amountToLoad > 0 && sourceColony.removeResource(task.resourceName, amountToLoad)) {
          const overflow = this.addResource(task.resourceName, amountToLoad);
          const loadedAmount = amountToLoad - overflow;

          if (overflow > 0) {
            sourceColony.addResource(task.resourceName, overflow);
          }

          task.amount = loadedAmount;
          task.phase = 'moving_to_destination';

          this.emitStateChanged('ship_transport_loaded', {
            transportTask: task,
            loadedAmount
          });

          const destinationPlanet = task.destination.planet ? task.destination.planet : task.destination;

          this.plotInterceptByDeltaV(destinationPlanet, 'rendezvous', {
            strategy: 'time',
            minDays: 8,
            maxDays: 90,
            missionType: 'transport'
          }).then((options) => {
            if (options && options.length > 0) {
              const bestOption = options.sort((a, b) => a.totalDeltaV - b.totalDeltaV)[0];
              if (this.canStartCourseOption(bestOption)) {
                this.executeCourseOption(bestOption);
              } else {
                console.error(`${this.name}: Not enough fuel for destination leg.`);
                this.notify(`${this.name} cannot afford the destination leg for this transport task.`, 'error');
                this.transportTask = null;
                this.clearNavigation();
              }
            } else {
              console.error(`${this.name}: Could not plot course to destination.`);
              this.notify(`${this.name} could not plot a course to the destination.`, 'error');
              this.transportTask = null;
              this.clearNavigation();
            }
          });
        } else {
          this.notify(`${this.name}: Source colony no longer has enough ${task.resourceName}.`, 'error');
          this.transportTask = null;
          this.clearNavigation();
        }
        break;
      }

      case 'moving_to_destination': {
        const destination = task.destination;
        const cargoAmount = this.cargo[task.resourceName] || 0;

        if (task.type === 'internal') {
          this.updateStatus('unloading');
          this.removeResource(task.resourceName, cargoAmount);
          destination.addResource(task.resourceName, cargoAmount);
          this.notify(`${this.name} delivered ${cargoAmount.toFixed(1)} ${task.resourceName} to ${destination.name}.`, 'success');

          this.emitStateChanged('ship_transport_delivered', {
            transportTask: task,
            destination,
            deliveredAmount: cargoAmount
          });

          this.finishMissionOrder(true, `Delivered ${cargoAmount.toFixed(1)} ${task.resourceName} to ${destination.name}.`);
          this.transportTask = null;
          this.clearNavigation();
          this.dispatchNextMissionOrder();
        } else if (task.type === 'sell') {
          this.updateStatus('selling');
          const market = destination.market;
          if (market.sellToMarket(this, task.resourceName, cargoAmount)) {
            this.emitStateChanged('ship_transport_sold', {
              transportTask: task,
              destination,
              soldAmount: cargoAmount
            });
          }
          this.finishMissionOrder(true, `Sold ${cargoAmount.toFixed(1)} ${task.resourceName} at ${destination.name}.`);
          this.transportTask = null;
          this.clearNavigation();
          this.dispatchNextMissionOrder();
        }

        break;
      }

      default:
        break;
    }
  },

  getResourceAmount(resourceName) {
    return this.cargo[resourceName] || 0;
  },

  addResource(resourceName, amount) {
    const totalCargo = Object.values(this.cargo).reduce((sum, value) => sum + value, 0);
    const availableSpace = this.cargoCapacity - totalCargo;
    const amountToAdd = Math.min(amount, availableSpace);

    if (amountToAdd > 0) {
      this.cargo[resourceName] = (this.cargo[resourceName] || 0) + amountToAdd;
    }

    if (amountToAdd < amount && !this.owner.isAI) {
      this.notify(`Cargo full on ${this.name}. ${(amount - amountToAdd).toFixed(1)} ${resourceName} could not be loaded.`, 'warning');
    }

    this.emitStateChanged('ship_cargo_changed', {
      resourceName,
      amountAdded: amountToAdd,
      overflow: amount - amountToAdd,
      cargo: { ...this.cargo }
    });

    return amount - amountToAdd;
  },

  removeResource(resourceName, amount) {
    if (this.getResourceAmount(resourceName) >= amount) {
      this.cargo[resourceName] -= amount;
      if (this.cargo[resourceName] <= 0.001) delete this.cargo[resourceName];

      this.emitStateChanged('ship_cargo_changed', {
        resourceName,
        amountRemoved: amount,
        cargo: { ...this.cargo }
      });

      return true;
    }
    return false;
  },

  updateStatus(newStatus, details = '') {
    this.status = newStatus;
    if (details) {
      console.log(`${this.name}: ${newStatus} - ${details}`);
    }

    this.emitStateChanged('ship_status_changed', {
      details
    });
  },

  calculateMass(engine, weapons, armor, sensor, quarters, storage, fuel) {
    let mass = 1000;
    mass += engine ? 500 : 0;
    mass += weapons.reduce((sum, weapon) => sum + 200, 0);
    mass += armor ? 300 : 0;
    mass += sensor ? 100 : 0;
    mass += quarters ? 400 : 0;
    mass += storage ? 250 : 0;
    mass += fuel ? 500 : 0;
    return mass;
  },

  calculateCost(engine, weapons, armor, sensor, quarters, storage, fuel) {
    let cost = 1000;
    cost += engine ? engine.cost : 0;
    cost += weapons.reduce((sum, weapon) => sum + weapon.cost, 0);
    cost += armor ? armor.cost : 0;
    cost += sensor ? sensor.cost : 0;
    cost += quarters ? quarters.cost : 0;
    cost += storage ? storage.cost : 0;
    cost += fuel ? fuel.cost : 0;
    return cost;
  },

  onNewTurn() {
    if (this.isDestroyed() || this.combat.isInCombat) {
      this.dispatchNextMissionOrder();
      return;
    }

    if (!this.activeMissionOrder && this.missionQueue?.length > 0) {
      this.dispatchNextMissionOrder();
    }

    if (this.currentOrbitingBody && this.isMineableBody(this.currentOrbitingBody)) {
      const intel = this.game?.getProspectingIntel?.(this.currentOrbitingBody, this.owner);

      if (!intel && this.hasProspectingCapability()) {
        this.performProspectingScan(this.currentOrbitingBody);
        this.checkMidCourseUpdate();
        return;
      }

      if (this.hasMiningCapability()) {
        this.extractResource(this.currentOrbitingBody, this.game?.daysPerTurn || 1);
      }
    }

    this.checkMidCourseUpdate();
  },

  explore() {
    if (!this.target) return;

    const wasAlreadyExplored = !!this.game?.isBodyExploredByPlayer?.(this.target.name, this.owner);

    console.log(`${this.name} has explored ${this.target.name}.`);
    this.updateStatus('exploring', `Exploring ${this.target.name}`);

    this.game.markBodyAsExplored(this.target, this.owner);
    this.notify(`${this.owner.name} spaceship ${this.name} explored ${this.target.name}.`, 'success');

    if (!wasAlreadyExplored) {
      this.applyExplorationReward(this.target);
    }

    if (this.isMineableBody(this.target) && this.hasProspectingCapability()) {
      this.performProspectingScan(this.target, { force: true });
    }

    this.emitStateChanged('body_explored', {
      body: this.target,
      explorer: this,
      owner: this.owner,
      firstExploration: !wasAlreadyExplored
    });
  }
};


// ===== public/classes/spaceship/SpaceshipNavigation.js =====
function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}
function createSpaceshipNavigationMethods({
  G,
  DISTANCE_SCALE,
  calculateHohmannTransfer,
  calculateOrbitalStateVectors
}) {
  return {
    getHeldOrbitRelativeState(relativePosition, relativeVelocity, parentMass, elapsedSeconds) {
      const BABYLON = window.BABYLON;
      const mu = G * parentMass;

      const radius = relativePosition.length();
      if (
        !Number.isFinite(radius) ||
        radius <= 0 ||
        !Number.isFinite(parentMass) ||
        parentMass <= 0 ||
        !Number.isFinite(elapsedSeconds)
      ) {
        return null;
      }

      if (Math.abs(elapsedSeconds) < 1e-6) {
        return {
          position: relativePosition.clone(),
          velocity: relativeVelocity.clone()
        };
      }

      const accel = (pos) => {
        const r = pos.length();
        if (!Number.isFinite(r) || r <= 0) {
          return new BABYLON.Vector3(0, 0, 0);
        }

        return pos.scale(-mu / (r * r * r));
      };

      let position = relativePosition.clone();
      let velocity = relativeVelocity.clone();

      const absElapsed = Math.abs(elapsedSeconds);
      const baseStep = absElapsed <= 3600
        ? 30
        : (absElapsed <= 86400 ? 120 : 300);

      const numSteps = Math.max(1, Math.min(720, Math.ceil(absElapsed / baseStep)));
      const stepDt = elapsedSeconds / numSteps;

      for (let i = 0; i < numSteps; i++) {
        const k1r = velocity.clone();
        const k1v = accel(position);

        const p2 = position.add(k1r.scale(0.5 * stepDt));
        const v2 = velocity.add(k1v.scale(0.5 * stepDt));
        const k2r = v2.clone();
        const k2v = accel(p2);

        const p3 = position.add(k2r.scale(0.5 * stepDt));
        const v3 = velocity.add(k2v.scale(0.5 * stepDt));
        const k3r = v3.clone();
        const k3v = accel(p3);

        const p4 = position.add(k3r.scale(stepDt));
        const v4 = velocity.add(k3v.scale(stepDt));
        const k4r = v4.clone();
        const k4v = accel(p4);

        position = position.add(
          k1r
            .add(k2r.scale(2))
            .add(k3r.scale(2))
            .add(k4r)
            .scale(stepDt / 6)
        );

        velocity = velocity.add(
          k1v
            .add(k2v.scale(2))
            .add(k3v.scale(2))
            .add(k4v)
            .scale(stepDt / 6)
        );
      }

      return {
        position,
        velocity
      };
    },

    getCourseDepartureOffsetSeconds() {
      return Number.isFinite(this.courseDepartureOffsetSec) ? this.courseDepartureOffsetSec : 0;
    },

    getCourseTransferTimeSeconds() {
      return Number.isFinite(this.courseTransferTimeOfFlight) && this.courseTransferTimeOfFlight > 0
        ? this.courseTransferTimeOfFlight
        : (
          Number.isFinite(this.timeToArrival) && this.timeToArrival > 0
            ? this.timeToArrival
            : 0
        );
    },

    getCourseReferenceEpochMs() {
      if (Number.isFinite(this.courseReferenceEpochMs)) {
        return this.courseReferenceEpochMs;
      }

      const now = this.game?.getCurrentGameDate?.();
      return now instanceof Date ? now.getTime() : Date.now();
    },

    getTrajectoryCentralBody() {
      const centralBodyName = this.currentTrajectoryFrame?.centralBodyName;
      if (!centralBodyName) {
        return null;
      }

      return (this.bodies || []).find((body) => body?.name === centralBodyName) || null;
    },

    hasDelayedCourseDeparture() {
      return this.getCourseDepartureOffsetSeconds() > 0;
    },

    executeDeferredDepartureBurn() {
      if (this.courseLaunchExecuted) {
        return true;
      }

      const departureDeltaV = Number.isFinite(this.plannedDepartureDeltaV)
        ? this.plannedDepartureDeltaV
        : 0;

      if (departureDeltaV > 0 && !this.consumeFuel(departureDeltaV)) {
        this.notify(`${this.name} lacks fuel for delayed departure burn.`, 'error');
        this.clearNavigation();
        return false;
      }

      this.courseLaunchExecuted = true;
      this.currentOrbitingBody = null;

      const departureState = this.sampleTrajectoryStateAtTransferElapsed(0);

      if (departureState) {
        this.position = departureState.position;
        this.velocity = departureState.velocity;
      } else {
        if (this.plannedDepartureStatePosition?.clone) {
          this.position = this.plannedDepartureStatePosition.clone();
        }

        if (this.plannedDepartureVelocity?.clone) {
          this.velocity = this.plannedDepartureVelocity.clone();
        } else if (this.plannedDepartureStateVelocity?.clone) {
          this.velocity = this.plannedDepartureStateVelocity.clone();
        }
      }

      this.syncRenderedPosition?.();

      this.emitStateChanged('ship_departed', {
        courseOption: this.activeCourseOption || null,
        contractId: this.assignedContractId || this.reservedForContractId || null,
        delayedDeparture: true
      });

      return true;
    },

    advanceCoastMotion(bodies, dt) {
      const BABYLON = window.BABYLON;

      if (this.currentOrbitingBody) {
        const parent = this.currentOrbitingBody;

        const relativePosition = this.position.subtract(parent.position);
        const relativeVelocity = this.velocity.subtract(parent.velocity);

        const relativeState = this.getHeldOrbitRelativeState(
          relativePosition,
          relativeVelocity,
          parent.mass,
          dt
        );

        if (relativeState) {
          const parentState = this.getBodyStateAtDate(
            parent,
            this.game?.getCurrentGameDate?.() || new Date()
          );

          this.position = parentState.position.add(relativeState.position);
          this.velocity = parentState.velocity.add(relativeState.velocity);
          this.syncRenderedPosition?.();
          return;
        }

        const fallbackParentPosition = parent.position?.clone
          ? parent.position.clone()
          : new BABYLON.Vector3(0, 0, 0);
        const fallbackParentVelocity = parent.velocity?.clone
          ? parent.velocity.clone()
          : new BABYLON.Vector3(0, 0, 0);

        this.position = fallbackParentPosition.add(relativePosition);
        this.velocity = fallbackParentVelocity.add(relativeVelocity);
        this.syncRenderedPosition?.();
        return;
      }

      const totalForce = new BABYLON.Vector3(0, 0, 0);

      bodies.forEach((body) => {
        if (body !== this && body.mass) {
          const direction = body.position.subtract(this.position);
          const distance = direction.length();
          if (distance > 0) {
            const forceMagnitude = (G * this.mass * body.mass) / (distance * distance);
            const force = direction.normalize().scale(forceMagnitude);
            totalForce.addInPlace(force);
          }
        }
      });

      const acceleration = totalForce.scale(1 / this.mass);
      this.velocity.addInPlace(acceleration.scale(dt));
      this.position.addInPlace(this.velocity.scale(dt));
      this.syncRenderedPosition?.();
    },

    getStateAtFutureTime(secondsFromNow) {
      const totalElapsed = (Number.isFinite(this.timeSinceDeparture) ? this.timeSinceDeparture : 0) + secondsFromNow;
      const departureOffsetSec = this.getCourseDepartureOffsetSeconds();
      const transferTimeSec = this.getCourseTransferTimeSeconds();
      const pathIsActiveAtTime = totalElapsed >= (departureOffsetSec - 1e-3);

      if (
        this.target &&
        Array.isArray(this.currentTrajectoryPositions) &&
        this.currentTrajectoryPositions.length > 1 &&
        Number.isFinite(transferTimeSec) &&
        transferTimeSec > 0 &&
        pathIsActiveAtTime
      ) {
        const transferElapsed = Math.max(
          0,
          Math.min(totalElapsed - departureOffsetSec, transferTimeSec)
        );

        const sampledState = this.sampleTrajectoryStateAtTransferElapsed(transferElapsed);
        if (sampledState) {
          return {
            position: sampledState.position,
            velocity: sampledState.velocity
          };
        }
      }

      if (this.currentOrbitingBody) {
        const relativePosition = this.position.subtract(this.currentOrbitingBody.position);
        const relativeVelocity = this.velocity.subtract(this.currentOrbitingBody.velocity);

        const relativeState = this.getHeldOrbitRelativeState(
          relativePosition,
          relativeVelocity,
          this.currentOrbitingBody.mass,
          secondsFromNow
        );

        if (relativeState) {
          const futureDate = this.game?.getCurrentGameDate
            ? new Date(this.game.getCurrentGameDate().getTime() + (secondsFromNow * 1000))
            : new Date(Date.now() + (secondsFromNow * 1000));

          const parentState = this.getBodyStateAtDate(this.currentOrbitingBody, futureDate);

          return {
            position: parentState.position.add(relativeState.position),
            velocity: parentState.velocity.add(relativeState.velocity)
          };
        }
      }

      return {
        position: this.position.clone().add(this.velocity.clone().scale(secondsFromNow)),
        velocity: this.velocity.clone()
      };
    },

    isCelestialTarget(target) {
      return !!(
        target &&
        Number.isFinite(target.mass) &&
        Number.isFinite(target.radius) &&
        target.type !== 'spaceship'
      );
    },

    completeObjectRendezvous(target) {
      const BABYLON = window.BABYLON;

      if (!target?.position || !target?.velocity) {
        return false;
      }

      if (this.currentManeuverType === 'rendezvous') {
        const arrivalVelocity = this.finalArrivalVelocity?.clone() || this.velocity.clone();
        const rendezvousDv = BABYLON.Vector3.Distance(arrivalVelocity, target.velocity);

        if (!this.consumeFuel(rendezvousDv)) {
          this.notify(`${this.name} lacks fuel to match velocity with ${target.name}.`, 'error');
          return false;
        }

        this.velocity = target.velocity.clone();
      }

      this.position = target.position.clone();
      this.syncRenderedPosition?.();

      this.emitStateChanged('ship_rendezvous_completed', {
        target,
        maneuverType: this.currentManeuverType
      });

      return true;
    },

    sampleTrajectoryStateAtTransferElapsed(transferElapsedSec) {
      const BABYLON = window.BABYLON;
      const transferTimeSec = this.getCourseTransferTimeSeconds();
      const trajectoryFrame = this.currentTrajectoryFrame || null;

      const usesCentralBodyRelativeFrame =
        trajectoryFrame?.mode === 'centralBodyRelative' &&
        Array.isArray(trajectoryFrame.relativePositions) &&
        trajectoryFrame.relativePositions.length > 0;

      const path = usesCentralBodyRelativeFrame
        ? trajectoryFrame.relativePositions
        : this.currentTrajectoryPositions;

      if (!Array.isArray(path) || path.length === 0) {
        return null;
      }

      if (!Number.isFinite(transferTimeSec) || transferTimeSec <= 0) {
        return null;
      }

      const clampedElapsed = Math.max(0, Math.min(transferElapsedSec, transferTimeSec));

      const sampleDt = Number.isFinite(this.currentTrajectoryDt) && this.currentTrajectoryDt > 0
        ? this.currentTrajectoryDt
        : (
          Number.isFinite(trajectoryFrame?.pathDt) && trajectoryFrame.pathDt > 0
            ? trajectoryFrame.pathDt
            : (transferTimeSec / Math.max(1, path.length - 1))
        );

      if (usesCentralBodyRelativeFrame && clampedElapsed <= 1e-6 && this.plannedDepartureStatePosition?.clone && this.plannedDepartureVelocity?.clone) {
        return {
          position: this.plannedDepartureStatePosition.clone(),
          velocity: this.plannedDepartureVelocity.clone(),
          index: 0
        };
      }

      if (!usesCentralBodyRelativeFrame && clampedElapsed <= 1e-6 && this.plannedDepartureStatePosition?.clone && this.plannedDepartureVelocity?.clone) {
        return {
          position: this.plannedDepartureStatePosition.clone(),
          velocity: this.plannedDepartureVelocity.clone(),
          index: 0
        };
      }

      if (path.length === 1) {
        if (usesCentralBodyRelativeFrame) {
          const centralBody = this.getTrajectoryCentralBody();
          if (!centralBody) {
            return null;
          }

          const absoluteTimeSec = this.getCourseDepartureOffsetSeconds() + clampedElapsed;
          const centralDate = new Date(this.getCourseReferenceEpochMs() + (absoluteTimeSec * 1000));
          const centralState = this.getBodyStateAtDate(centralBody, centralDate);
          const relativePosition = path[0].clone();
          const relativeVelocity = trajectoryFrame.initialRelativeVelocity?.clone
            ? trajectoryFrame.initialRelativeVelocity.clone()
            : (trajectoryFrame.finalRelativeVelocity?.clone
              ? trajectoryFrame.finalRelativeVelocity.clone()
              : (this.finalArrivalVelocity?.clone
                ? this.finalArrivalVelocity.clone().subtract(centralState.velocity)
                : this.velocity.clone().subtract(centralState.velocity)));

          return {
            position: centralState.position.add(relativePosition),
            velocity: centralState.velocity.add(relativeVelocity),
            index: 0
          };
        }

        return {
          position: path[0].clone().scale(1 / DISTANCE_SCALE),
          velocity: this.plannedDepartureVelocity?.clone() || this.finalArrivalVelocity?.clone() || this.velocity.clone(),
          index: 0
        };
      }

      const lastIndex = path.length - 1;
      let i0 = 0;
      let i1 = 1;
      let alpha = 0;
      let segmentDt = sampleDt;

      if (clampedElapsed >= (transferTimeSec - 1e-9)) {
        i0 = Math.max(0, lastIndex - 1);
        i1 = lastIndex;
        const segmentStartSec = Math.min(i0 * sampleDt, transferTimeSec);
        segmentDt = Math.max(1e-6, transferTimeSec - segmentStartSec);
        alpha = 1;
      } else {
        const nominalIndex = Math.floor(clampedElapsed / Math.max(sampleDt, 1e-6));
        i0 = Math.max(0, Math.min(nominalIndex, lastIndex - 1));
        i1 = Math.min(i0 + 1, lastIndex);

        const t0 = Math.min(i0 * sampleDt, transferTimeSec);
        const t1 = i1 === lastIndex
          ? transferTimeSec
          : Math.min(i1 * sampleDt, transferTimeSec);

        segmentDt = Math.max(1e-6, t1 - t0);
        alpha = Math.max(0, Math.min(1, (clampedElapsed - t0) / segmentDt));
      }

      if (usesCentralBodyRelativeFrame) {
        const centralBody = this.getTrajectoryCentralBody();
        if (!centralBody) {
          return null;
        }

        const p0 = path[i0].clone();
        const p1 = path[i1].clone();
        const relativePosition = BABYLON.Vector3.Lerp(p0, p1, alpha);

        const absoluteTimeSec = this.getCourseDepartureOffsetSeconds() + clampedElapsed;
        const centralDate = new Date(this.getCourseReferenceEpochMs() + (absoluteTimeSec * 1000));
        const centralState = this.getBodyStateAtDate(centralBody, centralDate);

        let relativeVelocity;
        if (i0 === 0 && trajectoryFrame.initialRelativeVelocity?.clone && clampedElapsed <= sampleDt) {
          relativeVelocity = trajectoryFrame.initialRelativeVelocity.clone();
        } else if (i1 > i0 && segmentDt > 0) {
          relativeVelocity = p1.subtract(p0).scale(1 / segmentDt);
        } else if (trajectoryFrame.finalRelativeVelocity?.clone) {
          relativeVelocity = trajectoryFrame.finalRelativeVelocity.clone();
        } else if (this.finalArrivalVelocity?.clone) {
          relativeVelocity = this.finalArrivalVelocity.clone().subtract(centralState.velocity);
        } else {
          relativeVelocity = this.velocity.clone().subtract(centralState.velocity);
        }

        return {
          position: centralState.position.add(relativePosition),
          velocity: centralState.velocity.add(relativeVelocity),
          index: i0
        };
      }

      const p0 = path[i0].clone().scale(1 / DISTANCE_SCALE);
      const p1 = path[i1].clone().scale(1 / DISTANCE_SCALE);

      const position = BABYLON.Vector3.Lerp(p0, p1, alpha);

      const velocity = (i0 === 0 && this.plannedDepartureVelocity?.clone && clampedElapsed <= sampleDt)
        ? this.plannedDepartureVelocity.clone()
        : ((i1 > i0 && segmentDt > 0)
          ? p1.subtract(p0).scale(1 / segmentDt)
          : (this.finalArrivalVelocity?.clone() || this.velocity.clone()));

      return {
        position,
        velocity,
        index: i0
      };
    },

    applyTrajectoryStateAtTransferElapsed(transferElapsedSec) {
      const state = this.sampleTrajectoryStateAtTransferElapsed(transferElapsedSec);
      if (!state) {
        return false;
      }

      this.position = state.position;
      this.velocity = state.velocity;
      this.currentTrajectoryIndex = state.index;
      this.syncRenderedPosition?.();

      return true;
    },

    getStraightLineSeed(targetPlanet, tofSec) {
      const sun = this.bodies.find((body) => body.name === 'Sun');
      const now = this.game.getCurrentGameDate();
      const arrivalDate = new Date(now.getTime() + tofSec * 1000);

      const { position: targetPos } =
        calculateOrbitalStateVectors(
          targetPlanet.orbitalElements,
          arrivalDate,
          sun.position,
          sun.velocity,
          sun.mass
        );

      const r1 = this.position.clone();
      const v1 = this.velocity.clone();
      const displacement = targetPos.subtract(r1);
      return v1.add(displacement.scale(1 / tofSec));
    },

    async performMidCourseUpdate() {
      if (!this.target) return;
      if (this.hasDelayedCourseDeparture() && !this.courseLaunchExecuted) return;

      console.log(`${this.name} is performing mid-course update.`);
      this.updateStatus('adjusting course', 'Performing mid-course correction');

      const remainingTimeSeconds = this.getRemainingTimeToArrivalSeconds();
      const remainingTimeDays = remainingTimeSeconds / 86400;

      if (remainingTimeDays <= 1) {
        this.midCourseUpdateDone = true;
        return;
      }

      const searchMinDays = Math.max(1, remainingTimeDays * 0.75);
      const searchMaxDays = Math.max(searchMinDays, remainingTimeDays * 1.25);

      const constraints = {
        strategy: 'time',
        minDays: searchMinDays,
        maxDays: searchMaxDays,
        minDepartureDelayDays: 0,
        maxDepartureDelayDays: 0,
        missionType: this.currentMission
      };

      const maneuverType = this.currentManeuverType || 'rendezvous';

      try {
        const courseOptions = await this.plotInterceptByDeltaV(this.target, maneuverType, constraints);

        if (courseOptions && courseOptions.length > 0) {
          const affordableOptions = courseOptions.filter((option) => this.canStartCourseOption(option));

          if (affordableOptions.length === 0) {
            console.warn(`[AI] ${this.name} skipped mid-course update: No affordable correction options.`);
            this.midCourseUpdateDone = true;
            return;
          }

          const bestOption = affordableOptions.reduce((previous, current) =>
            (previous.totalDeltaV < current.totalDeltaV) ? previous : current
          );

          this.executeCourseOption(bestOption);
          this.midCourseUpdateDone = true;
        } else {
          console.warn(`[AI] ${this.name} found no viable mid-course corrections.`);
          this.midCourseUpdateDone = true;
        }
      } catch (error) {
        console.error(`Error during mid-course update for ${this.name}:`, error);
        this.midCourseUpdateDone = true;
      }
    },

    enterOrbit() {
      const BABYLON = window.BABYLON;
      const planet = this.target;

      if (!planet) {
        console.error(`${this.name}: Cannot enter orbit without a target.`);
        this.clearNavigation();
        return;
      }

      if (!this.finalArrivalVelocity) {
        console.error(`${this.name}: Missing arrival velocity; falling back to simple orbit insertion at ${planet.name}.`);
        this.velocity = planet.velocity.clone();
        this.position = planet.position.clone().add(new BABYLON.Vector3(planet.radius * 1.1, 0, 0));
        this.currentOrbitingBody = planet;
        this.syncRenderedPosition?.();

        this.emitStateChanged('ship_entered_orbit', {
          planet,
          insertionDeltaV: 0,
          fallback: true
        });

        return;
      }

      const altitude = 200000;
      const orbitalRadius = planet.radius + altitude;
      const orbitalVelocityMagnitude = Math.sqrt(G * planet.mass / orbitalRadius);
      let radialDirection = this.position.subtract(planet.position).normalize();

      if (radialDirection.length() === 0) {
        radialDirection = new BABYLON.Vector3(1, 0, 0);
      }

      const tangentialDirection = BABYLON.Vector3.Cross(new BABYLON.Vector3(0, 0, 1), radialDirection).normalize();
      const desiredOrbitalVelocity = planet.velocity.add(tangentialDirection.scale(orbitalVelocityMagnitude));
      const insertionBurnVector = desiredOrbitalVelocity.subtract(this.finalArrivalVelocity);
      const insertionDeltaV = insertionBurnVector.length();

      if (this.getEffectiveDeltaV() < insertionDeltaV) {
        this.notify(`${this.name} has insufficient fuel for orbital insertion!`, 'error');
        this.currentOrbitingBody = null;
        this.clearNavigation();
        return;
      }

      this.consumeFuel(insertionDeltaV);

      this.position = planet.position.add(radialDirection.scale(orbitalRadius));
      this.velocity = desiredOrbitalVelocity.clone();
      this.currentOrbitingBody = planet;
      this.syncRenderedPosition?.();

      this.notify(`${this.name} entered orbit around ${planet.name}. Insertion burn: ${(insertionDeltaV / 1000).toFixed(2)} km/s`, 'success');

      this.emitStateChanged('ship_entered_orbit', {
        planet,
        insertionDeltaV,
        fallback: false
      });
    },

    updatePosition(bodies, days) {
      if (this.isDestroyed()) return;

      const dt = days * 24 * 3600;

      if (this.target && this.currentTrajectoryPositions && this.currentTrajectoryPositions.length > 0) {
        const previousPosition = this.position.clone();

        const departureOffsetSec = this.getCourseDepartureOffsetSeconds();
        const transferTimeSec = this.getCourseTransferTimeSeconds();
        const totalTripTimeSec = Number.isFinite(this.timeToArrival) && this.timeToArrival > 0
          ? this.timeToArrival
          : departureOffsetSec + transferTimeSec;

        //const driveFactor = this.getDrivePowerFactor?.() || 1;
        const missionDt = dt;

        const stepStartMissionElapsed = this.timeSinceDeparture;
        const stepEndMissionElapsed = stepStartMissionElapsed + missionDt;

        const pathWasActiveAtStepStart =
          this.courseLaunchExecuted ||
          departureOffsetSec <= 0 ||
          stepStartMissionElapsed >= departureOffsetSec;

        if (!pathWasActiveAtStepStart && stepEndMissionElapsed < (departureOffsetSec - 1e-3)) {
          this.timeSinceDeparture = stepEndMissionElapsed;
          this.advanceCoastMotion(bodies, dt);
        } else if (!pathWasActiveAtStepStart && stepEndMissionElapsed >= (departureOffsetSec - 1e-3)) {
          const coastMissionDt = Math.max(0, departureOffsetSec - stepStartMissionElapsed);
          const missionPostBurnDt = Math.max(0, missionDt - coastMissionDt);
          const realCoastDt = Math.max(0, dt - (dt * clamp(missionPostBurnDt / Math.max(1e-6, missionDt), 0, 1)));

          if (realCoastDt > 1e-6) {
            this.advanceCoastMotion(bodies, realCoastDt);
          }

          this.timeSinceDeparture = departureOffsetSec;

          if (!this.executeDeferredDepartureBurn()) {
            return;
          }

          if (missionPostBurnDt > 1e-6) {
            const transferElapsed = Math.max(0, Math.min(missionPostBurnDt, transferTimeSec));
            this.timeSinceDeparture = departureOffsetSec + missionPostBurnDt;
            this.applyTrajectoryStateAtTransferElapsed(transferElapsed);
          } else {
            this.syncRenderedPosition?.();
          }
        } else {
          this.timeSinceDeparture = stepEndMissionElapsed;

          const transferElapsed = Math.max(
            0,
            Math.min(stepEndMissionElapsed - departureOffsetSec, transferTimeSec)
          );

          this.applyTrajectoryStateAtTransferElapsed(transferElapsed);
        }

        const segmentDistance = window.BABYLON.Vector3.Distance(previousPosition, this.position);
        this.distanceTraveled += segmentDistance;

        const transferElapsedNow = Math.max(
          0,
          Math.min(this.timeSinceDeparture - departureOffsetSec, transferTimeSec)
        );

        const progress = transferTimeSec > 0
          ? Math.min(1, transferElapsedNow / transferTimeSec)
          : 1;

        if (this.timeSinceDeparture >= totalTripTimeSec || progress >= 1.0) {
          const finalState = this.sampleTrajectoryStateAtTransferElapsed(transferTimeSec);

          if (finalState) {
            this.position = finalState.position;
            this.velocity = this.finalArrivalVelocity?.clone()
              ? this.finalArrivalVelocity.clone()
              : finalState.velocity;
          } else if (this.currentTrajectoryPositions.length > 0) {
            const lastIndex = this.currentTrajectoryPositions.length - 1;
            this.position = this.currentTrajectoryPositions[lastIndex].clone().scale(1 / DISTANCE_SCALE);

            if (this.finalArrivalVelocity) {
              this.velocity = this.finalArrivalVelocity.clone();
            }
          }

          this.syncRenderedPosition?.();
          this.onArriveAtTarget();
        }
      } else {
        this.advanceCoastMotion(bodies, dt);
      }

      if (this.mesh?.metadata) {
        this.mesh.metadata.velocity = this.velocity;
      }
    },

    checkMidCourseUpdate() {
      if (this.status !== 'transiting' || !this.target || this.midCourseUpdateDone) {
        return;
      }

      if (this.hasDelayedCourseDeparture() && !this.courseLaunchExecuted) {
        return;
      }

      if (this.getRemainingTimeToArrivalSeconds() < (5 * 86400)) {
        return;
      }

      const departureOffsetSec = this.getCourseDepartureOffsetSeconds();
      const transferTimeSec = this.getCourseTransferTimeSeconds();
      const transferElapsed = Math.max(0, this.timeSinceDeparture - departureOffsetSec);
      const progress = transferTimeSec > 0 ? (transferElapsed / transferTimeSec) : 1;

      if (progress >= 0.5) {
        this.performMidCourseUpdate();
      }
    },

    solveLinearSystem3x3(A, b) {
      const BABYLON = window.BABYLON;
      const det = A[0] * (A[4] * A[8] - A[5] * A[7]) -
        A[1] * (A[3] * A[8] - A[5] * A[6]) +
        A[2] * (A[3] * A[7] - A[4] * A[6]);

      if (Math.abs(det) < 1e-12) return null;

      const invDet = 1.0 / det;
      const x = [
        (b[0] * (A[4] * A[8] - A[5] * A[7]) + b[1] * (A[2] * A[7] - A[1] * A[8]) + b[2] * (A[1] * A[5] - A[2] * A[4])) * invDet,
        (b[0] * (A[5] * A[6] - A[3] * A[8]) + b[1] * (A[0] * A[8] - A[2] * A[6]) + b[2] * (A[2] * A[3] - A[0] * A[5])) * invDet,
        (b[0] * (A[3] * A[7] - A[4] * A[6]) + b[1] * (A[1] * A[6] - A[0] * A[7]) + b[2] * (A[0] * A[4] - A[1] * A[3])) * invDet
      ];

      return new BABYLON.Vector3(x[0], x[1], x[2]);
    },

    getHohmannSeed(targetPlanet, centralBodyOverride = null) {
      const BABYLON = window.BABYLON;
      let centralBody = centralBodyOverride;

      if (!centralBody) {
        const parentName =
          this.currentOrbitingBody?.name ||
          targetPlanet?.orbitalElements?.centralBody ||
          targetPlanet?.centralBody ||
          'Sun';

        centralBody = this.bodies.find((body) => body.name === parentName)
          || this.bodies.find((body) => body.name === 'Sun');
      }

      if (!centralBody) {
        throw new Error('No central body available for Hohmann seed.');
      }

      const mu = G * centralBody.mass;
      const centerPos = centralBody.position;

      const r1Vec = this.position.subtract(centerPos);
      const r2Vec = targetPlanet.position.subtract(centerPos);

      const r1 = r1Vec.length();
      const r2 = r2Vec.length();

      if (!Number.isFinite(r1) || !Number.isFinite(r2) || r1 <= 0 || r2 <= 0) {
        throw new Error('Invalid radii for Hohmann seed.');
      }

      const { deltaV1, deltaV2, totalDeltaV, timeOfFlight } =
        calculateHohmannTransfer(r1, r2, mu);

      const radialDir = r1Vec.normalize();
      const relativeVelocity = this.velocity.subtract(centralBody.velocity);
      let orbitNormal = BABYLON.Vector3.Cross(r1Vec, relativeVelocity);

      if (orbitNormal.lengthSquared() < 1e-6) {
        orbitNormal = new BABYLON.Vector3(0, 0, 1);
      } else {
        orbitNormal.normalize();
      }

      const tangentialDir = BABYLON.Vector3.Cross(orbitNormal, radialDir).normalize();
      const vGuess = this.velocity.clone().add(tangentialDir.scale(deltaV1));

      return { vGuess, timeOfFlight, insertionDv: deltaV2, totalDeltaV };
    },

    getBodyStateAtDate(body, date) {
      const BABYLON = window.BABYLON;
      const sun = this.bodies.find((candidate) => candidate.name === 'Sun');

      if (!body) {
        return {
          position: new BABYLON.Vector3(0, 0, 0),
          velocity: new BABYLON.Vector3(0, 0, 0)
        };
      }

      if (body.name === 'Sun' || !body.orbitalElements) {
        return {
          position: body.position?.clone ? body.position.clone() : new BABYLON.Vector3(0, 0, 0),
          velocity: body.velocity?.clone ? body.velocity.clone() : new BABYLON.Vector3(0, 0, 0)
        };
      }

      let parentPosition = new BABYLON.Vector3(0, 0, 0);
      let parentVelocity = new BABYLON.Vector3(0, 0, 0);
      let parentMass = sun?.mass || 1.989e30;

      const parentName = body.orbitalElements.centralBody;
      if (parentName && parentName !== 'Sun') {
        const parentBody = this.bodies.find((candidate) => candidate.name === parentName) || sun;
        const parentState = this.getBodyStateAtDate(parentBody, date);
        parentPosition = parentState.position;
        parentVelocity = parentState.velocity;
        parentMass = parentBody?.mass || parentMass;
      }

      return calculateOrbitalStateVectors(
        body.orbitalElements,
        date,
        parentPosition,
        parentVelocity,
        parentMass
      );
    },

    getObjectStateAtDate(targetObject, date) {
      const BABYLON = window.BABYLON;

      if (!targetObject) {
        return {
          position: new BABYLON.Vector3(0, 0, 0),
          velocity: new BABYLON.Vector3(0, 0, 0)
        };
      }

      if (this.isCelestialTarget(targetObject)) {
        return this.getBodyStateAtDate(targetObject, date);
      }

      const now = this.game?.getCurrentGameDate?.() || new Date();
      const elapsedSeconds = (date.getTime() - now.getTime()) / 1000;

      if (typeof targetObject.getStateAtFutureTime === 'function') {
        return targetObject.getStateAtFutureTime(elapsedSeconds);
      }

      return {
        position: targetObject.position?.clone
          ? targetObject.position.clone().add(targetObject.velocity.clone().scale(elapsedSeconds))
          : new BABYLON.Vector3(0, 0, 0),
        velocity: targetObject.velocity?.clone
          ? targetObject.velocity.clone()
          : new BABYLON.Vector3(0, 0, 0)
      };
    },

    sampleCoursePreviewWorldStateAtElapsed(courseOption, missionElapsedSec) {
      const BABYLON = window.BABYLON;
      if (!courseOption) return null;

      const departureOffsetSec = Number(courseOption.departureOffsetSec || 0);
      const transferTimeSec = Number(courseOption.timeOfFlight || 0);
      const clampedMissionElapsed = Math.max(0, Math.min(missionElapsedSec, courseOption.totalMissionTime || (departureOffsetSec + transferTimeSec)));

      if (clampedMissionElapsed < departureOffsetSec) {
        if (this.currentOrbitingBody) {
          const relativePosition = this.position.subtract(this.currentOrbitingBody.position);
          const relativeVelocity = this.velocity.subtract(this.currentOrbitingBody.velocity);

          const relativeState = this.getHeldOrbitRelativeState(
            relativePosition,
            relativeVelocity,
            this.currentOrbitingBody.mass,
            clampedMissionElapsed
          );

          if (relativeState) {
            const futureDate = new Date(this.getCourseReferenceEpochMs() + (clampedMissionElapsed * 1000));
            const parentState = this.getBodyStateAtDate(this.currentOrbitingBody, futureDate);
            return {
              position: parentState.position.add(relativeState.position),
              velocity: parentState.velocity.add(relativeState.velocity)
            };
          }
        }

        return {
          position: this.position.clone().add(this.velocity.clone().scale(clampedMissionElapsed)),
          velocity: this.velocity.clone()
        };
      }

      const transferElapsed = Math.max(0, Math.min(clampedMissionElapsed - departureOffsetSec, transferTimeSec));
      const trajectoryFrame = courseOption.trajectoryFrame || null;
      const usesCentralBodyRelativeFrame =
        trajectoryFrame?.mode === 'centralBodyRelative' &&
        Array.isArray(trajectoryFrame.relativePositions) &&
        trajectoryFrame.relativePositions.length > 0;

      if (usesCentralBodyRelativeFrame) {
        const relativePositions = trajectoryFrame.relativePositions;
        const centralBody = (this.bodies || []).find((body) => body?.name === trajectoryFrame.centralBodyName);
        if (!centralBody) return null;

        const dt = Number(courseOption.dt || trajectoryFrame.pathDt || (transferTimeSec / Math.max(1, relativePositions.length - 1)));
        const scaledIndex = clamp(transferElapsed / Math.max(1e-6, dt), 0, Math.max(0, relativePositions.length - 1));
        const index0 = Math.floor(scaledIndex);
        const index1 = Math.min(index0 + 1, relativePositions.length - 1);
        const alpha = scaledIndex - index0;

        const relativePosition = index0 === index1
          ? relativePositions[index0].clone()
          : BABYLON.Vector3.Lerp(relativePositions[index0], relativePositions[index1], alpha);

        const missionDate = new Date(this.getCourseReferenceEpochMs() + (clampedMissionElapsed * 1000));
        const centralState = this.getBodyStateAtDate(centralBody, missionDate);

        return {
          position: centralState.position.add(relativePosition),
          velocity: centralState.velocity.clone()
        };
      }

      const positions = Array.isArray(courseOption.positions) ? courseOption.positions : [];
      if (positions.length === 0) return null;

      const dt = Number(courseOption.dt || (transferTimeSec / Math.max(1, positions.length - 1)));
      const scaledIndex = clamp(transferElapsed / Math.max(1e-6, dt), 0, Math.max(0, positions.length - 1));
      const index0 = Math.floor(scaledIndex);
      const index1 = Math.min(index0 + 1, positions.length - 1);
      const alpha = scaledIndex - index0;

      const p0 = positions[index0].clone().scale(1 / DISTANCE_SCALE);
      const p1 = positions[index1].clone().scale(1 / DISTANCE_SCALE);

      return {
        position: index0 === index1 ? p0 : BABYLON.Vector3.Lerp(p0, p1, alpha),
        velocity: this.velocity.clone()
      };
    },

    buildShipTrajectoryWorldPath(courseOption, sampleCount = 72) {
      if (!courseOption) return [];

      const totalMissionTime = Number(courseOption.totalMissionTime || (courseOption.departureOffsetSec || 0) + (courseOption.timeOfFlight || 0));
      if (!Number.isFinite(totalMissionTime) || totalMissionTime <= 0) {
        return [];
      }

      const points = [];
      for (let index = 0; index <= sampleCount; index += 1) {
        const elapsed = totalMissionTime * (index / sampleCount);
        const state = this.sampleCoursePreviewWorldStateAtElapsed(courseOption, elapsed);
        if (!state?.position) continue;
        points.push(state.position.clone());
      }

      return points;
    },

    buildTargetTrajectoryWorldPath(courseOption, sampleCount = 72) {
      const targetObject = courseOption?.targetPlanet || courseOption?.targetObject || this.target;
      if (!targetObject) return [];

      const totalMissionTime = Number(courseOption.totalMissionTime || (courseOption.departureOffsetSec || 0) + (courseOption.timeOfFlight || 0));
      const referenceEpoch = this.getCourseReferenceEpochMs();

      const points = [];
      for (let index = 0; index <= sampleCount; index += 1) {
        const elapsed = totalMissionTime * (index / sampleCount);
        const sampleDate = new Date(referenceEpoch + (elapsed * 1000));
        const state = this.getObjectStateAtDate(targetObject, sampleDate);
        if (!state?.position) continue;
        points.push(state.position.clone());
      }

      return points;
    },

    _clearTrajectoryVisuals() {
      const visuals = Array.isArray(this.trajectoryVizElements) ? this.trajectoryVizElements : [];
      visuals.forEach((element) => {
        try {
          element?.dispose?.();
        } catch (error) {
          console.warn('Unable to dispose trajectory visual.', error);
        }
      });

      this.trajectoryVizElements = [];
      this.previewedCourseOption = null;
      this.spaceshipTrajectory = null;
    },

    getTrajectoryVisualPalette(courseOption = null) {
      const highContrast = !!this.game?.userSettings?.highContrastTrajectories;
      const rawStrategy = String(
        courseOption?.profile ||
        courseOption?.strategy ||
        courseOption?.optimizationStrategy ||
        courseOption?.courseProfile ||
        'balanced'
      ).toLowerCase();

      const strategy = /fast|time/.test(rawStrategy)
        ? 'fastest'
        : /effic|fuel|delta/.test(rawStrategy)
          ? 'efficient'
          : 'balanced';

      const palettes = highContrast
        ? {
            fastest: { ship: [1, 0.38, 0.02], target: [1, 0.85, 0.05], connector: [1, 1, 1], marker: [1, 0.82, 0.1] },
            efficient: { ship: [0.05, 1, 0.34], target: [0.5, 1, 0.75], connector: [1, 1, 1], marker: [0.25, 1, 0.55] },
            balanced: { ship: [0.05, 0.72, 1], target: [0.35, 0.92, 1], connector: [1, 1, 1], marker: [0.2, 0.85, 1] }
          }
        : {
            fastest: { ship: [1, 0.45, 0.08], target: [1, 0.69, 0.24], connector: [1, 0.9, 0.48], marker: [1, 0.75, 0.15] },
            efficient: { ship: [0.24, 0.9, 0.47], target: [0.45, 0.8, 0.62], connector: [0.72, 0.95, 0.8], marker: [0.34, 0.94, 0.56] },
            balanced: { ship: [0.26, 0.88, 1], target: [1, 0.68, 0.22], connector: [1, 0.92, 0.45], marker: [1, 0.78, 0.18] }
          };

      return { strategy, ...palettes[strategy] };
    },

    configureTrajectoryPreviewMesh(mesh, role = 'trajectory') {
      if (!mesh) return mesh;

      mesh.isPickable = false;
      mesh.alwaysSelectAsActiveMesh = true;
      mesh.renderingGroupId = 2;
      mesh.metadata = {
        ...(mesh.metadata || {}),
        visualRole: 'trajectory',
        trajectoryRole: role,
        shipId: this.id || this.name
      };

      return mesh;
    },

    refreshTrajectoryVisualStyle(courseOption = this.previewedCourseOption || this.currentCourseOption || null) {
      const palette = this.getTrajectoryVisualPalette(courseOption);
      (this.trajectoryVizElements || []).forEach(element => {
        const role = element?.metadata?.trajectoryRole;
        const values = role === 'target'
          ? palette.target
          : role === 'connector' || role === 'cross'
            ? palette.connector
            : role === 'marker' || role === 'burn'
              ? palette.marker
              : palette.ship;
        if (element?.color && values) element.color = new BABYLON.Color3(...values);
        if (element?.material?.emissiveColor && values) {
          element.material.emissiveColor = new BABYLON.Color3(...values);
        }
      });
      return palette;
    },

    plotSpaceshipTrajectory(courseOption) {
      const BABYLON = window.BABYLON;
      const scene = this.game?.scene;

      if (!scene || !courseOption) {
        return false;
      }

      this._clearTrajectoryVisuals();

      const shipWorldPoints = this.buildShipTrajectoryWorldPath(courseOption, 80);
      const targetWorldPoints = this.buildTargetTrajectoryWorldPath(courseOption, 80);

      if (shipWorldPoints.length < 2) {
        return false;
      }

      const shipRenderPoints = shipWorldPoints.map((point) => point.clone().scale(DISTANCE_SCALE));
      const targetRenderPoints = targetWorldPoints.map((point) => point.clone().scale(DISTANCE_SCALE));

      const palette = this.getTrajectoryVisualPalette(courseOption);

      const shipArc = BABYLON.MeshBuilder.CreateLines(`${this.name}-ship-trajectory`, {
        points: shipRenderPoints,
        updatable: false
      }, scene);
      shipArc.color = new BABYLON.Color3(...palette.ship);
      shipArc.alpha = 0.95;
      this.configureTrajectoryPreviewMesh(shipArc, 'ship');

      const visuals = [shipArc];
      this.spaceshipTrajectory = shipArc;

      if (targetRenderPoints.length >= 2) {
        const targetArc = BABYLON.MeshBuilder.CreateLines(`${this.name}-target-trajectory`, {
          points: targetRenderPoints,
          updatable: false
        }, scene);
        targetArc.color = new BABYLON.Color3(...palette.target);
        targetArc.alpha = 0.7;
        this.configureTrajectoryPreviewMesh(targetArc, 'target');
        visuals.push(targetArc);
      }

      const shipInterceptPoint = shipWorldPoints[shipWorldPoints.length - 1];
      const targetInterceptPoint = targetWorldPoints.length > 0
        ? targetWorldPoints[targetWorldPoints.length - 1]
        : shipInterceptPoint.clone();

      const markerPosition = BABYLON.Vector3.Lerp(shipInterceptPoint, targetInterceptPoint, 0.5).scale(DISTANCE_SCALE);
      const interceptMarker = BABYLON.MeshBuilder.CreateSphere(`${this.name}-intercept-marker`, {
        diameter: Math.max(0.04, (this.radius || 0.02) * 0.65),
        segments: 12
      }, scene);
      interceptMarker.position.copyFrom(markerPosition);
      this.configureTrajectoryPreviewMesh(interceptMarker, 'marker');

      const markerMaterial = new BABYLON.StandardMaterial(`${this.name}-intercept-marker-mat`, scene);
      markerMaterial.emissiveColor = new BABYLON.Color3(...palette.marker);
      markerMaterial.diffuseColor = new BABYLON.Color3(0.22, 0.18, 0.04);
      interceptMarker.material = markerMaterial;
      visuals.push(interceptMarker);

      const interceptConnector = BABYLON.MeshBuilder.CreateLines(`${this.name}-intercept-link`, {
        points: [
          shipInterceptPoint.clone().scale(DISTANCE_SCALE),
          targetInterceptPoint.clone().scale(DISTANCE_SCALE)
        ]
      }, scene);
      interceptConnector.color = new BABYLON.Color3(...palette.connector);
      interceptConnector.alpha = 0.7;
      this.configureTrajectoryPreviewMesh(interceptConnector, 'connector');
      visuals.push(interceptConnector);

      const crossSize = Math.max(0.05, (this.radius || 0.02) * 0.9);
      const crossX = BABYLON.MeshBuilder.CreateLines(`${this.name}-intercept-cross-x`, {
        points: [
          markerPosition.add(new BABYLON.Vector3(-crossSize, 0, 0)),
          markerPosition.add(new BABYLON.Vector3(crossSize, 0, 0))
        ]
      }, scene);
      crossX.color = new BABYLON.Color3(...palette.connector);
      this.configureTrajectoryPreviewMesh(crossX, 'cross');

      const crossY = BABYLON.MeshBuilder.CreateLines(`${this.name}-intercept-cross-y`, {
        points: [
          markerPosition.add(new BABYLON.Vector3(0, -crossSize, 0)),
          markerPosition.add(new BABYLON.Vector3(0, crossSize, 0))
        ]
      }, scene);
      crossY.color = new BABYLON.Color3(...palette.connector);
      this.configureTrajectoryPreviewMesh(crossY, 'cross');

      visuals.push(crossX, crossY);

      if (courseOption.assistPlan?.flybyEpochSec != null) {
        const totalMissionTime = Number(
          courseOption.totalMissionTime ||
          (courseOption.departureOffsetSec || 0) + (courseOption.timeOfFlight || 0)
        );

        const assistMissionElapsed = Math.max(
          0,
          Math.min(courseOption.assistPlan.flybyEpochSec, totalMissionTime)
        );

        const flybyState = this.sampleCoursePreviewWorldStateAtElapsed(
          courseOption,
          assistMissionElapsed
        );

        if (flybyState?.position) {
          const flybyMarker = BABYLON.MeshBuilder.CreateSphere(`${this.name}-flyby-marker`, {
            diameter: Math.max(0.035, (this.radius || 0.02) * 0.55),
            segments: 10
          }, scene);

          flybyMarker.position.copyFrom(flybyState.position.clone().scale(DISTANCE_SCALE));
          this.configureTrajectoryPreviewMesh(flybyMarker, 'burn');

          const flybyMaterial = new BABYLON.StandardMaterial(`${this.name}-flyby-marker-mat`, scene);
          flybyMaterial.emissiveColor = new BABYLON.Color3(...palette.marker);
          flybyMaterial.diffuseColor = new BABYLON.Color3(0.08, 0.20, 0.26);
          flybyMarker.material = flybyMaterial;

          visuals.push(flybyMarker);
        }
      }

      this.previewedCourseOption = courseOption;
      this.trajectoryVizElements = visuals;
      this.refreshTrajectoryVisualStyle(courseOption);
      return true;
    },

    async plotInterceptByDeltaV(
      targetObject,
      maneuverType = 'intercept',
      constraints = { strategy: 'time', minDays: 60, maxDays: 300 }
    ) {
      return this.game.interceptManager.plotShipIntercept(
        this,
        targetObject,
        maneuverType,
        constraints
      );
    },

    getCourseWindowTitle() {
      const firstOption = this.courseOptions[0] || null;
      const targetName =
        firstOption?.targetObject?.name ||
        firstOption?.targetPlanet?.name ||
        this.target?.name ||
        'Target';

      return `Course Options: ${this.name} to ${targetName}`;
    },

    getDisplayableCourseOptions() {
      const maxDeltaV = this.getEffectiveDeltaV();
      return [...this.courseOptions]
        .sort((a, b) => a.totalDeltaV - b.totalDeltaV)
        .map((option, index) => {
          const targetBody = option.targetPlanet || option.targetObject || this.target || null;
          const targetRadius = targetBody?.radius || 0;
          const immediateDeltaV = this.getImmediateCourseDeltaV(option);
          const isAffordable = this.canStartCourseOption(option);
          const canCompleteMission = maxDeltaV >= option.totalDeltaV;
          const previewMissLimit = Number.isFinite(option.previewMissLimit)
            ? option.previewMissLimit
            : Math.max(targetRadius * 20, 1000000);

          const hasPoorAccuracy = Number.isFinite(option.missDistance)
            ? option.missDistance > previewMissLimit
            : false;

          const fuelRemainingPercent = maxDeltaV > 0
            ? Math.min(100, (maxDeltaV / option.totalDeltaV) * 100)
            : 0;

          let profileLabel = 'Balanced';
          const tofDays = (option.timeOfFlight || 0) / 86400;
          const depDays = (option.departureOffsetSec || 0) / 86400;
          const totalTripDays = (option.totalMissionTime || option.timeOfFlight) / 86400;

          if (option.isGravityAssist && option.totalDeltaV < option.timeOfFlight * 0.0003) {
            profileLabel = 'Efficient';
          } else if (tofDays > 0 && depDays <= 1 && tofDays < 60) {
            profileLabel = 'Fastest';
          } else if (option.totalDeltaV > 0 && fuelRemainingPercent > 80) {
            profileLabel = 'Fastest';
          } else if (option.totalDeltaV > 0 && fuelRemainingPercent < 40) {
            profileLabel = 'Efficient';
          }

          let riskLevel = 'low';
          if (hasPoorAccuracy || fuelRemainingPercent < 25) {
            riskLevel = 'high';
          } else if (fuelRemainingPercent < 50 || option.missDistance > previewMissLimit * 0.5) {
            riskLevel = 'medium';
          }

          return {
            index,
            name: option.name,
            profileLabel,
            departureDelayDays: depDays,
            timeOfFlightDays: tofDays,
            totalTripDays,
            totalDeltaV: option.totalDeltaV,
            immediateDeltaV,
            departureDeltaV: option.departureDeltaV,
            insertionDeltaV: option.insertionDeltaV,
            missDistance: option.missDistance,
            previewMissLimit,
            isAffordable,
            canCompleteMission,
            hasPoorAccuracy,
            fuelRemainingPercent: Math.round(fuelRemainingPercent),
            riskLevel,
            targetName: targetBody?.name || 'Target',
            isGravityAssist: !!option.isGravityAssist,
            assistSummary: option.assistSummary || null,
            assistBodyName: option.assistPlan?.bodyName || null,
            assistPeriapsisKm: Number.isFinite(option.assistPlan?.achievedPeriapsis)
              ? option.assistPlan.achievedPeriapsis / 1000
              : null,
            assistEpochDays: Number.isFinite(option.assistPlan?.flybyEpochSec)
              ? option.assistPlan.flybyEpochSec / 86400
              : null,
          };
        });
    },

    displayCourseOptions() {
      this.courseOptions.sort((a, b) => a.totalDeltaV - b.totalDeltaV);

      this.game?.eventEmitter?.emit?.('shipCourseOptionsRequested', {
        ship: this,
        shipName: this.name,
        title: this.getCourseWindowTitle(),
        options: this.getDisplayableCourseOptions()
      });

      this.emitStateChanged('ship_course_options_requested', {
        courseOptionsCount: this.courseOptions.length
      });
    },

    viewTrajectoryOption(courseOption) {
      if (!courseOption) {
        return false;
      }

      if (typeof this._clearTrajectoryVisuals === 'function') {
        this._clearTrajectoryVisuals();
      }

      if (typeof this.plotSpaceshipTrajectory !== 'function') {
        console.warn(`${this.name}: plotSpaceshipTrajectory is not available for preview.`);
        return false;
      }

      this.plotSpaceshipTrajectory(courseOption);
      this.previewedCourseOption = courseOption;
      return true;
    },

    previewCourseOptionByIndex(index) {
      const option = this.courseOptions[index];
      if (!option) return false;

      if (!this.viewTrajectoryOption(option)) {
        return false;
      }

      this.selectedCoursePreviewIndex = index;

      this.game?.eventEmitter?.emit?.('shipCoursePreviewSelected', {
        ship: this,
        shipName: this.name,
        optionIndex: index,
        optionSummary: this.getDisplayableCourseOptions()[index] || null
      });

      this.emitStateChanged('ship_course_preview_selected', {
        optionIndex: index
      });

      return true;
    },

    engageCourseOptionByIndex(index, contractId = null) {
      const option = this.courseOptions[index];
      if (!option) return false;

      this.executeCourseOption(option, contractId);
      return true;
    },

    precomputeCelestialPositions(bodies, dt, totalTime) {
      const numSteps = Math.ceil(totalTime / dt);
      const positionsOverTime = [];
      const startTime = this.game.getCurrentGameDate();

      for (let step = 0; step <= numSteps; step += 1) {
        const currentTime = new Date(startTime.getTime() + step * dt * 1000);
        const stateAtTime = {};

        const planets = bodies.filter((body) => body && body.orbitalElements && (!body.orbitalElements.centralBody || body.orbitalElements.centralBody === 'Sun'));
        const moons = bodies.filter((body) => body && body.orbitalElements && body.orbitalElements.centralBody && body.orbitalElements.centralBody !== 'Sun');

        planets.forEach((planet) => {
          stateAtTime[planet.name] = this.getBodyStateAtDate(planet, currentTime);
        });

        moons.forEach((moon) => {
          const parentName = moon.orbitalElements.centralBody;
          const parentBody = this.bodies.find((body) => body.name === parentName);

          if (!parentBody) {
            stateAtTime[moon.name] = {
              position: moon.position.clone(),
              velocity: moon.velocity.clone()
            };
            return;
          }

          const parentState = stateAtTime[parentName] || this.getBodyStateAtDate(parentBody, currentTime);

          stateAtTime[moon.name] = calculateOrbitalStateVectors(
            moon.orbitalElements,
            currentTime,
            parentState.position,
            parentState.velocity,
            parentBody.mass
          );
        });

        const finalPositionsAtTime = bodies.map((body) => {
          const state = stateAtTime[body.name];
          if (state?.position) {
            return [state.position.x, state.position.y, state.position.z];
          }
          return [body.position.x, body.position.y, body.position.z];
        });

        positionsOverTime.push(finalPositionsAtTime);
      }

      return positionsOverTime;
    },

    plotInterceptCourses(targetPlanet, missionType = 'explore', desiredDateToIntercept = null) {
      console.warn('plotInterceptCourses is deprecated. Using plotInterceptByDeltaV instead.');
      const constraints = { strategy: 'time', minDays: 12, maxDays: 180, missionType };
      return this.plotInterceptByDeltaV(targetPlanet, 'intercept', constraints);
    },

    setCourse(courseOption, contractId = null) {
      const courseStartDate = this.game?.getCurrentGameDate?.();

      this.target = courseOption.targetPlanet || courseOption.targetObject;
      this.timeToArrival = courseOption.totalMissionTime || (courseOption.departureOffsetSec || 0) + courseOption.timeOfFlight;
      this.timeSinceDeparture = 0;
      this.deltaV = courseOption.totalDeltaV;
      this.finalArrivalVelocity = courseOption.finalVelocity?.clone
        ? courseOption.finalVelocity.clone()
        : courseOption.finalVelocity;
      this.currentMission = courseOption.missionType;
      this.currentManeuverType = courseOption.maneuverType || 'rendezvous';
      this.assignedContractId = contractId || null;
      this.reservedForContractId = contractId || null;
      this.courseDepartureOffsetSec = Number.isFinite(courseOption.departureOffsetSec) ? courseOption.departureOffsetSec : 0;
      this.courseTransferTimeOfFlight = courseOption.timeOfFlight;
      this.activeCourseOption = courseOption;
      this.plannedDepartureDeltaV = courseOption.departureDeltaV;
      this.plannedDepartureVelocity = courseOption.initialVelocity?.clone?.() || null;
      this.plannedDepartureStatePosition = courseOption.departureStatePosition?.clone?.() || null;
      this.plannedDepartureStateVelocity = courseOption.departureStateVelocity?.clone?.() || null;
      this.courseReferenceEpochMs = courseStartDate instanceof Date ? courseStartDate.getTime() : Date.now();

      this.plotSpaceshipTrajectory(courseOption);

      this.currentTrajectoryPositions = Array.isArray(courseOption.positions)
        ? courseOption.positions.map((position) => position.clone())
        : null;

      this.currentTrajectoryFrame = courseOption.trajectoryFrame
        ? {
          ...courseOption.trajectoryFrame,
          relativePositions: Array.isArray(courseOption.trajectoryFrame.relativePositions)
            ? courseOption.trajectoryFrame.relativePositions.map((position) => position.clone())
            : [],
          finalRelativeVelocity: courseOption.trajectoryFrame.finalRelativeVelocity?.clone
            ? courseOption.trajectoryFrame.finalRelativeVelocity.clone()
            : null,
          initialRelativeVelocity: courseOption.trajectoryFrame.initialRelativeVelocity?.clone
            ? courseOption.trajectoryFrame.initialRelativeVelocity.clone()
            : null
        }
        : null;

      this.currentTrajectoryDt = Number.isFinite(courseOption.dt) && courseOption.dt > 0
        ? courseOption.dt
        : (
          courseOption.positions?.length > 1
            ? courseOption.timeOfFlight / (courseOption.positions.length - 1)
            : courseOption.timeOfFlight
        );

      this.currentTrajectoryIndex = 0;
      this.midCourseUpdateDone = false;

      if (this.courseDepartureOffsetSec > 0) {
        this.courseLaunchExecuted = false;
      } else {
        if (!this.consumeFuel(courseOption.departureDeltaV)) {
          this.notify(`${this.name} lacks fuel for departure burn.`, 'error');
          this.clearNavigation();
          return;
        }

        if (this.plannedDepartureStatePosition?.clone) {
          this.position = this.plannedDepartureStatePosition.clone();
        }

        if (this.plannedDepartureVelocity?.clone) {
          this.velocity = this.plannedDepartureVelocity.clone();
        } else if (this.plannedDepartureStateVelocity?.clone) {
          this.velocity = this.plannedDepartureStateVelocity.clone();
        } else {
          const departureState = this.sampleTrajectoryStateAtTransferElapsed(0);
          if (departureState) {
            this.position = departureState.position;
            this.velocity = departureState.velocity;
          } else {
            this.velocity = courseOption.initialVelocity.clone();
          }
        }

        this.currentOrbitingBody = null;
        this.courseLaunchExecuted = true;
        this.syncRenderedPosition?.();
      }

      this.emitStateChanged('ship_course_set', {
        courseOption,
        contractId
      });
    },

    executeCourseOption(courseOption, contractId) {
      const requiredImmediateDeltaV = this.getImmediateCourseDeltaV(courseOption);

      if (this.getEffectiveDeltaV() < requiredImmediateDeltaV) {
        this.notify('Not enough fuel for departure burn!', 'error');
        console.error(`${this.name} needs ${requiredImmediateDeltaV} ΔV but only has ${this.getEffectiveDeltaV()}`);
        return;
      }

      this._clearTrajectoryVisuals();
      this.setCourse(courseOption, contractId);
      this.updateStatus('transiting', `En route to ${(courseOption.targetPlanet || courseOption.targetObject).name}`);

      const departureDelayDays = (courseOption.departureOffsetSec || 0) / 86400;
      const assistText = courseOption.isGravityAssist && courseOption.assistPlan?.bodyName
        ? ` via gravity assist at ${courseOption.assistPlan.bodyName}`
        : '';

      if (departureDelayDays > 0) {
        this.notify(
          `${this.name} is holding for ${departureDelayDays.toFixed(1)} days before departing for ${(courseOption.targetPlanet || courseOption.targetObject).name}.`,
          'info',
          true
        );

        this.emitStateChanged('ship_departure_scheduled', {
          courseOption,
          contractId,
          departureDelayDays
        });
      } else {
        this.notify(
          `${this.name} is now en route to ${(courseOption.targetPlanet || courseOption.targetObject).name}${assistText}. Cost: ${(courseOption.departureDeltaV / 1000).toFixed(2)} km/s ΔV.`,
          'success',
          true
        );

        this.emitStateChanged('ship_departed', {
          courseOption,
          contractId
        });
      }
    },

    updateCourse() {
      if (!this.target) {
        console.log('No target to update course for.');
        return;
      }

      if (this.hasDelayedCourseDeparture() && !this.courseLaunchExecuted) {
        console.log('Skipping mid-course update before delayed departure burn.');
        return;
      }

      const remainingTimeDays = this.getRemainingTimeToArrivalDays();

      this.plotInterceptByDeltaV(this.target, this.currentManeuverType || 'intercept', {
        strategy: 'time',
        minDays: remainingTimeDays,
        maxDays: remainingTimeDays,
        minDepartureDelayDays: 0,
        maxDepartureDelayDays: 0,
        missionType: this.currentMission
      }).then((courseOptions) => {
        if (courseOptions && courseOptions.length > 0) {
          const bestOption = courseOptions.reduce((previous, current) => previous.totalDeltaV < current.totalDeltaV ? previous : current);
          if (this.canStartCourseOption(bestOption)) {
            this.executeCourseOption(bestOption, this.assignedContractId || this.reservedForContractId || null);
            console.log(`${this.name} has updated its course mid-flight.`);
          } else {
            console.warn(`${this.name} cannot afford mid-course correction.`);
          }
        } else {
          console.log('No updated course available.');
        }
      }).catch((error) => {
        console.error(`Error updating course: ${error}`);
      });
    }
  };
}


// ===== public/classes/Spaceship.js =====





class Spaceship {
  constructor(name, className, mass, position, velocity, textureUrl, scene, bodies, spaceshipOrbitalElements, owner, type = 'default', components = {}) {
    this.name = name;
    this.class = className;
    this.type = type;
    this.mass = mass;
    this.bodies = bodies;
    this.position = position;
    this.velocity = velocity;
    this.orbitalElements = spaceshipOrbitalElements;
    this.textureUrl = textureUrl;
    this.owner = owner;
    this.assignedContractId = null;
    this.reservedForContractId = null;
    this.assignedBuildingName = null;
    this.game = null;
    this.trajectoryVizElements = [];
    this.preCombatStatus = null;
    this.escrowCredits = 0;
    this.escrowPurpose = null;
    this.lastProspectingWarningTurn = -1;

    this.courseDepartureOffsetSec = 0;
    this.courseTransferTimeOfFlight = 0;
    this.courseLaunchExecuted = false;
    this.plannedDepartureDeltaV = 0;
    this.plannedDepartureVelocity = null;
    this.plannedDepartureStatePosition = null;
    this.plannedDepartureStateVelocity = null;
    this.courseReferenceEpochMs = null;

    this.components = components || {};
    this.hull = this.resolveHullComponent();
    this.engine = this.components.engine || { type: 'Standard', efficiency: 1.0, fuelEfficiency: 1.0, thrust: 100 };
    this.armor = this.components.armor || null;
    this.sensor = this.components.sensor || null;
    this.quarters = this.components.quarters || null;
    this.pds = this.components.pds || null;
    this.interceptRadiusMeters = this.hull?.interceptRadiusMeters || 25000;
    this.weapons = (this.components.weapons || []).map((weapon) => ({
      ...weapon,
      currentCooldown: 0,
      ammo: weapon.ammo === -1 ? Infinity : weapon.ammo
    }));

    this.fuelCapacity = this.components.fuel ? this.components.fuel.capacity : 50000;
    this.currentFuel = this.fuelCapacity;
    this.cargoCapacity = this.components.storage ? this.components.storage.capacity : 100;
    this.cargo = {};

    this.maxHullHP = 100;
    this.hullHP = this.maxHullHP;
    this.maxArmorHP = this.armor ? this.armor.defense : 0;
    this.armorHP = this.maxArmorHP;
    this.combat = {
      isInCombat: false,
      isEvading: false,
      isRetreating: false,
      heat: 0,
      maxHeat: 100
    };

    this.status = 'idle';
    this.target = null;
    this.timeToArrival = null;
    this.timeSinceDeparture = 0;
    this.finalArrivalVelocity = null;
    this.isColonyShip = type === 'colony';
    this.transportTask = null;
    this.currentOrbitingBody = null;
    this.distanceTraveled = 0;
    this.midCourseUpdateDone = false;
    this.courseOptions = [];
    this.currentManeuverType = null;
    this.currentTrajectoryPositions = null;
    this.currentTrajectoryFrame = null;
    this.currentTrajectoryDt = 0;
    this.currentTrajectoryIndex = 0;
    this.currentMission = null;
    this.selectedCoursePreviewIndex = null;
    this.missionQueue = [];
    this.activeMissionOrder = null;
    this.missionHistory = [];
    this.automationPolicy = {
      enabled: false,
      homeBodyName: null,
      patrolBodyNames: [],
      minimumFuelReservePercent: 25,
      repairThresholdPercent: 70,
      engagementPolicy: 'defensive',
      autoRefuel: true,
      autoRepair: true,
      loopPatrol: true
    };
    this.combatDoctrine = null;

    this.initializePowerSystems?.();
    this.initializeSubsystemState?.();
    this.combatDoctrine = this.createDefaultCombatDoctrine?.() || null;

    this.mesh = this.createProceduralShipMesh(scene);
    this.radius = this.estimateRadius();
    this._renderPositionScratch = new BABYLON.Vector3(0, 0, 0);
    this.syncRenderedPosition();

    const powerSummary = this.getPowerBudgetSnapshot?.();
    this.mesh.metadata = {
      ...(this.mesh.metadata || {}),
      ship: this,
      velocity: this.velocity,
      shipName: this.name,
      shipType: this.type,
      shipClass: this.class,
      componentSummary: {
        engine: this.engine?.type || null,
        armor: this.armor?.type || null,
        sensor: this.sensor?.type || null,
        cargoCapacity: this.cargoCapacity,
        fuelCapacity: this.fuelCapacity,
        weaponCount: this.weapons.length,
        miningRig: this.components?.mining?.name || null,
        prospectingCapable: !!(
          this.sensor && (
            String(this.sensor?.name || '').toLowerCase().includes('advanced') ||
            Number(this.sensor?.detectionRange || 0) >= 150000000
          )
        )
      },
      powerSummary: powerSummary
        ? {
          mode: powerSummary.mode,
          reactorOutput: powerSummary.reactorOutput,
          totalDemand: powerSummary.totalDemand,
          margin: powerSummary.margin
        }
        : null
    };
    this.applyShipMetadataToMeshTree(this.mesh);
  }

  syncRenderedPosition(worldPosition = this.position) {
    if (!this.mesh || !worldPosition) return;
    this._renderPositionScratch.copyFrom(worldPosition);
    this._renderPositionScratch.scaleInPlace(DISTANCE_SCALE);
    this.mesh.position.copyFrom(this._renderPositionScratch);
  }
}

Object.assign(Spaceship.prototype, spaceshipVisualMethods);
Object.assign(Spaceship.prototype, spaceshipSystemMethods);
Object.assign(
  Spaceship.prototype,
  createSpaceshipNavigationMethods({
    G,
    DISTANCE_SCALE,
    calculateHohmannTransfer,
    calculateOrbitalStateVectors
  })
);

const originalOnArriveAtTarget = Spaceship.prototype.onArriveAtTarget;

if (typeof originalOnArriveAtTarget === 'function') {
  Spaceship.prototype.onArriveAtTarget = function onArriveAtTargetWithManualHumanSurvey(...args) {
    const game = this.game;
    const owner = this.owner;
    const shouldBlockAutoProspecting = !!game
      && !!owner
      && !owner.isAI
      && this.activeMissionOrder?.type !== 'survey'
      && typeof game.performProspectingScan === 'function';

    let originalPerformProspectingScan = null;

    if (shouldBlockAutoProspecting) {
      originalPerformProspectingScan = game.performProspectingScan;

      game.performProspectingScan = (payload = {}) => {
        const payloadShip = payload.ship || this;

        if (payloadShip === this) {
          const targetBody = payload.targetBody
            || this.target?.body
            || this.currentOrbitingBody
            || this.target;

          if (targetBody?.name) {
            if (this.lastProspectingWarningTurn !== game.turnNumber) {
              this.lastProspectingWarningTurn = game.turnNumber;
              game.notify?.(
                `${this.name} arrived at ${targetBody.name}. Prospecting is now manual for player-controlled ships — use Scan / Survey to characterize the site.`,
                'info',
                false,
                { ship: this, targetBody }
              );
            }

            return null;
          }
        }

        return originalPerformProspectingScan.call(game, payload);
      };
    }

    try {
      return originalOnArriveAtTarget.apply(this, args);
    } finally {
      if (originalPerformProspectingScan) {
        game.performProspectingScan = originalPerformProspectingScan;
      }
    }
  };
}
Spaceship;


// ===== public/classes/ConstructionShip.js =====

class ConstructionShip extends Spaceship {
    constructor(
        name, // Unique ship name
        className,
        mass,
        position,
        velocity,
        textureUrl,
        scene,
        bodies,
        spaceshipOrbitalElements,
        owner,
        type = 'construction', // Default type for construction ships
        components = {}
    ) {
        super(
            name,
            className,
            mass,
            position,
            velocity,
            textureUrl,
            scene,
            bodies,
            spaceshipOrbitalElements,
            owner,
            type,
            components
        );
    }

    async constructBuilding() {
        if (!this.currentOrbitingBody) {
            console.error(`Construction ship ${this.name} is not orbiting any body.`);
            showToast(`Construction ship ${this.name} is not orbiting any body.`, 'error');
            return;
        }

        if (!this.assignedBuildingName) {
            console.error(`Construction ship ${this.name} has no assigned building.`);
            showToast(`Construction ship ${this.name} has no assigned building.`, 'error');
            return;
        }

        console.log(`${this.name} is constructing ${this.assignedBuildingName} on ${this.currentOrbitingBody.name}.`);

        try {
            const success = this.game.buildBuildingOnPlanet(
                this.currentOrbitingBody,
                this.assignedBuildingName,
                this.owner,
                {
                    constructionShip: this,  // Pass the construction ship to be disposed
                    forceBuild: true  // Force build since we're using a construction ship
                }
            );

            if (success) {
                showToast(
                    `${this.owner.name} constructed building ${this.assignedBuildingName} on ${this.currentOrbitingBody.name}`,
                    'success'
                );

                if (this.assignedContract) {
                    this.assignedContract.checkCompletion(this.game);
                }
            }
        } catch (error) {
            console.error(`Error during construction by ${this.name}:`, error);
        }
    }
    plotCourse(targetBody) {
        super.plotCourse(targetBody, 'build');
        this.target = targetBody; // Assign the target for colonization
    }
}ConstructionShip;


// ===== public/classes/managers/SpaceshipManager.js =====
// public/classes/managers/SpaceshipManager.js
class SpaceshipManager {
  constructor(game) {
    this.game = game;
    this.spaceships = [];
    this.spaceshipOrbitalElements = {
      semiMajorAxis: 400000000,
      eccentricity: 0,
      inclination: 0,
      longitudeOfAscendingNode: 0,
      argumentOfPeriapsis: 0,
      meanAnomalyAtEpoch: 0,
      epoch: 2451545.0,
    };
    this.vfxHandler = this.game.vfxHandler;
    this.nextShipEntityId = 1;
  }

  generateUniqueShipName(prefix) {
    // Initialize a counter on the manager if it doesn't exist
    this.shipCounter = this.shipCounter || 0;
    this.shipCounter++;

    // Grab the first word of the class name (e.g., "Pathfinder Scout" -> "Pathfinder")
    const baseName = prefix.split(' ')[0].replace(/[^a-zA-Z0-9-]/g, '');

    return `${baseName}-${this.shipCounter}`;
  }

  createSpaceships() {
    this.createPlayerSpaceship();

    // Only give AI starting ships if Phase 1 is over (or disabled)
    if (!this.game.isPhaseOneActive?.()) {
      const aiPlayers = this.game.players.filter(p => p.isAI);
      aiPlayers.forEach(aiPlayer => {
        this.createAISpaceship(aiPlayer, 'explorer');
        this.createAISpaceship(aiPlayer, 'construction');
      });
    }

    this.game.windowManager?.refreshHud?.();
  }

  createSpaceship(options) {
    const {
      type,
      className,
      name,
      centralBodyName,
      orbitalElements,
      position,
      velocity,
      textureUrl,
      owner,
      mass,
      components,
      blueprint,
    } = options;

    let shipBlueprint = blueprint;
    if (!shipBlueprint) {
      shipBlueprint = this.game.shipBlueprints.find((s) => s.class === className && s.type === type);
      if (!shipBlueprint) {
        console.error(`Ship blueprint for type "${type}" and class "${className}" not found.`);
        return;
      }
    }

    const shipMass = mass || shipBlueprint.mass || 1e5;
    const shipComponents = components || shipBlueprint.components;
    const shipTextureUrl = textureUrl || shipBlueprint.textureUrl;

    let shipPosition = position;
    let shipVelocity = velocity;

    if (!shipPosition || !shipVelocity) {
      if (!centralBodyName || !orbitalElements) {
        console.error(`Either position and velocity, or centralBodyName and orbitalElements must be provided for ship "${name}".`);
        return;
      }

      const centralBody = this.game.bodies.find((b) => b.name === centralBodyName);
      if (!centralBody) {
        console.error(`Central body "${centralBodyName}" not found for spaceship "${name}".`);
        return;
      }

      ({ position: shipPosition, velocity: shipVelocity } = calculateOrbitalStateVectors(
        orbitalElements,
        this.game.getCurrentGameDate(),
        centralBody.position,
        centralBody.velocity,
        centralBody.mass
      ));
    }

    let SpaceshipClass = Spaceship;
    if (type === 'construction' || type === 'colony') {
      SpaceshipClass = ConstructionShip;
    }

    const spaceship = new SpaceshipClass(
      name,
      className,
      shipMass,
      shipPosition,
      shipVelocity,
      shipTextureUrl,
      this.game.scene,
      this.game.bodies,
      orbitalElements,
      owner,
      type.toLowerCase(),
      shipComponents
    );

    spaceship.game = this.game;
    spaceship.id = spaceship.id || `ship_${String(this.nextShipEntityId++).padStart(5, '0')}`;
    spaceship.entityType = 'ship';

    if (centralBodyName) {
      const orbitingBody = this.game.bodies.find(body => body.name === centralBodyName);
      if (orbitingBody) {
        spaceship.currentOrbitingBody = orbitingBody;
      }
    }

    // ENGINE_GLOW: commented out - can be restored later
    // this.vfxHandler?.createEngineGlow?.(spaceship.mesh);

    this.spaceships.push(spaceship);
    createLabel(this.game, spaceship, 'spaceship');

    console.log(`${type.charAt(0).toUpperCase() + type.slice(1)} "${name}" created for ${owner.name}.`);
    showToast(`${type.charAt(0).toUpperCase() + type.slice(1)} "${name}" created.`);
    this.game.eventEmitter.emit('shipAdded', spaceship);
    this.game.windowManager?.refreshHud?.();
  }

  createPlayerSpaceship() {
    const player = this.game.players.find(p => !p.isAI);
    if (!player) {
      console.error('Player not found.');
      showToast('Error: Player not found.', 'error');
      return;
    }

    const blueprint = this.game.shipBlueprints.find(bp => bp.type === 'explorer');
    if (!blueprint) {
      console.error('No explorer blueprint found for starting player ship.');
      return;
    }

    const uniqueShipName = this.generateUniqueShipName(blueprint.class);

    this.createSpaceship({
      type: blueprint.type,
      className: blueprint.class,
      name: uniqueShipName,
      centralBodyName: 'Earth',
      orbitalElements: this.spaceshipOrbitalElements,
      textureUrl: blueprint.textureUrl,
      owner: player,
      blueprint: blueprint
    });
  }

  createAISpaceship(aiPlayer, type) {
    let blueprint;
    let textureUrl;

    if (type === 'explorer') {
      blueprint = this.game.shipBlueprints.find(bp => bp.type === 'explorer');
      textureUrl = blueprint?.textureUrl || 'img/textures/ai_ship.png';
    } else if (type === 'construction') {
      blueprint = this.game.shipBlueprints.find(bp => bp.type === 'construction');
      textureUrl = blueprint?.textureUrl || 'img/textures/basic_colony_ship.png';
    }

    if (!blueprint) {
      console.error(`AI could not find a blueprint for a starting '${type}' ship.`);
      return;
    }

    const uniqueShipName = this.generateUniqueShipName(blueprint.class);

    const orbitalElements = {
      ...this.spaceshipOrbitalElements,
      meanAnomalyAtEpoch: this.game.random() * 360,
    };

    this.createSpaceship({
      type: blueprint.type,
      className: blueprint.class,
      name: uniqueShipName,
      centralBodyName: 'Earth',
      orbitalElements: orbitalElements,
      textureUrl: textureUrl,
      owner: aiPlayer,
      blueprint: blueprint
    });
  }

  addSpaceship(spaceship) {
    this.spaceships.push(spaceship);
    createLabel(this.game, spaceship, 'spaceship');
    this.game.eventEmitter.emit('shipAdded', spaceship);
    this.game.windowManager?.refreshHud?.();
  }

  removeSpaceship(ship) {
    if (!ship) return;

    const labelId = `#label-${ship.name.replace(/[^a-zA-Z0-9-]/g, '-').toLowerCase()}`;
    const labelElement = $(labelId);
    if (labelElement.length > 0) {
      labelElement.remove();
    }

    if (ship.spaceshipTrajectory) {
      ship.spaceshipTrajectory.dispose();
    }

    if (ship.mesh) {
      // ENGINE_GLOW: commented out - can be restored later
      // if (ship.mesh.engineGlow) {
      //   ship.mesh.engineGlow.stop();
      //   ship.mesh.engineGlow.dispose();
      // }
      if (ship.mesh.material) {
        ship.mesh.material.dispose();
      }
      ship.mesh.dispose();
    }

    const index = this.spaceships.indexOf(ship);
    if (index > -1) {
      this.spaceships.splice(index, 1);
    }

    if (this.game.selectedSpaceship === ship) {
      this.game.selectedSpaceship = null;
    }

    if (this.game.focusedObject === ship) {
      this.game.focusedObject = null;
    }

    if ($('#course-window').length > 0 && this.game.windowManager.infoWindow.currentlySelectedObject === ship.name) {
      this.game.windowManager.closeWindow('course-window');
    }

    if (ship.transportTask) {
      ship.transportTask = null;
    }

    if (ship.owner && ship.owner.fleet) {
      const fleetIndex = ship.owner.fleet.indexOf(ship);
      if (fleetIndex > -1) {
        ship.owner.fleet.splice(fleetIndex, 1);
      }
    }

    this.game.eventEmitter.emit('shipRemoved', ship);
    console.log(`Ship ${ship.name} has been completely removed from the game.`);
    this.game.windowManager?.refreshHud?.();
  }

  updateSpaceships(inGameDays) {
    const shipsToUpdate = [...this.spaceships];
    shipsToUpdate.forEach(spaceship => {
      spaceship.updatePosition(this.game.bodies, inGameDays);
    });
  }

  getShipByIdOrName(reference) {
    if (!reference) return null;
    if (typeof reference === 'object') return reference;
    return this.spaceships.find(ship => ship.id === reference || ship.name === reference) || null;
  }

  issueMission(shipReference, missionOrder, options = {}) {
    const ship = this.getShipByIdOrName(shipReference);
    if (!ship || ship.isDestroyed?.()) {
      this.game.notify?.('Unable to issue mission: ship not found or destroyed.', 'error');
      return false;
    }
    if (missionOrder?.contractId && ship.reservedForContractId && ship.reservedForContractId !== missionOrder.contractId) {
      this.game.notify?.(`${ship.name} is reserved for another contract.`, 'warning');
      return false;
    }
    return ship.queueMissionOrder?.(missionOrder, options) || false;
  }

  configureShipAutomation(shipReference, policy = {}) {
    const ship = this.getShipByIdOrName(shipReference);
    if (!ship) return false;
    ship.setAutomationPolicy?.(policy);
    return true;
  }

  getFriendlyServiceColonies(ship, { requireFuel = false, requireShipyard = false } = {}) {
    return (ship?.owner?.colonies || []).filter(colony => {
      if (!colony?.planet) return false;
      if (requireFuel && Number(colony.getResourceAmount?.('Fuel') || 0) <= 0) return false;
      if (requireShipyard && !(colony.buildings || []).some(building => building.type === 'shipyard')) return false;
      return true;
    });
  }

  findNearestServiceColony(ship, requirements = {}) {
    const colonies = this.getFriendlyServiceColonies(ship, requirements);
    if (colonies.length === 0) return null;
    return colonies.reduce((best, colony) => {
      const distance = BABYLON.Vector3.Distance(ship.position, colony.planet.position);
      if (!best || distance < best.distance) return { colony, distance };
      return best;
    }, null)?.colony || null;
  }

  getShipAutomationReadiness(ship) {
    if (!ship) return { needsAction: false, actions: [] };
    const policy = ship.automationPolicy || {};
    const fuelPercent = (Number(ship.currentFuel || 0) / Math.max(1, Number(ship.fuelCapacity || 1))) * 100;
    const hullPercent = (Number(ship.hullHP || 0) / Math.max(1, Number(ship.maxHullHP || 1))) * 100;
    const damagedSubsystems = ship.getSubsystemSummary?.().filter(subsystem => subsystem.hp < subsystem.maxHP) || [];
    const actions = [];

    if (policy.autoRepair && (hullPercent < Number(policy.repairThresholdPercent || 70) || damagedSubsystems.some(subsystem => subsystem.disabled))) {
      actions.push({ type: 'return_repair', priority: 100, reason: `Hull ${hullPercent.toFixed(0)}% or subsystem damage.` });
    }
    if (policy.autoRefuel && fuelPercent < Number(policy.minimumFuelReservePercent || 25)) {
      actions.push({ type: 'refuel', priority: 90, reason: `Fuel reserve ${fuelPercent.toFixed(0)}%.` });
    }
    if ((policy.patrolBodyNames || []).length > 0) {
      actions.push({ type: 'patrol', priority: 20, reason: 'Standing patrol route.' });
    }

    actions.sort((a, b) => b.priority - a.priority);
    return { needsAction: actions.length > 0, actions, fuelPercent, hullPercent, damagedSubsystems };
  }

  processShipAutomation(ship) {
    const policy = ship?.automationPolicy || {};
    if (!policy.enabled || ship.isDestroyed?.() || ship.combat?.isInCombat) return false;
    if (ship.activeMissionOrder || (ship.missionQueue || []).length > 0 || ship.status === 'transiting') return false;

    const readiness = this.getShipAutomationReadiness(ship);
    const action = readiness.actions[0];
    if (!action) return false;

    if (action.type === 'return_repair') {
      const colony = this.findNearestServiceColony(ship, { requireShipyard: true });
      if (!colony) return false;
      return !!this.issueMission(ship, {
        type: 'return_repair',
        target: colony.planet,
        coursePreference: 'efficient',
        metadata: { automated: true, reason: action.reason }
      });
    }

    if (action.type === 'refuel') {
      const colony = this.findNearestServiceColony(ship, { requireFuel: true });
      if (!colony) return false;
      return !!this.issueMission(ship, {
        type: 'refuel',
        target: colony.planet,
        coursePreference: 'efficient',
        metadata: { automated: true, reason: action.reason }
      });
    }

    if (action.type === 'patrol') {
      const routeBodyNames = [...(policy.patrolBodyNames || [])];
      const firstBody = this.game.bodies.find(body => body.name === routeBodyNames[0]);
      if (!firstBody) return false;
      return !!this.issueMission(ship, {
        type: 'patrol',
        target: firstBody,
        targetName: firstBody.name,
        routeBodyNames,
        repeat: !!policy.loopPatrol,
        coursePreference: 'balanced',
        metadata: { automated: true }
      });
    }

    return false;
  }

  onNewTurn() {
    this.spaceships.forEach(ship => {
      if (ship && typeof ship.onNewTurn === 'function') {
        ship.onNewTurn();
      }
    });

    this.spaceships.forEach(ship => this.processShipAutomation(ship));
    this.game.windowManager?.refreshHud?.();
  }

  getSelectedSpaceship() {
    return this.game.selectedSpaceship;
  }

  clearSelectedSpaceship() {
    this.game.selectedSpaceship = null;
    this.game.windowManager?.refreshHud?.();
  }
}SpaceshipManager;

// ===== public/classes/managers/EventListenerManager.js =====
// public/classes/managers/EventListenerManager.js

class EventListenerManager {
    constructor(game) {
        this.game = game;
    }

    meshBelongsToItem(mesh, item) {
        if (!mesh || !item?.mesh) return false;

        let current = mesh;
        while (current) {
            if (current === item.mesh) {
                return true;
            }
            current = current.parent || null;
        }

        return false;
    }

    addEventListeners() {
        $('#endTurnButton').off('click').on('click', () => {
            this.game.commandDispatcher?.execute('endTurn');
        });

        $('#saveGameButton').off('click').on('click', () => {
            this.game.saveGameState?.();
        });

        $('#loadGameButton').off('click').on('click', () => {
            this.game.loadGameState?.();
        });

        this.game.scene.onPointerObservable.add((pointerInfo) => {
            if (pointerInfo.type !== BABYLON.PointerEventTypes.POINTERPICK || !pointerInfo.pickInfo.hit) {
                return;
            }

            const pickedMesh = pointerInfo.pickInfo.pickedMesh;
            const metadataEntity = pickedMesh?.metadata?.colony || pickedMesh?.metadata?.ship || pickedMesh?.metadata?.body || null;
            if (metadataEntity) {
                this.game.selectionManager?.select(metadataEntity, { source: 'scene-metadata-pick' });
                return;
            }

            const selectedColony = this.game.players
                .flatMap(player => player.colonies)
                .find(colony => this.meshBelongsToItem(pickedMesh, colony));

            if (selectedColony) {
                this.game.selectionManager?.select(selectedColony, { type: 'colony', source: 'scene-pick' });
                return;
            }

            const selectedShip = this.game.spaceshipManager?.spaceships.find(ship => this.meshBelongsToItem(pickedMesh, ship));
            if (selectedShip) {
                this.game.selectionManager?.select(selectedShip, { type: 'spaceship', source: 'scene-pick' });
                return;
            }

            const selectedBody = this.game.bodies.find(body => this.meshBelongsToItem(pickedMesh, body));
            if (selectedBody) {
                this.game.selectionManager?.select(selectedBody, { type: selectedBody.type, source: 'scene-pick' });
            }
        });

        $(window).on('resize', () => {
            if (this.game.engine) {
                this.game.engine.resize();
            }
        });
    }
}
EventListenerManager;


// ===== public/classes/navigation/GravityAssistPlanner.js =====
// public/classes/navigation/GravityAssistPlanner.js

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function uniqueRounded(values, quantum = 1) {
  return [...new Set(values.map((value) => Math.round(value / quantum) * quantum))];
}

class GravityAssistPlanner {
  constructor(interceptManager) {
    this.manager = interceptManager;
  }

  isCelestialTarget(target) {
    return !!(
      target &&
      Number.isFinite(target.mass) &&
      Number.isFinite(target.radius) &&
      target.type !== 'spaceship'
    );
  }

  canSearchGravityAssist({ planningShip, targetObject, normalizedConstraints, centralBody }) {
    if (!normalizedConstraints?.allowGravityAssist) {
      return false;
    }

    if (!this.isCelestialTarget(targetObject)) {
      return false;
    }

    if (!centralBody || centralBody.name !== 'Sun') {
      return false;
    }

    if (!planningShip?.position || !targetObject?.position) {
      return false;
    }

    return true;
  }

  normalizeAssistSettings(normalizedConstraints = {}) {
    const preferredFlybyBodies = Array.isArray(normalizedConstraints.preferredFlybyBodies)
      ? normalizedConstraints.preferredFlybyBodies.filter(Boolean)
      : (normalizedConstraints.preferredFlybyBodies ? [normalizedConstraints.preferredFlybyBodies] : []);

    return {
      allowGravityAssist: !!normalizedConstraints.allowGravityAssist,
      maxFlybyBodies: clamp(Number(normalizedConstraints.maxFlybyBodies || 2), 1, 4),
      flybyMinAltitudeKm: Math.max(100, Number(normalizedConstraints.flybyMinAltitudeKm || 500)),
      flybyMaxAltitudeKm: Math.max(500, Number(normalizedConstraints.flybyMaxAltitudeKm || 25000)),
      preferredFlybyBodies
    };
  }

  getOrbitRadius(body, centralBody) {
    if (Number.isFinite(body?.orbitalElements?.semiMajorAxis)) {
      return body.orbitalElements.semiMajorAxis;
    }

    if (body?.position && centralBody?.position) {
      return body.position.subtract(centralBody.position).length();
    }

    return Number.POSITIVE_INFINITY;
  }

  rankFlybyBodies({ planningShip, targetObject, centralBody, settings }) {
    const bodies = this.manager.game.bodies.filter((body) => {
      if (!this.isCelestialTarget(body)) return false;
      if (body.name === 'Sun') return false;
      if (body.name === targetObject.name) return false;
      if (body.name === planningShip.currentOrbitingBody?.name) return false;
      return (body.orbitalElements?.centralBody || 'Sun') === 'Sun';
    });

    const departureRadius = planningShip.position.subtract(centralBody.position).length();
    const targetRadius = targetObject.position.subtract(centralBody.position).length();
    const corridorMin = Math.min(departureRadius, targetRadius);
    const corridorMax = Math.max(departureRadius, targetRadius);
    const corridorMid = Math.max(1, (corridorMin + corridorMax) * 0.5);
    const preferred = new Set(settings.preferredFlybyBodies || []);

    return bodies
      .map((body) => {
        const orbitRadius = this.getOrbitRadius(body, centralBody);
        const corridorMismatch = Math.abs(Math.log(Math.max(1, orbitRadius) / corridorMid));
        const corridorBonus = orbitRadius >= (corridorMin * 0.7) && orbitRadius <= (corridorMax * 1.3) ? 1.2 : 0;
        const massScore = Math.log10(Math.max(body.mass, 1));
        const preferredBonus = preferred.has(body.name) ? 3.0 : 0;

        return {
          body,
          score: preferredBonus + massScore - (corridorMismatch * 1.3) + corridorBonus,
          orbitRadius
        };
      })
      .sort((a, b) => b.score - a.score)
      .slice(0, settings.maxFlybyBodies);
  }

  samplePeriapsisTargets(body, settings) {
    const minimum = body.radius + (settings.flybyMinAltitudeKm * 1000);
    const maximum = Math.max(minimum, body.radius + (settings.flybyMaxAltitudeKm * 1000));
    const midpoint = minimum + ((maximum - minimum) * 0.35);

    return uniqueRounded([minimum, midpoint, maximum], 50000)
      .filter((value) => value > body.radius)
      .slice(0, 2);
  }

  getDirectCenters(rawCourseOptions, normalizedConstraints, estimatedSec) {
    if (Array.isArray(rawCourseOptions) && rawCourseOptions.length > 0) {
      return [...rawCourseOptions]
        .sort((a, b) => {
          if (Math.abs(a.totalDeltaV - b.totalDeltaV) > 1e-6) {
            return a.totalDeltaV - b.totalDeltaV;
          }
          return a.missDistance - b.missDistance;
        })
        .slice(0, 2)
        .map((option) => ({
          departureOffsetSec: option.departureOffsetSec || 0,
          totalTofSec: option.totalMissionTime || option.timeOfFlight,
          referenceName: option.name
        }));
    }

    const minSec = Math.max(86400, Number(normalizedConstraints.minDays || 30) * 86400);
    const maxSec = Math.max(minSec, Number(normalizedConstraints.maxDays || 400) * 86400);
    return uniqueRounded([
      clamp(estimatedSec * 1.05, minSec, maxSec),
      clamp(estimatedSec * 1.25, minSec, maxSec)
    ], 21600).map((totalTofSec) => ({
      departureOffsetSec: 0,
      totalTofSec,
      referenceName: 'estimated'
    }));
  }

  sampleFlybyFractions({ departureState, targetArrivalState, flybyBody, centralBody }) {
    const departureRadius = departureState.position.subtract(centralBody.position).length();
    const targetRadius = targetArrivalState.position.subtract(centralBody.position).length();
    const flybyRadius = this.getOrbitRadius(flybyBody, centralBody);
    const span = Math.max(1, Math.abs(targetRadius - departureRadius));
    const radialFraction = clamp(Math.abs(flybyRadius - departureRadius) / span, 0.25, 0.75);

    return uniqueRounded([
      radialFraction,
      clamp(radialFraction - 0.12, 0.22, 0.78),
      clamp(radialFraction + 0.12, 0.22, 0.78),
      0.4,
      0.6
    ], 0.01).slice(0, 3);
  }

  buildSearchTuples({ planningShip, targetObject, centralBody, settings, directCenters }) {
    const rankedBodies = this.rankFlybyBodies({ planningShip, targetObject, centralBody, settings });
    const tuples = [];

    directCenters.forEach((center) => {
      const departureState = this.manager.getTargetStateAtTime(planningShip, center.departureOffsetSec || 0);
      const targetArrivalState = this.manager.getTargetStateAtTime(targetObject, (center.departureOffsetSec || 0) + center.totalTofSec);

      rankedBodies.forEach(({ body }) => {
        const fractions = this.sampleFlybyFractions({
          departureState,
          targetArrivalState,
          flybyBody: body,
          centralBody
        });
        const periapsisTargets = this.samplePeriapsisTargets(body, settings);

        fractions.forEach((fraction) => {
          periapsisTargets.forEach((targetPeriapsis) => {
            tuples.push({
              departureOffsetSec: center.departureOffsetSec || 0,
              totalTofSec: center.totalTofSec,
              flybyFraction: fraction,
              flybyTofSec: center.totalTofSec * fraction,
              flybyBody: body,
              targetPeriapsis,
              referenceName: center.referenceName
            });
          });
        });
      });
    });

    return tuples.slice(0, 16);
  }

  buildSeedVelocity({ planningShip, centralBody, departureState, departureOffsetSec, flybyBody, flybyTofSec }) {
    const flybyEpochSec = departureOffsetSec + flybyTofSec;
    const flybyState = this.manager.getTargetStateAtTime(flybyBody, flybyEpochSec);

    return this.manager.getSeedVelocity(
      planningShip,
      flybyBody,
      departureState,
      departureOffsetSec,
      flybyTofSec,
      flybyState,
      centralBody
    );
  }

  computeInsertionDeltaV({ maneuverType, targetObject, finalVelocity, targetArrivalVelocity }) {
    const BABYLON = window.BABYLON;

    if (
      maneuverType === 'rendezvous' ||
      !Number.isFinite(targetObject.mass) ||
      !Number.isFinite(targetObject.radius) ||
      targetObject.type === 'spaceship'
    ) {
      return BABYLON.Vector3.Distance(finalVelocity, targetArrivalVelocity);
    }

    const relVel = finalVelocity.subtract(targetArrivalVelocity).length();
    const orbitRad = targetObject.radius * 1.1;
    const vCirc = Math.sqrt(G * targetObject.mass / orbitRad);
    const vHypPeri = Math.sqrt(relVel * relVel + (2 * G * targetObject.mass / orbitRad));
    return Math.abs(vHypPeri - vCirc);
  }

  async evaluateTuple({
    planningShip,
    targetObject,
    maneuverType,
    normalizedConstraints,
    interceptRadius,
    viabilityMissLimit,
    previewMissLimit,
    centralBody,
    tuple,
    positionsOverTime,
    celestialMasses,
    ephemDt
  }) {
    const BABYLON = window.BABYLON;

    const departureOffsetSec = tuple.departureOffsetSec;
    const totalTofSec = tuple.totalTofSec;
    const flybyTofSec = tuple.flybyTofSec;
    const flybyEpochSec = departureOffsetSec + flybyTofSec;
    const totalArrivalSec = departureOffsetSec + totalTofSec;

    const departureState = this.manager.getTargetStateAtTime(planningShip, departureOffsetSec);
    const targetArrivalState = this.manager.getTargetStateAtTime(targetObject, totalArrivalSec);

    const seedVelocity = this.buildSeedVelocity({
      planningShip,
      centralBody,
      departureState,
      departureOffsetSec,
      flybyBody: tuple.flybyBody,
      flybyTofSec
    });

    const solveDt = Math.max(1800, Math.min(14400, totalTofSec / 260));
    const pathDt = Math.max(900, Math.min(10800, totalTofSec / 520));
    const windowHalfWidth = Math.max(18 * 3600, Math.min(3 * 86400, totalTofSec * 0.06));
    const periapsisTolerance = Math.max(25000, tuple.targetPeriapsis * 0.2);
    const minimumClearance = tuple.flybyBody.radius + Math.max(25000, (normalizedConstraints.flybyMinAltitudeKm || 500) * 500);

    const flybyBodyIndex = this.manager.game.bodies.findIndex((body) => body?.name === tuple.flybyBody.name);
    if (flybyBodyIndex < 0) {
      return null;
    }

    const result = await this.manager.pool.exec('solveFlybyCandidate', [{
      r1: [departureState.position.x, departureState.position.y, departureState.position.z],
      shipVelocity: [departureState.velocity.x, departureState.velocity.y, departureState.velocity.z],
      seedVelocity: [seedVelocity.x, seedVelocity.y, seedVelocity.z],
      solveDt,
      pathDt,
      totalTime: totalTofSec,
      celestialPositions: positionsOverTime,
      celestialMasses,
      ephemDt,
      startTimeOffset: departureOffsetSec,
      targetArrivalPosition: [
        targetArrivalState.position.x,
        targetArrivalState.position.y,
        targetArrivalState.position.z
      ],
      targetRadius: interceptRadius,
      isInterplanetary: true,
      maxIters: 8,
      flyby: {
        bodyIndex: flybyBodyIndex,
        targetTime: flybyEpochSec,
        windowHalfWidth,
        targetPeriapsis: tuple.targetPeriapsis,
        periapsisTolerance,
        minimumClearance
      }
    }]);

    const flybyMetrics = result.flyby || null;
    if (!flybyMetrics || !Number.isFinite(flybyMetrics.closestDistance)) {
      return null;
    }

    const periapsisError = Math.abs(flybyMetrics.closestDistance - tuple.targetPeriapsis);
    const flybyTimeError = Math.abs((flybyMetrics.closestTime ?? flybyEpochSec) - flybyEpochSec);
    const initialVelocity = new BABYLON.Vector3(...result.initialVelocity);
    const finalVelocity = new BABYLON.Vector3(...result.finalVelocity);
    const departureDeltaV = BABYLON.Vector3.Distance(initialVelocity, departureState.velocity);
    const insertionDeltaV = this.computeInsertionDeltaV({
      maneuverType,
      targetObject,
      finalVelocity,
      targetArrivalVelocity: targetArrivalState.velocity.clone()
    });
    const positions = result.positions.map((p) => new BABYLON.Vector3(...p).scale(DISTANCE_SCALE));

    const isPeriapsisAcceptable = periapsisError <= Math.max(periapsisTolerance, tuple.targetPeriapsis * 0.25);
    const isTimingAcceptable = flybyTimeError <= windowHalfWidth;
    const isCollisionFree = flybyMetrics.closestDistance > minimumClearance;
    const isViable =
      Number.isFinite(result.missDistance) &&
      result.missDistance <= viabilityMissLimit &&
      isPeriapsisAcceptable &&
      isTimingAcceptable &&
      isCollisionFree;

    const achievedPeriapsisKm = flybyMetrics.closestDistance / 1000;
    const targetPeriapsisKm = tuple.targetPeriapsis / 1000;
    const flybyEpochDays = (flybyMetrics.closestTime ?? flybyEpochSec) / 86400;

    return {
      name: `Assist via ${tuple.flybyBody.name} / TOF ${(totalTofSec / 86400).toFixed(1)} d`,
      timeOfFlight: totalTofSec,
      totalMissionTime: departureOffsetSec + totalTofSec,
      departureOffsetSec,
      initialVelocity,
      finalVelocity,
      positions,
      departureDeltaV,
      insertionDeltaV,
      totalDeltaV: departureDeltaV + insertionDeltaV,
      targetPlanet: targetObject,
      targetObject,
      missionType: normalizedConstraints.missionType || 'explore',
      maneuverType,
      missDistance: result.missDistance,
      targetArrivalPosition: targetArrivalState.position.clone(),
      departureStatePosition: departureState.position.clone(),
      departureStateVelocity: departureState.velocity.clone(),
      dt: result.pathDt,
      previewMissLimit,
      isViable,
      isGravityAssist: true,
      assistSummary: `Assist via ${tuple.flybyBody.name} · periapsis ${achievedPeriapsisKm.toFixed(0)} km`,
      assistPlan: {
        bodyName: tuple.flybyBody.name,
        targetPeriapsis: tuple.targetPeriapsis,
        achievedPeriapsis: flybyMetrics.closestDistance,
        periapsisError,
        targetFlybyEpochSec: flybyEpochSec,
        flybyEpochSec: flybyMetrics.closestTime ?? flybyEpochSec,
        flybyTimeErrorSec: flybyTimeError,
        targetPeriapsisKm,
        achievedPeriapsisKm,
        flybyEpochDays,
        relativeSpeed: flybyMetrics.relativeSpeed || null
      },
      debug: {
        solveDt,
        pathDt,
        seedVelocity: seedVelocity.clone(),
        flybyBodyName: tuple.flybyBody.name,
        flybyEpochSec,
        flybyWindowHalfWidthSec: windowHalfWidth,
        periapsisTargetKm: targetPeriapsisKm,
        achievedPeriapsisKm,
        periapsisErrorKm: periapsisError / 1000,
        flybyTimeErrorHours: flybyTimeError / 3600,
        referenceName: tuple.referenceName,
        workerScore: result.score
      }
    };
  }

  async buildAssistOptions({
    planningShip,
    targetObject,
    maneuverType,
    normalizedConstraints,
    rawCourseOptions,
    estimatedSec,
    positionsOverTime,
    celestialMasses,
    ephemDt,
    interceptRadius,
    centralBody,
    viabilityMissLimit,
    previewMissLimit
  }) {
    const settings = this.normalizeAssistSettings(normalizedConstraints);
    if (!this.canSearchGravityAssist({ planningShip, targetObject, normalizedConstraints: settings, centralBody })) {
      return [];
    }

    const directCenters = this.getDirectCenters(rawCourseOptions, normalizedConstraints, estimatedSec);
    const tuples = this.buildSearchTuples({
      planningShip,
      targetObject,
      centralBody,
      settings,
      directCenters
    });

    if (tuples.length === 0) {
      return [];
    }

    const results = await Promise.all(
      tuples.map((tuple) => this.evaluateTuple({
        planningShip,
        targetObject,
        maneuverType,
        normalizedConstraints: settings,
        interceptRadius,
        viabilityMissLimit,
        previewMissLimit,
        centralBody,
        tuple,
        positionsOverTime,
        celestialMasses,
        ephemDt
      }))
    );

    return results
      .filter(Boolean)
      .sort((a, b) => {
        if (Math.abs(a.totalDeltaV - b.totalDeltaV) > 1e-6) {
          return a.totalDeltaV - b.totalDeltaV;
        }
        if (Math.abs(a.missDistance - b.missDistance) > 1e-6) {
          return a.missDistance - b.missDistance;
        }
        return a.totalMissionTime - b.totalMissionTime;
      })
      .slice(0, 6);
  }
}
GravityAssistPlanner;


// ===== public/classes/managers/InterceptManager.js =====
// public/classes/managers/InterceptManager.js



class InterceptManager {
  constructor(game) {
    this.game = game;
    this.pool = null;

    this.turnStamp = null;

    this.bodyStateCache = new Map();
    this.ephemerisCache = new Map();
    this.courseCache = new Map();
    this.projectileCache = new Map();

    this.maxCourseCacheSize = 200;
    this.maxProjectileCacheSize = 500;
    this.requestGenerations = new Map();
    this.aiCandidateBudget = 18;

    this.gravityAssistPlanner = new GravityAssistPlanner(this);
    this.game?.eventEmitter?.on?.('selectionChanged', ({ entity } = {}) => {
      for (const ship of this.game?.spaceshipManager?.spaceships || []) {
        if (!ship?.owner?.isAI && entity !== ship) this.invalidateRequestsForShip(ship);
      }
    }, { scope: 'intercept-manager' });
  }

  isHumanControlled(ship) {
    return !!ship && !ship.owner?.isAI;
  }

  getRequestKey(ship) {
    return String(ship?.id || ship?.name || 'unknown-ship');
  }

  nextRequestGeneration(ship) {
    const key = this.getRequestKey(ship);
    const generation = (this.requestGenerations.get(key) || 0) + 1;
    this.requestGenerations.set(key, generation);
    return generation;
  }

  isRequestCurrent(ship, generation) {
    return this.requestGenerations.get(this.getRequestKey(ship)) === generation;
  }

  invalidateRequestsForShip(ship) {
    this.nextRequestGeneration(ship);
  }


  beginPlayerCalculation(ship, targetObject, label) {
    this.game.pendingCalculations += 1;

    if (!this.isHumanControlled(ship)) {
      return;
    }

    this.game.showCalculationOverlay?.(label || `Calculating ${ship?.name || 'maneuver'}...`, {
      shipName: ship?.name || null,
      targetName: targetObject?.name || null
    });
  }

  updatePlayerCalculation(ship, targetObject, label) {
    if (!this.isHumanControlled(ship) || this.game.pendingCalculations <= 0) {
      return;
    }

    this.game.updateCalculationOverlay?.(label || `Calculating ${ship?.name || 'maneuver'}...`, {
      shipName: ship?.name || null,
      targetName: targetObject?.name || null
    });
  }

  finishPlayerCalculation(ship) {
    this.game.pendingCalculations = Math.max(0, this.game.pendingCalculations - 1);

    if (!this.isHumanControlled(ship)) {
      return;
    }

    if (this.game.pendingCalculations === 0) {
      this.game.hideCalculationOverlay?.();
    } else {
      this.game.updateCalculationOverlay?.(this.game.pendingCalculationLabel || 'Calculating maneuver...');
    }
  }

  async ensurePool() {
    if (this.pool) return;

    const wp = window.workerpool;
    if (!wp) {
      throw new Error('workerpool is not loaded on window.');
    }

    const hw = navigator.hardwareConcurrency || 4;
    const maxWorkers = Math.max(2, Math.min(6, hw - 1));

    this.pool = wp.pool('/rk4Worker.js', {
      minWorkers: 1,
      maxWorkers
    });
  }

  findBodyByName(name) {
    return this.game?.bodies?.find(body => body.name === name) || null;
  }

  getTurnDurationDays() {
    const stepSeconds = Number.isFinite(this.game?.timeStepSeconds)
      ? this.game.timeStepSeconds
      : TIME_STEP;

    return Math.max(0.25, stepSeconds / 86400);
  }

  getParentBody(target) {
    if (!target) {
      return this.findBodyByName('Sun');
    }

    const parentName =
      target.currentOrbitingBody?.name ||
      target.orbitalElements?.centralBody ||
      target.centralBody ||
      'Sun';

    return this.findBodyByName(parentName) || this.findBodyByName('Sun');
  }

  getParentChain(target, maxDepth = 8) {
    const chain = [];
    let current = target;
    let depth = 0;

    while (current && depth < maxDepth) {
      const parent = this.getParentBody(current);

      if (!parent) {
        break;
      }

      if (current.name && parent.name === current.name) {
        break;
      }

      chain.push(parent);

      if (parent.name === 'Sun') {
        break;
      }

      current = parent;
      depth++;
    }

    return chain;
  }

  isObjectInCentralBodySystem(target, centralBodyName) {
    if (!target || !centralBodyName) {
      return false;
    }

    if (target.name === centralBodyName) {
      return true;
    }

    return this.getParentChain(target).some(body => body?.name === centralBodyName);
  }

  isLocalTransferTarget(ship, target, centralBody = null) {
    const isCelestialTarget = !!(
      target &&
      Number.isFinite(target.mass) &&
      Number.isFinite(target.radius) &&
      target.type !== 'spaceship'
    );

    if (!isCelestialTarget) {
      return false;
    }

    const resolvedCentralBody = centralBody || this.resolveTransferCentralBody(ship, target);
    if (!resolvedCentralBody || resolvedCentralBody.name === 'Sun') {
      return false;
    }

    return (
      this.isObjectInCentralBodySystem(ship, resolvedCentralBody.name) &&
      this.isObjectInCentralBodySystem(target, resolvedCentralBody.name)
    );
  }

  resolveTransferCentralBody(ship, target) {
    const sun = this.findBodyByName('Sun');
    if (!target) {
      return sun;
    }

    const shipChain = [ship, ...this.getParentChain(ship)];
    const targetChain = [target, ...this.getParentChain(target)];
    const targetNames = new Set(
      targetChain
        .map(body => body?.name)
        .filter(Boolean)
    );

    const commonNonSunBody = shipChain.find(
      body => body && body.name && body.name !== 'Sun' && targetNames.has(body.name)
    );

    if (commonNonSunBody) {
      return this.findBodyByName(commonNonSunBody.name) || commonNonSunBody;
    }

    const targetParent = this.getParentBody(target);
    if (targetParent && targetParent.name !== 'Sun' && ship?.position && targetParent.position && sun?.position) {
      const shipToLocalParent = ship.position.subtract(targetParent.position).length();
      const shipToSun = ship.position.subtract(sun.position).length();

      if (shipToLocalParent < shipToSun * 0.25) {
        return targetParent;
      }
    }

    return sun || targetParent || this.getParentBody(ship);
  }

  normalizeInterceptConstraints(ship, targetObject, maneuverType, constraints = {}) {
    const estimatedSec = Math.max(3600, this.getEstimatedTransferTimeSec(ship, targetObject));
    const estimatedDays = estimatedSec / 86400;
    const turnDays = this.getTurnDurationDays();
    const centralBody = this.resolveTransferCentralBody(ship, targetObject);
    const isLocalTransfer = this.isLocalTransferTarget(ship, targetObject, centralBody);
    const isCelestialTarget = !!(
      targetObject &&
      Number.isFinite(targetObject.mass) &&
      Number.isFinite(targetObject.radius) &&
      targetObject.type !== 'spaceship'
    );
    const isInterplanetary = !!(isCelestialTarget && centralBody?.name === 'Sun');

    const dynamicMinDays = isLocalTransfer
      ? Math.max(0.5, Math.min(estimatedDays * 0.5, turnDays * 0.5))
      : Math.max(1, estimatedDays * 0.5);

    const dynamicMaxDays = isLocalTransfer
      ? Math.max(dynamicMinDays + 1, Math.min(Math.max(estimatedDays * 4, turnDays * 4), 45))
      : Math.max(dynamicMinDays + turnDays, estimatedDays * 2.0);

    let minDays = Number.isFinite(constraints.minDays) ? constraints.minDays : dynamicMinDays;
    let maxDays = Number.isFinite(constraints.maxDays) ? constraints.maxDays : dynamicMaxDays;

    if (isLocalTransfer && estimatedDays < 45) {
      minDays = Math.min(minDays, dynamicMinDays);
      maxDays = Math.min(maxDays, dynamicMaxDays);
    }

    if (!Number.isFinite(minDays) || minDays <= 0) {
      minDays = dynamicMinDays;
    }

    if (!Number.isFinite(maxDays) || maxDays <= minDays) {
      maxDays = Math.max(minDays + Math.max(1, turnDays * 0.5), dynamicMaxDays);
    }

    const dynamicMinDepartureDelayDays = isInterplanetary ? 0 : 0;
    const dynamicMaxDepartureDelayDays = isInterplanetary
      ? 360
      : (
        isLocalTransfer
          ? 0
          : (
            isCelestialTarget
              ? Math.max(0, Math.min(30, turnDays * 4))
              : 0
          )
      );

    let minDepartureDelayDays = Number.isFinite(constraints.minDepartureDelayDays)
      ? constraints.minDepartureDelayDays
      : dynamicMinDepartureDelayDays;

    let maxDepartureDelayDays = Number.isFinite(constraints.maxDepartureDelayDays)
      ? constraints.maxDepartureDelayDays
      : dynamicMaxDepartureDelayDays;

    if (!Number.isFinite(minDepartureDelayDays) || minDepartureDelayDays < 0) {
      minDepartureDelayDays = dynamicMinDepartureDelayDays;
    }

    if (!Number.isFinite(maxDepartureDelayDays) || maxDepartureDelayDays < minDepartureDelayDays) {
      maxDepartureDelayDays = Math.max(minDepartureDelayDays, dynamicMaxDepartureDelayDays);
    }

    const preferredFlybyBodies = Array.isArray(constraints.preferredFlybyBodies)
      ? constraints.preferredFlybyBodies.filter(Boolean)
      : (constraints.preferredFlybyBodies ? [constraints.preferredFlybyBodies] : []);

    return {
      strategy: constraints.strategy || 'time',
      minDays,
      maxDays,
      minDepartureDelayDays,
      maxDepartureDelayDays,
      missionType: constraints.missionType || 'explore',
      allowGravityAssist: Boolean(
        constraints.allowGravityAssist ?? isInterplanetary
      ),
      maxFlybyBodies: Number.isFinite(constraints.maxFlybyBodies)
        ? Math.max(1, Math.min(4, constraints.maxFlybyBodies))
        : (isInterplanetary ? 2 : 0),
      flybyMinAltitudeKm: Number.isFinite(constraints.flybyMinAltitudeKm)
        ? Math.max(100, constraints.flybyMinAltitudeKm)
        : 500,
      flybyMaxAltitudeKm: Number.isFinite(constraints.flybyMaxAltitudeKm)
        ? Math.max(1000, constraints.flybyMaxAltitudeKm)
        : 25000,
      preferredFlybyBodies,
    };
  }

  dispose() {
    if (this.pool) {
      this.pool.terminate();
      this.pool = null;
    }
  }

  getTurnStamp() {
    return `${Math.floor(this.game.inGameDay * 24)}`;
  }

  ensureFreshCaches() {
    const nextStamp = this.getTurnStamp();
    if (nextStamp === this.turnStamp) return;

    this.turnStamp = nextStamp;
    this.bodyStateCache.clear();
    this.ephemerisCache.clear();
    this.courseCache.clear();
    this.projectileCache.clear();
  }

  clearProjectileCache() {
    this.projectileCache.clear();
  }

  quantize(value, quantum) {
    return Math.round(value / quantum);
  }

  canCacheState(target) {
    return !!(target && (target.name === 'Sun' || target.orbitalElements));
  }

  cloneState(state) {
    return {
      position: state.position.clone(),
      velocity: state.velocity.clone()
    };
  }

  getStateCacheQuantumSec(target, tSec = 0) {
    if (!target) {
      return 60;
    }

    if (target.name === 'Sun') {
      return 86400;
    }

    const absSec = Math.abs(Number.isFinite(tSec) ? tSec : 0);
    const isOrbitalBody = Boolean(target.orbitalElements);
    const isNestedOrbitalBody = Boolean(
      target.orbitalElements?.centralBody &&
      target.orbitalElements.centralBody !== 'Sun'
    );

    if (isNestedOrbitalBody) {
      if (absSec <= 60 * 86400) return 60;
      if (absSec <= 365 * 86400) return 300;
      return 1800;
    }

    if (isOrbitalBody) {
      if (absSec <= 30 * 86400) return 60;
      if (absSec <= 180 * 86400) return 300;
      if (absSec <= 730 * 86400) return 1800;
      return 3600;
    }

    if (absSec <= 7 * 86400) return 1;
    if (absSec <= 60 * 86400) return 60;
    return 300;
  }

  getStateCacheKey(target, tSec) {
    const quantumSec = this.getStateCacheQuantumSec(target, tSec);
    return `${target.name}|${quantumSec}|${Math.round(tSec / quantumSec)}`;
  }

  getTargetStateAtTime(target, tSec, localCache = new Map()) {
    const BABYLON = window.BABYLON;

    if (!target) {
      return {
        position: new BABYLON.Vector3(0, 0, 0),
        velocity: new BABYLON.Vector3(0, 0, 0)
      };
    }

    if (this.canCacheState(target)) {
      const key = this.getStateCacheKey(target, tSec);
      const cached = this.bodyStateCache.get(key);
      if (cached) return this.cloneState(cached);

      const state = typeof target.getStateAtFutureTime === 'function'
        ? target.getStateAtFutureTime(tSec, localCache)
        : {
          position: target.position.clone(),
          velocity: target.velocity.clone()
        };

      this.bodyStateCache.set(key, this.cloneState(state));
      return state;
    }

    if (typeof target.getStateAtFutureTime === 'function') {
      return target.getStateAtFutureTime(tSec, localCache);
    }

    if (target.position && target.velocity) {
      return {
        position: target.position.clone().add(target.velocity.clone().scale(tSec)),
        velocity: target.velocity.clone()
      };
    }

    return {
      position: new BABYLON.Vector3(0, 0, 0),
      velocity: new BABYLON.Vector3(0, 0, 0)
    };
  }

  getInterceptRadius(target) {
    if (!target) return 1000;

    if (Number.isFinite(target.interceptRadiusMeters)) {
      return target.interceptRadiusMeters;
    }

    if (Number.isFinite(target.radius) && Number.isFinite(target.mass) && target.type !== 'spaceship') {
      return Math.max(1000, target.radius);
    }

    return 25000;
  }

  getEphemerisKey(maxSec, ephemDt) {
    const horizonDays = Math.ceil(maxSec / 86400);
    return `${this.turnStamp}|${ephemDt}|${horizonDays}|${this.game.bodies.length}`;
  }

  precomputeCelestialPositions(ephemDt, maxSec) {
    const key = this.getEphemerisKey(maxSec, ephemDt);
    const cached = this.ephemerisCache.get(key);
    if (cached) return cached;

    const numSteps = Math.ceil(maxSec / ephemDt);
    const positionsOverTime = [];

    for (let step = 0; step <= numSteps; step++) {
      const tSec = step * ephemDt;
      const localCache = new Map();

      const stepPositions = this.game.bodies.map(body => {
        const state = this.getTargetStateAtTime(body, tSec, localCache);
        return [state.position.x, state.position.y, state.position.z];
      });

      positionsOverTime.push(stepPositions);
    }

    const data = {
      positionsOverTime,
      celestialMasses: this.game.bodies.map(b => b.mass)
    };

    this.ephemerisCache.set(key, data);
    return data;
  }

  getEstimatedTransferTimeSec(ship, target) {
    const BABYLON = window.BABYLON;

    const isCelestialTarget = !!(
      target &&
      Number.isFinite(target.mass) &&
      Number.isFinite(target.radius) &&
      target.type !== 'spaceship'
    );

    if (isCelestialTarget && ship.position && target?.position) {
      const centralBody = this.resolveTransferCentralBody(ship, target);

      if (centralBody?.position && Number.isFinite(centralBody.mass) && centralBody.mass > 0) {
        const r1 = ship.position.subtract(centralBody.position).length();
        const r2 = target.position.subtract(centralBody.position).length();

        if (r1 > 0 && r2 > 0) {
          return calculateHohmannTransfer(r1, r2, G * centralBody.mass).timeOfFlight;
        }
      }
    }

    const targetVel = target?.velocity || BABYLON.Vector3.Zero();
    const relPos = target.position.subtract(ship.position);
    const relVel = targetVel.subtract(ship.velocity);
    const speed = Math.max(500, relVel.length());

    return Math.max(3600, relPos.length() / speed);
  }

  getSeedVelocity(ship, target, departureState, departureOffsetSec, tofSec, targetArrivalState, centralBodyOverride = null) {
    const BABYLON = window.BABYLON;
    const arrivalSec = departureOffsetSec + tofSec;

    if (target && Number.isFinite(target.mass) && Number.isFinite(target.radius) && target.type !== 'spaceship') {
      try {
        const centralBody = centralBodyOverride || this.resolveTransferCentralBody(ship, target);

        if (centralBody?.mass > 0) {
          const centralDepartureState = this.getTargetStateAtTime(centralBody, departureOffsetSec);
          const centralArrivalState = this.getTargetStateAtTime(centralBody, arrivalSec);

          const mu = G * centralBody.mass;
          const r1Vec = departureState.position.subtract(centralDepartureState.position);
          const r2Vec = targetArrivalState.position.subtract(centralArrivalState.position);

          const r1 = r1Vec.length();
          const r2 = r2Vec.length();

          if (r1 > 0 && r2 > 0) {
            const { deltaV1, timeOfFlight: hohSec } = calculateHohmannTransfer(r1, r2, mu);

            const radialDir = r1Vec.normalize();
            const relativeDepartureVelocity = departureState.velocity.subtract(centralDepartureState.velocity);

            let orbitNormal = BABYLON.Vector3.Cross(r1Vec, relativeDepartureVelocity);
            if (orbitNormal.lengthSquared() < 1e-6) {
              orbitNormal = new BABYLON.Vector3(0, 0, 1);
            } else {
              orbitNormal.normalize();
            }

            let tangentialDir = BABYLON.Vector3.Cross(orbitNormal, radialDir);
            if (tangentialDir.lengthSquared() < 1e-6) {
              tangentialDir = BABYLON.Vector3.Cross(new BABYLON.Vector3(0, 0, 1), radialDir);
            }

            if (tangentialDir.lengthSquared() < 1e-6) {
              tangentialDir = new BABYLON.Vector3(1, 0, 0);
            } else {
              tangentialDir.normalize();
            }

            let vGuess = departureState.velocity.clone().add(tangentialDir.scale(deltaV1));

            if (Number.isFinite(hohSec) && hohSec > 0 && Math.abs(tofSec - hohSec) >= 60) {
              const burn = vGuess.subtract(departureState.velocity);
              const scale = Math.sqrt(hohSec / Math.max(1, tofSec));
              vGuess = departureState.velocity.clone().add(burn.scale(scale));
            }

            return vGuess;
          }
        }
      } catch (err) {
      }
    }

    const displacement = targetArrivalState.position.subtract(departureState.position);
    return departureState.velocity.clone().add(displacement.scale(1 / Math.max(1, tofSec)));
  }

  sampleTofCandidates(minSec, maxSec, centerSec) {
    const samples = [
      minSec,
      minSec + (maxSec - minSec) * 0.15,
      minSec + (maxSec - minSec) * 0.33,
      minSec + (maxSec - minSec) * 0.50,
      minSec + (maxSec - minSec) * 0.67,
      minSec + (maxSec - minSec) * 0.85,
      maxSec
    ];

    if (Number.isFinite(centerSec)) {
      samples.push(centerSec, centerSec * 0.85, centerSec * 1.15);
    }

    return [...new Set(
      samples
        .map(v => Math.max(minSec, Math.min(maxSec, v)))
        .map(v => Math.round(v / 3600) * 3600)
    )].sort((a, b) => a - b);
  }

  sampleDepartureOffsets(minSec, maxSec) {
    if (!Number.isFinite(maxSec) || maxSec <= 0) {
      return [0];
    }

    const samples = [
      minSec,
      minSec + (maxSec - minSec) * 0.08,
      minSec + (maxSec - minSec) * 0.17,
      minSec + (maxSec - minSec) * 0.33,
      minSec + (maxSec - minSec) * 0.50,
      minSec + (maxSec - minSec) * 0.67,
      minSec + (maxSec - minSec) * 0.83,
      maxSec
    ];

    return [...new Set(
      samples
        .map(v => Math.max(minSec, Math.min(maxSec, v)))
        .map(v => Math.round(v / 21600) * 21600)
    )].sort((a, b) => a - b);
  }

  sampleRefinedTofCandidates(centerSec, minSec, maxSec) {
    const ratios = [0.85, 0.92, 0.96, 0.98, 0.99, 1.0, 1.01, 1.02, 1.04, 1.08, 1.15];
    const fixedOffsets = [0.125, 0.25, 0.5, 1.0].map(days => days * 86400);
    const samples = [];

    ratios.forEach(ratio => {
      samples.push(centerSec * ratio);
    });

    fixedOffsets.forEach(offset => {
      samples.push(centerSec - offset);
      samples.push(centerSec + offset);
    });

    return [...new Set(
      samples
        .map(v => Math.max(minSec, Math.min(maxSec, v)))
        .map(v => Math.round(v / 900) * 900)
    )].sort((a, b) => a - b);
  }

  getPairKey(departureOffsetSec, tofSec) {
    return `${Math.round(departureOffsetSec)}|${Math.round(tofSec)}`;
  }

  buildRefinedCandidatePairs(existingPairs, rawCourseOptions, minSec, maxSec, isLocalTransfer) {
    const existingKeys = new Set(existingPairs.map(pair => this.getPairKey(pair.departureOffsetSec, pair.tofSec)));
    const refinedPairs = [];
    const ranked = [...rawCourseOptions]
      .sort((a, b) => {
        if (Math.abs(a.missDistance - b.missDistance) > 1e-6) {
          return a.missDistance - b.missDistance;
        }

        if (Math.abs(a.totalDeltaV - b.totalDeltaV) > 1e-6) {
          return a.totalDeltaV - b.totalDeltaV;
        }

        return a.timeOfFlight - b.timeOfFlight;
      });

    const maxCenters = isLocalTransfer ? 4 : 3;
    const usedCenters = new Set();

    for (const option of ranked) {
      const centerKey = this.getPairKey(option.departureOffsetSec || 0, option.timeOfFlight);
      if (usedCenters.has(centerKey)) {
        continue;
      }

      usedCenters.add(centerKey);

      const refinedTofs = this.sampleRefinedTofCandidates(option.timeOfFlight, minSec, maxSec);
      refinedTofs.forEach(tofSec => {
        const key = this.getPairKey(option.departureOffsetSec || 0, tofSec);
        if (existingKeys.has(key)) {
          return;
        }

        existingKeys.add(key);
        refinedPairs.push({
          departureOffsetSec: option.departureOffsetSec || 0,
          tofSec
        });
      });

      if (usedCenters.size >= maxCenters) {
        break;
      }
    }

    return refinedPairs;
  }

  convertRelativePathToAbsolute(relativePositions, centralBody, departureOffsetSec, pathDt, totalTime) {
    const BABYLON = window.BABYLON;
    const absolutePositions = [];
    const totalSamples = relativePositions.length;

    for (let i = 0; i < totalSamples; i++) {
      const elapsedSec = Math.min(totalTime, i * pathDt);
      const absoluteTimeSec = departureOffsetSec + elapsedSec;
      const centralState = this.getTargetStateAtTime(centralBody, absoluteTimeSec);

      absolutePositions.push(
        new BABYLON.Vector3(...relativePositions[i])
          .add(centralState.position)
          .scale(DISTANCE_SCALE)
      );
    }

    return absolutePositions;
  }

  getCourseCacheKey(ship, target, maneuverType, constraints) {
    const qPos = 5e5;
    const qVel = 5;

    return [
      this.turnStamp,
      ship.name,
      target?.name || target?.id || 'target',
      maneuverType,
      constraints.strategy || 'time',
      constraints.minDays || 0,
      constraints.maxDays || 0,
      constraints.minDepartureDelayDays || 0,
      constraints.maxDepartureDelayDays || 0,
      constraints.missionType || '',
      constraints.allowGravityAssist ? 1 : 0,
      constraints.maxFlybyBodies || 0,
      constraints.flybyMinAltitudeKm || 0,
      constraints.flybyMaxAltitudeKm || 0,
      Array.isArray(constraints.preferredFlybyBodies)
        ? constraints.preferredFlybyBodies.join(',')
        : '',
      this.quantize(ship.position.x, qPos),
      this.quantize(ship.position.y, qPos),
      this.quantize(ship.position.z, qPos),
      this.quantize(ship.velocity.x, qVel),
      this.quantize(ship.velocity.y, qVel),
      this.quantize(ship.velocity.z, qVel),
      this.quantize(target?.position?.x || 0, qPos),
      this.quantize(target?.position?.y || 0, qPos),
      this.quantize(target?.position?.z || 0, qPos),
      this.quantize(target?.velocity?.x || 0, qVel),
      this.quantize(target?.velocity?.y || 0, qVel),
      this.quantize(target?.velocity?.z || 0, qVel)
    ].join('|');
  }

  async evaluateInterceptPairs({
    planningShip,
    targetObject,
    maneuverType,
    normalizedConstraints,
    candidatePairs,
    positionsOverTime,
    celestialMasses,
    ephemDt,
    interceptRadius,
    centralBody,
    isLocalTransfer,
    isInterplanetary,
    viabilityMissLimit,
    previewMissLimit
  }) {
    const BABYLON = window.BABYLON;

    const centralBodyIndex = centralBody
      ? this.game.bodies.findIndex(body => body?.name === centralBody.name)
      : -1;

    const tasks = candidatePairs.map(async ({ departureOffsetSec, tofSec }) => {
      const solveDt = isLocalTransfer
        ? Math.max(900, Math.min(1800, tofSec / 160))
        : Math.max(3600, Math.min(43200, tofSec / 96));

      const pathDt = isLocalTransfer
        ? Math.max(300, Math.min(900, tofSec / 480))
        : Math.max(1800, Math.min(21600, tofSec / 256));

      const arrivalSec = departureOffsetSec + tofSec;

      const departureState = this.getTargetStateAtTime(planningShip, departureOffsetSec);
      const targetArrivalState = this.getTargetStateAtTime(targetObject, arrivalSec);

      const seedVelocity = this.getSeedVelocity(
        planningShip,
        targetObject,
        departureState,
        departureOffsetSec,
        tofSec,
        targetArrivalState,
        centralBody
      );

      const seedDepartureDeltaV = BABYLON.Vector3.Distance(seedVelocity, departureState.velocity);
      const hardDepartureCap = isInterplanetary
        ? Math.max(seedDepartureDeltaV * 12.0, seedDepartureDeltaV + 20000, 15000)
        : Math.max(seedDepartureDeltaV * 4.0, seedDepartureDeltaV + 6000, 4000);

      let solveR1 = departureState.position.clone();
      let solveShipVelocity = departureState.velocity.clone();
      let solveSeedVelocity = seedVelocity.clone();
      let solveTargetArrivalPosition = targetArrivalState.position.clone();
      let departureReferenceVelocity = departureState.velocity.clone();
      let arrivalReferenceVelocity = targetArrivalState.velocity.clone();
      let localFrame = null;
      let centralDepartureState = null;
      let centralArrivalState = null;

      if (isLocalTransfer && centralBody && centralBodyIndex >= 0 && centralBody.name !== 'Sun') {
        centralDepartureState = this.getTargetStateAtTime(centralBody, departureOffsetSec);
        centralArrivalState = this.getTargetStateAtTime(centralBody, arrivalSec);

        solveR1 = departureState.position.subtract(centralDepartureState.position);
        solveShipVelocity = departureState.velocity.subtract(centralDepartureState.velocity);
        solveSeedVelocity = seedVelocity.subtract(centralDepartureState.velocity);
        solveTargetArrivalPosition = targetArrivalState.position.subtract(centralArrivalState.position);
        departureReferenceVelocity = solveShipVelocity.clone();
        arrivalReferenceVelocity = targetArrivalState.velocity.subtract(centralArrivalState.velocity);

        localFrame = {
          mode: 'centralBodyRelative',
          centralBodyIndex
        };
      }

      const result = await this.pool.exec('solveInterceptCandidate', [{
        r1: [solveR1.x, solveR1.y, solveR1.z],
        shipVelocity: [solveShipVelocity.x, solveShipVelocity.y, solveShipVelocity.z],
        seedVelocity: [solveSeedVelocity.x, solveSeedVelocity.y, solveSeedVelocity.z],
        solveDt,
        pathDt,
        totalTime: tofSec,
        celestialPositions: positionsOverTime,
        celestialMasses,
        ephemDt,
        startTimeOffset: departureOffsetSec,
        targetArrivalPosition: [
          solveTargetArrivalPosition.x,
          solveTargetArrivalPosition.y,
          solveTargetArrivalPosition.z
        ],
        targetRadius: interceptRadius,
        isInterplanetary,
        localFrame,
        maxIters: isInterplanetary ? 8 : (isLocalTransfer ? 7 : 5)
      }]);

      let initialVelocity = new BABYLON.Vector3(...result.initialVelocity);
      let finalVelocity = new BABYLON.Vector3(...result.finalVelocity);
      let targetArrivalVelocity = targetArrivalState.velocity.clone();
      let positions = result.positions.map(p => new BABYLON.Vector3(...p).scale(DISTANCE_SCALE));
      let trajectoryFrame = null;

      if (localFrame && centralBody && centralDepartureState && centralArrivalState) {
        const relativePositions = result.positions.map((p) => new BABYLON.Vector3(...p));
        const initialRelativeVelocity = initialVelocity.clone();
        const finalRelativeVelocity = finalVelocity.clone();

        initialVelocity = initialVelocity.add(centralDepartureState.velocity);
        finalVelocity = finalVelocity.add(centralArrivalState.velocity);
        targetArrivalVelocity = targetArrivalVelocity.clone();
        positions = this.convertRelativePathToAbsolute(
          result.positions,
          centralBody,
          departureOffsetSec,
          result.pathDt,
          tofSec
        );

        trajectoryFrame = {
          mode: 'centralBodyRelative',
          centralBodyName: centralBody.name,
          relativePositions,
          pathDt: result.pathDt,
          initialRelativeVelocity,
          finalRelativeVelocity
        };
      }

      const departureDeltaV = BABYLON.Vector3.Distance(initialVelocity, departureState.velocity);

      let insertionDeltaV = 0;

      if (
        maneuverType === 'rendezvous' ||
        !Number.isFinite(targetObject.mass) ||
        !Number.isFinite(targetObject.radius) ||
        targetObject.type === 'spaceship'
      ) {
        insertionDeltaV = BABYLON.Vector3.Distance(finalVelocity, targetArrivalVelocity);
      } else {
        const relVel = finalVelocity.subtract(targetArrivalVelocity).length();
        const orbitRad = targetObject.radius * 1.1;
        const vCirc = Math.sqrt(G * targetObject.mass / orbitRad);
        const vHypPeri = Math.sqrt(relVel * relVel + (2 * G * targetObject.mass / orbitRad));
        insertionDeltaV = Math.abs(vHypPeri - vCirc);
      }

      return {
        name: `D+${(departureOffsetSec / 86400).toFixed(1)} d / TOF ${(tofSec / 86400).toFixed(1)} d`,
        timeOfFlight: tofSec,
        totalMissionTime: departureOffsetSec + tofSec,
        departureOffsetSec,
        initialVelocity,
        finalVelocity,
        positions,
        trajectoryFrame,
        departureDeltaV,
        insertionDeltaV,
        totalDeltaV: departureDeltaV + insertionDeltaV,
        targetPlanet: targetObject,
        targetObject,
        missionType: normalizedConstraints.missionType || 'explore',
        maneuverType,
        missDistance: result.missDistance,
        targetArrivalPosition: targetArrivalState.position.clone(),
        departureStatePosition: departureState.position.clone(),
        departureStateVelocity: departureState.velocity.clone(),
        dt: result.pathDt,
        previewMissLimit,
        isViable: Number.isFinite(result.missDistance) && result.missDistance <= viabilityMissLimit,
        debug: {
          solveDt,
          pathDt,
          isInterplanetary,
          isLocalTransfer,
          usedLocalFrame: !!localFrame,
          departureOffsetSec,
          arrivalSec,
          departureStatePosition: departureState.position.clone(),
          departureStateVelocity: departureState.velocity.clone(),
          targetArrivalPosition: targetArrivalState.position.clone(),
          targetArrivalVelocity: targetArrivalState.velocity.clone(),
          seedVelocity: seedVelocity.clone(),
          seedDepartureDeltaV,
          hardDepartureCap: result.hardDepartureCap || hardDepartureCap,
          departureCapHit: departureDeltaV >= ((result.hardDepartureCap || hardDepartureCap) * 0.999),
          departureReferenceVelocity,
          arrivalReferenceVelocity
        }
      };
    });

    return (await Promise.all(tasks))
      .filter(option =>
        option.positions.length > 1 &&
        Number.isFinite(option.totalDeltaV) &&
        Number.isFinite(option.missDistance)
      );
  }

  async plotShipIntercept(
    ship,
    targetObject,
    maneuverType = 'intercept',
    constraints = { strategy: 'time' }
  ) {
    this.ensureFreshCaches();
    const requestGeneration = this.nextRequestGeneration(ship);

    const shipState = typeof ship.getStateAtFutureTime === 'function'
      ? ship.getStateAtFutureTime(0)
      : {
        position: ship.position.clone(),
        velocity: ship.velocity.clone()
      };

    const planningShip = Object.create(Object.getPrototypeOf(ship));
    Object.assign(planningShip, ship, {
      position: shipState.position.clone(),
      velocity: shipState.velocity.clone()
    });

    const normalizedConstraints = this.normalizeInterceptConstraints(
      planningShip,
      targetObject,
      maneuverType,
      constraints
    );

    const cacheKey = this.getCourseCacheKey(
      planningShip,
      targetObject,
      maneuverType,
      normalizedConstraints
    );

    const cached = this.courseCache.get(cacheKey);
    if (cached) {
      ship.courseOptions = cached;
      if (!ship.owner.isAI) {
        console.groupCollapsed(`[INTERCEPT DEBUG] Cache hit: ${ship.name} → ${targetObject.name}`);
        console.log('maneuverType:', maneuverType);
        console.log('constraints:', normalizedConstraints);
        console.log('cachedOptions:', cached.map(option => ({
          name: option.name,
          departureDelayDays: Number(((option.departureOffsetSec || 0) / 86400).toFixed(2)),
          tofDays: Number((option.timeOfFlight / 86400).toFixed(2)),
          totalTripDays: Number(((option.totalMissionTime || option.timeOfFlight) / 86400).toFixed(2)),
          totalDeltaV: Number(option.totalDeltaV.toFixed(2)),
          departureDeltaV: Number(option.departureDeltaV.toFixed(2)),
          insertionDeltaV: Number(option.insertionDeltaV.toFixed(2)),
          missDistanceKm: Number((option.missDistance / 1000).toFixed(2)),
          isViable: option.isViable,
          isGravityAssist: !!option.isGravityAssist,
          assistBody: option.assistPlan?.bodyName || null
        })));
        console.groupEnd();

        if (cached.length === 0) {
          showToast(`No viable course found to ${targetObject.name}.`, 'error');
        } else {
          ship.displayCourseOptions();
        }
      }
      return cached;
    }

    await this.ensurePool();
    if (!this.isRequestCurrent(ship, requestGeneration)) return [];

    this.beginPlayerCalculation(
      ship,
      targetObject,
      `Calculating ${ship.name} → ${targetObject.name}`
    );

    try {
      if (!ship.owner.isAI) {
        showToast(`Calculating trajectories for ${ship.name} → ${targetObject.name}`, 'info', false);
      }

      const estimatedSec = this.getEstimatedTransferTimeSec(planningShip, targetObject);

      const minSec = normalizedConstraints.strategy === 'time'
        ? normalizedConstraints.minDays * 86400
        : Math.max(normalizedConstraints.minDays * 86400, 0.5 * estimatedSec);

      const maxSec = normalizedConstraints.strategy === 'time'
        ? normalizedConstraints.maxDays * 86400
        : Math.min(normalizedConstraints.maxDays * 86400, 2.0 * estimatedSec);

      const departureOffsetCandidates = this.sampleDepartureOffsets(
        normalizedConstraints.minDepartureDelayDays * 86400,
        normalizedConstraints.maxDepartureDelayDays * 86400
      );

      const coarseTofCandidates = this.sampleTofCandidates(minSec, maxSec, estimatedSec);
      let coarseCandidatePairs = departureOffsetCandidates.flatMap(departureOffsetSec =>
        coarseTofCandidates.map(tofSec => ({ departureOffsetSec, tofSec }))
      );
      if (ship.owner?.isAI && coarseCandidatePairs.length > this.aiCandidateBudget) {
        const stride = coarseCandidatePairs.length / this.aiCandidateBudget;
        coarseCandidatePairs = Array.from({ length: this.aiCandidateBudget }, (_, index) =>
          coarseCandidatePairs[Math.min(coarseCandidatePairs.length - 1, Math.floor(index * stride))]
        );
      }

      const maxArrivalSec = Math.max(...departureOffsetCandidates) + Math.max(...coarseTofCandidates);

      const ephemDt = Math.max(3600, Math.min(21600, maxArrivalSec / 240));
      const { positionsOverTime, celestialMasses } = this.precomputeCelestialPositions(ephemDt, maxArrivalSec);

      const interceptRadius = this.getInterceptRadius(targetObject);
      const centralBody = this.resolveTransferCentralBody(planningShip, targetObject);

      const isCelestialTarget = !!(
        targetObject &&
        Number.isFinite(targetObject.mass) &&
        Number.isFinite(targetObject.radius) &&
        targetObject.type !== 'spaceship'
      );

      const isLocalTransfer = this.isLocalTransferTarget(planningShip, targetObject, centralBody);
      const isInterplanetary = !!(isCelestialTarget && centralBody?.name === 'Sun');

      const viabilityMissLimit = isInterplanetary
        ? Math.max(interceptRadius * 250, 1000000)
        : (
          isLocalTransfer
            ? Math.max(interceptRadius * 5, 500000)
            : Math.max(interceptRadius * 2, interceptRadius + 25000)
        );

      const previewMissLimit = isInterplanetary
        ? Math.max(interceptRadius * 20, 1000000)
        : Math.max(interceptRadius * 10, 250000);

      console.groupCollapsed(`[INTERCEPT DEBUG] Plotting ${ship.name} → ${targetObject.name}`);
      console.log('maneuverType:', maneuverType);
      console.log('normalizedConstraints:', normalizedConstraints);
      console.log('estimatedTransferDays:', Number((estimatedSec / 86400).toFixed(3)));
      console.log('minDays:', Number((minSec / 86400).toFixed(3)));
      console.log('maxDays:', Number((maxSec / 86400).toFixed(3)));
      console.log('departureOffsetCandidatesDays:', departureOffsetCandidates.map(sec => Number((sec / 86400).toFixed(3))));
      console.log('tofCandidatesDays:', coarseTofCandidates.map(sec => Number((sec / 86400).toFixed(3))));
      console.log('centralBody:', centralBody?.name || null);
      console.log('isCelestialTarget:', isCelestialTarget);
      console.log('isLocalTransfer:', isLocalTransfer);
      console.log('isInterplanetary:', isInterplanetary);
      console.log('centralBodyStateCacheQuantumSec:', centralBody ? this.getStateCacheQuantumSec(centralBody, estimatedSec) : null);
      console.log('targetStateCacheQuantumSec:', targetObject ? this.getStateCacheQuantumSec(targetObject, estimatedSec) : null);
      console.log('interceptRadiusKm:', Number((interceptRadius / 1000).toFixed(3)));
      console.log('viabilityMissLimitKm:', Number((viabilityMissLimit / 1000).toFixed(3)));
      console.log('previewMissLimitKm:', Number((previewMissLimit / 1000).toFixed(3)));
      console.log('shipPosition:', {
        x: planningShip.position.x,
        y: planningShip.position.y,
        z: planningShip.position.z
      });
      console.log('shipVelocity:', {
        x: planningShip.velocity.x,
        y: planningShip.velocity.y,
        z: planningShip.velocity.z
      });
      console.log('targetPositionNow:', {
        x: targetObject.position?.x ?? null,
        y: targetObject.position?.y ?? null,
        z: targetObject.position?.z ?? null
      });
      console.log('targetVelocityNow:', {
        x: targetObject.velocity?.x ?? null,
        y: targetObject.velocity?.y ?? null,
        z: targetObject.velocity?.z ?? null
      });

      this.updatePlayerCalculation(ship, targetObject, `Scanning direct trajectories for ${targetObject.name}`);

      const coarseRawCourseOptions = await this.evaluateInterceptPairs({
        planningShip,
        targetObject,
        maneuverType,
        normalizedConstraints,
        candidatePairs: coarseCandidatePairs,
        positionsOverTime,
        celestialMasses,
        ephemDt,
        interceptRadius,
        centralBody,
        isLocalTransfer,
        isInterplanetary,
        viabilityMissLimit,
        previewMissLimit
      });
      if (!this.isRequestCurrent(ship, requestGeneration)) return [];

      let refinedCandidatePairs = this.buildRefinedCandidatePairs(
        coarseCandidatePairs,
        coarseRawCourseOptions,
        minSec,
        maxSec,
        isLocalTransfer
      );

      if (refinedCandidatePairs.length > 0) {
        this.updatePlayerCalculation(ship, targetObject, `Refining best windows for ${targetObject.name}`);
      }

      const refinedRawCourseOptions = refinedCandidatePairs.length > 0
        ? await this.evaluateInterceptPairs({
          planningShip,
          targetObject,
          maneuverType,
          normalizedConstraints,
          candidatePairs: refinedCandidatePairs,
          positionsOverTime,
          celestialMasses,
          ephemDt,
          interceptRadius,
          centralBody,
          isLocalTransfer,
          isInterplanetary,
          viabilityMissLimit,
          previewMissLimit
        })
        : [];
      if (!this.isRequestCurrent(ship, requestGeneration)) return [];

      if (normalizedConstraints.allowGravityAssist) {
        this.updatePlayerCalculation(ship, targetObject, `Evaluating gravity assists for ${targetObject.name}`);
      } else {
        this.updatePlayerCalculation(ship, targetObject, `Finalizing maneuver options for ${targetObject.name}`);
      }

      const rawCourseOptions = [...coarseRawCourseOptions, ...refinedRawCourseOptions];

      const gravityAssistOptions = await this.gravityAssistPlanner.buildAssistOptions({
        planningShip,
        targetObject,
        maneuverType,
        normalizedConstraints,
        rawCourseOptions,
        estimatedSec,
        positionsOverTime,
        celestialMasses,
        ephemDt,
        interceptRadius,
        centralBody,
        viabilityMissLimit,
        previewMissLimit
      });

      if (!this.isRequestCurrent(ship, requestGeneration)) return [];
      const mergedRawCourseOptions = [...rawCourseOptions, ...gravityAssistOptions];

      console.table(mergedRawCourseOptions.map(option => ({
        name: option.name,
        departureDelayDays: Number((option.departureOffsetSec / 86400).toFixed(3)),
        tofDays: Number((option.timeOfFlight / 86400).toFixed(3)),
        totalTripDays: Number((option.totalMissionTime / 86400).toFixed(3)),
        missDistanceKm: Number((option.missDistance / 1000).toFixed(3)),
        totalDeltaV: Number(option.totalDeltaV.toFixed(3)),
        departureDeltaV: Number(option.departureDeltaV.toFixed(3)),
        insertionDeltaV: Number(option.insertionDeltaV.toFixed(3)),
        seedDepartureDeltaV: Number(option.debug?.seedDepartureDeltaV?.toFixed?.(3) ?? 0),
        hardDepartureCap: Number(option.debug?.hardDepartureCap?.toFixed?.(3) ?? 0),
        departureCapHit: option.debug?.departureCapHit,
        usedLocalFrame: option.debug?.usedLocalFrame,
        solveDtHours: Number(((option.debug?.solveDt || 0) / 3600).toFixed(2)),
        pathDtHours: Number(((option.debug?.pathDt || 0) / 3600).toFixed(2)),
        viable: option.isViable,
        gravityAssist: !!option.isGravityAssist,
        assistBody: option.assistPlan?.bodyName || null,
        assistPeriapsisKm: Number.isFinite(option.assistPlan?.achievedPeriapsis)
          ? Number((option.assistPlan.achievedPeriapsis / 1000).toFixed(1))
          : null
      })));

      const courseOptions = mergedRawCourseOptions
        .filter(option => option.isViable)
        .sort((a, b) => {
          if (Math.abs(a.totalDeltaV - b.totalDeltaV) > 1e-6) {
            return a.totalDeltaV - b.totalDeltaV;
          }

          if (Math.abs(a.missDistance - b.missDistance) > 1e-6) {
            return a.missDistance - b.missDistance;
          }

          return a.totalMissionTime - b.totalMissionTime;
        });

      const bestRawOption = mergedRawCourseOptions.length > 0
        ? [...mergedRawCourseOptions].sort((a, b) => a.missDistance - b.missDistance)[0]
        : null;

      console.log('coarseCandidateCount:', coarseCandidatePairs.length);
      console.log('refinedCandidateCount:', refinedCandidatePairs.length);
      console.log('assistCandidateCount:', gravityAssistOptions.length);
      console.log('rawCandidateCount:', mergedRawCourseOptions.length);
      console.log('viableCandidateCount:', courseOptions.length);
      console.log(
        'bestRawCandidate:',
        bestRawOption
          ? {
            name: bestRawOption.name,
            departureDelayDays: Number((bestRawOption.departureOffsetSec / 86400).toFixed(3)),
            tofDays: Number((bestRawOption.timeOfFlight / 86400).toFixed(3)),
            totalTripDays: Number((bestRawOption.totalMissionTime / 86400).toFixed(3)),
            missDistanceKm: Number((bestRawOption.missDistance / 1000).toFixed(3)),
            totalDeltaV: Number(bestRawOption.totalDeltaV.toFixed(3)),
            departureDeltaV: Number(bestRawOption.departureDeltaV.toFixed(3)),
            insertionDeltaV: Number(bestRawOption.insertionDeltaV.toFixed(3)),
            seedDepartureDeltaV: Number(bestRawOption.debug?.seedDepartureDeltaV?.toFixed?.(3) ?? 0),
            hardDepartureCap: Number(bestRawOption.debug?.hardDepartureCap?.toFixed?.(3) ?? 0),
            departureCapHit: bestRawOption.debug?.departureCapHit,
            usedLocalFrame: bestRawOption.debug?.usedLocalFrame,
            targetArrivalPosition: {
              x: bestRawOption.debug?.targetArrivalPosition?.x,
              y: bestRawOption.debug?.targetArrivalPosition?.y,
              z: bestRawOption.debug?.targetArrivalPosition?.z
            },
            isGravityAssist: !!bestRawOption.isGravityAssist,
            assistBody: bestRawOption.assistPlan?.bodyName || null
          }
          : null
      );
      console.groupEnd();

      if (!this.isRequestCurrent(ship, requestGeneration)) return [];

      if (this.courseCache.size >= this.maxCourseCacheSize) {
        this.courseCache.clear();
      }
      this.courseCache.set(cacheKey, courseOptions);

      ship.courseOptions = courseOptions;

      if (!ship.owner.isAI) {
        if (courseOptions.length === 0) {
          if (bestRawOption) {
            showToast(
              `No viable course found to ${targetObject.name}. Best miss distance was ${Math.round(bestRawOption.missDistance / 1000).toLocaleString()} km.`,
              'error'
            );
          } else {
            showToast(`No viable course found to ${targetObject.name}.`, 'error');
          }
        } else {
          ship.displayCourseOptions();
        }
      }

      return courseOptions;
    } catch (err) {
      console.error('[INTERCEPT DEBUG] plotShipIntercept failed:', err);
      return [];
    } finally {
      this.finishPlayerCalculation(ship);
      this.game.windowManager?.refreshHud?.();
    }
  }

  solveProjectileIntercept({
    shooterPosition,
    shooterVelocity = BABYLON.Vector3.Zero(),
    targetPosition,
    targetVelocity = BABYLON.Vector3.Zero(),
    projectileSpeed,
    targetAcceleration = BABYLON.Vector3.Zero(),
    inheritShooterVelocity = true,
    maxTime = Infinity,
    cacheKey = null
  }) {
    this.ensureFreshCaches();

    if (!projectileSpeed || projectileSpeed <= 0) return null;

    const inheritedVelocity = inheritShooterVelocity
      ? shooterVelocity.clone()
      : BABYLON.Vector3.Zero();

    const key = cacheKey || [
      this.turnStamp,
      projectileSpeed,
      inheritShooterVelocity ? 1 : 0,
      this.quantize(shooterPosition.x, 50),
      this.quantize(shooterPosition.y, 50),
      this.quantize(shooterPosition.z, 50),
      this.quantize(shooterVelocity.x, 0.5),
      this.quantize(shooterVelocity.y, 0.5),
      this.quantize(shooterVelocity.z, 0.5),
      this.quantize(targetPosition.x, 50),
      this.quantize(targetPosition.y, 50),
      this.quantize(targetPosition.z, 50),
      this.quantize(targetVelocity.x, 0.5),
      this.quantize(targetVelocity.y, 0.5),
      this.quantize(targetVelocity.z, 0.5)
    ].join('|');

    const cached = this.projectileCache.get(key);
    if (cached) {
      return {
        interceptTime: cached.interceptTime,
        aimPoint: cached.aimPoint.clone(),
        aimDirection: cached.aimDirection.clone(),
        predictedTargetVelocity: cached.predictedTargetVelocity.clone()
      };
    }

    const solveTime = (predictedTargetPos, predictedTargetVel) => {
      const relPos = predictedTargetPos.subtract(shooterPosition);
      const relVel = predictedTargetVel.subtract(inheritedVelocity);

      const a = relVel.lengthSquared() - (projectileSpeed * projectileSpeed);
      const b = 2 * BABYLON.Vector3.Dot(relPos, relVel);
      const c = relPos.lengthSquared();

      if (Math.abs(a) < 1e-8) {
        if (Math.abs(b) < 1e-8) return null;
        const t = -c / b;
        return t > 0 ? t : null;
      }

      const disc = (b * b) - (4 * a * c);
      if (disc < 0) return null;

      const sqrtDisc = Math.sqrt(disc);
      const t1 = (-b - sqrtDisc) / (2 * a);
      const t2 = (-b + sqrtDisc) / (2 * a);

      const candidates = [t1, t2].filter(t => t > 0);
      if (candidates.length === 0) return null;

      return Math.min(...candidates);
    };

    let t = solveTime(targetPosition.clone(), targetVelocity.clone());
    if (!Number.isFinite(t) || t <= 0 || t > maxTime) {
      return null;
    }

    let predictedPos = targetPosition.clone();
    let predictedVel = targetVelocity.clone();

    for (let i = 0; i < 3; i++) {
      predictedPos = targetPosition.clone()
        .add(targetVelocity.clone().scale(t))
        .add(targetAcceleration.clone().scale(0.5 * t * t));

      predictedVel = targetVelocity.clone()
        .add(targetAcceleration.clone().scale(t));

      const nextT = solveTime(predictedPos, predictedVel);
      if (!Number.isFinite(nextT) || nextT <= 0) break;

      if (Math.abs(nextT - t) < 1e-3) {
        t = nextT;
        break;
      }

      t = nextT;
    }

    if (t > maxTime) return null;

    predictedPos = targetPosition.clone()
      .add(targetVelocity.clone().scale(t))
      .add(targetAcceleration.clone().scale(0.5 * t * t));

    predictedVel = targetVelocity.clone()
      .add(targetAcceleration.clone().scale(t));

    const aimVector = predictedPos
      .subtract(shooterPosition)
      .subtract(inheritedVelocity.scale(t));

    if (aimVector.lengthSquared() === 0) return null;

    const result = {
      interceptTime: t,
      aimPoint: predictedPos,
      aimDirection: aimVector.normalize(),
      predictedTargetVelocity: predictedVel
    };

    if (this.projectileCache.size >= this.maxProjectileCacheSize) {
      this.projectileCache.clear();
    }

    this.projectileCache.set(key, {
      interceptTime: result.interceptTime,
      aimPoint: result.aimPoint.clone(),
      aimDirection: result.aimDirection.clone(),
      predictedTargetVelocity: result.predictedTargetVelocity.clone()
    });

    return result;
  }
}
InterceptManager;


