class Resource {
  constructor(name, basePrice, isTradable = true) {
    this.name = name;
    this.basePrice = basePrice;
    this.isTradable = isTradable;
  }
}Resource;

// ===== public/classes/managers/ResourceManager.js =====

class ResourceManager {
  constructor() {
    this.resources = [
      new Resource('Minerals', 10),
      new Resource('RefinedMetals', 18),
      new Resource('Food', 5),
      new Resource('Water', 4),
      new Resource('Goods', 15),
      new Resource('AdvancedComponents', 42),
      new Resource('Fuel', 8, true),
      new Resource('Power', 2, false),
      new Resource('RareMetals', 22),
      new Resource('Electronics', 30),
      new Resource('Volatiles', 11),
      new Resource('Helium3', 26)
    ];
  }

  getResourceByName(name) {
    return this.resources.find(resource => resource.name === name);
  }
}ResourceManager;

// ===== public/classes/Contract.js =====
function clampContractValue(value, min, max) {
    return Math.max(min, Math.min(max, value));
}

class Contract {
  constructor({
    id,
    task,
    issuer,
    reward,
    requirements,
    status = 'open',
    kind = 'contract',
    directiveType = null,
    description = '',
    icon = 'mdi-clipboard-text-outline',
    severity = 'info',
    visibility = 'open',
    autoAssign = false,
    rewardPackage = null,
    completionEffects = null,
    boardSection = 'directives',
    phaseAvailability = null,
    deadlineTurn = null,
    acceptedTurn = null,
    completedTurn = null,
    failedTurn = null,
    reputationReward = 0,
    reputationPenalty = 0,
    trustReward = 0,
    trustPenalty = 0,
    minimumStanding = 0,
    strategicContext = null,
    decisionOptions = [],
    selectedDecisionId = null,
    failureReason = null
  }) {
    this.id = id;
    this.task = task;
    this.issuer = issuer;
    this.reward = reward;
    this.requirements = requirements;
    this.status = status;
    this.bids = [];
    this.awardedTo = null;
    this.game = null;

    this.deadlineTurn = deadlineTurn;
    this.acceptedTurn = acceptedTurn;
    this.completedTurn = completedTurn;
    this.failedTurn = failedTurn;
    this.reputationReward = reputationReward;
    this.reputationPenalty = reputationPenalty;
    this.trustReward = trustReward;
    this.trustPenalty = trustPenalty;
    this.minimumStanding = minimumStanding;
    this.strategicContext = strategicContext;
    this.decisionOptions = decisionOptions;
    this.selectedDecisionId = selectedDecisionId;
    this.failureReason = failureReason;

    this.storyTag = null;
    this.storySequence = null;
    this.storyMeta = null;
    this.priorityAlpha = false;
    this.createdTurn = 0;

    this.kind = kind;
    this.directiveType = directiveType;
    this.description = description;
    this.icon = icon;
    this.severity = severity;
    this.visibility = visibility;
    this.autoAssign = autoAssign;
    this.rewardPackage = rewardPackage || {};
    this.completionEffects = completionEffects || {};
    this.boardSection = boardSection;
    this.phaseAvailability = phaseAvailability;
    this.progressCache = {
      current: 0,
      target: 0,
      label: 'No progress yet.',
      percent: 0
    };
  }

  addBid(player, bidAmount) {
    if (this.kind === 'directive') {
      return;
    }

    if (this.status !== 'open') {
      console.log(`Cannot bid on contract "${this.task}" as it is not open.`);
      return;
    }

    if (this.hasPlayerBid(player)) {
      console.log(`${player.name} has already placed a bid on this contract.`);
      return;
    }

    if (!this.canPlayerBid(player)) {
      console.log(`${player.name} cannot bid on this contract due to insufficient standing.`);
      return;
    }

    this.bids.push({ player, bidAmount });
    console.log(`${player.name} bid ${bidAmount} credits on contract "${this.task}".`);

    if (this.game?.eventEmitter) {
      this.game.eventEmitter.emit('contractBid', {
        contract: this,
        player,
        bidAmount
      });
    }
  }

  hasPlayerBid(player) {
    return this.bids.some((bid) => bid.player === player);
  }

  getPlayerBid(player) {
    const bid = this.bids.find((entry) => entry.player === player);
    return bid ? bid.bidAmount : 'No bid';
  }

  getIssuerRelationship(player) {
    if (!this.issuer || !player) return null;
    return this.game?.contractManager?.getRelationship?.(this.issuer, player) || null;
  }

  canPlayerBid(player) {
    if (!player) return false;
    if (this.minimumStanding > 0) {
      const relationship = this.getIssuerRelationship(player);
      const standing = relationship?.standing ?? 0;
      if (standing < this.minimumStanding) return false;
    }
    if (this.deadlineTurn && this.game?.turnNumber && this.game.turnNumber > this.deadlineTurn) return false;
    return true;
  }

  getSelectedDecision() {
    if (!this.selectedDecisionId || !this.decisionOptions?.length) return null;
    return this.decisionOptions.find(d => d.id === this.selectedDecisionId) || null;
  }

  chooseDecision(decisionId) {
    const decision = this.decisionOptions?.find(d => d.id === decisionId);
    if (!decision) return null;
    this.selectedDecisionId = decisionId;
    return decision;
  }

  getEffectiveReward() {
    let base = Number(this.reward || 0);
    if (this.issuer && this.awardedTo) {
      const relationship = this.getIssuerRelationship(this.awardedTo);
      const standing = relationship?.standing ?? 0;
      const bonus = Math.max(0, standing / 100) * 0.25;
      base += Math.round(base * bonus);
    }
    return Math.max(0, Math.round(base));
  }

  applyReputationOutcome(game) {
    const recipient = this.awardedTo || game?.getHumanPlayer?.();
    if (!recipient || !this.issuer) return;

    if (this.reputationReward > 0 && game?.contractManager?.modifyRelationship) {
      game.contractManager.modifyRelationship(this.issuer, recipient, this.reputationReward);
    }
    if (this.reputationPenalty > 0 && game?.contractManager?.modifyRelationship) {
      game.contractManager.modifyRelationship(this.issuer, recipient, -this.reputationPenalty);
    }

    if (this.trustReward > 0 && game?.contractManager?.modifyTrust) {
      game.contractManager.modifyTrust(this.issuer, recipient, this.trustReward);
    }
    if (this.trustPenalty > 0 && game?.contractManager?.modifyTrust) {
      game.contractManager.modifyTrust(this.issuer, recipient, -this.trustPenalty);
    }
  }

  fail(game, reason) {
    if (this.status === 'failed' || this.status === 'completed') return;
    this.status = 'failed';
    this.failedTurn = game?.turnNumber || 0;
    this.failureReason = reason || 'Unknown failure reason.';

    this.applyReputationOutcome(game);

    if (game?.eventEmitter) {
      game.eventEmitter.emit('contractFailed', this);
    }

    if (game?.emitStateChanged) {
      game.emitStateChanged('contract_failed', { contract: this });
    }

    showToast(`Contract "${this.task}" has failed: ${this.failureReason}`, 'error');
  }

  assignDirective(player) {
    if (this.kind !== 'directive' || !player) {
      return;
    }

    this.awardedTo = player;
    if (this.status === 'open') {
      this.status = 'awarded';
    }
  }

  awardContract() {
    if (this.kind === 'directive') {
      if (this.awardedTo) {
        this.status = 'awarded';
      }
      return;
    }

    if (this.status !== 'open') {
      console.log(`Contract "${this.task}" is not open for awarding.`);
      return;
    }

    if (this.bids.length === 0) {
      console.log(`No bids placed for contract "${this.task}".`);
      return;
    }

    this.bids.sort((a, b) => a.bidAmount - b.bidAmount);
    const winningBid = this.bids[0];

    this.awardedTo = winningBid.player;
    this.status = 'awarded';
    this.acceptedTurn = this.game?.turnNumber || 0;

    if (this.awardedTo?.isAI && this.decisionOptions?.length > 0) {
      this.chooseDecision(this.decisionOptions[0].id);
    }

    showToast(`Contract "${this.task}" awarded to ${this.awardedTo.name}.`, 'info');
    console.log(`Contract "${this.task}" awarded to ${this.awardedTo.name} with a bid of ${winningBid.bidAmount} credits.`);

    if (this.game?.eventEmitter) {
      this.game.eventEmitter.emit('contractAwarded', this);
    }

    if (this.game?.emitStateChanged) {
      this.game.emitStateChanged('contract_awarded', {
        contract: this
      });
    }

    if (this.awardedTo.isAI && this.awardedTo.contractManager) {
      this.awardedTo.contractManager.handleContract(this);
    } else {
      showToast(`You have been awarded contract "${this.task}".`);
    }
  }

  normalize(value) {
    return String(value || '').trim().toLowerCase();
  }

  getCurrentStoryPhase(game = this.game) {
    return game?.storyManager?.state?.currentPhase || 'phase_1_earth_crisis';
  }

  getStoryPhaseIndex(phaseId) {
    const sequence = [
      'phase_1_earth_crisis',
      'phase_2_inner_system_expansion',
      'phase_3_outer_worlds'
    ];

    const index = sequence.indexOf(String(phaseId || 'phase_1_earth_crisis'));
    return index >= 0 ? index : 0;
  }

  isAvailableForCurrentPhase(game = this.game) {
    const minPhase = this.phaseAvailability?.min || this.storyMeta?.phase || null;
    const maxPhase = this.phaseAvailability?.max || null;
    const currentPhase = this.getCurrentStoryPhase(game);

    if (minPhase && this.getStoryPhaseIndex(currentPhase) < this.getStoryPhaseIndex(minPhase)) {
      return false;
    }

    if (maxPhase && this.getStoryPhaseIndex(currentPhase) > this.getStoryPhaseIndex(maxPhase)) {
      return false;
    }

    return true;
  }

  findTargetBody(game, targetName) {
    if (!game || !targetName) return null;
    const normalizedTarget = this.normalize(targetName);
    return game.bodies.find((body) => this.normalize(body.name) === normalizedTarget) || null;
  }

  findAwardedPlayerColonyOnTarget(game, targetName) {
    if (!game || !this.awardedTo) return null;

    const targetBody = this.findTargetBody(game, targetName);
    if (!targetBody) {
      return null;
    }

    return this.awardedTo.colonies.find((colony) => colony.planet === targetBody) || null;
  }

  buildingMatchesRequirement(building, requiredName, requiredType) {
    const normalizedRequiredName = this.normalize(requiredName);
    const normalizedRequiredType = this.normalize(requiredType);

    const buildingName = this.normalize(building.name);
    const blueprintName = this.normalize(building.blueprintName);
    const buildingType = this.normalize(building.type);

    return (
      buildingName === normalizedRequiredName ||
      blueprintName === normalizedRequiredName ||
      buildingType === normalizedRequiredType ||
      (normalizedRequiredName && buildingName.includes(normalizedRequiredName)) ||
      (normalizedRequiredName && blueprintName.includes(normalizedRequiredName))
    );
  }

  applyDirectiveRewards(game) {
    const recipient = this.awardedTo || game?.getHumanPlayer?.();
    const creditReward = Number(this.rewardPackage?.credits ?? this.reward ?? 0);

    if (recipient && creditReward > 0) {
      recipient.credits += creditReward;
    }

    if (game?.isPhaseOneActive?.() && this.rewardPackage?.fundingBoost) {
      game.phaseOneState.fundingRecoveryBonus = Math.max(
        0,
        Number(game.phaseOneState.fundingRecoveryBonus || 0) + Number(this.rewardPackage.fundingBoost || 0)
      );
    }

    if (game?.isPhaseOneActive?.() && this.rewardPackage?.shipyardCapacityBonus) {
      game.phaseOneState.shipyardRecoveryBonus = Math.max(
        0,
        Number(game.phaseOneState.shipyardRecoveryBonus || 0) + Number(this.rewardPackage.shipyardCapacityBonus || 0)
      );
    }

    if (this.completionEffects?.syncCrisisBoard !== false) {
      game?.crisisOperationsBoard?.sync?.();
    }
  }

  complete(game) {
    if (this.status === 'completed') return;
    if (!this.awardedTo && this.kind !== 'directive') return;

    this.status = 'completed';
    this.completedTurn = game?.turnNumber || 0;

    if (this.kind === 'directive') {
      this.applyDirectiveRewards(game);
      const rewardText = Number(this.rewardPackage?.credits ?? this.reward ?? 0) > 0
        ? ` +${Number(this.rewardPackage?.credits ?? this.reward ?? 0)} credits`
        : '';

      if (typeof showToast === 'function') {
        showToast(`Directive complete: ${this.task}${rewardText}.`, 'success');
      }

      if (game?.notify) {
        game.notify(`Directive complete: ${this.task}${rewardText}.`, 'success', true, {
          contract: this,
          boardSection: this.boardSection
        });
      }
    } else {
      const reward = this.getEffectiveReward();
      this.awardedTo.credits += reward;

      showToast(
        `${this.awardedTo.name} completed contract "${this.task}" and received ${reward} credits.`,
        'success'
      );
      console.log(
        `${this.awardedTo.name} completed contract "${this.task}" and received ${reward} credits.`
      );

      if (this.awardedTo.isAI && this.awardedTo.currentContracts) {
        delete this.awardedTo.currentContracts[this.id];
      }
    }

    this.applyReputationOutcome(game);

    if (game?.eventEmitter) {
      game.eventEmitter.emit('contractCompleted', this);
    }

    if (game?.emitStateChanged) {
      game.emitStateChanged('contract_completed', {
        contract: this
      });
    }
  }

  checkExploreCompletion(game, target) {
    return game.isBodyExploredByPlayer(target, this.awardedTo);
  }

  checkBuildCompletion(game, target, buildingName) {
    const targetColony = this.findAwardedPlayerColonyOnTarget(game, target);
    if (!targetColony) {
      return false;
    }

    const normalizedBuilding = this.normalize(buildingName);

    if (!buildingName || normalizedBuilding === 'habitat') {
      return true;
    }

    const requiredBlueprint = game.buildingBlueprints.find(
      (bp) => this.normalize(bp.name) === normalizedBuilding
    );
    const requiredType = requiredBlueprint ? requiredBlueprint.type : buildingName;

    return targetColony.buildings.some((existingBuilding) =>
      this.buildingMatchesRequirement(existingBuilding, buildingName, requiredType)
    );
  }

  resolveDeliveredAmount(game, target, resource) {
    if (typeof game?.getDeliveredContractProgress === 'function') {
      return Math.max(
        0,
        Number(
          game.getDeliveredContractProgress({
            contract: this,
            target,
            resource,
            player: this.awardedTo
          }) || 0
        )
      );
    }

    if (typeof game?.storyManager?.getDeliveredAmountToTarget === 'function') {
      return Math.max(
        0,
        Number(
          game.storyManager.getDeliveredAmountToTarget(
            target,
            resource,
            this.awardedTo,
            this
          ) || 0
        )
      );
    }

    if (this.normalize(target) === 'earth' && this.normalize(resource) === 'minerals') {
      return Math.max(0, Number(game?.phaseOneState?.mineralsDeliveredToEarth || 0));
    }

    return 0;
  }

  checkDeliverCompletion(game, target, resource, amount) {
    const requiredAmount = Math.max(0, Number(amount || 0));
    const deliveredAmount = this.resolveDeliveredAmount(game, target, resource);
    return deliveredAmount >= requiredAmount;
  }

  getOffEarthColonyCount(player) {
    if (!player?.colonies?.length) {
      return 0;
    }

    return player.colonies.filter((colony) => this.normalize(colony?.planet?.name) !== 'earth').length;
  }

  getCompletedResearchCount(player) {
    return Array.isArray(player?.completedResearch) ? player.completedResearch.length : 0;
  }

  getCompletedContractCount(game, player) {
    const narrativeTag = this.requirements?.narrativeContext || null;
    return (game?.contractManager?.contracts || []).filter((contract) => {
      if (contract.kind === 'directive') {
        return false;
      }
      if (contract.status !== 'completed') {
        return false;
      }
      if (player && contract.awardedTo !== player) {
        return false;
      }
      if (narrativeTag && contract.storyMeta?.narrativeContext !== narrativeTag) {
        return false;
      }
      return true;
    }).length;
  }

  getDirectiveProgress(game) {
    const requirements = this.requirements || {};
    const target = requirements.target;
    const normalizedTask = this.normalize(requirements.task || this.directiveType || this.task);
    const awardedPlayer = this.awardedTo || game?.getHumanPlayer?.();

    if (!this.isAvailableForCurrentPhase(game)) {
      return {
        current: 0,
        target: 1,
        percent: 0,
        label: 'Locked until a later story phase.'
      };
    }

    if (normalizedTask === 'tutorial') {
      const tutorialProgress = game?.tutorialManager?.getDirectiveProgress?.(this);
      if (tutorialProgress) {
        return tutorialProgress;
      }
    }

    if (normalizedTask === 'prospect' || normalizedTask === 'survey') {
      const intel = game?.getProspectingIntel?.(target, awardedPlayer);
      const current = intel?.characterized ? 1 : 0;
      return {
        current,
        target: 1,
        percent: current * 100,
        label: current
          ? `${target} characterized by ${intel.scanShipName || 'survey craft'}.`
          : `Scan ${target} with a Pathfinder, Scout, or advanced sensor ship.`
      };
    }

    if (normalizedTask === 'deliver') {
      const current = this.resolveDeliveredAmount(game, target, requirements.resource);
      const progressTarget = Math.max(1, Number(requirements.amount || 1));
      return {
        current,
        target: progressTarget,
        percent: Math.min(100, (current / progressTarget) * 100),
        label: `${Math.floor(current)}/${progressTarget} ${requirements.resource} delivered to ${target}.`
      };
    }

    if (normalizedTask === 'stability') {
      const score = Number(game?.resolveEarthStabilityState?.().score || 0);
      const progressTarget = Math.max(1, Number(requirements.amount || 100));
      return {
        current: score,
        target: progressTarget,
        percent: Math.min(100, (score / progressTarget) * 100),
        label: `Earth stability at ${score.toFixed(0)}% / ${progressTarget}% target.`
      };
    }

    if (normalizedTask === 'build') {
      const done = this.checkBuildCompletion(game, target, requirements.building);
      return {
        current: done ? 1 : 0,
        target: 1,
        percent: done ? 100 : 0,
        label: done
          ? `${requirements.building} operational on ${target}.`
          : `Construct ${requirements.building} on ${target}.`
      };
    }

    if (normalizedTask === 'explore') {
      const done = this.checkExploreCompletion(game, target);
      return {
        current: done ? 1 : 0,
        target: 1,
        percent: done ? 100 : 0,
        label: done ? `${target} explored.` : `Explore ${target}.`
      };
    }

    if (normalizedTask === 'colony_count') {
      const current = this.getOffEarthColonyCount(awardedPlayer);
      const progressTarget = Math.max(1, Number(requirements.amount || 1));
      return {
        current,
        target: progressTarget,
        percent: Math.min(100, (current / progressTarget) * 100),
        label: `${current}/${progressTarget} off-Earth colonies established.`
      };
    }

    if (normalizedTask === 'research_count') {
      const current = this.getCompletedResearchCount(awardedPlayer);
      const progressTarget = Math.max(1, Number(requirements.amount || 1));
      return {
        current,
        target: progressTarget,
        percent: Math.min(100, (current / progressTarget) * 100),
        label: `${current}/${progressTarget} technologies completed.`
      };
    }

    if (normalizedTask === 'contract_count') {
      const current = this.getCompletedContractCount(game, awardedPlayer);
      const progressTarget = Math.max(1, Number(requirements.amount || 1));
      return {
        current,
        target: progressTarget,
        percent: Math.min(100, (current / progressTarget) * 100),
        label: `${current}/${progressTarget} operational contracts completed.`
      };
    }

    return {
      current: 0,
      target: 1,
      percent: 0,
      label: 'Awaiting progress.'
    };
  }

  updateDirective(game) {
    if (this.kind !== 'directive') {
      return;
    }

    if (!this.awardedTo) {
      this.assignDirective(game?.getHumanPlayer?.());
    }

    this.progressCache = this.getDirectiveProgress(game);

    if (this.status === 'completed') {
      return;
    }

    if (this.visibility === 'hidden') {
      return;
    }

    if (!this.isAvailableForCurrentPhase(game)) {
      return;
    }

    if (this.status === 'open') {
      this.status = 'awarded';
    }

    const progressTarget = Math.max(1, Number(this.progressCache.target || 1));
    const current = Number(this.progressCache.current || 0);

    if (current >= progressTarget) {
      this.complete(game);
    }
  }

  checkCompletion(game) {
    if (this.kind === 'directive') {
      this.updateDirective(game);
      return;
    }

    if (this.status !== 'awarded' || !this.awardedTo) {
      return;
    }

    const { task, target, building, resource, amount } = this.requirements || {};
    const normalizedTask = this.normalize(task);

    let requirementsMet = false;

    if (normalizedTask === 'explore') {
      requirementsMet = this.checkExploreCompletion(game, target);
    } else if (normalizedTask === 'build') {
      requirementsMet = this.checkBuildCompletion(game, target, building);
    } else if (normalizedTask === 'deliver') {
      requirementsMet = this.checkDeliverCompletion(game, target, resource, amount);
    } else if (normalizedTask === 'colony_count') {
      requirementsMet = this.getOffEarthColonyCount(this.awardedTo) >= Math.max(1, Number(amount || 1));
    } else if (normalizedTask === 'research_count') {
      requirementsMet = this.getCompletedResearchCount(this.awardedTo) >= Math.max(1, Number(amount || 1));
    } else if (normalizedTask === 'contract_count') {
      requirementsMet = this.getCompletedContractCount(game, this.awardedTo) >= Math.max(1, Number(amount || 1));
    }

    if (requirementsMet) {
      this.complete(game);
    }
  }
}
Contract;


// ===== public/classes/managers/ContractManager.js =====

class ContractManager {
  constructor(game) {
    this.game = game;
    this.contracts = [];
    this.nextContractId = 1;

    this.lastGenerationTurn = -999;
    this.minTurnsBetweenGenerations = 2;
    this.lastEmergencyBountyTurn = -999;
    this.maxActiveEmergencyBounties = 2;
    this.defaultContractDurationTurns = 12;
    this.contractOutcomeHistory = [];
  }

  normalizeText(value) {
    return String(value || '').trim().toLowerCase();
  }

  getCurrentStoryPhase() {
    return this.game?.storyManager?.getCurrentPhase?.() || this.game?.storyManager?.state?.currentPhase || 'phase_1_earth_crisis';
  }

  getStoryPhaseIndex(phaseId = this.getCurrentStoryPhase()) {
    const sequence = [
      'phase_1_earth_crisis',
      'phase_2_inner_system_expansion',
      'phase_3_outer_worlds'
    ];

    const index = sequence.indexOf(String(phaseId || 'phase_1_earth_crisis'));
    return index >= 0 ? index : 0;
  }

  getNarrativeDirectiveCompletionRatio() {
    return this.game?.crisisOperationsBoard?.getNarrativeCompletionRatio?.() || 0;
  }

  resolveIssuerPlayer(issuer) {
    if (!issuer) return null;

    if (typeof issuer === 'object') {
      return issuer;
    }

    return this.game.players.find((player) => player.name === issuer) || null;
  }

  getContractKey(requirements = {}) {
    return [
      this.normalizeText(requirements.task),
      this.normalizeText(requirements.target),
      this.normalizeText(requirements.building),
      this.normalizeText(requirements.resource),
      String(requirements.amount || '')
    ].join('|');
  }

  hasDuplicateActiveContract(contractDef) {
    const nextKey = this.getContractKey(contractDef.requirements);

    return this.contracts.some((contract) => {
      if (!['open', 'awarded'].includes(contract.status)) return false;
      return this.getContractKey(contract.requirements) === nextKey;
    });
  }

  buildFallbackTaskLabel(requirements = {}) {
    if (requirements.task === 'explore' && requirements.target) {
      return `Explore ${requirements.target}`;
    }

    if (requirements.task === 'build' && requirements.target && requirements.building) {
      return `Build ${requirements.building} on ${requirements.target}`;
    }

    if (requirements.task === 'deliver' && requirements.target && requirements.resource) {
      return `Deliver ${requirements.resource} to ${requirements.target}`;
    }

    return 'Contract';
  }

  isStoryContract(contract) {
    return Boolean(contract?.storyMeta || contract?.priorityAlpha || contract?.storyTag || contract?.kind === 'directive');
  }

  getPriorityAlphaIssuer() {
    const unitedEarthDirectorate = this.game.players.find(
      (player) => player.isAI && player.aiType === 'government' && player.name === 'United Earth Directorate'
    );

    if (unitedEarthDirectorate) {
      return unitedEarthDirectorate;
    }

    const governmentAI = this.game.players.find((player) => player.isAI && player.aiType === 'government');
    return governmentAI || this.game.players.find((player) => player.isAI) || null;
  }

  getActivePriorityAlphaContract() {
    return null;
  }

  initializeFactionRelationships() {
    const players = this.game?.players || [];
    players.forEach(player => {
      players.forEach(other => {
        if (player === other) return;
        let initialStanding = 0;
        if (!player.isAI && other?.factionProfile?.archetype === 'government') initialStanding = 10;
        if (player.isAI && !other.isAI && player?.factionProfile?.archetype === 'government') initialStanding = 10;
        player.initializeRelationship?.(other, initialStanding);
      });
    });
  }

  deriveStrategicContext(requirements = {}, issuer = null) {
    const task = this.normalizeText(requirements.task);
    const targetBody = this.game?.bodies?.find(body => this.normalizeText(body.name) === this.normalizeText(requirements.target));
    const targetColonies = (this.game?.players || []).flatMap(player => player.colonies || []).filter(colony => colony.planet === targetBody);
    const resource = requirements.resource;
    const shortage = resource
      ? targetColonies.reduce((sum, colony) => sum + Math.max(0, Number(requirements.amount || 0) - Number(colony.getResourceAmount?.(resource) || 0)), 0)
      : 0;

    return {
      task,
      target: requirements.target || null,
      resource: resource || null,
      shortage,
      issuerArchetype: issuer?.factionProfile?.archetype || issuer?.aiType || 'independent',
      issuerGoals: [...(issuer?.factionProfile?.goals || [])],
      generatedFromSimulation: shortage > 0 || ['build', 'deliver', 'patrol', 'escort'].includes(task),
      generatedTurn: this.game?.turnNumber || 0
    };
  }

  buildContractDecisionOptions(requirements = {}, issuer = null) {
    const task = this.normalizeText(requirements.task);
    const issuerName = issuer?.name || 'Issuer';

    if (task === 'deliver' || task === 'trade') {
      return [
        { id: 'relief_priority', label: 'Relief Priority', description: `Accept a lower margin and prioritize public access for ${issuerName}.`, rewardMultiplier: 0.9, standingDelta: 12, trustDelta: 9, aiWeight: 1.05 },
        { id: 'standard_delivery', label: 'Standard Delivery', description: 'Fulfil the shipment under normal commercial terms.', rewardMultiplier: 1, standingDelta: 8, trustDelta: 5, aiWeight: 1 },
        { id: 'premium_expedite', label: 'Premium Expedite', description: 'Charge more for a faster, higher-risk commitment.', rewardMultiplier: 1.18, standingDelta: 4, trustDelta: 1, aiWeight: 0.9 }
      ];
    }

    if (['explore', 'prospect', 'survey'].includes(task)) {
      return [
        { id: 'share_all_data', label: 'Share Full Survey Data', description: `Transfer complete scientific records to ${issuerName}.`, rewardMultiplier: 0.92, standingDelta: 12, trustDelta: 10, aiWeight: 1.1 },
        { id: 'licensed_data', label: 'License the Findings', description: 'Share mission-critical results while retaining commercial rights.', rewardMultiplier: 1.05, standingDelta: 7, trustDelta: 4, aiWeight: 1 },
        { id: 'retain_discovery', label: 'Retain Discovery Rights', description: 'Keep exclusive rights to secondary findings.', rewardMultiplier: 1.2, standingDelta: 2, trustDelta: -2, aiWeight: 0.8 }
      ];
    }

    if (task === 'build' || task === 'colonize') {
      return [
        { id: 'local_partnership', label: 'Local Partnership', description: 'Use local contractors and share operational control.', rewardMultiplier: 0.95, standingDelta: 11, trustDelta: 8, aiWeight: 1.05 },
        { id: 'standard_build', label: 'Standard Build', description: 'Deliver the installation to the agreed specification.', rewardMultiplier: 1, standingDelta: 8, trustDelta: 5, aiWeight: 1 },
        { id: 'rapid_deployment', label: 'Rapid Deployment', description: 'Prioritize speed over long-term political goodwill.', rewardMultiplier: 1.15, standingDelta: 4, trustDelta: 1, aiWeight: 0.9 }
      ];
    }

    if (['patrol', 'escort', 'intercept'].includes(task)) {
      return [
        { id: 'protect_civilians', label: 'Protect Civilian Traffic', description: 'Adopt restrictive engagement rules and prioritize transports.', rewardMultiplier: 0.95, standingDelta: 12, trustDelta: 9, aiWeight: 1.05 },
        { id: 'mission_first', label: 'Mission First', description: 'Use standard rules of engagement.', rewardMultiplier: 1, standingDelta: 8, trustDelta: 5, aiWeight: 1 },
        { id: 'aggressive_deterrence', label: 'Aggressive Deterrence', description: 'Accept escalation risk for a higher payout.', rewardMultiplier: 1.18, standingDelta: 3, trustDelta: 0, aiWeight: 0.85 }
      ];
    }

    return [];
  }

  estimateContractDeadlineTurns(requirements = {}) {
    const task = this.normalizeText(requirements.task);
    const base = task === 'explore' || task === 'prospect' ? 16 : task === 'build' || task === 'colonize' ? 18 : task === 'deliver' ? 12 : this.defaultContractDurationTurns;
    const amountBonus = Math.min(8, Math.ceil(Number(requirements.amount || 0) / 100));
    return base + amountBonus;
  }

  processContractDeadlines() {
    const turn = Number(this.game?.turnNumber || 0);
    this.contracts.forEach(contract => {
      if (!['open', 'awarded'].includes(contract.status)) return;
      if (!Number.isFinite(contract.deadlineTurn)) return;
      if (turn <= contract.deadlineTurn) return;
      contract.fail?.(this.game, contract.status === 'open' ? 'Bidding period expired.' : 'Operational deadline missed.');
    });
  }

  recordContractOutcome(contract) {
    if (!contract) return;
    this.contractOutcomeHistory.push({
      contractId: contract.id,
      task: contract.task,
      issuerName: contract.issuer?.name || contract.issuer,
      awardedToName: contract.awardedTo?.name || null,
      status: contract.status,
      completedTurn: contract.completedTurn || null,
      failedTurn: contract.failedTurn || null,
      decisionId: contract.selectedDecisionId || null
    });
    if (this.contractOutcomeHistory.length > 100) this.contractOutcomeHistory.shift();
  }

  createContract({ task, issuer, reward, requirements, status = 'open', ...extra }) {
    const issuerPlayer = this.resolveIssuerPlayer(issuer);
    if (!issuerPlayer) {
      console.error(`Issuer "${issuer}" not found. Cannot create contract.`);
      return null;
    }

    if (!requirements || !requirements.task || !requirements.target) {
      console.error('Invalid contract requirements. Cannot create contract.', {
        task,
        issuer,
        reward,
        requirements
      });
      return null;
    }

    if (this.hasDuplicateActiveContract({ requirements })) {
      console.warn('Skipping duplicate active contract.', {
        task,
        issuer: issuerPlayer.name,
        requirements
      });
      return null;
    }

    const normalizedReward = Math.max(100, Math.round(Number(reward) || 0));

    const strategicContext = extra.strategicContext || this.deriveStrategicContext(requirements, issuerPlayer);
    const decisionOptions = Array.isArray(extra.decisionOptions)
      ? extra.decisionOptions
      : this.buildContractDecisionOptions(requirements, issuerPlayer);
    const deadlineTurn = Number.isFinite(extra.deadlineTurn)
      ? extra.deadlineTurn
      : (this.game.turnNumber + this.estimateContractDeadlineTurns(requirements));

    const contract = new Contract({
      id: this.nextContractId++,
      task: task || this.buildFallbackTaskLabel(requirements),
      issuer: issuerPlayer,
      reward: normalizedReward,
      requirements,
      status
    });

    contract.game = this.game;
    Object.assign(contract, extra, {
      strategicContext,
      decisionOptions,
      deadlineTurn,
      createdTurn: this.game.turnNumber,
      reputationReward: Number(extra.reputationReward ?? (strategicContext.shortage > 0 ? 10 : 8)),
      reputationPenalty: Number(extra.reputationPenalty ?? -10),
      minimumStanding: Number(extra.minimumStanding ?? -40)
    });
    this.contracts.push(contract);

    this.game.eventEmitter?.emit('contractCreated', contract);
    console.log(`Contract created: "${contract.task}" by ${issuerPlayer.name}`);
    return contract;
  }

  getContractsForPlayer(player) {
    return this.contracts.filter((contract) => {
      if (contract.status === 'open') {
        return contract.hasPlayerBid(player);
      }
      return contract.awardedTo === player;
    });
  }

  getOpenContracts() {
    return this.contracts.filter((contract) => contract.status === 'open');
  }

  getContractsForUI() {
    const openContracts = this.getOpenContracts();
    const awardedContracts = this.contracts.filter((contract) => contract.status === 'awarded');
    const completedContracts = this.contracts.filter((contract) => contract.status === 'completed');
    const queuedContracts = this.contracts.filter((contract) => contract.status === 'queued');

    return {
      openContracts,
      awardedContracts,
      completedContracts,
      queuedContracts
    };
  }

  checkContractsForMissionCompletion(ship, missionType) {
    const playerContracts = this.contracts.filter((contract) =>
      contract.awardedTo === ship.owner && contract.status === 'awarded'
    );

    playerContracts.forEach((contract) => {
      if (this.isPriorityAlphaContract(contract)) return;
      contract.checkCompletion(this.game, ship, missionType);
    });
  }

  getHumanPlayer() {
    return this.game.players.find((player) => !player.isAI) || null;
  }

  getAIPlayers() {
    return this.game.players.filter((player) => player.isAI);
  }

  getEarthColony(player = this.getHumanPlayer()) {
    return player?.colonies?.find((colony) => colony?.planet?.name === 'Earth') || null;
  }

  getEarthCrisisSeverity() {
    const earthState = this.game?.resolveEarthStabilityState?.() || {};
    const foodCoverage = Number(earthState.foodCoverage || 0);
    const waterCoverage = Number(earthState.waterCoverage || 0);
    const score = Number(earthState.score || 0);

    const shortagePressure = Math.max(0, 10 - Math.min(foodCoverage, waterCoverage));
    const stabilityPressure = Math.max(0, 25 - score) / 5;

    return Number((shortagePressure + stabilityPressure).toFixed(2));
  }

  isEarthInStarvationEmergency() {
    if (this.getCurrentStoryPhase() !== 'phase_1_earth_crisis') {
      return false;
    }

    const earthState = this.game?.resolveEarthStabilityState?.() || {};
    const foodCoverage = Number(earthState.foodCoverage || 0);
    const waterCoverage = Number(earthState.waterCoverage || 0);
    const score = Number(earthState.score || 0);

    return score < 25 || foodCoverage < 10 || waterCoverage < 10;
  }

  getActiveEmergencyBounties() {
    return this.contracts.filter((contract) =>
      contract.kind === 'emergency_bounty' &&
      ['open', 'awarded'].includes(contract.status)
    );
  }

  expireResolvedEmergencyBounties() {
    if (this.isEarthInStarvationEmergency()) {
      return;
    }

    this.contracts.forEach((contract) => {
      if (contract.kind === 'emergency_bounty' && contract.status === 'open') {
        contract.status = 'fulfilled';
      }
    });
  }

  buildEmergencyBountyCandidates() {
    if (!this.isEarthInStarvationEmergency()) {
      return [];
    }

    const issuer = this.getPriorityAlphaIssuer();
    const earthState = this.game?.resolveEarthStabilityState?.() || {};
    const severity = this.getEarthCrisisSeverity();
    const earthColony = this.getEarthColony();
    const player = this.getHumanPlayer();

    if (!issuer || !player) {
      return [];
    }

    const candidates = [];
    const foodCoverage = Number(earthState.foodCoverage || 0);
    const waterCoverage = Number(earthState.waterCoverage || 0);
    const score = Number(earthState.score || 0);

    if (foodCoverage < 12) {
      candidates.push({
        task: 'Emergency Food Lift: Earth',
        issuer: issuer.name,
        reward: Math.round(3600 + (Math.max(0, 12 - foodCoverage) * 260) + (severity * 220)),
        requirements: {
          task: 'deliver',
          target: 'Earth',
          resource: 'Food',
          amount: 160
        },
        description: 'Directorate rationing has failed. Run a hazardous food convoy into Earth orbit before the next distribution collapse.',
        icon: 'mdi-food-drumstick-outline',
        severity: 'error',
        kind: 'emergency_bounty',
        rewardPackage: {
          credits: Math.round(3600 + (Math.max(0, 12 - foodCoverage) * 260) + (severity * 220))
        }
      });
    }

    if (waterCoverage < 12) {
      candidates.push({
        task: 'Emergency Water Lift: Earth',
        issuer: issuer.name,
        reward: Math.round(3800 + (Math.max(0, 12 - waterCoverage) * 280) + (severity * 240)),
        requirements: {
          task: 'deliver',
          target: 'Earth',
          resource: 'Water',
          amount: 180
        },
        description: 'Hydration coverage is breaking down planet-side. The Directorate is offering crisis-rate hazard pay for any ship that can deliver emergency water.',
        icon: 'mdi-water-alert-outline',
        severity: 'error',
        kind: 'emergency_bounty',
        rewardPackage: {
          credits: Math.round(3800 + (Math.max(0, 12 - waterCoverage) * 280) + (severity * 240))
        }
      });
    }

    if (score < 20) {
      candidates.push({
        task: 'Hazard Pay Minerals Run',
        issuer: issuer.name,
        reward: Math.round(3200 + ((20 - score) * 120) + (severity * 160)),
        requirements: {
          task: 'deliver',
          target: 'Earth',
          resource: 'Minerals',
          amount: 220
        },
        description: 'Earth’s stabilization build queue is stalled for lack of off-world minerals. The Directorate is posting an oversized payout for a fast, risky shipment.',
        icon: 'mdi-pickaxe',
        severity: 'warning',
        kind: 'emergency_bounty',
        rewardPackage: {
          credits: Math.round(3200 + ((20 - score) * 120) + (severity * 160))
        }
      });
    }

    const existingBuildings = new Set(
      (earthColony?.buildings || []).map((building) => this.normalizeText(building?.blueprintName || building?.name || building?.type))
    );

    if (!existingBuildings.has('water extractor')) {
      candidates.push({
        task: 'Emergency Contract: Earth Water Extractor',
        issuer: issuer.name,
        reward: Math.round(4200 + (severity * 180)),
        requirements: {
          task: 'build',
          target: 'Earth',
          building: 'Water Extractor'
        },
        description: 'The Directorate is paying premium crisis construction rates for a water-extractor project that can survive current shortages.',
        icon: 'mdi-water-pump',
        severity: 'warning',
        kind: 'emergency_bounty',
        rewardPackage: {
          credits: Math.round(4200 + (severity * 180))
        }
      });
    }

    if (!existingBuildings.has('farm')) {
      candidates.push({
        task: 'Emergency Contract: Earth Farm',
        issuer: issuer.name,
        reward: Math.round(4000 + (severity * 170)),
        requirements: {
          task: 'build',
          target: 'Earth',
          building: 'Farm'
        },
        description: 'Food coverage is failing. Build an emergency farm line and collect a massive Phase One famine bounty.',
        icon: 'mdi-sprout',
        severity: 'warning',
        kind: 'emergency_bounty',
        rewardPackage: {
          credits: Math.round(4000 + (severity * 170))
        }
      });
    }

    return candidates
      .filter((candidate) => !this.hasDuplicateActiveContract(candidate))
      .sort((a, b) => b.reward - a.reward);
  }

  ensureEmergencyBounties({ force = false } = {}) {
    this.expireResolvedEmergencyBounties();

    if (!this.isEarthInStarvationEmergency()) {
      return [];
    }

    const active = this.getActiveEmergencyBounties();
    const currentTurn = Number(this.game?.turnNumber || 0);

    if (!force && active.length >= this.maxActiveEmergencyBounties) {
      return active;
    }

    if (!force && (currentTurn - this.lastEmergencyBountyTurn) < 1) {
      return active;
    }

    const created = [];
    const candidates = this.buildEmergencyBountyCandidates();

    for (const candidate of candidates) {
      if ((active.length + created.length) >= this.maxActiveEmergencyBounties) {
        break;
      }

      const contract = this.createContract(candidate);
      if (!contract) continue;

      created.push(contract);
      this.game?.notify?.(
        `Emergency bounty posted: ${contract.task}. Directorate payout ${Math.round(contract.reward).toLocaleString()} ₵.`,
        'warning',
        true,
        { contract }
      );
    }

    if (created.length > 0) {
      this.lastEmergencyBountyTurn = currentTurn;
    }

    return created;
  }

  isPriorityAlphaContract(contract) {
    return false;
  }

  arePriorityAlphaContractsFinished() {
    return false;
  }

  isFactoryBlueprint(blueprintOrName) {
    const name = this.normalizeText(typeof blueprintOrName === 'string' ? blueprintOrName : blueprintOrName?.name);
    const type = this.normalizeText(typeof blueprintOrName === 'string' ? '' : blueprintOrName?.type);
    return name.includes('factory') || type === 'factory';
  }

  isMineBlueprint(blueprintOrName) {
    const name = this.normalizeText(typeof blueprintOrName === 'string' ? blueprintOrName : blueprintOrName?.name);
    const type = this.normalizeText(typeof blueprintOrName === 'string' ? '' : blueprintOrName?.type);
    return name.includes('mine') || type === 'mine' || name.includes('extractor mine');
  }

  isEarthStabilizationBlueprint(blueprintOrName) {
    const name = this.normalizeText(typeof blueprintOrName === 'string' ? blueprintOrName : blueprintOrName?.name);
    const type = this.normalizeText(typeof blueprintOrName === 'string' ? '' : blueprintOrName?.type);

    return (
      name.includes('farm') ||
      name.includes('hydropon') ||
      name.includes('water extractor') ||
      name.includes('water reclam') ||
      type === 'farm' ||
      type === 'water'
    );
  }

  seedPriorityAlphaContracts() {
    return [];
  }

  unlockNextPriorityAlphaContract() {
    return null;
  }

  completePriorityAlphaContract() {
    return null;
  }

  processPriorityAlphaContracts() {
    return null;
  }

  processContracts() {
    this.processPriorityAlphaContracts();
    this.ensureEmergencyBounties();
    this.processContractDeadlines();

    this.contracts.forEach((contract) => {
      if (contract.kind === 'directive') {
        return;
      }

      if (contract.status === 'open') {
        contract.awardContract();
      } else if (contract.status === 'awarded') {
        contract.checkCompletion(this.game);
      }
    });

    this.contracts = this.contracts.filter((contract) => contract.status !== 'fulfilled');

    if (this.getCurrentStoryPhase() === 'phase_1_earth_crisis') {
      this.ensurePhaseOneContractFlow({
        minimumOpenContracts: this.isEarthInStarvationEmergency() ? 2 : 1
      });
      return;
    }

    this.generateSmartContracts();
  }

  getExploredBodiesForPlayer(player) {
    if (!player) return [];
    return this.game.exploredBodies[player.name] || [];
  }

  getExploredBodyNameSet(player) {
    return new Set(
      this.getExploredBodiesForPlayer(player).map((name) => this.normalizeText(name))
    );
  }

  getPlayerHomeBody(player) {
    if (player?.colonies?.length) {
      return player.colonies[0].planet || null;
    }

    return this.game.bodies.find((body) => body.name === 'Earth') || null;
  }

  getDistanceBetweenBodies(fromBody, toBody) {
    if (!fromBody || !toBody) return Infinity;
    if (fromBody === toBody) return 0;

    if (
      typeof window !== 'undefined' &&
      window.BABYLON?.Vector3 &&
      fromBody.position &&
      toBody.position
    ) {
      return window.BABYLON.Vector3.Distance(fromBody.position, toBody.position);
    }

    const fromAxis = Number(fromBody?.orbitalElements?.semiMajorAxis || 0);
    const toAxis = Number(toBody?.orbitalElements?.semiMajorAxis || 0);

    if (fromAxis > 0 || toAxis > 0) {
      return Math.abs(toAxis - fromAxis);
    }

    return Infinity;
  }

  getBodyProximityScore(player, body) {
    const homeBody = this.getPlayerHomeBody(player);
    const distance = this.getDistanceBetweenBodies(homeBody, body);

    if (!Number.isFinite(distance)) return 1;

    if (distance <= 5e10) return 4.5;
    if (distance <= 2e11) return 3.5;
    if (distance <= 6e11) return 2.5;
    if (distance <= 1.5e12) return 1.5;
    if (distance <= 3e12) return 0.75;

    return 0.25;
  }

  estimateTransferMargin(targetBody, shipType = 'construction') {
    const referencePlayer = this.getHumanPlayer();
    const stagingBody =
      this.getPlayerHomeBody(referencePlayer) ||
      this.game.bodies.find((body) => body.name === 'Earth');

    if (!stagingBody || !targetBody) {
      return shipType === 'construction' ? 500 : 280;
    }

    const distance = this.getDistanceBetweenBodies(stagingBody, targetBody);
    const base = shipType === 'construction' ? 500 : 280;
    const variable = Number.isFinite(distance) ? (distance / 1e11) : 2;

    return Math.round(base + (variable * (shipType === 'construction' ? 800 : 450)));
  }

  getContractGenerationStage() {
    const humanPlayer = this.getHumanPlayer();
    const colonyCount = humanPlayer?.colonies?.length || 0;
    const exploredCount = this.getExploredBodiesForPlayer(humanPlayer).length;
    const researchCount = humanPlayer?.completedResearch?.length || 0;
    const turn = Number(this.game.turnNumber || 0);

    let score = 0;

    if (turn >= 18) score += 1;
    if (turn >= 40) score += 1;
    if (turn >= 80) score += 1;

    if (colonyCount >= 2) score += 1;
    if (colonyCount >= 4) score += 1;

    if (exploredCount >= 4) score += 1;
    if (exploredCount >= 8) score += 1;

    if (researchCount >= 3) score += 1;
    if (researchCount >= 7) score += 1;

    if (score <= 1) return 'opening';
    if (score <= 4) return 'early_expansion';
    if (score <= 7) return 'midgame';
    return 'late';
  }

  getStageContractTypeWeights(stage) {
    const phaseId = this.getCurrentStoryPhase();

    if (phaseId === 'phase_1_earth_crisis') {
      switch (stage) {
        case 'opening':
          return { explore: 9.0, colonize: 0, infrastructure: 0.5 };
        case 'early_expansion':
          return { explore: 6.2, colonize: 0.2, infrastructure: 1.1 };
        default:
          return { explore: 4.5, colonize: 0.4, infrastructure: 1.4 };
      }
    }

    if (phaseId === 'phase_2_inner_system_expansion') {
      switch (stage) {
        case 'opening':
          return { explore: 4.8, colonize: 2.2, infrastructure: 1.4 };
        case 'early_expansion':
          return { explore: 3.8, colonize: 2.9, infrastructure: 2.0 };
        default:
          return { explore: 3.1, colonize: 3.0, infrastructure: 2.5 };
      }
    }

    switch (stage) {
      case 'opening':
        return { explore: 3.0, colonize: 2.0, infrastructure: 2.0 };
      case 'early_expansion':
        return { explore: 2.8, colonize: 2.6, infrastructure: 2.4 };
      case 'midgame':
        return { explore: 2.4, colonize: 2.7, infrastructure: 2.9 };
      default:
        return { explore: 2.2, colonize: 2.5, infrastructure: 3.0 };
    }
  }

  getStageBuildCreditCap(stage) {
    const phaseId = this.getCurrentStoryPhase();

    if (phaseId === 'phase_1_earth_crisis') {
      return 2400;
    }

    switch (stage) {
      case 'opening':
        return 2200;
      case 'early_expansion':
        return 3600;
      case 'midgame':
        return 6500;
      default:
        return Infinity;
    }
  }

  playerHasColonyOn(player, body) {
    if (!player || !body) return false;

    if (typeof player.hasColonyOn === 'function') {
      return player.hasColonyOn(body);
    }

    return Array.isArray(player.colonies) && player.colonies.some((colony) => colony.planet === body);
  }

  hasRequiredResearch(player, requiredResearch) {
    if (!player) return false;
    if (!requiredResearch) return true;

    if (Array.isArray(requiredResearch) && requiredResearch.length === 0) {
      return true;
    }

    if (typeof player.hasAllRequiredResearch === 'function') {
      return player.hasAllRequiredResearch(requiredResearch);
    }

    return true;
  }

  getBlueprintByName(name) {
    return this.game.buildingBlueprints.find((blueprint) => blueprint.name === name) || null;
  }

  getBlueprintEconomicValue(blueprint) {
    if (!blueprint?.costToBuild) return 1000;

    return Object.entries(blueprint.costToBuild).reduce((sum, [resourceName, amount]) => {
      if (resourceName === 'Credits') {
        return sum + amount;
      }

      const resource = this.game.resourceManager.getResourceByName(resourceName);
      const unitValue = resource?.basePrice || 10;
      return sum + (amount * unitValue);
    }, 0);
  }

  roundReward(value) {
    return Math.max(500, Math.round(value / 50) * 50);
  }

  getBodyRemotenessBonus(body) {
    const semiMajorAxis = Number(body?.orbitalElements?.semiMajorAxis || 0);

    if (semiMajorAxis >= 4e12) return 2600;
    if (semiMajorAxis >= 2e12) return 1800;
    if (semiMajorAxis >= 9e11) return 1100;
    if (semiMajorAxis >= 4e11) return 650;
    if (semiMajorAxis >= 2e11) return 300;

    return 0;
  }

  getPhaseOneNarrativeScore(body) {
    if (this.getCurrentStoryPhase() !== 'phase_1_earth_crisis' || !body) {
      return 0;
    }

    const surveyTarget = this.game.getPhaseOneSurveyTarget?.();
    const earth = this.game.bodies.find((candidate) => candidate.name === 'Earth');
    const tags = new Set(body.resourceTags || []);
    const distanceFromEarth = this.getDistanceBetweenBodies(earth, body);

    let score = 0;

    if (body.name === 'Moon') score += 12;
    if (surveyTarget?.name === body.name) score += 14;
    if (tags.has('metals')) score += 9;
    if (tags.has('rare-metals')) score += 7;
    if (tags.has('industry')) score += 3;
    if (tags.has('construction')) score += 2;
    if (body.strategicValue) score += Number(body.strategicValue) * 0.4;
    if (body.isColonizable) score += 1.5;

    if (Number.isFinite(distanceFromEarth)) {
      score += Math.max(0, 5 - (distanceFromEarth / 1.25e11));
    }

    return score;
  }

  getPhaseBodyBias(body) {
    const phaseId = this.getCurrentStoryPhase();
    const semiMajorAxis = Number(body?.orbitalElements?.semiMajorAxis || 0);

    if (phaseId === 'phase_1_earth_crisis') {
      if (body?.name === 'Moon') return 8;
      if (semiMajorAxis <= 2e11) return 4;
      return -8;
    }

    if (phaseId === 'phase_2_inner_system_expansion') {
      if (semiMajorAxis <= 1.2e12) return 4;
      if (semiMajorAxis <= 2.0e12) return 1.5;
      return -4;
    }

    if (semiMajorAxis >= 9e11) return 4;
    return -1;
  }

  getExploreContractTaskLabel(body, stage) {
    if (this.getCurrentStoryPhase() === 'phase_1_earth_crisis') {
      const surveyTarget = this.game.getPhaseOneSurveyTarget?.();
      const tags = new Set(body.resourceTags || []);

      if (surveyTarget?.name === body.name) {
        return `Priority Recon: ${body.name}`;
      }

      if (body.name === 'Moon') {
        return 'Mineral Survey: Moon';
      }

      if (tags.has('metals') || tags.has('rare-metals') || tags.has('industry') || tags.has('construction')) {
        return `Mineral Prospecting: ${body.name}`;
      }

      return `Relief Survey: ${body.name}`;
    }

    if (this.getCurrentStoryPhase() === 'phase_2_inner_system_expansion') {
      return `Expansion Survey: ${body.name}`;
    }

    return `Deep Survey: ${body.name}`;
  }

  getBuildContractTaskLabel(body, buildingName) {
    const normalizedBuildingName = this.normalizeText(buildingName);

    if (this.getCurrentStoryPhase() === 'phase_1_earth_crisis') {
      if (body?.name === 'Earth' && this.isEarthStabilizationBlueprint(buildingName)) {
        return `Earth Stabilization: ${buildingName}`;
      }

      if (normalizedBuildingName === 'habitat') {
        return `Frontier Relief Base on ${body.name}`;
      }

      return `Stabilization Build: ${buildingName} on ${body.name}`;
    }

    if (this.getCurrentStoryPhase() === 'phase_2_inner_system_expansion') {
      if (normalizedBuildingName === 'habitat') {
        return `Settlement Push: ${body.name}`;
      }
      return `Expansion Build: ${buildingName} on ${body.name}`;
    }

    if (normalizedBuildingName === 'habitat') {
      return `Deep Frontier Base on ${body.name}`;
    }

    return `Outer Worlds Construction: ${buildingName} on ${body.name}`;
  }

  calculateExploreReward(body, player, stage) {
    const strategic = Number(body?.strategicValue || 1) * 300;
    const colonizableBonus = body?.isColonizable ? 250 : 0;
    const proximityBonus = this.getBodyProximityScore(player, body) * 150;
    const remotenessWeight = stage === 'late' ? 0.5 : stage === 'midgame' ? 0.25 : 0.1;
    const remoteness = this.getBodyRemotenessBonus(body) * remotenessWeight;
    const narrativeBonus = this.getPhaseOneNarrativeScore(body) * 110;
    const phaseBias = this.getPhaseBodyBias(body) * 120;
    const stageMultiplier =
      stage === 'opening' ? 0.84 :
      stage === 'early_expansion' ? 0.92 :
      1;

    return this.roundReward((1500 + strategic + colonizableBonus + proximityBonus + remoteness + narrativeBonus + phaseBias) * stageMultiplier);
  }

  calculateBuildReward(body, buildingName, player, stage) {
    const blueprint = this.getBlueprintByName(buildingName);
    const economicValue = blueprint ? this.getBlueprintEconomicValue(blueprint) : 2500;
    const strategic = Number(body?.strategicValue || 1) * 220;
    const proximityBonus = this.getBodyProximityScore(player, body) * 120;
    const remotenessWeight = stage === 'late' ? 0.5 : stage === 'midgame' ? 0.3 : 0.12;
    const remoteness = this.getBodyRemotenessBonus(body) * remotenessWeight;
    const complexityPremium = this.normalizeText(buildingName) === 'habitat' ? 700 : 325;
    const narrativeBonus = this.getPhaseOneNarrativeScore(body) * 85;
    const earthStabilizationBonus = body?.name === 'Earth' && this.isEarthStabilizationBlueprint(buildingName) ? 900 : 0;
    const stageMultiplier =
      stage === 'opening' ? 0.82 :
      stage === 'early_expansion' ? 0.90 :
      1;

    return this.roundReward(
      ((economicValue * 1.22) + strategic + proximityBonus + remoteness + complexityPremium + narrativeBonus + earthStabilizationBonus) * stageMultiplier
    );
  }

  isBodyEligibleForExploration(body) {
    if (!body) return false;
    if (body.name === 'Sun') return false;
    if (body.type === 'star') return false;

    return ['planet', 'moon', 'dwarf_planet', 'asteroid', 'gas_giant'].includes(body.type);
  }

  getExploreCandidateScore(body, player, stage) {
    let score = Number(body?.strategicValue || 1);
    const proximity = this.getBodyProximityScore(player, body);

    if (body?.isColonizable) score += 2.5;
    if (body?.type === 'moon') score += 1.2;
    if (body?.type === 'planet') score += 1.6;

    const resourceTags = Array.isArray(body?.resourceTags) ? body.resourceTags : [];
    if (resourceTags.includes('water')) score += 1.4;
    if (resourceTags.includes('industry')) score += 1.2;
    if (resourceTags.includes('helium3')) score += 1.0;
    if (resourceTags.includes('shipbuilding')) score += 1.2;
    if (resourceTags.includes('metals')) score += 1.1;

    score += proximity * (stage === 'opening' ? 2.8 : stage === 'early_expansion' ? 2.0 : 1.2);
    score += this.getBodyRemotenessBonus(body) / (stage === 'late' ? 900 : 2600);
    score += this.getPhaseOneNarrativeScore(body) * (stage === 'opening' ? 1.35 : 0.95);
    score += this.getPhaseBodyBias(body);

    if (stage === 'opening' && this.estimateTransferMargin(body, 'explorer') > 900) {
      score -= 2.25;
    }

    return score;
  }

  getColonizationCandidateScore(body, player, stage) {
    let score = Number(body?.strategicValue || 1) * 1.35;
    const proximity = this.getBodyProximityScore(player, body);

    const resourceTags = Array.isArray(body?.resourceTags) ? body.resourceTags : [];
    if (resourceTags.includes('water')) score += 2;
    if (resourceTags.includes('industry')) score += 1.75;
    if (resourceTags.includes('trade')) score += 1.0;
    if (resourceTags.includes('construction')) score += 1.0;
    if (resourceTags.includes('frontier')) score += 0.5;

    score += proximity * (stage === 'early_expansion' ? 2.4 : 1.6);
    score += this.getBodyRemotenessBonus(body) / (stage === 'late' ? 1000 : 3200);
    score += this.getPhaseOneNarrativeScore(body) * 0.75;
    score += this.getPhaseBodyBias(body);

    return score;
  }

  colonyResourcePressure(colony, resourceName, multiplier = 1) {
    const coverageDays = colony.getEstimatedStockCoverageDays?.(resourceName, { includeGrowth: true }) ?? Infinity;
    if (!Number.isFinite(coverageDays)) return 0;

    return Math.max(0, ((16 - Math.min(16, coverageDays)) / 16) * multiplier);
  }

  getInfrastructureNeedsForColony(colony, availableBlueprints) {
    const existingNames = new Set(
      (colony.buildings || []).map((building) =>
        this.normalizeText(building.blueprintName || building.name)
      )
    );

    const existingTypes = new Set(
      (colony.buildings || []).map((building) =>
        this.normalizeText(building.type)
      )
    );

    const queuedNames = new Set(
      (colony.constructionQueue || []).map((project) =>
        this.normalizeText(project.blueprintName)
      )
    );

    return availableBlueprints
      .map((blueprint) => {
        const normalizedName = this.normalizeText(blueprint.name);
        const normalizedType = this.normalizeText(blueprint.type);

        if (existingNames.has(normalizedName) || queuedNames.has(normalizedName)) {
          return null;
        }

        let weight = 1;

        if (
          !existingTypes.has('shipyard') &&
          (normalizedType === 'shipyard' || normalizedName.includes('shipyard'))
        ) {
          weight += 5;
        }

        if (
          (colony.powerEfficiency ?? 1) < 0.95 &&
          (
            normalizedName.includes('solar') ||
            normalizedName.includes('reactor') ||
            normalizedName.includes('power') ||
            normalizedType === 'power'
          )
        ) {
          weight += 4;
        }

        if (normalizedName.includes('water')) {
          weight += this.colonyResourcePressure(colony, 'Water', 2.5);
        }

        if (
          normalizedName.includes('food') ||
          normalizedName.includes('farm') ||
          normalizedName.includes('hydropon')
        ) {
          weight += this.colonyResourcePressure(colony, 'Food', 2.5);
        }

        if (
          normalizedName.includes('goods') ||
          normalizedName.includes('factory') ||
          normalizedName.includes('manufact')
        ) {
          weight += this.colonyResourcePressure(colony, 'Goods', 1.75);
        }

        if (
          normalizedName.includes('mine') ||
          normalizedName.includes('extract') ||
          normalizedName.includes('refinery')
        ) {
          weight += 2.25;
        }

        if ((colony.population || 0) > 2500 && normalizedName.includes('hab')) {
          weight += 1.5;
        }

        if ((colony.constructionQueue || []).length === 0) {
          weight += 0.5;
        }

        return {
          blueprint,
          weight
        };
      })
      .filter(Boolean)
      .sort((a, b) => b.weight - a.weight);
  }

  pickRandomIssuer(aiPlayers) {
    if (!aiPlayers || aiPlayers.length === 0) return null;
    return this.game.pickRandom(aiPlayers);
  }

  pickIssuerForCandidate(aiPlayers, excludedPlayers = []) {
    const excludedSet = new Set(excludedPlayers);
    const availableIssuers = aiPlayers.filter((ai) => !excludedSet.has(ai));

    if (availableIssuers.length > 0) {
      return this.pickRandomIssuer(availableIssuers);
    }

    return this.pickRandomIssuer(aiPlayers);
  }

  pickWeightedCandidate(candidates) {
    if (!candidates || candidates.length === 0) return null;

    const totalWeight = candidates.reduce((sum, candidate) => sum + Math.max(0.1, candidate.weight || 1), 0);
    let roll = this.game.random() * totalWeight;

    for (const candidate of candidates) {
      roll -= Math.max(0.1, candidate.weight || 1);
      if (roll <= 0) {
        return candidate;
      }
    }

    return candidates[candidates.length - 1];
  }

  getMaxOpenContracts() {
    const humanPlayer = this.getHumanPlayer();
    const colonyCount = humanPlayer?.colonies?.length || 0;
    const exploredCount = this.getExploredBodiesForPlayer(humanPlayer).length;
    const researchCount = humanPlayer?.completedResearch?.length || 0;
    const phaseId = this.getCurrentStoryPhase();
    const directiveRatio = this.getNarrativeDirectiveCompletionRatio();

    let maxOpen = 4;

    if (colonyCount >= 2) maxOpen += 1;
    if (exploredCount >= 6) maxOpen += 1;
    if (researchCount >= 4) maxOpen += 1;

    if (phaseId === 'phase_1_earth_crisis') {
      if (this.isEarthInStarvationEmergency()) {
        return Math.max(3, this.maxActiveEmergencyBounties + 1);
      }
      if (directiveRatio < 0.25) return 1;
      if (directiveRatio < 0.6) return 2;
      return 3;
    }

    if (phaseId === 'phase_2_inner_system_expansion') {
      maxOpen = Math.max(maxOpen, 4);
    }

    if (phaseId === 'phase_3_outer_worlds') {
      maxOpen = Math.max(maxOpen, 5);
    }

    return Math.min(7, maxOpen);
  }

  shouldGenerateNewContract() {
    const openContracts = this.getOpenContracts();
    const maxOpen = this.getMaxOpenContracts();
    const stage = this.getContractGenerationStage();
    const phaseId = this.getCurrentStoryPhase();
    const directiveRatio = this.getNarrativeDirectiveCompletionRatio();
    const minTurns =
      stage === 'opening' ? 1 :
      stage === 'early_expansion' ? 1 :
      this.minTurnsBetweenGenerations;

    if (openContracts.length >= maxOpen) return false;
    if ((this.game.turnNumber - this.lastGenerationTurn) < minTurns) return false;

    const shortage = Math.max(1, maxOpen - openContracts.length);
    let baseChance;

    if (phaseId === 'phase_1_earth_crisis') {
      baseChance = directiveRatio < 0.25 ? 0.2 : directiveRatio < 0.6 ? 0.35 : 0.5;
    } else if (phaseId === 'phase_2_inner_system_expansion') {
      baseChance = stage === 'opening' ? 0.38 : stage === 'early_expansion' ? 0.30 : 0.22;
    } else {
      baseChance = stage === 'opening' ? 0.32 : stage === 'early_expansion' ? 0.26 : 0.18;
    }

    const chance = Math.min(0.9, baseChance + (shortage * 0.12));
    return this.game.randomChance(chance);
  }

  getPotentialBuildBidders(aiPlayers, body, buildingName, options = {}) {
    const {
      habitatNeeded = false,
      requireExistingColony = false
    } = options;

    const buildingBlueprint = this.getBlueprintByName(buildingName);
    const habitatBlueprint = this.getBlueprintByName('Habitat');
    const requiredUpfrontCredits = this.estimateBuildUpfrontCredits(body, buildingName, { habitatNeeded });

    return aiPlayers.filter((ai) => {
      const spendableCredits =
        typeof ai.getAvailableCredits === 'function' ? ai.getAvailableCredits() : ai.credits;

      if (spendableCredits < requiredUpfrontCredits) {
        return false;
      }

      if (buildingBlueprint && !this.hasRequiredResearch(ai, buildingBlueprint.requiredResearch)) {
        return false;
      }

      if (habitatNeeded && habitatBlueprint && !this.hasRequiredResearch(ai, habitatBlueprint.requiredResearch)) {
        return false;
      }

      if (requireExistingColony && !this.playerHasColonyOn(ai, body)) {
        return false;
      }

      if (habitatNeeded) {
        const exploredBodies = this.getExploredBodyNameSet(ai);
        if (!exploredBodies.has(this.normalizeText(body.name))) {
          return false;
        }
      }

      return true;
    });
  }

  estimateBuildUpfrontCredits(targetBody, buildingName, { habitatNeeded = false } = {}) {
    const habitatCreditCost = habitatNeeded
      ? (this.getBlueprintByName('Habitat')?.costToBuild?.Credits || 0)
      : 0;

    const normalizedBuildingName = this.normalizeText(buildingName);
    const buildingCreditCost =
      normalizedBuildingName === 'habitat' && habitatNeeded
        ? 0
        : (this.getBlueprintByName(buildingName)?.costToBuild?.Credits || 0);

    const transferMargin = this.estimateTransferMargin(targetBody, 'construction');

    return habitatCreditCost + buildingCreditCost + Math.ceil(transferMargin * 0.15);
  }

  hasAnyAIExploredBody(aiPlayers, body) {
    const normalizedBodyName = this.normalizeText(body?.name);
    return aiPlayers.some((ai) => this.getExploredBodyNameSet(ai).has(normalizedBodyName));
  }

  isBodyValidForCurrentPhase(body) {
    const phaseId = this.getCurrentStoryPhase();
    const semiMajorAxis = Number(body?.orbitalElements?.semiMajorAxis || 0);

    if (phaseId === 'phase_1_earth_crisis') {
      return body?.name === 'Moon' || semiMajorAxis <= 2e11;
    }

    if (phaseId === 'phase_2_inner_system_expansion') {
      return semiMajorAxis <= 1.5e12;
    }

    return semiMajorAxis >= 4e11 || body?.name === 'Ceres' || body?.name === 'Europa' || body?.name === 'Titan';
  }

  buildExploreContractCandidates(player, aiPlayers, stage) {
    const explored = this.getExploredBodyNameSet(player);
    const sliceCount =
      this.getCurrentStoryPhase() === 'phase_1_earth_crisis'
        ? (stage === 'opening' ? 8 : stage === 'early_expansion' ? 7 : 8)
        : (stage === 'opening' ? 5 : stage === 'early_expansion' ? 6 : 8);

    return this.game.bodies
      .filter((body) =>
        this.isBodyEligibleForExploration(body) &&
        this.isBodyValidForCurrentPhase(body) &&
        !explored.has(this.normalizeText(body.name))
      )
      .sort((a, b) => this.getExploreCandidateScore(b, player, stage) - this.getExploreCandidateScore(a, player, stage))
      .slice(0, sliceCount)
      .map((body) => {
        const issuer = this.pickRandomIssuer(aiPlayers);
        if (!issuer) return null;

        return {
          task: this.getExploreContractTaskLabel(body, stage),
          issuer: issuer.name,
          reward: this.calculateExploreReward(body, player, stage),
          requirements: {
            task: 'explore',
            target: body.name
          },
          weight: this.getExploreCandidateScore(body, player, stage),
          storyMeta: {
            phase: this.getCurrentStoryPhase(),
            narrativeContext: this.getCurrentStoryPhase() === 'phase_1_earth_crisis' ? 'earth_stabilization' : this.getCurrentStoryPhase()
          }
        };
      })
      .filter(Boolean);
  }

  buildColonizationContractCandidates(player, aiPlayers, stage) {
    if (stage === 'opening' || this.getCurrentStoryPhase() === 'phase_1_earth_crisis') {
      return [];
    }

    const habitatBlueprint = this.getBlueprintByName('Habitat');
    if (habitatBlueprint && !this.hasRequiredResearch(player, habitatBlueprint.requiredResearch)) {
      return [];
    }

    const explored = this.getExploredBodyNameSet(player);
    const sliceCount = stage === 'early_expansion' ? 2 : 4;

    return this.game.bodies
      .filter((body) =>
        body?.isColonizable &&
        body.name !== 'Earth' &&
        this.isBodyValidForCurrentPhase(body) &&
        explored.has(this.normalizeText(body.name)) &&
        !this.playerHasColonyOn(player, body) &&
        this.hasAnyAIExploredBody(aiPlayers, body)
      )
      .sort((a, b) => this.getColonizationCandidateScore(b, player, stage) - this.getColonizationCandidateScore(a, player, stage))
      .slice(0, sliceCount)
      .map((body) => {
        const capableBidders = this.getPotentialBuildBidders(aiPlayers, body, 'Habitat', {
          habitatNeeded: true,
          requireExistingColony: false
        });

        if (capableBidders.length === 0) {
          return null;
        }

        const issuer = this.pickIssuerForCandidate(aiPlayers, capableBidders);
        if (!issuer) {
          return null;
        }

        return {
          task: this.getBuildContractTaskLabel(body, 'Habitat'),
          issuer: issuer.name,
          reward: this.calculateBuildReward(body, 'Habitat', player, stage),
          requirements: {
            task: 'build',
            target: body.name,
            building: 'Habitat'
          },
          weight: this.getColonizationCandidateScore(body, player, stage),
          storyMeta: {
            phase: this.getCurrentStoryPhase(),
            narrativeContext: this.getCurrentStoryPhase() === 'phase_2_inner_system_expansion' ? 'inner_system_expansion' : 'outer_worlds'
          }
        };
      })
      .filter(Boolean);
  }

  buildInfrastructureContractCandidates(player, aiPlayers, stage) {
    if (stage === 'opening' || !player?.colonies?.length) {
      return [];
    }

    const buildCreditCap = this.getStageBuildCreditCap(stage);
    const phaseId = this.getCurrentStoryPhase();

    let availableBlueprints = this.game.buildingBlueprints.filter((blueprint) =>
      blueprint &&
      blueprint.name &&
      blueprint.type !== 'habitat' &&
      (blueprint.costToBuild?.Credits || 0) <= buildCreditCap &&
      this.hasRequiredResearch(player, blueprint.requiredResearch) &&
      aiPlayers.some((ai) => this.hasRequiredResearch(ai, blueprint.requiredResearch))
    );

    let candidateColonies = player.colonies.filter((colony) =>
      aiPlayers.some((ai) => this.playerHasColonyOn(ai, colony.planet))
    );

    if (phaseId === 'phase_1_earth_crisis') {
      const earthColony = this.getEarthColony(player);

      availableBlueprints = availableBlueprints.filter((blueprint) =>
        this.isEarthStabilizationBlueprint(blueprint) &&
        !this.isFactoryBlueprint(blueprint) &&
        !this.isMineBlueprint(blueprint)
      );

      candidateColonies = earthColony ? [earthColony] : [];
    } else if (phaseId === 'phase_2_inner_system_expansion') {
      availableBlueprints = availableBlueprints.filter((blueprint) => !this.isFactoryBlueprint(blueprint) || this.normalizeText(blueprint.name).includes('goods'));
      candidateColonies = candidateColonies.filter((colony) => this.normalizeText(colony?.planet?.name) !== 'earth');
    }

    if (availableBlueprints.length === 0 || candidateColonies.length === 0) {
      return [];
    }

    const candidates = [];

    candidateColonies.forEach((colony) => {
      const colonyNeeds = this.getInfrastructureNeedsForColony(
        colony,
        availableBlueprints
      ).slice(0, stage === 'early_expansion' ? 1 : 2);

      colonyNeeds.forEach(({ blueprint, weight }) => {
        const requireExistingColony = phaseId !== 'phase_1_earth_crisis';
        const capableBidders = this.getPotentialBuildBidders(aiPlayers, colony.planet, blueprint.name, {
          habitatNeeded: false,
          requireExistingColony
        });

        if (capableBidders.length === 0) {
          return;
        }

        const issuer = this.pickIssuerForCandidate(aiPlayers, capableBidders);
        if (!issuer) {
          return;
        }

        candidates.push({
          task: this.getBuildContractTaskLabel(colony.planet, blueprint.name),
          issuer: issuer.name,
          reward: this.calculateBuildReward(colony.planet, blueprint.name, player, stage),
          requirements: {
            task: 'build',
            target: colony.planet.name,
            building: blueprint.name
          },
          weight: weight + (this.getBodyProximityScore(player, colony.planet) * 0.6),
          storyMeta: {
            phase: this.getCurrentStoryPhase(),
            narrativeContext: phaseId === 'phase_1_earth_crisis' ? 'earth_stabilization' : phaseId
          }
        });
      });
    });

    return candidates
      .sort((a, b) => (b.weight || 1) - (a.weight || 1))
      .slice(0, stage === 'early_expansion' ? 3 : 8);
  }

  buildFactionStrategicCandidates(player, aiPlayers, stage) {
    const candidates = [];
    const exploredNames = this.getExploredBodyNameSet(player);

    aiPlayers.forEach(issuer => {
      const archetype = issuer.factionProfile?.archetype || issuer.aiType || 'independent';
      const issuerColony = issuer.colonies?.[0] || null;

      if (archetype === 'scientific') {
        const body = this.game.bodies.find(candidate =>
          ['planet', 'moon', 'dwarf_planet', 'asteroid'].includes(candidate.type) &&
          candidate.name !== 'Earth' &&
          !exploredNames.has(this.normalizeText(candidate.name))
        );
        if (body) {
          candidates.push({
            task: `Share a complete survey of ${body.name}`,
            issuer,
            reward: this.calculateExploreReward(body, player, stage) * 1.1,
            requirements: { task: 'explore', target: body.name },
            weight: 1.2,
            storyMeta: { narrativeContext: 'faction_science' }
          });
        }
      }

      if (archetype === 'commercial' && issuerColony) {
        const resource = ['Fuel', 'Goods', 'Food'].sort((a, b) =>
          Number(issuerColony.getResourceAmount?.(a) || 0) - Number(issuerColony.getResourceAmount?.(b) || 0)
        )[0];
        const amount = 80;
        candidates.push({
          task: `Secure ${resource} supply for ${issuerColony.planet.name}`,
          issuer,
          reward: this.roundReward(900 + this.getBodyRemotenessBonus(issuerColony.planet)),
          requirements: { task: 'deliver', target: issuerColony.planet.name, resource, amount },
          weight: 1.1,
          storyMeta: { narrativeContext: 'faction_trade' }
        });
      }

      if (archetype === 'military' && issuerColony) {
        candidates.push({
          task: `Patrol the approaches to ${issuerColony.planet.name}`,
          issuer,
          reward: this.roundReward(1100 + this.getBodyRemotenessBonus(issuerColony.planet)),
          requirements: { task: 'patrol', target: issuerColony.planet.name },
          weight: 0.9,
          storyMeta: { narrativeContext: 'faction_security' }
        });
      }
    });

    return candidates;
  }

  generateFallbackPhaseOneContract() {
    const humanPlayer = this.getHumanPlayer();
    const aiPlayers = this.getAIPlayers();

    if (!humanPlayer || aiPlayers.length === 0) {
      return null;
    }

    const surveyTarget = this.game.getPhaseOneSurveyTarget?.();
    const moon = this.game.bodies.find((body) => body.name === 'Moon');
    const explored = this.getExploredBodyNameSet(humanPlayer);

    const body =
      [moon, surveyTarget]
        .filter(Boolean)
        .find((candidate) => !explored.has(this.normalizeText(candidate.name))) ||
      this.game.bodies.find((candidate) =>
        this.isBodyEligibleForExploration(candidate) &&
        this.isBodyValidForCurrentPhase(candidate) &&
        !explored.has(this.normalizeText(candidate.name))
      );

    if (!body) {
      return null;
    }

    const issuer = this.pickRandomIssuer(aiPlayers)?.name;
    const fallbackCandidate = {
      task: this.getExploreContractTaskLabel(body, 'opening'),
      issuer,
      reward: this.calculateExploreReward(body, humanPlayer, 'opening'),
      requirements: {
        task: 'explore',
        target: body.name
      },
      storyMeta: {
        phase: 'phase_1_earth_crisis',
        narrativeContext: 'earth_stabilization'
      }
    };

    if (!fallbackCandidate.issuer || this.hasDuplicateActiveContract(fallbackCandidate)) {
      return null;
    }

    const created = this.createContract(fallbackCandidate);
    if (!created) {
      return null;
    }

    this.lastGenerationTurn = this.game.turnNumber;
    this.game.windowManager?.refreshHud?.();
    return created;
  }

  ensurePhaseOneContractFlow({ force = false, minimumOpenContracts = 1 } = {}) {
    if (this.getCurrentStoryPhase() !== 'phase_1_earth_crisis') {
      return null;
    }

    let created = null;
    let safety = 0;

    this.ensureEmergencyBounties({ force });

    while (this.getOpenContracts().length < minimumOpenContracts && safety < 5) {
      const nextContract = this.generateSmartContracts({ force: true });
      if (!nextContract) {
        break;
      }
      created = nextContract;
      safety += 1;
    }

    if (this.getOpenContracts().length === 0) {
      const fallback = this.generateFallbackPhaseOneContract();
      if (fallback) {
        created = fallback;
      }
    }

    if (!force && this.getOpenContracts().length >= minimumOpenContracts) {
      const incidental = this.generateSmartContracts();
      if (incidental) {
        created = incidental;
      }
    }

    return created;
  }

  generateSmartContracts({ force = false } = {}) {
    if (!force && !this.shouldGenerateNewContract()) {
      return null;
    }

    const humanPlayer = this.getHumanPlayer();
    const aiPlayers = this.getAIPlayers();

    if (!humanPlayer || aiPlayers.length === 0) {
      return null;
    }

    const stage = this.getContractGenerationStage();
    const typeWeights = this.getStageContractTypeWeights(stage);

    const exploreCandidates = this.buildExploreContractCandidates(humanPlayer, aiPlayers, stage)
      .map((candidate) => ({
        ...candidate,
        weight: (candidate.weight || 1) * typeWeights.explore
      }));

    const colonizationCandidates = this.buildColonizationContractCandidates(humanPlayer, aiPlayers, stage)
      .map((candidate) => ({
        ...candidate,
        weight: (candidate.weight || 1) * typeWeights.colonize
      }));

    const infrastructureCandidates = this.buildInfrastructureContractCandidates(humanPlayer, aiPlayers, stage)
      .map((candidate) => ({
        ...candidate,
        weight: (candidate.weight || 1) * typeWeights.infrastructure
      }));

    const factionCandidates = this.buildFactionStrategicCandidates(humanPlayer, aiPlayers, stage);

    const candidates = [
      ...exploreCandidates,
      ...colonizationCandidates,
      ...infrastructureCandidates,
      ...factionCandidates
    ].filter((candidate) => !this.hasDuplicateActiveContract(candidate));

    if (candidates.length === 0) {
      return null;
    }

    const selected = this.pickWeightedCandidate(candidates);
    if (!selected) {
      return null;
    }

    const created = this.createContract(selected);
    if (!created) {
      return null;
    }

    this.lastGenerationTurn = this.game.turnNumber;

    this.game.logAI?.(
      null,
      'CONTRACT_MARKET',
      `Generated contract "${created.task}"`,
      {
        stage,
        phase: this.getCurrentStoryPhase(),
        issuer: created.issuer?.name || selected.issuer,
        reward: created.reward,
        requirements: created.requirements,
        narrativeContext: created.storyMeta?.narrativeContext || null
      }
    );

    this.game.windowManager?.refreshHud?.();
    return created;
  }
}
ContractManager;


// ===== public/classes/managers/EventEmitter.js =====

class EventEmitter {
  constructor() {
    this.events = new Map();
    this.scopes = new Map();
  }

  on(event, listener, options = {}) {
    if (!event || typeof listener !== 'function') return () => {};
    if (!this.events.has(event)) this.events.set(event, new Set());
    const entry = { listener, once: !!options.once, scope: options.scope || null };
    this.events.get(event).add(entry);
    if (entry.scope) {
      if (!this.scopes.has(entry.scope)) this.scopes.set(entry.scope, new Set());
      this.scopes.get(entry.scope).add({ event, entry });
    }
    return () => this.off(event, listener);
  }

  once(event, listener, options = {}) {
    return this.on(event, listener, { ...options, once: true });
  }

  emit(event, ...args) {
    const entries = [...(this.events.get(event) || [])];
    entries.forEach(entry => {
      try {
        entry.listener(...args);
      } catch (error) {
        console.error(`Event listener failed for ${event}:`, error);
      }
      if (entry.once) this.off(event, entry.listener);
    });
    return entries.length;
  }

  off(event, listenerToRemove) {
    const entries = this.events.get(event);
    if (!entries) return false;
    let removed = false;
    [...entries].forEach(entry => {
      if (!listenerToRemove || entry.listener === listenerToRemove) {
        entries.delete(entry);
        removed = true;
      }
    });
    if (!entries.size) this.events.delete(event);
    return removed;
  }

  clearScope(scope) {
    const scoped = this.scopes.get(scope);
    if (!scoped) return;
    scoped.forEach(({ event, entry }) => this.events.get(event)?.delete(entry));
    this.scopes.delete(scope);
  }

  clear() {
    this.events.clear();
    this.scopes.clear();
  }
}
EventEmitter;


