function listify(value) {
  if (!value) return [];
  return Array.isArray(value) ? value.filter(Boolean) : [value];
}

function titleCase(value) {
  return String(value || '')
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase());
}

const STORY_PHASE_SEQUENCE = [
  'phase_1_earth_crisis',
  'phase_2_inner_system_expansion',
  'phase_3_outer_worlds'
];

function getStoryPhaseIndex(phaseId) {
  const index = STORY_PHASE_SEQUENCE.indexOf(String(phaseId || 'phase_1_earth_crisis'));
  return index >= 0 ? index : 0;
}

function normalizeStoryPhaseList(value) {
  const phases = listify(value);
  return phases.length > 0 ? phases : ['phase_1_earth_crisis'];
}
